--
-- TOC entry 635 (class 1255 OID 53740)
-- Name: amplitude_transito_atual(character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.amplitude_transito_atual(idprod character varying) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
declare 
    amp numeric;
begin 
   
   select
	round(((tempo_medio_ressuprimento-amplitude))::numeric,1)
 into amp
from
	(
	select
		vw_requisicoes.idproduto::varchar,
		data_prevista_cal,
		(case
			when data_previsao is null then (data_prevista_cal - current_date)
			else (data_prevista_cal - current_date)
		end) amplitude,
		perfil_demanda,
		tempo_medio_ressuprimento
	from
		vw_requisicoes
	 inner join produtos
   on produtos.idproduto = vw_requisicoes.idproduto::varchar
	where
		vw_requisicoes.idproduto::varchar = idprod
		and data_entrada isnull  order by data_solicitacao desc limit 1)a;
	
    
    return coalesce(amp,0);

end;

$$;


ALTER FUNCTION public.amplitude_transito_atual(idprod character varying) OWNER TO systock;

--
-- TOC entry 636 (class 1255 OID 53741)
-- Name: amplitude_transito_atual_filial(numeric, character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.amplitude_transito_atual_filial(p_filial numeric, idprod character varying) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
declare amp numeric;
begin
	select round(((tempo_medio_ressuprimento - amplitude))::numeric, 1)
	into amp
	from (
		select vw_requisicoes.idproduto::varchar
			,data_prevista_cal
			,(
				case 
					when data_previsao is null
						then (data_prevista_cal - current_date)
					else (data_prevista_cal - current_date)
					end
				) amplitude
			,perfil_demanda
			,tempo_medio_ressuprimento
		from vw_requisicoes
		inner join  produtos_filial as produtos on  produtos.filial = vw_requisicoes.filial and produtos.idproduto = vw_requisicoes.idproduto::varchar
		where vw_requisicoes.idproduto::varchar = idprod
			and vw_requisicoes.filial = p_filial
			and data_entrada isnull
		order by data_solicitacao desc limit 1
		) a;
	return coalesce(amp, 0);
end;$$;


