CREATE FUNCTION public.first_day(dataref date) RETURNS date
    LANGUAGE plpgsql
    AS $_$
declare
first_day date;
begin
    first_day = (select (date_trunc('month', $1) - interval '1 month' + interval '1 month')::date);
   
    return first_day;
 end;
$_$;


ALTER FUNCTION public.first_day(dataref date) OWNER TO systock;

--
-- TOC entry 644 (class 1255 OID 53749)
-- Name: first_day_trimestre(date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.first_day_trimestre(dataref date) RETURNS date
    LANGUAGE plpgsql
    AS $$
declare
first_day date;
begin
      
	select 
		case 
		when date_part('quarter',dataref)  = 1 then (date_trunc('month', ('01/01'||to_char(dataref,'/yyyy'))::date))::date
		when date_part('quarter',dataref)  = 2 then (date_trunc('month', ('01/04'||to_char(dataref,'/yyyy'))::date))::date
		when date_part('quarter',dataref)  = 3 then (date_trunc('month', ('01/07'||to_char(dataref,'/yyyy'))::date))::date
		when date_part('quarter',dataref)  = 4 then (date_trunc('month', ('01/10'||to_char(dataref,'/yyyy'))::date))::date
		end 
	into first_day;

    return first_day;
 end;
$$;


ALTER FUNCTION public.first_day_trimestre(dataref date) OWNER TO systock;

