--
-- TOC entry 648 (class 1255 OID 53753)
-- Name: gerar_gatilho_compras_grupo(); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.gerar_gatilho_compras_grupo() RETURNS void
    LANGUAGE plpgsql
    AS $$
declare 

  rec_prod record;
  existe numeric;
  tmp_forecast int4;
 
begin

 -- Em gatilho de Compra 
 	
  for rec_prod in (select id_grupo,idproduto,'CP' as tipo,round(estoque::numeric,4) estoque,ceil(lote_compras) as sugestao,ponto_pedido,tempo_ressuprimento,desvio_padrao_ressuprimento,arvore_decisao
					   FROM produtos_compras_grupo vgcp
					     JOIN departamentos dpto ON dpto.iddepartamento = vgcp.idfamilia_produto
					  WHERE vgcp.lote_compras > 0::numeric AND vgcp.sob_encomenda = 0 
					       AND vgcp.revenda::text = 'S'::text 
					       AND vgcp.revenda::text <> 'FL'::text 
					       AND dpto.descricao_departamento::text !~~ '%FEIRAO%'::text 
					       AND dpto.descricao_departamento::text !~~ '%AVARIA%'::text
 					 )
  loop
  
          
      
           select count(*) into existe from hist_gatilho_compras_grupo where grupo=rec_prod.id_grupo and idproduto=rec_prod.idproduto and tipo='CP' and status='A';
          
           if existe = 0 then 
           
               INSERT INTO hist_gatilho_compras_grupo
				(grupo, idproduto, "data", tipo, status, estoque, ponto_pedido, sugestao, arvore_decisao, tempo_reposicao, std_dv_tempo_reposicao)
				VALUES(rec_prod.id_grupo,rec_prod.idproduto,current_date,rec_prod.tipo, 'A'::character varying,rec_prod.estoque,rec_prod.ponto_pedido,
			            rec_prod.sugestao,rec_prod.arvore_decisao,rec_prod.tempo_ressuprimento, rec_prod.desvio_padrao_ressuprimento);
                    
           end if;
 

  end loop;
 
 -- Em gatilho de Compra Transito
 
 for rec_prod in (SELECT t.id_grupo,
				    'TR'::text AS tipo,
				    t.idproduto,
				    round(t.estoque::numeric,4) as estoque,
				    ceil(t.lote_compras) AS sugestao
				   FROM produtos_transito t
				  WHERE t.lote_compras > 0::double precision)
  loop
  
          
           select count(*) into existe from hist_gatilho_compras_grupo where grupo=rec_prod.id_grupo and idproduto=rec_prod.idproduto and tipo='TR' and status='A';
          
           if existe = 0 then 
           
               INSERT INTO hist_gatilho_compras_grupo
				(grupo, idproduto, "data", tipo, status, estoque, sugestao)
				VALUES(rec_prod.id_grupo,rec_prod.idproduto,current_date,rec_prod.tipo, 'A'::character varying,rec_prod.estoque,rec_prod.sugestao);
                    
           end if;
 

  end loop;
 
 -- Em Forecast
 

 
 for rec_prod in (SELECT t.id_grupo,
				    t.idfornecedor,
				    'FC'::text AS tipo,
				    t.idproduto,
				    round(t.estoque::numeric,4) as estoque ,
				    ceil(t.lote_compras) AS sugestao
				   FROM produtos_forecast t)
  loop
  
           select f.tempo_forecast  into tmp_forecast from fornecedor f  where f.id = rec_prod.idfornecedor;
  
          
           select count(*) into existe from hist_gatilho_compras_grupo where grupo=rec_prod.id_grupo and idproduto=rec_prod.idproduto and tipo='FC' and status='A';
          
           if existe = 0 then 
           
               INSERT INTO hist_gatilho_compras_grupo
				(grupo, idproduto, "data", tipo, status, estoque, sugestao)
				VALUES(rec_prod.id_grupo,rec_prod.idproduto,(current_date+tmp_forecast),rec_prod.tipo, 'A'::character varying,rec_prod.estoque,rec_prod.sugestao);
                    
           end if;
 

  end loop;
 
 -- Fechamento do Gatilho por Pedido de Compras 
 
 for rec_prod in (select
					    distinct 
						gf.id_grupo,
						pf.idproduto,
						ultima_riquisicao_entrada ,
						data_ultima_riquisicao
					from
						produtos_filial pf
					inner join grupo_filial gf on
						gf.filial = pf.filial
					where
						status_suprimento_sku = 'AGUARDANDO ENTRADA')
  loop
          
   
         UPDATE public.hist_gatilho_compras_grupo SET status='F', idrequisicao=rec_prod.ultima_riquisicao_entrada::numeric,data_requisicao=rec_prod.data_ultima_riquisicao 
          WHERE grupo=rec_prod.id_grupo and idproduto=rec_prod.idproduto AND status='A' and "data" <= rec_prod.data_ultima_riquisicao;

  end loop;
 
 -- Fechamento de itens por sairem de momento de compras

 for rec_prod in (select
						grupo,
						idproduto,
						0 as ultima_riquisicao_entrada ,
						current_date as data_ultima_riquisicao
					from
						hist_gatilho_compras_grupo hgcg
					where
						(grupo,
						idproduto ) in (
						select
							id_grupo ,
							idproduto
						from
							produtos_compras_grupo vgcp
						where
							lote_compras = 0)
						and status = 'A')
  loop
          
   
         UPDATE public.hist_gatilho_compras_grupo SET status='F', idrequisicao=rec_prod.ultima_riquisicao_entrada::numeric,data_requisicao=rec_prod.data_ultima_riquisicao 
          WHERE grupo=rec_prod.grupo and idproduto=rec_prod.idproduto AND status='A' and "data" <= rec_prod.data_ultima_riquisicao;

  end loop;
 
 
  --Limpando Itens em Forecast que já sairam e mudaram para categoria;
 
   delete from hist_gatilho_compras_grupo where (grupo,idproduto) not in (SELECT t.id_grupo,t.idproduto FROM produtos_forecast t) and status='A' and tipo='FC';
 
 --Limpando Itens em Transito que já sairam e mudaram para outra categoria; 
 
   delete from hist_gatilho_compras_grupo where (grupo,idproduto) not in (select id_grupo,idproduto FROM produtos_transito ) and status='A' and tipo='TR'; 


end;


$$;


ALTER FUNCTION public.gerar_gatilho_compras_grupo() OWNER TO systock;

--
-- TOC entry 649 (class 1255 OID 53754)
-- Name: gerar_lote_embalagem(numeric, numeric); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.gerar_lote_embalagem(lote numeric, lote_minimo numeric) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
declare 

    resto_lote numeric;
    resultado numeric;
   
begin
	
	if coalesce(lote_minimo,1) = 0 then lote_minimo=1; end if;
	
	
	resto_lote =  ceil(mod(lote,lote_minimo))/lote_minimo;
	
    if resto_lote >=0.5 then 
    
    
        resultado = ((lote_minimo - MOD(lote,lote_minimo))+ lote);
    
    
      else
      
      
       resultado = ((lote - MOD(lote,lote_minimo)));
      
      
    end if; 
	
		     
    return resultado;

end;

$$;


ALTER FUNCTION public.gerar_lote_embalagem(lote numeric, lote_minimo numeric) OWNER TO systock;

--
-- TOC entry 650 (class 1255 OID 53755)
-- Name: gerar_lote_embalagem_dist(numeric, numeric); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.gerar_lote_embalagem_dist(lote numeric, lote_minimo numeric) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
declare 

    resto_lote numeric;
    resultado numeric;
   
begin
    
    if coalesce(lote_minimo, 1) = 0 then 
        lote_minimo = 1; 
    end if;

    resto_lote =  CEIL(mod(lote, lote_minimo)) / lote_minimo;
    
    if resto_lote >= 0.5 then 
    
        RETURN (lote_minimo - MOD(lote, lote_minimo)) + lote;
          
    end if;
        
    RETURN lote - MOD(lote, lote_minimo);

end;
$$;


ALTER FUNCTION public.gerar_lote_embalagem_dist(lote numeric, lote_minimo numeric) OWNER TO systock;

--
-- TOC entry 651 (class 1255 OID 53756)
-- Name: gerar_prisma_diario(date, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.gerar_prisma_diario(dataini date, datafim date) RETURNS void
    LANGUAGE plpgsql
    AS $$
declare 

  rec_prod record;
begin

  for rec_prod in (select idproduto,"data" from saldos where "data" between dataini and datafim and arvore_decisao is null  order by idproduto,"data")
  loop
  
       update saldos set arvore_decisao=get_prismas_analise(idproduto,rec_prod.data::date) where idproduto =rec_prod.idproduto and data = rec_prod.data::date;

  end loop;

end;

$$;


ALTER FUNCTION public.gerar_prisma_diario(dataini date, datafim date) OWNER TO systock;

--
-- TOC entry 652 (class 1255 OID 53757)
-- Name: gerar_prisma_diario_filial(date, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.gerar_prisma_diario_filial(dataini date, datafim date) RETURNS void
    LANGUAGE plpgsql
    AS $$
declare 
  rec_prod record;
begin

  for rec_prod in (select filial,idproduto,"data" from saldo_filiais sf where "data" between dataini and datafim and arvore_decisao is null  order by idproduto,"data",filial)

  loop

       update saldo_filiais set arvore_decisao=get_prismas_analise_filial(rec_prod.filial,idproduto,rec_prod.data::date) where filial =rec_prod.filial and idproduto =rec_prod.idproduto and data = rec_prod.data::date;

  end loop;

end;

$$;


ALTER FUNCTION public.gerar_prisma_diario_filial(dataini date, datafim date) OWNER TO systock;

--
-- TOC entry 653 (class 1255 OID 53758)
-- Name: gerar_prismas_filiais(numeric, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.gerar_prismas_filiais(p_filial numeric, dataref date DEFAULT ('now'::text)::date) RETURNS TABLE(produto character varying, arvore text)
    LANGUAGE plpgsql PARALLEL SAFE
    AS $$
declare retorno varchar;
table_temp1 varchar;
table_temp2 varchar;
table_temp3 varchar;
table_temp4 varchar;
begin
	
		 
		table_temp1 = 'f' || p_filial || '_tmp_classificacao_financeira_' || to_char(dataref, 'mmyyyy');
		table_temp2 = 'f' || p_filial || '_tmp_classificacao_criticidade_' || to_char(dataref, 'mmyyyy');
		table_temp3 = 'f' || p_filial || '_tmp_classificacao_popularidade_' || to_char(dataref, 'mmyyyy');

	
		-- 1- Prisma Financeiro;	
		execute format('create temporary  table if not exists %I  as  select
		idproduto,
	    coalesce(getclassfinanceira(sum(acomulado.perc_csm) OVER (ORDER BY acomulado.csm DESC)),''C'') as class_abc
	
			from
	
		(  select idproduto,csm,total_saidas,(csm / nullif(total_saidas,0)) as perc_csm from(
	
			      select idproduto,(get_cmm_filial(%L,idproduto,last_day(%L))*custo_unitario) as csm,
	
				   (select sum(get_cmm_filial(%L,idproduto,last_day(%L))*custo_unitario) from produtos_filial where filial=%L) as total_saidas
	
			          from produtos_filial where filial=%L
	
			             order by csm desc,	idproduto) prod
	
		 ) acomulado', table_temp1, p_filial, dataref, p_filial, dataref, p_filial, p_filial);
		
		
		
		 
		--2- Prisma Criticidade
		execute format('create  temporary  table if not exists %I as  
	
	      SELECT acomulado.idproduto,
	
	        CASE
	
	            WHEN  getclassfinanceira(sum(acomulado.perc_csm) OVER (ORDER BY acomulado.csm DESC))::text = ''A''::text THEN ''Z''::text
	
	            WHEN  getclassfinanceira(sum(acomulado.perc_csm) OVER (ORDER BY acomulado.csm DESC))::text = ''B''::text THEN ''Y''::text
	
	            ELSE ''X''::text
	
	        END AS class_xyz
	
	from
	
		(  select idproduto,csm::numeric,total_saidas::numeric,(csm / nullif(total_saidas,0))::numeric as perc_csm from(
	
			      select idproduto,(get_cmm_filial(%L,idproduto,last_day(%L))*valor_unitario) as csm,
	
				   (select sum(get_cmm_filial(%L,idproduto,last_day(%L))*valor_unitario) from produtos_filial where filial=%L) as total_saidas
	
			          from produtos_filial where filial=%L
	
			             order by csm desc,	idproduto) prod
	
		 ) acomulado', table_temp2, p_filial, dataref, p_filial, dataref, p_filial, p_filial);
		
		
		-- 3- Prisma Popularidade 
		execute format('create  temporary table if not exists %I as
	
	         select idproduto,tma,perc_tma,
	
				sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC rows between unbounded preceding and current row) AS perc_acomulado,
	
				(case when sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC rows between unbounded preceding and current row) > 0 and sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC rows between unbounded preceding and current row) <= 0.8 then ''P''
	
	      	when sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC rows between unbounded preceding and current row) > 0.8 and sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC rows between unbounded preceding and current row) <= 0.95 then ''Q''
	
	     	else ''R''  end ) class_pqr from(
	
				select idproduto,tma,(tma/nullif(total_tma,0)) as perc_tma from (
	
				select idproduto,get_tma_filial(%L,idproduto,last_day(%L)) as tma,
	
				(select sum(get_tma_filial(%L,idproduto,last_day(%L))) from  produtos_filial where filial=%L) as total_tma
	
			from  produtos_filial where filial=%L order by tma desc ,idproduto) prod) tma_acomulado', table_temp3, p_filial, dataref, p_filial, dataref, 
				p_filial, p_filial);
			
			
		 return query  execute format('select c.idproduto::varchar,coalesce(f.class_abc::varchar,''C'')||coalesce(c.class_xyz::varchar,''X'')||coalesce(get123(f.idproduto::varchar),''3'')||coalesce(p.class_pqr::varchar,''R'')::varchar   

           from %I f 

             inner join %I c    

              on f.idproduto = c.idproduto

              inner join %I p    

              on f.idproduto = p.idproduto', table_temp1, table_temp2, table_temp3);
        
        
end;$$;


ALTER FUNCTION public.gerar_prismas_filiais(p_filial numeric, dataref date) OWNER TO systock;

--
-- TOC entry 654 (class 1255 OID 53759)
-- Name: gerar_prismas_filiais_3(numeric, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.gerar_prismas_filiais_3(p_filial numeric, dataref date DEFAULT ('now'::text)::date) RETURNS TABLE(produto character varying, arvore text)
    LANGUAGE plpgsql
    AS $$
declare 
retorno varchar;
begin
	
		
	
			
   return query  execute format('
           with projecao as ( select a.*,(nullif(a.valor_unitario,0)*nullif(cmm_venda,0)) csm_venda, (nullif(a.custo_unitario,0)*nullif(cmm_venda,0)) csm_custo from (
		                       select filial ,idproduto,valor_unitario ,custo_unitario , 
		                          get_cmm_filial(filial,idproduto,last_day(%L)) as cmm_venda,
		                          get_tma_filial(filial,idproduto,last_day(%L)) as total_tma 
		                          from produtos_filial where filial=%L) a),
    analise_financeira  as ( select
		idproduto,
	    coalesce(getclassfinanceira(sum(acomulado.perc_csm) OVER (ORDER BY acomulado.csm DESC)),''C'') as class_abc from (                       
		                          
			  select
			   idproduto,
			    csm_custo as csm,
			    csm_custo / nullif(sum(csm_custo) over(),0) perc_csm,
			   sum(csm_custo) over() as total
			  from projecao ) acomulado),
			  
	analise_criticidade as (
	     
	    SELECT acomulado.idproduto,
	
	        CASE
	
	            WHEN  getclassfinanceira(sum(acomulado.perc_csm) OVER (ORDER BY acomulado.csm DESC))::text = ''A''::text THEN ''Z''::text
	
	            WHEN  getclassfinanceira(sum(acomulado.perc_csm) OVER (ORDER BY acomulado.csm DESC))::text = ''B''::text THEN ''Y''::text
	
	            ELSE ''X''::text
	
	        END AS class_xyz from (                       
		                          
			  select
			   idproduto,
			    csm_venda as csm,
			    csm_venda / nullif(sum(csm_venda) over(),0) perc_csm,
			   sum(csm_venda) over() as total
			  from projecao ) acomulado ),
	analise_popularidade as (
	
	     select idproduto,tma,perc_tma,
	
				sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC rows between unbounded preceding and current row) AS perc_acomulado,
	
				(case when sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC rows between unbounded preceding and current row) > 0 and sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC rows between unbounded preceding and current row) <= 0.8 then ''P''
	
	      	when sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC rows between unbounded preceding and current row) > 0.8 and sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC rows between unbounded preceding and current row) <= 0.95 then ''Q''
	
	     	else ''R''  end ) class_pqr from(                     
			  select
			   idproduto,
			    total_tma as tma,
			    total_tma / nullif(sum(total_tma) over(),0) perc_tma,
			   sum(total_tma) over() as total
			  from projecao) tma_acomulado )		  
	     
			  select c.idproduto::varchar,coalesce(f.class_abc::varchar,''C'')||coalesce(c.class_xyz::varchar,''X'')||coalesce(get123_filial(%L,f.idproduto::varchar),''3'')||coalesce(p.class_pqr::varchar,''R'')::varchar as arvore  

           from analise_financeira f 

             inner join analise_criticidade c    

              on f.idproduto = c.idproduto

              inner join analise_popularidade p    

              on f.idproduto = p.idproduto
          ', dataref,dataref, p_filial,p_filial);
        
        
end;$$;


ALTER FUNCTION public.gerar_prismas_filiais_3(p_filial numeric, dataref date) OWNER TO systock;

--
-- TOC entry 655 (class 1255 OID 53760)
-- Name: gerar_prismas_rentabilidade_filiais(integer); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.gerar_prismas_rentabilidade_filiais(p_filial integer) RETURNS TABLE(idproduto character varying, classificacao_rentabilidade character varying)
    LANGUAGE sql
    AS $$
    WITH _produtos AS (
        SELECT
            pf.filial ,
            pf.idproduto,
            pf.descricao_produto ,
            pf.valor_unitario,
            pf.custo_unitario,
            pf.preco_medio_venda,
            pf.consumo_medio_mensal,
            COALESCE((pf.preco_medio_venda-pf.custo_unitario * pf.consumo_medio_mensal), 0) prej_rentabilidade
        FROM produtos_filial pf
        WHERE pf.filial = p_filial
    ),
    _produtos_com_percentual_rentablidade AS (
        SELECT
            p.filial,
            p.idproduto,
            p.prej_rentabilidade,
            (p.prej_rentabilidade / NULLIF(sum(p.prej_rentabilidade) OVER(), 0)) AS perc_rentabilidade
        FROM
            _produtos p
    )
    SELECT
        p.idproduto,
        CASE
            WHEN sum(p.perc_rentabilidade) OVER (ORDER BY p.prej_rentabilidade DESC) <= 0.8 THEN 'A'
            WHEN sum(p.perc_rentabilidade) OVER (ORDER BY p.prej_rentabilidade DESC) > 0.8 AND sum(p.perc_rentabilidade) OVER (ORDER BY p.prej_rentabilidade DESC) <= 0.95 THEN 'B'
            ELSE 'C'
        END AS classificacao_rentabilidade
    FROM _produtos_com_percentual_rentablidade p
$$;


