							union 
						  select distinct idfilial ,idproduto from entrada_mercadorias em  where idfilial = p_filial and data_entrada  between current_date - 1095 and current_date
						    union 
						  select filial,idproduto from hist_estoque he  where filial =p_filial and "data" between dataini and datafim and qtde > 0  
                         ) 
