						nivel_servico,
						sugestao
						into 
					    v_esseg, 
					    v_ppd,
					    v_emax,
					    v_saldo_estoque,
					    v_cmm,
					    v_cmm_std,
					    v_fes,
					    v_nivel_servico,
					    v_sugestao
					from
						get_calculo_parametros_estoque(rec_prod.filial,rec_prod.idproduto,arv,rec_data.data::date);
				 
				 else 
				 
				  v_esseg = rec_prod.esseg;
				  v_ppd = rec_prod.ppd;
				  v_emax = rec_prod.emax;
				  v_saldo_estoque = rec_prod.saldo_estoque;
				  v_cmm = rec_prod.cmm;
				  v_cmm_std = rec_prod.cmm_std;
				  v_fes = rec_prod.fes;
				  v_nivel_servico = rec_prod.nivel_servico;
				  v_sugestao = rec_prod.lote_compras; 
		
		        end if;
		
		    
		       --Saldos Diarios
		    
		        saldo_com =(select get_consumo_diario_filial(rec_prod.filial,rec_prod.idproduto,rec_data.data::date));
		
		        saldo_ent =(select get_entradas_filial(rec_prod.filial,rec_prod.idproduto,rec_data.data::date));
		
		        saldo_est =(select get_estoque_diario_filial(rec_prod.filial,rec_prod.idproduto,rec_data.data::date));
		       
		        select coalesce(arvore_decisao,'CX2R') into arv from prismas_filiais pf  where filial=rec_prod.filial and idproduto =rec_prod.idproduto and data_ref = date_trunc('month',rec_data.data::date);
		
		
		        if saldo_est < 0 then saldo_est = 0; end if;
		       
		        update
					saldo_filiais
				set
					entradas = saldo_ent,
					saidas = saldo_com,
					estoque = saldo_est,
					processamento = current_timestamp,
					arvore_decisao = arv,
					esseg = v_esseg,
					ppd = v_ppd,
					emax = v_emax,
					saldo_estoque = v_saldo_estoque,
					cmm = v_cmm,
					cmm_std = v_cmm_std,
					fes = v_fes,
					nivel_servico = v_nivel_servico,
					sugestao_compras = v_sugestao
				where
					filial = rec_prod.filial
					and idproduto = rec_prod.idproduto
					and data = rec_data.data::date;
				
				
		        IF NOT FOUND THEN
		           
		          		        
		          insert into saldo_filiais(
		                filial,
						idproduto,
						data,
						ano,
						mes,
						trimestre,
						cod_trimestre,
						entradas,
						saidas,
						estoque,
						processamento,
						tempo_ressuprimento,
						desvio_padrao_ressuprimento,
						arvore_decisao,
						esseg,
					    ppd,
					    emax,
					    saldo_estoque,
					    cmm,
					    cmm_std,
					    fes,
					    nivel_servico,
					    sugestao_compras
						)
				values (rec_prod.filial,
						rec_prod.idproduto,
						rec_data.data::date,
						date_part('year', rec_data.data::date),
						date_part('month', rec_data.data::date),
						date_part('quarter', rec_data.data::date),
						to_char(rec_data.data::date, 'YYYYQ')::numeric,
						saldo_ent,
						saldo_com,
						saldo_est,
						current_timestamp,
						rec_prod.tempo_ressuprimento,
						rec_prod.desvio_padrao_ressuprimento,
						arv,
					    v_esseg,
						v_ppd,
						v_emax,
						v_saldo_estoque,
						v_cmm,
						v_cmm_std,
						v_fes,
						v_nivel_servico,
						v_sugestao
						);
		           
		        END IF;
		
		     
		
		    end loop;
		
		
		
		 end loop;
   
   
  end if; 
	
 
 return '1';



end;



$$;


ALTER FUNCTION public.gerar_saldos_diario_filial(dataini date, datafim date, mov numeric) OWNER TO systock;

--
-- TOC entry 658 (class 1255 OID 53765)
-- Name: gerar_saldos_diario_filial_prod(bigint, character varying, date, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.gerar_saldos_diario_filial_prod(p_filial bigint, p_prod character varying, dataini date DEFAULT ('now'::text)::date, datafim date DEFAULT ('now'::text)::date) RETURNS character varying
    LANGUAGE plpgsql
    AS $$

declare

  retorno  character varying;

  rec_data record;

  rec_prod record;

  saldo_ent numeric;

  saldo_com numeric;

  saldo_est numeric;

  existe numeric;

  saida varchar;
 
  arv varchar;

begin
	
for rec_prod in (select filial,idproduto,tempo_ressuprimento,desvio_padrao_ressuprimento,data_cadastro,arvore_decisao from produtos_filial pf where pf.filial = p_filial and pf.idproduto = p_prod order by idproduto,filial)
  loop



    for rec_data in (SELECT to_char(day :: date, 'DD/MM/YYYY') as data

                     FROM generate_series(dataini, datafim, '1 day') day)

    loop

    
        saldo_com =(select get_consumo_diario_filial(rec_prod.filial,rec_prod.idproduto,rec_data.data::date));

        saldo_ent =(select get_entradas_filial(rec_prod.filial,rec_prod.idproduto,rec_data.data::date));

        saldo_est =(select get_estoque_diario_filial(rec_prod.filial,rec_prod.idproduto,rec_data.data::date));
       
        select coalesce(arvore_decisao,'CX2R') into arv from prismas_filiais pf  where filial=rec_prod.filial and idproduto =rec_prod.idproduto and data_ref = date_trunc('month',rec_data.data::date);


        if saldo_est < 0 then saldo_est = 0; end if;

       
        update saldo_filiais set entradas=saldo_ent, saidas=saldo_com, estoque=saldo_est,tempo_ressuprimento=rec_prod.tempo_ressuprimento,
               desvio_padrao_ressuprimento=rec_prod.desvio_padrao_ressuprimento,processamento=current_timestamp,arvore_decisao = arv
        where filial= rec_prod.filial and idproduto =rec_prod.idproduto and data = rec_data.data::date;
       
       
        if not found then 
        
            insert into  saldo_filiais (filial,idproduto, data,ano, mes, trimestre,cod_trimestre, entradas, saidas, estoque,processamento,tempo_ressuprimento,desvio_padrao_ressuprimento,arvore_decisao)  

                values (rec_prod.filial,rec_prod.idproduto,rec_data.data::date,date_part('year', rec_data.data::date),date_part('month', rec_data.data::date),

               date_part('quarter', rec_data.data::date),to_char(rec_data.data::date,'YYYYQ')::numeric,saldo_ent,saldo_com,saldo_est,current_timestamp,rec_prod.tempo_ressuprimento,rec_prod.desvio_padrao_ressuprimento,arv);
        
        end if;
      

    end loop;

  end loop;
   
return '1';

end;

$$;


ALTER FUNCTION public.gerar_saldos_diario_filial_prod(p_filial bigint, p_prod character varying, dataini date, datafim date) OWNER TO systock;

--
-- TOC entry 659 (class 1255 OID 53766)
-- Name: gerar_saldos_diario_prod(character varying, date, date); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.gerar_saldos_diario_prod(produto character varying, dataini date, datafim date) RETURNS void
    LANGUAGE plpgsql
    AS $$
declare
  retorno  character varying;
  rec_data record;
  rec_prod record;
  saldo_ent numeric;
  saldo_com numeric;
  saldo_est numeric;
  existe numeric;
  saida varchar;
begin

  for rec_prod in (select idproduto,tempo_ressuprimento,desvio_padrao_ressuprimento from produtos where idproduto=produto order by idproduto)
  loop

    for rec_data in (SELECT to_char(day :: date, 'DD/MM/YYYY') as data
                     FROM generate_series(dataini, datafim, '1 day') day)
    loop

        saldo_com =(select get_consumo_diario(rec_prod.idproduto,rec_data.data::date));
        saldo_ent =(select get_entradas(rec_prod.idproduto,rec_data.data::date));
        saldo_est =(select get_estoque_diario(rec_prod.idproduto,rec_data.data::date));


        if saldo_est < 0 then saldo_est = 0; end if;
       
        existe = (select count(*) from saldos where idproduto =rec_prod.idproduto and saldos.data = rec_data.data::date);

        if existe = 0 then

            insert into  saldos (idproduto, data,ano, mes, trimestre,cod_trimestre, entradas, saidas, estoque,processamento,tempo_ressuprimento,desvio_padrao_ressuprimento)  
                values (rec_prod.idproduto,rec_data.data::date,date_part('year', rec_data.data::date),date_part('month', rec_data.data::date),
                 date_part('quarter', rec_data.data::date),to_char(rec_data.data::date,'YYYYQ')::numeric,saldo_ent,saldo_com,saldo_est,current_timestamp,rec_prod.tempo_ressuprimento,rec_prod.desvio_padrao_ressuprimento);

          else

          update saldos set entradas=saldo_ent, saidas=saldo_com, estoque=saldo_est,processamento=current_timestamp where idproduto =rec_prod.idproduto and data = rec_data.data::date;

        end if;
      

    end loop;

  end loop;
 
end;

$$;


ALTER FUNCTION public.gerar_saldos_diario_prod(produto character varying, dataini date, datafim date) OWNER TO postgres;

--
-- TOC entry 660 (class 1255 OID 53767)
-- Name: gerar_status_mensal(numeric, numeric); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.gerar_status_mensal(p_ano numeric, p_mes numeric) RETURNS character varying
    LANGUAGE plpgsql
    AS $$
declare 

    tot_est_real numeric;
    qtd_itens_real numeric;
   
    tot_est_residual numeric;
    qtd_itens_residual numeric;
    perc_est_residual numeric;
   
    tot_est_exc numeric;
    qtd_itens_exc numeric;
    perc_est_exc numeric;
   
    tot_est_ideal numeric;
    qtd_itens_ideal numeric;
    perc_est_ideal numeric;
   
   
    tot_est_nece numeric;
    qtd_itens_nece numeric;
    perc_est_nece numeric;
   
    table_temp varchar;
    dataref  date;
    existe numeric;
   
begin
	
	table_temp =  '_tmp_status_mensal';
    
    select last_day(('01/'||lpad(CAST(p_mes AS VARCHAR),2,'0')||'/'||p_ano)::date) into dataref;
    
   -- dataref = current_date-2;
    
    drop table if exists _tmp_status_mensal;
	
	 EXECUTE format('create temporary table if not exists %I  as
                select s.ano,s.mes, 
    			p.descricao_produto,
   				(p.custo_unitario*p.fator_conversao) custo_unitario,
			    (p.valor_unitario*p.fator_conversao) valor_unitario,
			    s.estoque,
			    h.filial,
			    h.idproduto,
			    h.data_solicitacao,
			    h.arvore_decisao,
			    h.estoque_seguranca,
			    h.ponto_pedido,
			    h.estoque_maximo,
                (h.estoque_maximo*ns.peso) estoque_maximo_elast,
			    h.consumo_medio,
			    h.sugestao,
			    h.processamento,
                case  when h.ponto_pedido >(s.estoque+ getcompra_transito(h.idproduto)) then (h.estoque_maximo*ns.peso) - (s.estoque+ getcompra_transito(h.idproduto)) else 0 end necessidade
			   FROM saldos s
			     JOIN hist_analise_compras h ON h.idproduto::text = s.idproduto::text AND h.data_solicitacao = s.data
			     JOIN produtos p ON p.idproduto::text = s.idproduto::text
                  inner join familia_produtos
			     on p.idfamilia_produto = familia_produtos.idfamilia_produto
                 inner join nivel_servico ns  on ns.descricao_nivel_servico = p.nivel_servico 
			  WHERE s.data = ''%I'' and (data_solicitacao-p.data_cadastro) > 180
			       and p.status <>''FL'' and p.revenda=''S''
                   AND familia_produtos.filtro=''N''',table_temp,dataref); 
			 
			 --Real
	 
			select sum(custo_unitario*estoque) ,count(*) into tot_est_real,qtd_itens_real from _tmp_status_mensal;
		
		
		    -- Ideal
		    
			select sum(custo_unitario*estoque_maximo) ,count(*) into tot_est_ideal,qtd_itens_ideal from _tmp_status_mensal;
		
		    -- Excesso

			select sum(custo_unitario*(estoque-estoque_maximo_elast)),count(*) into tot_est_exc,qtd_itens_exc from _tmp_status_mensal 
			where estoque > estoque_maximo_elast;
		
		   -- Resisual
		
		   tot_est_residual = tot_est_real - tot_est_exc ;
		   qtd_itens_residual = qtd_itens_real - qtd_itens_exc ;
		  
		  --Necessidade
		  
		   select sum(custo_unitario*(necessidade)),count(*) into tot_est_nece,qtd_itens_nece from _tmp_status_mensal 
			where necessidade > 0;
		  
	       --tot_est_nece = tot_est_ideal - tot_est_residual;
	       --qtd_itens_nece = qtd_itens_ideal - qtd_itens_residual;
		  
		   perc_est_residual = round(((tot_est_residual / tot_est_real)*100),2);
		   perc_est_exc = round(((tot_est_exc / tot_est_real)*100),2);
		   perc_est_nece = round(((tot_est_nece / tot_est_real)*100),2);
		   perc_est_ideal = round(((tot_est_ideal / tot_est_real)*100),2);
		  
		   select count(*) into existe from analise_status_mensal where ano = p_ano and mes = p_mes;
		  		  
		  if existe > 0 then 
		 	
				update
						public.analise_status_mensal
					set
						total_estoque_real = tot_est_real,
						qtde_itens_real = qtd_itens_real,
						total_estoque_residual = tot_est_residual,
						qtde_itens_residual = qtd_itens_residual,
						perc_estoque_residual = perc_est_residual,
						total_estoque_excesso = tot_est_exc,
						qtde_itens_excesso = qtd_itens_exc,
						perc_estoque_excesso = perc_est_exc,
						total_estoque_necessidade = tot_est_nece,
						qtde_itens_necessidade = qtd_itens_nece,
						perc_estoque_necessidade = perc_est_nece,
						total_estoque_ideal = tot_est_ideal,
						qtde_itens_ideal = qtd_itens_ideal,
						perc_estoque_ideal = perc_est_ideal,
						processamento = now()
					where
						ano = p_ano
						and mes = p_mes;

		    else
		    
				    insert
					into public.analise_status_mensal (ano,mes,
					    total_estoque_real,
						qtde_itens_real,
						total_estoque_residual,
						qtde_itens_residual,
						perc_estoque_residual,
						total_estoque_excesso,
						qtde_itens_excesso,
						perc_estoque_excesso,
						total_estoque_necessidade,
						qtde_itens_necessidade,
						perc_estoque_necessidade,
						total_estoque_ideal,
						qtde_itens_ideal,
						perc_estoque_ideal,
						processamento)
					values( p_ano,p_mes,
					        tot_est_real,
							qtd_itens_real,
							tot_est_residual,
							qtd_itens_residual,
							perc_est_residual,
							tot_est_exc,
							qtd_itens_exc,
							perc_est_exc,
							tot_est_nece,
							qtd_itens_nece,
							perc_est_nece,
							tot_est_ideal,
							qtd_itens_ideal,
							perc_est_ideal,
							now());

		  end if;
		     
    return '1';

end;

$$;


ALTER FUNCTION public.gerar_status_mensal(p_ano numeric, p_mes numeric) OWNER TO systock;

--
-- TOC entry 661 (class 1255 OID 53768)
-- Name: gerar_status_mensal_filial(numeric, numeric); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.gerar_status_mensal_filial(p_ano numeric, p_mes numeric) RETURNS character varying
    LANGUAGE plpgsql
    AS $$
declare 
    

    rec_data record;
    rec_dados record;

    tot_est_real numeric;
    qtd_itens_real numeric;
   
    tot_est_residual numeric;
    qtd_itens_residual numeric;
    perc_est_residual numeric;
   
    tot_est_exc numeric;
    qtd_itens_exc numeric;
    perc_est_exc numeric;
   
    tot_est_ideal numeric;
    qtd_itens_ideal numeric;
    perc_est_ideal numeric;
   
    tot_est_nece numeric;
    qtd_itens_nece numeric;
    perc_est_nece numeric;
   
   
    tot_est_matu numeric;
    qtd_itens_matu numeric;
    perc_est_matu numeric;
   
    table_temp varchar;
    dataref  date;
    existe numeric;
   
begin
	
	table_temp =  '_tmp_status_mensal_filial';
    
    select last_day(('01/'||lpad(CAST(p_mes AS VARCHAR),2,'0')||'/'||p_ano)::date) into dataref;
   
   
    if dataref > current_date then
    
       dataref = current_date -1;
     
    end if; 
    
    
    drop table if exists _tmp_status_mensal_filial;
	
	 EXECUTE format('create temporary table if not exists %I  as
				select g.id_grupo,
                s.ano,s.mes, 
    			p.descricao_produto,
   				(coalesce(nullif(s.preco_custo,0),p.custo_unitario)*p.fator_conversao) custo_unitario,
			    (p.valor_unitario*p.fator_conversao) valor_unitario,
			    s.estoque,
			    h.filial,
			    h.idproduto,
			    h.data_solicitacao,
			    h.arvore_decisao,
			    h.estoque_seguranca,
			    h.ponto_pedido,
			    h.estoque_maximo,
                (h.estoque_maximo*ns.peso) estoque_maximo_elast,
			    h.consumo_medio,
			    h.sugestao,
			    h.processamento,
			    getcompra_transito_grupo(g.id_grupo,h.idproduto)/p.fator_conversao as compra_transito_grupo,
                case  when h.ponto_pedido >(s.estoque+ (getcompra_transito_grupo(g.id_grupo,h.idproduto)/p.fator_conversao)) then (h.estoque_maximo*ns.peso) - (s.estoque+ (getcompra_transito_grupo(g.id_grupo,h.idproduto)/p.fator_conversao)) else 0 end necessidade,
                p.tempo_medio_apanhe,
                (data_solicitacao-p.data_cadastro) as tempo_vida_produto,
                p.status,
                p.revenda
			   FROM saldo_filiais s
			     JOIN hist_analise_compras_filial h ON h.filial  = s.filial  and h.idproduto::text = s.idproduto::text AND h.data_solicitacao = s.data
			     JOIN produtos_filial p on p.filial= s.filial  and p.idproduto::text = s.idproduto::text
                  inner join familia_produtos
			     on p.idfamilia_produto = familia_produtos.idfamilia_produto
                 inner join nivel_servico ns  on ns.descricao_nivel_servico = p.nivel_servico
                 inner join grupo_filial  g on g.filial = s.filial  
			  WHERE s.data = ''%I'' AND familia_produtos.filtro=''N''',table_temp,dataref); 
                  
                  
                  
          for rec_dados in (select * from _tmp_status_mensal_filial where revenda ='S')
           loop
           
              select count(*) into existe from analise_status_mensal_filial_analitica asmfa 
                  where asmfa.id_grupo = rec_dados.id_grupo 
                  and  asmfa.filial = rec_dados.filial
                  and asmfa.ano = rec_dados.ano
                  and asmfa.mes = rec_dados.mes 
                  and asmfa.idproduto = rec_dados.idproduto;
                 
                 if existe=0 then
                 
                    INSERT INTO analise_status_mensal_filial_analitica
						(id_grupo, ano, mes, descricao_produto, custo_unitario, valor_unitario, estoque, filial, idproduto, data_solicitacao, arvore_decisao, estoque_seguranca, ponto_pedido, estoque_maximo, estoque_maximo_elast, consumo_medio, sugestao, processamento, compra_transito_grupo, necessidade, tempo_medio_apanhe, tempo_vida_produto, status, revenda)
					VALUES(rec_dados.id_grupo, rec_dados.ano, rec_dados.mes, rec_dados.descricao_produto, rec_dados.custo_unitario, rec_dados.valor_unitario, rec_dados.estoque, rec_dados.filial, rec_dados.idproduto, rec_dados.data_solicitacao, rec_dados.arvore_decisao, rec_dados.estoque_seguranca, rec_dados.ponto_pedido,
				           rec_dados.estoque_maximo, rec_dados.estoque_maximo_elast, rec_dados.consumo_medio, rec_dados.sugestao, rec_dados.processamento, rec_dados.compra_transito_grupo, rec_dados.necessidade, rec_dados.tempo_medio_apanhe, rec_dados.tempo_vida_produto, rec_dados.status, rec_dados.revenda);

                 
                  else
                  
                   UPDATE analise_status_mensal_filial_analitica
					SET descricao_produto=rec_dados.descricao_produto,
					   custo_unitario=rec_dados.custo_unitario,
					   valor_unitario=rec_dados.valor_unitario,
					   estoque=rec_dados.estoque,
					   data_solicitacao=rec_dados.data_solicitacao,
					   arvore_decisao=rec_dados.arvore_decisao,
					   estoque_seguranca=rec_dados.estoque_seguranca,
					   ponto_pedido=rec_dados.ponto_pedido,
					   estoque_maximo=rec_dados.estoque_maximo,
					   estoque_maximo_elast=rec_dados.estoque_maximo_elast,
					   consumo_medio=rec_dados.consumo_medio,
					   sugestao=rec_dados.sugestao,
					   processamento=rec_dados.processamento,
					   compra_transito_grupo=rec_dados.compra_transito_grupo,
					   necessidade=rec_dados.necessidade,
					   tempo_medio_apanhe=rec_dados.tempo_medio_apanhe,
					   tempo_vida_produto=rec_dados.tempo_vida_produto,
					   status=rec_dados.status,
					   revenda=rec_dados.revenda
				   WHERE id_grupo=rec_dados.id_grupo AND filial=rec_dados.filial AND ano=rec_dados.ano AND mes=rec_dados.mes AND idproduto=rec_dados.idproduto;

                  
                 end if; 
           
           end loop;
          
          
          
          
                       
          for rec_data in ( select distinct id_grupo,filial,ano,mes from _tmp_status_mensal_filial) 
            loop 
			 
			 --Real                  
	 
			select sum(custo_unitario*estoque) ,count(*) into tot_est_real,qtd_itens_real from _tmp_status_mensal_filial 
		        where filial= rec_data.filial  and revenda='S' ; -- and tempo_vida_produto > 180 and status <>'FL'
		
		
		    -- Ideal
		    
			select sum(custo_unitario*estoque_maximo) ,count(*) into tot_est_ideal,qtd_itens_ideal from _tmp_status_mensal_filial 
		         where filial= rec_data.filial   and status <>'FL' and revenda='S';-- and tempo_vida_produto > 180
		
		    -- Excesso

			select sum(custo_unitario*(estoque-estoque_maximo_elast)),count(*) into tot_est_exc,qtd_itens_exc from _tmp_status_mensal_filial 
			where  filial= rec_data.filial and  estoque > estoque_maximo_elast   and revenda='S'; -- and tempo_vida_produto > 180 and status <>'FL'
		
		   -- Resisual
		
		   tot_est_residual = tot_est_real - tot_est_exc ;
		   qtd_itens_residual = qtd_itens_real - qtd_itens_exc ;
		  
		  --Necessidade
		  
		   select sum(custo_unitario*(necessidade)),count(*) into tot_est_nece,qtd_itens_nece from _tmp_status_mensal_filial 
			 where filial= rec_data.filial and necessidade > 0   and status <>'FL' and revenda='S'; --and tempo_vida_produto > 180
			
			
	      --Itens Maturação
	      
		   select sum(custo_unitario*estoque) ,count(*) into tot_est_matu,qtd_itens_matu from _tmp_status_mensal_filial 
		     where filial= rec_data.filial and tempo_vida_produto <= 180   and revenda='S' ; --and status <>'FL'
		  
	       --tot_est_nece = tot_est_ideal - tot_est_residual;
	       --qtd_itens_nece = qtd_itens_ideal - qtd_itens_residual;
		  
		   perc_est_residual = round(((tot_est_residual / nullif(tot_est_real,0))*100),2);
		   perc_est_exc = round(((tot_est_exc / nullif(tot_est_real,0))*100),2);
		   perc_est_nece = round(((tot_est_nece / nullif(tot_est_real,0))*100),2);
		   perc_est_ideal = round(((tot_est_ideal / nullif(tot_est_real,0))*100),2);
		   perc_est_matu = 0; 
		  
		   select count(*) into existe from analise_status_mensal_filial where filial= rec_data.filial and  ano = rec_data.ano and mes = rec_data.mes;
		  		  
		  if existe > 0 then 
		 	
				update
						public.analise_status_mensal_filial
					set
						total_estoque_real = coalesce(tot_est_real,0),
						qtde_itens_real = coalesce(qtd_itens_real,0),
						total_estoque_residual = coalesce(tot_est_residual,0),
						qtde_itens_residual = coalesce(qtd_itens_residual,0),
						perc_estoque_residual = coalesce(perc_est_residual,0),
						total_estoque_excesso = coalesce(tot_est_exc,0),
						qtde_itens_excesso = coalesce(qtd_itens_exc,0),
						perc_estoque_excesso = coalesce(perc_est_exc,0),
						total_estoque_necessidade = coalesce(tot_est_nece,0),
						qtde_itens_necessidade = coalesce(qtd_itens_nece,0),
						perc_estoque_necessidade = coalesce(perc_est_nece,0),
						total_estoque_ideal = coalesce(tot_est_ideal,0),
						qtde_itens_ideal = coalesce(qtd_itens_ideal,0),
						perc_estoque_ideal = coalesce(perc_est_ideal,0),
					    total_estoque_novo = coalesce(tot_est_matu,0),
						qtde_itens_novo = coalesce(qtd_itens_matu,0),
						perc_estoque_novo = coalesce(perc_est_matu,0),
						processamento = now()
					where
					    filial =rec_data.filial 
						and ano = rec_data.ano
						and mes = rec_data.mes;

		    else
		    
				    insert
					into public.analise_status_mensal_filial (grupo,filial,ano,mes,
					    total_estoque_real,
						qtde_itens_real,
						total_estoque_residual,
						qtde_itens_residual,
						perc_estoque_residual,
						total_estoque_excesso,
						qtde_itens_excesso,
						perc_estoque_excesso,
						total_estoque_necessidade,
						qtde_itens_necessidade,
						perc_estoque_necessidade,
						total_estoque_ideal,
						qtde_itens_ideal,
						perc_estoque_ideal,
						total_estoque_novo ,
						qtde_itens_novo ,
						perc_estoque_novo ,
						processamento)
					values( rec_data.id_grupo,
					        rec_data.filial,
					        rec_data.ano,rec_data.mes,
					        coalesce(tot_est_real,0),
							coalesce(qtd_itens_real,0),
							coalesce(tot_est_residual,0),
							coalesce(qtd_itens_residual,0),
							coalesce(perc_est_residual,0),
							coalesce(tot_est_exc,0),
							coalesce(qtd_itens_exc,0),
							coalesce(perc_est_exc,0),
							coalesce(tot_est_nece,0),
							coalesce(qtd_itens_nece,0),
							coalesce(perc_est_nece,0),
							coalesce(tot_est_ideal,0),
							coalesce(qtd_itens_ideal,0),
							coalesce(perc_est_ideal,0),
						    coalesce(tot_est_matu,0),
							coalesce(qtd_itens_matu,0),
							coalesce(perc_est_matu,0),
							now());

		  end if;
		 
		end loop; 
		     
    return '1';

end;

$$;


ALTER FUNCTION public.gerar_status_mensal_filial(p_ano numeric, p_mes numeric) OWNER TO systock;

--
-- TOC entry 662 (class 1255 OID 53770)
-- Name: gerar_tabela_relatorio_sugestao_compras(text, integer[], integer[], integer[]); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.gerar_tabela_relatorio_sugestao_compras(grupo_id text, fornecedor_id integer[] DEFAULT NULL::integer[], comprador_id integer[] DEFAULT NULL::integer[], segmento_id integer[] DEFAULT NULL::integer[]) RETURNS TABLE(id_grupo text, idfornecedor text, razao_social text, idproduto text, descricao_produto text, unidade_compra text, lote_minimo text, estoque text, compra_transito text, media_tres_meses text, media_seis_meses text, media_doze_meses text, qtde_ultima_compra text, data_ultima_compra text, sugestao_compra text)
    LANGUAGE plpgsql PARALLEL SAFE
    AS $$
DECLARE
    table_temp text;
    filtro_fornecedor text;
    filtro_comprador text;
    filtro_segmento text;
BEGIN
    table_temp = 'g' || grupo_id || '_tmp_sugestao_compra';

    create temporary table if not exists table_temp as
        SELECT
            pcg.id_grupo::text,
            pcg.idfornecedor::text,
            f.razao_social::text,
            pcg.idproduto::text,
            pcg.descricao_produto::text,
            pcg.unidade_compra::text,
            pcg.lote_minimo::text,
            pcg.estoque::text,
            pcg.compra_transito::text,
            (COALESCE(sum(c.qtde) FILTER (WHERE c.emissao >= (current_date - 90)), 0) / 3)::text AS media_tres_meses,
            (COALESCE(sum(c.qtde) FILTER (WHERE c.emissao >= (current_date - 180)), 0) / 6)::text AS media_seis_meses,
            (COALESCE(sum(c.qtde) FILTER (WHERE c.emissao >= (current_date - 365)), 0) / 12)::text AS media_doze_meses,
            COALESCE(max(r.qtde), 0)::text AS qtde_ultima_compra,
            max(r.data_solicitacao)::text AS data_ultima_compra,
            COALESCE(vw.sugestao, 0)::text AS sugestao_compra
        FROM
            produtos_compras_grupo pcg
            JOIN fornecedor f ON f.id::text = pcg.idfornecedor::text
            LEFT JOIN vw_lista_compras_dinamica_grupo vw ON vw.id_grupo = pcg.id_grupo AND vw.idproduto = pcg.idproduto
            LEFT JOIN consumos c ON c.idproduto = pcg.idproduto
            LEFT JOIN requisicoes r ON r.idproduto = pcg.idproduto
        WHERE
            pcg.id_grupo::int = grupo_id::int
            AND c.emissao >= (current_date - 365)
            AND (pcg.idfornecedor::int = ANY(fornecedor_id) or fornecedor_id is null)
            AND (pcg.idfamilia_produto::int = ANY(segmento_id) or segmento_id is null)
            AND (pcg.idcomprador::int = ANY(comprador_id) or comprador_id is null)
        GROUP BY
            pcg.id_grupo,
            pcg.idfornecedor,
            f.razao_social,
            pcg.idproduto,
            vw.idproduto,
            pcg.descricao_produto,
            pcg.unidade_compra,
            pcg.lote_minimo,
            pcg.estoque,
            pcg.compra_transito,
            vw.sugestao
        ORDER BY
            vw.idproduto;

    RETURN query select * from table_temp;

    DROP TABLE IF EXISTS table_temp;

    RETURN;

END;
$$;


ALTER FUNCTION public.gerar_tabela_relatorio_sugestao_compras(grupo_id text, fornecedor_id integer[], comprador_id integer[], segmento_id integer[]) OWNER TO systock;

