--

CREATE FUNCTION public.get_cmm_filial(p_idfilial numeric, p_idproduto character varying, p_data_referencia date DEFAULT ('now'::text)::date) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
    DECLARE
        tipo_projecao_vendas varchar(35);
    BEGIN
        SELECT t.tipo INTO tipo_projecao_vendas
        FROM sys_tipos_projecao_vendas_produtos_filial t
        WHERE t.filial = p_idfilial AND t.idproduto = p_idproduto;

        IF tipo_projecao_vendas IS NULL THEN
          RETURN get_cmm_filial_padrao_systock(p_idfilial::int, p_idproduto, p_data_referencia);
        END IF;

        IF tipo_projecao_vendas = 'media_sazonal' THEN
            IF NOT EXISTS (
                SELECT v.*
                FROM sys_tipo_projecao_media_sazonal_produtos_filial v
                WHERE v.filial = p_idfilial AND v.idproduto = p_idproduto AND p_data_referencia BETWEEN v.data_inicial_aplicacao AND v.data_final_aplicacao
            ) THEN
                RETURN get_cmm_filial_padrao_systock(p_idfilial::int, p_idproduto, p_data_referencia);
            END IF;

            RETURN get_cmm_filial_media_sazonal(p_idfilial::int, p_idproduto, p_data_referencia);
        END IF;

        IF tipo_projecao_vendas = 'suavizacao_exponencial' THEN
          RETURN get_cmm_filial_suavizacao_exponencial(p_idfilial::int, p_idproduto, p_data_referencia);
        END IF;

        IF tipo_projecao_vendas = 'media_aritmetica_simples_trimestre' THEN
          RETURN get_cmm_filial_media_aritmetica_simples(p_idfilial::int, p_idproduto, 3, p_data_referencia);
        END IF;

        IF tipo_projecao_vendas = 'media_aritmetica_simples_semestre' THEN
          RETURN get_cmm_filial_media_aritmetica_simples(p_idfilial::int, p_idproduto, 6, p_data_referencia);
        END IF;

        IF tipo_projecao_vendas = 'media_aritmetica_simples_ano' THEN
          RETURN get_cmm_filial_media_aritmetica_simples(p_idfilial::int, p_idproduto, 12, p_data_referencia);
        END IF;

        IF tipo_projecao_vendas = 'media_geometrica' THEN
          RETURN get_cmm_filial_media_geometrica(p_idfilial::int, p_idproduto, p_data_referencia);
        END IF;

        IF tipo_projecao_vendas = 'media_movel_ponderada' THEN
          RETURN get_cmm_filial_media_movel_ponderada(p_idfilial::int, p_idproduto, p_data_referencia);
        END IF;

        IF tipo_projecao_vendas = 'mediana' THEN
          RETURN get_cmm_filial_mediana(p_idfilial::int, p_idproduto, p_data_referencia);
        END IF;

        RETURN get_cmm_filial_padrao_systock(p_idfilial::int, p_idproduto, p_data_referencia);
    END; $$;


ALTER FUNCTION public.get_cmm_filial(p_idfilial numeric, p_idproduto character varying, p_data_referencia date) OWNER TO systock;

--
-- TOC entry 670 (class 1255 OID 53778)
-- Name: get_cmm_filial_media_aritmetica_simples(integer, character varying, integer, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_cmm_filial_media_aritmetica_simples(p_idfilial integer, p_idproduto character varying, qtde_meses integer, p_data_referencia date DEFAULT ('now'::text)::date) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
    DECLARE
        v_data_referencia date;
    BEGIN
        v_data_referencia := to_char(p_data_referencia, 'yyyy-mm-01')::date - 1;
        RETURN (
            SELECT trunc((sum(c.qtde) / qtde_meses)::NUMERIC, 4) AS media
            FROM consumos c
            WHERE
                c.filial = p_idfilial
                AND c.idproduto = p_idproduto
                AND c.emissao BETWEEN (v_data_referencia - make_interval(months := qtde_meses)) AND v_data_referencia
        );

    END; $$;


ALTER FUNCTION public.get_cmm_filial_media_aritmetica_simples(p_idfilial integer, p_idproduto character varying, qtde_meses integer, p_data_referencia date) OWNER TO systock;

--
-- TOC entry 671 (class 1255 OID 53779)
-- Name: get_cmm_filial_media_geometrica(integer, character varying, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_cmm_filial_media_geometrica(p_idfilial integer, p_idproduto character varying, p_data_referencia date DEFAULT ('now'::text)::date) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
    DECLARE
        qtde_vendida_mensal float[];
        value numeric;
        qtde_vendida_mensal_multiplicado numeric := 1.0;
    BEGIN

        qtde_vendida_mensal := ARRAY(
            SELECT trunc(sum(c.qtde)::NUMERIC, 4) AS qtde
            FROM consumos c
            WHERE
                c.filial = p_idfilial
                AND c.idproduto = p_idproduto
                AND c.emissao BETWEEN first_day((p_data_referencia - INTERVAL '3 months')::date) AND last_day((p_data_referencia - INTERVAL '1 months')::date)
            GROUP BY to_char(c.emissao, 'YYYY-MM-01')
        );

        FOREACH value IN ARRAY qtde_vendida_mensal LOOP
            qtde_vendida_mensal_multiplicado := qtde_vendida_mensal_multiplicado * value;
        END LOOP;


        IF qtde_vendida_mensal_multiplicado < 0 THEN
            RETURN 0;
        END IF;

        RETURN POWER(qtde_vendida_mensal_multiplicado, 1.0 / NULLIF(array_length(qtde_vendida_mensal, 1), 0));

    END; $$;


ALTER FUNCTION public.get_cmm_filial_media_geometrica(p_idfilial integer, p_idproduto character varying, p_data_referencia date) OWNER TO systock;

--
-- TOC entry 672 (class 1255 OID 53780)
-- Name: get_cmm_filial_media_movel_ponderada(integer, character varying, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_cmm_filial_media_movel_ponderada(p_idfilial integer, p_idproduto character varying, p_data_referencia date DEFAULT ('now'::text)::date) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
    DECLARE
        qtde_vendida_mensal float[];
        qtde_vendida_acumulada numeric;
    BEGIN

        qtde_vendida_mensal := ARRAY(
            WITH referencias AS (
                SELECT DISTINCT to_char(v.referencia, 'YYYY-MM-01')::date AS referencia
                FROM generate_series((p_data_referencia - INTERVAL '3 months')::date, p_data_referencia - INTERVAL '1 months', '1 month') AS v(referencia)
            ),
            vendas AS (
                SELECT
                    to_char(c.emissao, 'YYYY-MM-01')::date AS referencia,
                    trunc(sum(COALESCE(c.qtde, 0))::NUMERIC, 4) AS qtde
                FROM consumos c
                WHERE
                    c.filial = p_idfilial
                    AND c.idproduto = p_idproduto
                    AND c.emissao BETWEEN first_day((p_data_referencia - INTERVAL '3 months')::date) AND last_day((p_data_referencia - INTERVAL '1 months')::date)
                GROUP BY to_char(c.emissao, 'YYYY-MM-01')
            )
            SELECT COALESCE(v.qtde, 0) AS qtde
            FROM referencias r
                LEFT JOIN vendas v ON v.referencia = r.referencia
        );

        FOR chave IN 1 .. array_length(qtde_vendida_mensal, 1) LOOP
            qtde_vendida_acumulada = coalesce(qtde_vendida_acumulada, 0) + (chave * qtde_vendida_mensal[chave]);
        END LOOP;

        RETURN (qtde_vendida_acumulada / 6)::NUMERIC(12, 4);

    END; $$;


ALTER FUNCTION public.get_cmm_filial_media_movel_ponderada(p_idfilial integer, p_idproduto character varying, p_data_referencia date) OWNER TO systock;

--
-- TOC entry 834 (class 1255 OID 84591)
-- Name: get_cmm_filial_media_sazonal(integer, character varying, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_cmm_filial_media_sazonal(p_idfilial integer, p_idproduto character varying, p_data_referencia date DEFAULT ('now'::text)::date) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
    DECLARE
        parametros record;
        projecao_vendas numeric(12, 4);
        fator_influencia NUMERIC(12, 4);
    BEGIN

        SELECT
            v.data_inicial_vendas,
            v.data_final_vendas,
            v.data_inicial_aplicacao,
            v.data_final_aplicacao,
            v.tipo_influencia,
            v.percentual_influencia
            INTO
            parametros
        FROM sys_tipo_projecao_media_sazonal_produtos_filial v
        WHERE
            v.filial = p_idfilial
            AND v.idproduto = p_idproduto
            AND v.data_final_aplicacao >= current_date
        ORDER BY data_inicial_aplicacao, data_final_aplicacao;

        IF NOT p_data_referencia BETWEEN parametros.data_inicial_aplicacao AND parametros.data_final_aplicacao THEN
            RETURN 0;
        END IF;

        IF parametros.tipo_influencia = 'REDUCAO' THEN
            fator_influencia := (parametros.percentual_influencia / 100::NUMERIC) * -1;
        ELSE
            fator_influencia := (parametros.percentual_influencia / 100::NUMERIC);
        END IF;

        SELECT COALESCE(sum(c.qtde) / NULLIF(EXTRACT(MONTH FROM AGE(parametros.data_final_vendas, parametros.data_inicial_vendas)) + 1, 0), 0) INTO projecao_vendas
        FROM consumos c
        WHERE
            c.filial = p_idfilial
            AND c.idproduto = p_idproduto
            AND c.emissao BETWEEN parametros.data_inicial_vendas AND parametros.data_final_vendas;

        RETURN projecao_vendas + (projecao_vendas * fator_influencia)::NUMERIC;

    END; $$;


ALTER FUNCTION public.get_cmm_filial_media_sazonal(p_idfilial integer, p_idproduto character varying, p_data_referencia date) OWNER TO systock;

--
-- TOC entry 673 (class 1255 OID 53782)
-- Name: get_cmm_filial_mediana(integer, character varying, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_cmm_filial_mediana(p_idfilial integer, p_idproduto character varying, p_data_referencia date DEFAULT ('now'::text)::date) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
    BEGIN

        RETURN (
            SELECT trunc(sum(c.qtde)::NUMERIC, 4) AS qtde
            FROM consumos c
            WHERE
                c.filial = p_idfilial
                AND c.idproduto = p_idproduto
                AND c.emissao BETWEEN first_day((p_data_referencia - INTERVAL '3 months')::date) AND last_day((p_data_referencia - INTERVAL '1 months')::date)
            GROUP BY to_char(c.emissao, 'YYYY-MM-01')
            ORDER BY 1
            LIMIT 1 OFFSET 1
        );

    END; $$;


ALTER FUNCTION public.get_cmm_filial_mediana(p_idfilial integer, p_idproduto character varying, p_data_referencia date) OWNER TO systock;

--
-- TOC entry 674 (class 1255 OID 53783)
-- Name: get_cmm_filial_padrao_systock(numeric, character varying, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_cmm_filial_padrao_systock(p_filial numeric, idprod character varying, dataref date DEFAULT ('now'::text)::date) RETURNS numeric
    LANGUAGE plpgsql
    AS $$  

declare cmm3 numeric;

cmm6 numeric;
cmm numeric;
cmm_atual numeric;
primeiro_consumo numeric;
qtde3 numeric;
qtde6 numeric;
idforn numeric;
fator_atuacao  numeric;
tipo_fator varchar;
grupo numeric;
prod_heranca varchar;
modo_heranca int4;
tempo_heranca numeric;
cmm_heranca  numeric;
data_calc_cmm_heranca date;
lim_inf numeric;
lim_sup numeric;
begin

select
	current_date - min(emissao) into primeiro_consumo
from
	consumos c
where
	c.filial = p_filial
	and c.idproduto = idprod;




--Ajuste para aplicacao_fator de atuacao

 select
	idfornecedor,
	tipo_fator_atuacao,
	id_grupo,
	heranca,
	tipo_heranca,
	current_date - cadastro_heranca,
	limite_inferior,
	limite_superior
	
into
	idforn,
	tipo_fator,
	grupo,
	prod_heranca,
	modo_heranca,
	tempo_heranca,
	lim_inf, lim_sup
from
	produtos_filial pf
inner join grupo_filial gf on
	gf.filial = pf.filial
where
	pf.filial = p_filial
	and pf.idproduto = idprod;


--90 dias de análise;

SELECT
	coalesce(
		round(
			cast(
				sum(saidas) /(
					abs(
						case
							when abs(
								datediff(
									'mm',
									cast(to_char(dataref, 'YYYYMMDD') as date),
									cast(min(mes) || '01' as date)
								)
							) + 1 > 3 then 3
							when abs(
								datediff(
									'mm',
									cast(to_char(dataref, 'YYYYMMDD') as date),
									cast(min(mes) || '01' as date)
								)
							) + 1 < 3
							and primeiro_consumo >= 90 then 3
							else abs(
								datediff(
									'mm',
									cast(to_char(dataref, 'YYYYMMDD') as date),
									cast(min(mes) || '01' as date)
								)
							) + 1
						end
					)
				) as numeric
			),
			2
		),
		0
	),
	(
		abs(
			case
				when abs(
					datediff(
						'mm',
						cast(to_char(dataref, 'YYYYMMDD') as date),
						cast(min(mes) || '01' as date)
					)
				) + 1 > 3 then 3
				when abs(
					datediff(
						'mm',
						cast(to_char(dataref, 'YYYYMMDD') as date),
						cast(min(mes) || '01' as date)
					)
				) + 1 < 3
				and primeiro_consumo >= 90 then 3
				else abs(
					datediff(
						'mm',
						cast(to_char(dataref, 'YYYYMMDD') as date),
						cast(min(mes) || '01' as date)
					)
				) + 1
			end
		)
	) into cmm3,
	qtde3
FROM
	(
		SELECT
			to_char(emissao, 'YYYYMM') AS mes,
			to_char(emissao, 'YYYYMMDD') AS dia,
			sum(qtde) AS saidas
		FROM
			consumos
		WHERE
			consumos.filial = p_filial
			and consumos.idproduto = idprod
			AND emissao BETWEEN (dataref - 90)
			AND dataref
		GROUP BY
			mes,
			dia 
		having sum(qtde) between 0 and lim_sup
	) com;



--180 dias de análise;

SELECT
	coalesce(
		round(
			cast(
				sum(saidas) /(
					abs(
						case
							when abs(
								datediff(
									'mm',
									cast(to_char(dataref, 'YYYYMMDD') as date),
									cast(min(mes) || '01' as date)
								)
							) + 1 > 6 then 6
							when abs(
								datediff(
									'mm',
									cast(to_char(dataref, 'YYYYMMDD') as date),
									cast(min(mes) || '01' as date)
								)
							) + 1 < 6
							and primeiro_consumo >= 180 then 6
							else abs(
								datediff(
									'mm',
									cast(to_char(dataref, 'YYYYMMDD') as date),
									cast(min(mes) || '01' as date)
								)
							) + 1
						end
					)
				) as numeric
			),
			2
		),
		0
	),
	(
		abs(
			case
				when abs(
					datediff(
						'mm',
						cast(to_char(dataref, 'YYYYMMDD') as date),
						cast(min(mes) || '01' as date)
					)
				) + 1 > 6 then 6
				when abs(
					datediff(
						'mm',
						cast(to_char(dataref, 'YYYYMMDD') as date),
						cast(min(mes) || '01' as date)
					)
				) + 1 < 6
				and primeiro_consumo >= 180 then 6
				else abs(
					datediff(
						'mm',
						cast(to_char(dataref, 'YYYYMMDD') as date),
						cast(min(mes) || '01' as date)
					)
				) + 1
			end
		)
	) into cmm6,
	qtde6
FROM
	(
		SELECT
			to_char(emissao, 'YYYYMM') AS mes,
			to_char(emissao, 'YYYYMMDD') AS dia,
			sum(qtde) AS saidas
		FROM
			consumos
		WHERE
			consumos.filial = p_filial
			and consumos.idproduto = idprod
			AND emissao BETWEEN (dataref - 180)
			AND dataref
		GROUP BY
			mes,
			dia
	    having sum(qtde) between 0 and lim_sup		
	) com;




if qtde6 < 6 then cmm6 = cmm3;

end if;


-- Venda Atual Corrente 


SELECT	
	greatest(coalesce(sum(qtde),0),0) AS saidas
  into cmm_atual		
FROM
	consumos
WHERE
	consumos.filial = p_filial
	and consumos.idproduto = idprod
	AND emissao BETWEEN (dataref - 30)
	AND dataref;


cmm = (cmm3 + cmm6 + cmm_atual) / 3;


 
if tipo_fator ='F' then

--     select fator into fator_atuacao  from hist_fator_atuacao where id  = ( select max(id) from hist_fator_atuacao where id_grupo=grupo and id_fornecedor=idforn  and idproduto is null);
  	SELECT COALESCE(nullif(p.fator_atuacao, 0), 1) into fator_atuacao FROM produtos_filial p WHERE p.filial = p_filial AND p.idproduto = idprod;

  else
  
--     select fator into fator_atuacao  from hist_fator_atuacao where id  = ( select max(id) from hist_fator_atuacao where id_grupo=grupo and id_fornecedor=idforn and idproduto =idprod);
  	SELECT COALESCE(nullif(p.fator_atuacao, 0), 1) into fator_atuacao FROM produtos_filial p WHERE p.filial = p_filial AND p.idproduto = idprod;
  
end if;

-- Herança de comportamento

cmm_heranca = 0;

 if prod_heranca <> '' then 
     -- 1-Lançamento
     -- 2-Continua
 
	   if modo_heranca =  1 then
	  
	       select
	         min(emissao)+ 90
	         into data_calc_cmm_heranca
			from
				consumos c
			where
				c.filial = p_filial
				and c.idproduto = prod_heranca ;
	   
		   if tempo_heranca <= 60 then	
	           cmm_heranca = (select get_cmm_heranca_filial(p_filial,prod_heranca,data_calc_cmm_heranca));
	           cmm = 0;
	   
	       end if;    
	    else 
	    
	      if tempo_heranca <= 60 then	
	       	   cmm_heranca = (select get_cmm_heranca_filial(p_filial,prod_heranca));
	      end if;
	    
	   end if; 

	  
    else
    
     cmm_heranca = 0;
      
 
 end if;
 


fator_atuacao = coalesce(fator_atuacao,1); 
 

return ((cmm +cmm_heranca)) * fator_atuacao;


end;
 $$;


ALTER FUNCTION public.get_cmm_filial_padrao_systock(p_filial numeric, idprod character varying, dataref date) OWNER TO systock;

--
-- TOC entry 675 (class 1255 OID 53785)
-- Name: get_cmm_filial_suavizacao_exponencial(integer, character varying, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_cmm_filial_suavizacao_exponencial(p_idfilial integer, p_idproduto character varying, p_data_referencia date DEFAULT ('now'::text)::date) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
    declare
        suavizacao_exponencial suavizacao_exponencial_type;
    BEGIN

        suavizacao_exponencial := get_suavizacao_exponencial_filial(p_idfilial, p_idproduto, p_data_referencia);
        RETURN suavizacao_exponencial.projecoes[array_length(suavizacao_exponencial.projecoes, 1)];

    END; $$;


ALTER FUNCTION public.get_cmm_filial_suavizacao_exponencial(p_idfilial integer, p_idproduto character varying, p_data_referencia date) OWNER TO systock;

--
-- TOC entry 676 (class 1255 OID 53786)
-- Name: get_cmm_heranca_filial(numeric, character varying, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_cmm_heranca_filial(p_filial numeric, idprod character varying, dataref date DEFAULT ('now'::text)::date) RETURNS numeric
    LANGUAGE plpgsql
    AS $$ 

declare cmm3 numeric;

cmm6 numeric;
cmm numeric;
primeiro_consumo numeric;
qtde3 numeric;
qtde6 numeric;
idforn numeric;
fator_atuacao  numeric;
tipo_fator varchar;
grupo numeric;

begin

IF substring(idprod, 0, 8) = 'SYSCOMB' THEN
    return (
        SELECT sum(COALESCE(get_cmm_heranca_filial(p_filial, s.idproduto, dataref), 0))
        FROM sys_produtos_combinados_itens s
        WHERE s.id_produto_combinado = idprod
    );
END IF;

select
	current_date - min(emissao) into primeiro_consumo
from
	consumos c
where
	c.filial = p_filial
	and c.idproduto = idprod;

--Media do Consumo  sai 365 para  (90+180)/2 
-- 30/05/2019 - Inclusao do abatimento Corte nas saidas
SELECT
	coalesce(
		round(
			cast(
				sum(saidas) /(
					abs(
						case
							when abs(
								datediff(
									'mm',
									cast(to_char(dataref, 'YYYYMMDD') as date),
									cast(min(mes) || '01' as date)
								)
							) + 1 > 3 then 3
							when abs(
								datediff(
									'mm',
									cast(to_char(dataref, 'YYYYMMDD') as date),
									cast(min(mes) || '01' as date)
								)
							) + 1 < 3
							and primeiro_consumo >= 90 then 3
							else abs(
								datediff(
									'mm',
									cast(to_char(dataref, 'YYYYMMDD') as date),
									cast(min(mes) || '01' as date)
								)
							) + 1
						end
					)
				) as numeric
			),
			2
		),
		0
	),
	(
		abs(
			case
				when abs(
					datediff(
						'mm',
						cast(to_char(dataref, 'YYYYMMDD') as date),
						cast(min(mes) || '01' as date)
					)
				) + 1 > 3 then 3
				when abs(
					datediff(
						'mm',
						cast(to_char(dataref, 'YYYYMMDD') as date),
						cast(min(mes) || '01' as date)
					)
				) + 1 < 3
				and primeiro_consumo >= 90 then 3
				else abs(
					datediff(
						'mm',
						cast(to_char(dataref, 'YYYYMMDD') as date),
						cast(min(mes) || '01' as date)
					)
				) + 1
			end
		)
	) into cmm3,
	qtde3
FROM
	(
		SELECT
			to_char(emissao, 'YYYYMM') AS mes,
			to_char(emissao, 'YYYYMMDD') AS dia,
			sum(qtde) AS saidas
		FROM
			consumos
		WHERE
			consumos.filial = p_filial
			and consumos.idproduto = idprod
			AND emissao BETWEEN (dataref - 90)
			AND dataref
		GROUP BY
			mes,
			dia
	) com;

SELECT
	coalesce(
		round(
			cast(
				sum(saidas) /(
					abs(
						case
							when abs(
								datediff(
									'mm',
									cast(to_char(dataref, 'YYYYMMDD') as date),
									cast(min(mes) || '01' as date)
								)
							) + 1 > 6 then 6
							when abs(
								datediff(
									'mm',
									cast(to_char(dataref, 'YYYYMMDD') as date),
									cast(min(mes) || '01' as date)
								)
							) + 1 < 6
							and primeiro_consumo >= 180 then 6
							else abs(
								datediff(
									'mm',
									cast(to_char(dataref, 'YYYYMMDD') as date),
									cast(min(mes) || '01' as date)
								)
							) + 1
						end
					)
				) as numeric
			),
			2
		),
		0
	),
	(
		abs(
			case
				when abs(
					datediff(
						'mm',
						cast(to_char(dataref, 'YYYYMMDD') as date),
						cast(min(mes) || '01' as date)
					)
				) + 1 > 6 then 6
				when abs(
					datediff(
						'mm',
						cast(to_char(dataref, 'YYYYMMDD') as date),
						cast(min(mes) || '01' as date)
					)
				) + 1 < 6
				and primeiro_consumo >= 180 then 6
				else abs(
					datediff(
						'mm',
						cast(to_char(dataref, 'YYYYMMDD') as date),
						cast(min(mes) || '01' as date)
					)
				) + 1
			end
		)
	) into cmm6,
	qtde6
FROM
	(
		SELECT
			to_char(emissao, 'YYYYMM') AS mes,
			to_char(emissao, 'YYYYMMDD') AS dia,
			sum(qtde) AS saidas
		FROM
			consumos
		WHERE
			consumos.filial = p_filial
			and consumos.idproduto = idprod
			AND emissao BETWEEN (dataref - 180)
			AND dataref
		GROUP BY
			mes,
			dia
	) com;

if qtde6 < 6 then cmm6 = cmm3;

end if;

cmm = (cmm3 + cmm6) / 2;

if cmm = 0 then
 
   return 0;

else 

return cmm ;

end if;

end;
$$;


ALTER FUNCTION public.get_cmm_heranca_filial(p_filial numeric, idprod character varying, dataref date) OWNER TO systock;

--
-- TOC entry 831 (class 1255 OID 84241)
-- Name: get_cmm_heranca_produto_combinado(integer, character varying, integer); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_cmm_heranca_produto_combinado(p_idgrupo integer, p_idproduto_combinado character varying, p_filial integer DEFAULT 0) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
    BEGIN
        return coalesce((
            WITH herancas AS (
                SELECT s.id_produto_combinado, p.idproduto, s.tipo_heranca
                FROM sys_herancas_produtos_combinados s
                    INNER JOIN produtos_filial p ON p.idproduto = s.idproduto_heranca
                WHERE (current_date - s.created_at::date) <= 60 AND s.id_produto_combinado = p_idproduto_combinado
                GROUP BY s.id_produto_combinado, p.idproduto

                UNION ALL

                SELECT s.id_produto_combinado, s2.idproduto, s.tipo_heranca
                FROM sys_herancas_produtos_combinados s
                    INNER JOIN sys_produtos_combinados_itens s2 ON s2.id_produto_combinado = s.idproduto_heranca
                WHERE (current_date - s.created_at::date) <= 60 AND s.id_produto_combinado = p_idproduto_combinado
                GROUP BY s.id_produto_combinado, s2.idproduto
            )
            SELECT
                sum((coalesce(CASE
                    WHEN h.tipo_heranca = 1 THEN get_cmm_heranca_filial(g.filial, h.idproduto, (SELECT min(emissao) + 90 from consumos c where c.filial = g.filial and c.idproduto = h.idproduto))
                    ELSE get_cmm_heranca_filial(g.filial, h.idproduto)
                END, 0))) AS cmm_heranca
            FROM herancas h
                CROSS JOIN grupo_filial g
            WHERE
                g.id_grupo = p_idgrupo
                AND (g.filial = p_filial OR p_filial = 0)
        ), 0);
    END; $$;


ALTER FUNCTION public.get_cmm_heranca_produto_combinado(p_idgrupo integer, p_idproduto_combinado character varying, p_filial integer) OWNER TO systock;

--
-- TOC entry 677 (class 1255 OID 53787)
-- Name: get_cobertura_compras_curva(integer, character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_cobertura_compras_curva(p_filial integer, p_produto character varying) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
declare 
    produto_rec record;
    curvas_produto_rec record;
begin 
    
    select 
       idfornecedor, 
       idfamilia_produto 
       into 
       produto_rec 
    from produtos_filial pf 
    where pf.filial = p_filial and pf.idproduto = p_produto;
    
    select 
        substring(arvore_decisao, 4, 1) AS pqr,
        substring(arvore_decisao, 2, 1) AS xyz
        into
        curvas_produto_rec
    from prismas_grupos pg 
    where 
       id_grupo in (select id_grupo from grupo_filial gf where filial = p_filial) 
       and idproduto = p_produto and data_ref = first_day(current_date); 


    RETURN COALESCE(
        (SELECT v.tempo_cobertura FROM tempo_cobertura_compras_produtos v WHERE v.idproduto = p_produto AND v.deleted_at IS NULL),
        (SELECT v.tempo_cobertura FROM tempo_cobertura_compras_fornecedor v WHERE v.idfornecedor = produto_rec.idfornecedor AND v.deleted_at IS NULL),
        (SELECT v.tempo_cobertura FROM tempo_cobertura_compras_segmentos v WHERE v.idfamilia_produto = produto_rec.idfamilia_produto AND v.deleted_at IS NULL),
        (SELECT v.tempo_cobertura FROM tempo_cobertura_compras v WHERE v.filial = p_filial AND v.pqr = curvas_produto_rec.pqr AND v.xyz = curvas_produto_rec.xyz AND v.deleted_at IS NULL),
        0
    );
   
end;

$$;


ALTER FUNCTION public.get_cobertura_compras_curva(p_filial integer, p_produto character varying) OWNER TO systock;

--
-- TOC entry 678 (class 1255 OID 53788)
-- Name: get_cobertura_esseg(integer, character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_cobertura_esseg(p_filial integer, p_produto character varying) RETURNS double precision
    LANGUAGE plpgsql
    AS $$
    DECLARE
        cobertura int;
        tipo record;
    BEGIN
        SELECT
            pf.classificacao_criticidade AS xyz,
            pf.classificacao_popularidade AS pqr,
            pf.idfamilia_produto,
            pf.idfornecedor,
            pf.idproduto,
            pf.status_tempo_esseg AS status
        INTO tipo
        FROM produtos_filial pf
        WHERE
            pf.filial = p_filial
            AND pf.idproduto = p_produto;

        IF tipo.status = 1 THEN

            SELECT tempo_cobertura_esseg
            INTO cobertura
            FROM tempo_cobertura_compras_geral tccg
            WHERE
                pqr = tipo.pqr
                AND xyz = tipo.xyz
            GROUP BY tempo_cobertura_esseg ;

        ELSEIF tipo.status = 2 THEN

            SELECT tempo_cobertura_esseg
            INTO cobertura
            FROM tempo_cobertura_compras_segmentos tccs
            WHERE idfamilia_produto = tipo.idfamilia_produto
            GROUP BY tempo_cobertura_esseg ;

        ELSEIF tipo.status = 3 THEN

            SELECT tempo_cobertura_esseg
            INTO cobertura
            FROM tempo_cobertura_compras_fornecedor tccf
            WHERE idfornecedor = tipo.idfornecedor
            GROUP BY tempo_cobertura_esseg ;

        ELSEIF tipo.status = 4 THEN

            SELECT tempo_cobertura_esseg
            INTO cobertura
            FROM tempo_cobertura_compras_produtos tccp
            WHERE idproduto::TEXT = tipo.idproduto::TEXT
            GROUP BY tempo_cobertura_esseg ;

        ELSE

            cobertura = 0;

        END IF;

        RETURN COALESCE (cobertura, 0);

    END;

    $$;


ALTER FUNCTION public.get_cobertura_esseg(p_filial integer, p_produto character varying) OWNER TO systock;

--
-- TOC entry 679 (class 1255 OID 53789)
-- Name: get_compra_faturada_filial(numeric, character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_compra_faturada_filial(filial_id numeric, produto_id character varying) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
    DECLARE 
        compra_faturada numeric;
    BEGIN 
        select sum(r.qtde_faturada * pf.fator_conversao)
        into compra_faturada
        from requisicoes r
        inner join produtos_filial pf on r.idfilial = pf.filial and r.idproduto = pf.idproduto
        where
            r.idproduto = produto_id
            and r.qtde_pendente > 0
            and r.qtde_faturada > 0
            and r.data_faturamento is not null
            and r.idfilial = filial_id;

        if compra_faturada is null then compra_faturada = 0;
        end if;

        return compra_faturada;
    END;
    $$;


ALTER FUNCTION public.get_compra_faturada_filial(filial_id numeric, produto_id character varying) OWNER TO systock;

--
-- TOC entry 680 (class 1255 OID 53790)
-- Name: get_compra_faturada_grupo(numeric, character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_compra_faturada_grupo(grupo_id numeric, produto_id character varying) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
    DECLARE 
        compra_faturada numeric;
    BEGIN 
        select sum(r.qtde_faturada * pf.fator_conversao)
        into compra_faturada
        from requisicoes r
        inner join produtos_filial pf on r.idfilial = pf.filial and r.idproduto = pf.idproduto
        where
            r.idproduto = produto_id
            and r.qtde_pendente > 0
            and r.qtde_faturada > 0
            and r.data_faturamento is not null
            and r.idfilial in (
                select gf.filial
                from grupo_filial gf
                where gf.id_grupo = grupo_id
            );

        if compra_faturada is null then compra_faturada = 0;
        end if;

        return compra_faturada;
    END;
    $$;


