--
-- TOC entry 832 (class 1255 OID 84257)
-- Name: get_estoque_similar_produto_combinado(integer, integer, character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_estoque_similar_produto_combinado(p_idgrupo integer, p_filial integer, p_idproduto character varying) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
    DECLARE
    BEGIN
        return coalesce((
            SELECT sum(greatest(p.estoque - COALESCE(p.estoque_similar, 0), 0))
            FROM produtos_filial p
                inner join grupo_filial g ON g.filial = p.filial
            WHERE
                g.id_grupo = p_idgrupo
                AND (p.filial = p_filial OR p_filial = 0)
                AND p.idproduto IN (
                    SELECT i.idproduto
                    FROM similares s
                        INNER JOIN sys_produtos_combinados_itens i ON i.id_produto_combinado = s.id_item_filho
                    WHERE s.agregar_estoque = 'S' AND s.id_item_pai = p_idproduto

                    UNION ALL

                    SELECT s.id_item_filho
                    FROM similares s
                    WHERE s.agregar_estoque = 'S' AND s.id_item_pai = p_idproduto AND substring(s.id_item_filho, 0, 8) <> 'SYSCOMB'
                )
        ), 0);
    END;
    $$;


ALTER FUNCTION public.get_estoque_similar_produto_combinado(p_idgrupo integer, p_filial integer, p_idproduto character varying) OWNER TO systock;

--
-- TOC entry 697 (class 1255 OID 53807)
-- Name: get_forecast(character varying, numeric); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_forecast(idprod character varying, tempo_dias numeric) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
declare 
    saldo_estoque numeric;
    compra_transito numeric;
    consumo_futuro numeric;
    saldo_futuro numeric;
begin 


    select getconsumo_provisionado(idprod,tempo_dias),coalesce(estoque,0) 
           into consumo_futuro,saldo_estoque 
    from produtos where idproduto=idprod; 

    
   saldo_futuro = (saldo_estoque-consumo_futuro);
    
    return saldo_futuro;

end;

$$;


ALTER FUNCTION public.get_forecast(idprod character varying, tempo_dias numeric) OWNER TO systock;

--
-- TOC entry 698 (class 1255 OID 53808)
-- Name: get_forecast_filial(numeric, character varying, numeric); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_forecast_filial(p_filial numeric, idprod character varying, tempo_dias numeric) RETURNS numeric
    LANGUAGE plpgsql
    AS $$

declare 

    saldo_estoque numeric;

    compra_transito numeric;

    consumo_futuro numeric;

    saldo_futuro numeric;
   
    fator numeric;

begin 





    select getconsumo_provisionado_filial(p_filial,idprod,tempo_dias),coalesce(estoque,0),coalesce(fator_conversao,1) 

           into consumo_futuro,saldo_estoque,fator 

    from produtos_filial where filial = p_filial and  idproduto=idprod; 



    

   saldo_futuro = round((saldo_estoque-consumo_futuro)*fator,4);

    

    return saldo_futuro;



end;



$$;


ALTER FUNCTION public.get_forecast_filial(p_filial numeric, idprod character varying, tempo_dias numeric) OWNER TO systock;

--
-- TOC entry 699 (class 1255 OID 53809)
-- Name: get_forecast_grupo(numeric, character varying, numeric); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_forecast_grupo(p_grupo numeric, idprod character varying, tempo_dias numeric) RETURNS numeric
    LANGUAGE plpgsql
    AS $$

declare 

    saldo_estoque numeric;

    compra_transito numeric;

    consumo_futuro numeric;

    saldo_futuro numeric;

begin 





    select sum(getconsumo_provisionado_filial(p.filial,p.idproduto,tempo_dias)*p.fator_conversao),sum(coalesce(estoque*p.fator_conversao,0)) 

           into consumo_futuro,saldo_estoque 

    from produtos_filial p where p.filial  in (select filial from grupo_filial gf where gf.id_grupo=p_grupo) and  p.idproduto=idprod; 



    

   saldo_futuro = (saldo_estoque-consumo_futuro);

    

    return coalesce(saldo_futuro,0);



end;



$$;


ALTER FUNCTION public.get_forecast_grupo(p_grupo numeric, idprod character varying, tempo_dias numeric) OWNER TO systock;

--
-- TOC entry 700 (class 1255 OID 53810)
-- Name: get_freq_ruptura(character varying, integer, integer); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_freq_ruptura(idprod character varying, p_ano integer, p_mes integer) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
declare
   rec_data record;
   saida numeric;
   flag numeric;
begin
 
  flag = 0;
  saida = 0;


  for rec_data in (select estoque,media_trimestre from saldos where idproduto= idprod and ano=p_ano and mes=p_mes order by data)
  loop

           if rec_data.estoque = 0 and flag = 0 and rec_data.media_trimestre > 0 then 
             
              flag =1; 
             
              saida = saida + 1;
           
            else
            
              flag= 0;
             
           end if; 
  end loop;
 
  return saida;
 
end;

$$;


ALTER FUNCTION public.get_freq_ruptura(idprod character varying, p_ano integer, p_mes integer) OWNER TO systock;

--
-- TOC entry 701 (class 1255 OID 53811)
-- Name: get_idcomprador_carteira_comprador(integer, character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_idcomprador_carteira_comprador(p_filial integer, p_produto character varying) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
    declare
        produto_rec record;
    begin

        select
           pf.idfornecedor, pf.iddepartamento, pf.idsecao, pf.idcomprador
           into
           produto_rec
        from produtos_filial pf
        where pf.filial = p_filial and pf.idproduto = p_produto;

        RETURN COALESCE(
            (SELECT nullif(pf.idcomprador_systock, 0) FROM produtos_filial pf WHERE pf.filial = p_filial AND pf.idproduto = p_produto LIMIT 1),
            (SELECT nullif(f.idcomprador, 0) FROM fornecedor f WHERE f.id = produto_rec.idfornecedor),
            (SELECT nullif(d.idcomprador, 0) FROM departamentos d WHERE d.iddepartamento::TEXT = produto_rec.iddepartamento),
            (SELECT nullif(s.idcomprador, 0) FROM secao s WHERE s.idsecao::TEXT = produto_rec.idsecao),
            0
        );

    end; $$;


ALTER FUNCTION public.get_idcomprador_carteira_comprador(p_filial integer, p_produto character varying) OWNER TO systock;

--
-- TOC entry 702 (class 1255 OID 53812)
-- Name: get_preco_medio_venda_filial(numeric, character varying, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_preco_medio_venda_filial(p_filial numeric, idprod character varying, dataref date DEFAULT ('now'::text)::date) RETURNS numeric
    LANGUAGE plpgsql
    AS $$ 

declare 

preco_mv3 numeric;
preco_mv6 numeric;
preco_mv  numeric;
preco_unit numeric;


begin
	
	  select coalesce(valor_unitario*fator_conversao,0)  into preco_unit from produtos_filial pf  where pf.filial = p_filial and pf.idproduto = idprod;
	
			
      select round((sum(total)/nullif(sum(total_qtde),0))::numeric,2)  into preco_mv6 from (   
        SELECT
			(qtde * valor_unit) total, 
			qtde as total_qtde
		FROM
			consumos
		WHERE
			consumos.filial = p_filial
			and consumos.idproduto = idprod
			AND emissao BETWEEN (dataref - 180)	AND dataref
		    and qtde > 0) a;


preco_mv = coalesce(round(preco_mv6,2),0);	

if preco_mv = 0 then  preco_mv= preco_unit; end if;
	
	
return preco_mv;
	

end;
$$;


ALTER FUNCTION public.get_preco_medio_venda_filial(p_filial numeric, idprod character varying, dataref date) OWNER TO systock;

--
-- TOC entry 703 (class 1255 OID 53813)
-- Name: get_prismas_analise(character varying, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_prismas_analise(produto character varying, dataref date DEFAULT ('now'::text)::date) RETURNS character varying
    LANGUAGE plpgsql
    AS $$ 
declare

retorno varchar;
table_temp1 varchar;
table_temp2 varchar;
table_temp3 varchar;

begin
	
	
	table_temp1 =  '_tmp_classificacao_financeira_'||to_char(dataref,'mmyyyy');
    table_temp2 =  '_tmp_classificacao_criticidade_'||to_char(dataref,'mmyyyy');
    table_temp3 =  '_tmp_classificacao_popularidade_'||to_char(dataref,'mmyyyy');
    
	
  -- 1- Prisma Financeiro;	
  
   
  EXECUTE format('create temporary table if not exists %I  as 
  select
	idproduto,
    getclassfinanceira(sum(acomulado.perc_csm) OVER (ORDER BY acomulado.csm DESC)) as class_abc
from
	(  select idproduto,csm,total_saidas,(csm / total_saidas) as perc_csm from(
		      select idproduto,(getconsumomediomensal(idproduto,last_day(''%I''))*custo_unitario) as csm,
			   (select sum(getconsumomediomensal(idproduto,last_day(''%I''))*custo_unitario)	from produtos) as total_saidas
		          from produtos
		             order by csm desc,	idproduto) prod
	 ) acomulado',table_temp1,dataref,dataref); 

   
  
  
                         
       --2- Prisma Criticidade
       
    EXECUTE format('create temporary table if not exists %I as  
      SELECT acomulado.idproduto,
        CASE
            WHEN  getclassfinanceira(sum(acomulado.perc_csm) OVER (ORDER BY acomulado.csm DESC))::text = ''A''::text THEN ''Z''::text
            WHEN  getclassfinanceira(sum(acomulado.perc_csm) OVER (ORDER BY acomulado.csm DESC))::text = ''B''::text THEN ''Y''::text
            ELSE ''X''::text
        END AS class_xyz
from
	(  select idproduto,csm::numeric,total_saidas::numeric,(csm / total_saidas)::numeric as perc_csm from(
		      select idproduto,(getconsumomediomensal(idproduto,last_day(''%I''))*valor_unitario) as csm,
			   (select sum(getconsumomediomensal(idproduto,last_day(''%I''))*valor_unitario)	from produtos) as total_saidas
		          from produtos
		             order by csm desc,	idproduto) prod
	 ) acomulado',table_temp2,dataref,dataref);



      -- 3- Prisma Popularidade 
      
      EXECUTE format('create temporary table if not exists %I as
         select idproduto,tma,perc_tma,
			sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC) AS perc_acomulado,
			(case when sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC) > 0 and sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC) <= 0.8 then ''P''
      	when sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC) > 0.8 and sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC) <= 0.95 then ''Q''
     	else ''R''  end ) class_pqr from(
			select idproduto,tma,(tma/total_tma) as perc_tma from (
			select idproduto,gettma(idproduto,last_day(''%I'')) as tma,
			(select sum(gettma(idproduto,last_day(''%I''))) from  produtos) as total_tma
		from  produtos order by tma desc ,idproduto) prod) tma_acomulado',table_temp3,dataref,dataref);
       

    execute format('select coalesce(f.class_abc::varchar,''C'')||coalesce(c.class_xyz::varchar,''X'')||coalesce(get123(f.idproduto::varchar),''3'')||coalesce(p.class_pqr::varchar,''R'')  
           from %I f 
             inner join %I c    
              on f.idproduto = c.idproduto
              inner join %I p    
              on f.idproduto = p.idproduto
         where f.idproduto =''%s''',table_temp1,table_temp2,table_temp3,produto)
    into retorno;
     
                         
      
       return retorno;                   
                       
   
end; 
 $$;


ALTER FUNCTION public.get_prismas_analise(produto character varying, dataref date) OWNER TO systock;

--
-- TOC entry 704 (class 1255 OID 53814)
-- Name: get_prismas_analise_filial(numeric, character varying, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_prismas_analise_filial(codfilial numeric, produto character varying, dataref date DEFAULT ('now'::text)::date) RETURNS character varying
    LANGUAGE plpgsql
    AS $$
declare retorno varchar;
table_temp1 varchar;
table_temp2 varchar;
table_temp3 varchar;
begin
	table_temp1 = 'f' || codfilial || '_tmp_classificacao_financeira_' || to_char(dataref, 'mmyyyy');
	table_temp2 = 'f' || codfilial || '_tmp_classificacao_criticidade_' || to_char(dataref, 'mmyyyy');
	table_temp3 = 'f' || codfilial || '_tmp_classificacao_popularidade_' || to_char(dataref, 'mmyyyy');
	-- 1- Prisma Financeiro;	
	execute format('create temporary table if not exists %I  as  select
	idproduto,
    coalesce(getclassfinanceira(sum(acomulado.perc_csm) OVER (ORDER BY acomulado.csm DESC)),''C'') as class_abc

		from

	(  select idproduto,csm,total_saidas,(csm / nullif(total_saidas,0)) as perc_csm from(

		      select idproduto,(get_cmm_filial(%L,idproduto,last_day(%L))*custo_unitario) as csm,

			   (select sum(get_cmm_filial(%L,idproduto,last_day(%L))*custo_unitario) from produtos_filial where filial=%L) as total_saidas

		          from produtos_filial where filial=%L

		             order by csm desc,	idproduto) prod

	 ) acomulado', table_temp1, codfilial, dataref, codfilial, dataref, codfilial, codfilial);
	 
	--2- Prisma Criticidade
	execute format('create temporary table if not exists %I as  

      SELECT acomulado.idproduto,

        CASE

            WHEN  getclassfinanceira(sum(acomulado.perc_csm) OVER (ORDER BY acomulado.csm DESC))::text = ''A''::text THEN ''Z''::text

            WHEN  getclassfinanceira(sum(acomulado.perc_csm) OVER (ORDER BY acomulado.csm DESC))::text = ''B''::text THEN ''Y''::text

            ELSE ''X''::text

        END AS class_xyz

from

	(  select idproduto,csm::numeric,total_saidas::numeric,(csm / nullif(total_saidas,0))::numeric as perc_csm from(

		      select idproduto,(get_cmm_filial(%L,idproduto,last_day(%L))*valor_unitario) as csm,

			   (select sum(get_cmm_filial(%L,idproduto,last_day(%L))*valor_unitario) from produtos_filial where filial=%L) as total_saidas

		          from produtos_filial where filial=%L

		             order by csm desc,	idproduto) prod

	 ) acomulado', table_temp2, codfilial, dataref, codfilial, dataref, codfilial, codfilial);
	-- 3- Prisma Popularidade 
	execute format('create temporary table if not exists %I as

         select idproduto,tma,perc_tma,

			sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC) AS perc_acomulado,

			(case when sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC) > 0 and sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC) <= 0.8 then ''P''

      	when sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC) > 0.8 and sum(tma_acomulado.perc_tma) OVER (ORDER BY tma_acomulado.tma DESC) <= 0.95 then ''Q''

     	else ''R''  end ) class_pqr from(

			select idproduto,tma,(tma/nullif(total_tma,0)) as perc_tma from (

			select idproduto,get_tma_filial(%L,idproduto,last_day(%L)) as tma,

			(select sum(get_tma_filial(%L,idproduto,last_day(%L))) from  produtos_filial where filial=%L) as total_tma

		from  produtos_filial where filial=%L order by tma desc ,idproduto) prod) tma_acomulado', table_temp3, codfilial, dataref, codfilial, dataref, 
			codfilial, codfilial);
	execute format('select coalesce(f.class_abc::varchar,''C'')||coalesce(c.class_xyz::varchar,''X'')||coalesce(get123(f.idproduto::varchar),''3'')||coalesce(p.class_pqr::varchar,''R'')  

           from %I f 

             inner join %I c    

              on f.idproduto = c.idproduto

              inner join %I p    

              on f.idproduto = p.idproduto

         where f.idproduto =%L', table_temp1, table_temp2, table_temp3, produto)
	into retorno;
	return retorno;
end;$$;


