--
-- TOC entry 706 (class 1255 OID 53816)
-- Name: get_quantidade_meses_movimentacoes_ultimo_semestre(bigint, bigint, character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_quantidade_meses_movimentacoes_ultimo_semestre(p_grupo bigint, p_filial bigint, p_produto character varying) RETURNS integer
    LANGUAGE plpgsql
    AS $$
    BEGIN
        IF substring(p_produto, 0, 8) = 'SYSCOMB' THEN
            return (
                SELECT count(DISTINCT to_char(c.DATA, 'yyyy-mm-01')::date)
                FROM (
                    SELECT to_char(c.emissao, 'yyyy-mm-01')::date AS DATA, sum(c.qtde) AS qtde
                    FROM consumos c
                    WHERE
                        c.emissao BETWEEN current_date - 180 AND current_date
                        AND c.filial IN (SELECT gf.filial FROM grupo_filial gf WHERE gf.id_grupo = p_grupo)
                        AND (c.filial = p_filial OR p_filial = 0)
                        AND exists(
                            SELECT 1
                            FROM sys_produtos_combinados_itens i
                            WHERE i.id_produto_combinado = p_produto AND i.idproduto = c.idproduto
                        )
                    GROUP BY to_char(c.emissao, 'yyyy-mm-01')
                ) c
                WHERE qtde > 0
            );
        END IF;

        return (
            SELECT count(DISTINCT to_char(c.DATA, 'yyyy-mm-01')::date)
            FROM (
                SELECT to_char(c.emissao, 'yyyy-mm-01')::date AS DATA, sum(c.qtde) AS qtde
                FROM consumos c
                WHERE
                    c.emissao BETWEEN current_date - 180 AND current_date
                    AND c.filial IN (SELECT gf.filial FROM grupo_filial gf WHERE gf.id_grupo = p_grupo)
                    AND (c.filial = p_filial OR p_filial = 0)
                    AND c.idproduto = p_produto
                GROUP BY to_char(c.emissao, 'yyyy-mm-01')
            ) c
            WHERE qtde > 0
        );
    END; $$;


ALTER FUNCTION public.get_quantidade_meses_movimentacoes_ultimo_semestre(p_grupo bigint, p_filial bigint, p_produto character varying) OWNER TO systock;

--
-- TOC entry 707 (class 1255 OID 53817)
-- Name: get_stat_produto(numeric, character varying, numeric); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_stat_produto(p_filial numeric, idprod character varying, tempo_dias numeric DEFAULT 30) RETURNS TABLE(t_q1 numeric, t_q3 numeric, t_iqr numeric, t_limite_inferior numeric, t_limite_superior numeric)
    LANGUAGE plpgsql
    AS $$ 
declare 

qt_1 numeric;
qt_3 numeric;
vl_iqr numeric;
lim_inf numeric;
lim_sup numeric;

begin

   select q1,q3,iqr,floor((q1-(1.5*iqr)))linf ,ceil((q3+(1.5*iqr)))lisup 
	    into qt_1,qt_3,vl_iqr,lim_inf,lim_sup
   from (     
   select 
   avg(saidas) media,
   percentile_cont(0.25) within group (order by u.saidas) q1,
   percentile_cont(0.5) within group (order by u.saidas) q2,
   percentile_cont(0.75) within group (order by u.saidas) q3,
   percentile_cont(0.75) within group (order by u.saidas) - percentile_cont(0.25) within group (order by u.saidas) iqr
    from(            
         
      with tempo as (
         select distinct to_char(day :: date, 'YYYYMMDD') as referencia
         FROM generate_series(current_date - tempo_dias::integer , current_date, '1 day') day 
         order by to_char(day :: date, 'YYYYMMDD'))

		SELECT
			 t.referencia AS mes,
			coalesce(sum(c.qtde),0) AS saidas
		from tempo t
		left join consumos c
		     on c.filial =  p_filial
			and c.idproduto = idprod
		    and to_char(c.emissao , 'YYYYMMDD') = t.referencia
		WHERE
			c.filial =  p_filial
			and c.idproduto = idprod
			AND c.emissao BETWEEN (current_date - tempo_dias::integer) AND current_date
		GROUP BY
			t.referencia    		
	
		)u)a;     
	
	   if lim_inf < 0 then lim_inf=0; end if;
	   if lim_sup < 0 then lim_sup=0; end if;
	
	
	   t_q1:=qt_1;
	   t_q3:=qt_3;
	   t_iqr:=vl_iqr;
	   t_limite_inferior:=lim_inf;
	   t_limite_superior:=lim_sup;



return next;
end;

$$;


ALTER FUNCTION public.get_stat_produto(p_filial numeric, idprod character varying, tempo_dias numeric) OWNER TO systock;

--
-- TOC entry 708 (class 1255 OID 53818)
-- Name: get_stddev_consumo(numeric, character varying, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_stddev_consumo(p_filial numeric, p_produto character varying, p_dataref date DEFAULT ('now'::text)::date) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
declare 
desvio numeric;
linf numeric;
lisup numeric;
prod_heranca varchar;
modo_heranca int4;
tempo_heranca numeric; 
desvio_heranca numeric;
data_calc_cmm_heranca date;

begin
	
	  --select limite_inferior ,limite_superior into linf,lisup  from analise_statistica_produtos where filial=p_filial and idproduto=p_produto;
	 

	 
	  select
			heranca,
			tipo_heranca,
			current_date - cadastro_heranca,
			coalesce(limite_inferior,0),
			coalesce(limite_superior,0)
			
		into
			prod_heranca,
			modo_heranca,
			tempo_heranca,
			linf,
			lisup
			
		from
			produtos_filial pf
		inner join grupo_filial gf on
			gf.filial = pf.filial
		where
			pf.filial = p_filial
			and pf.idproduto = p_produto;
		
		-- Espaço amostral sai de 365 para 180;
		select coalesce(round(cast(stddev_pop(saidas) as numeric), 2), 0)
			into desvio
			from (
		     select * from (	
			  select to_char(emissao, 'YYYYMM') as mes
					,sum(qtde) as saidas
				from consumos c
				where c.filial = p_filial
					and c.idproduto = p_produto
					and c.emissao between (p_dataref - 180)
						and p_dataref
				group by mes) a where a.saidas between linf and lisup
				) com;
		
	    
		desvio_heranca=0;	
		
		if prod_heranca <>'' then 
		
		
		    if modo_heranca = 1 then
		    
		         
			       select
			         min(emissao)+ 90
			         into data_calc_cmm_heranca
					from
						consumos c
					where
						c.filial = p_filial
						and c.idproduto = prod_heranca ;
			
			   
				   if tempo_heranca <= 60 then	
				   
			           desvio_heranca = (select get_stddev_heranca_consumo(p_filial,prod_heranca,data_calc_cmm_heranca));
			           desvio = 0;
			          
			   
			       end if;
			      
			      
			      return round((desvio+desvio_heranca),2);
			
		    
		      else 
		      
		          if tempo_heranca <= 60 then	
		          
		              desvio_heranca = (select get_stddev_heranca_consumo(p_filial,prod_heranca));
		          
		          end if;
		         
		         return round(((desvio+desvio_heranca)/2),2);
		      
		            
		    end if;  
		
		
		 else
		 
	         
			 return desvio;
		 
		 
		end if;
	
	

end;$$;


ALTER FUNCTION public.get_stddev_consumo(p_filial numeric, p_produto character varying, p_dataref date) OWNER TO systock;

--
-- TOC entry 709 (class 1255 OID 53819)
-- Name: get_stddev_heranca_consumo(numeric, character varying, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_stddev_heranca_consumo(p_filial numeric, p_produto character varying, p_dataref date DEFAULT ('now'::text)::date) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
declare 
desvio numeric;
linf numeric;
lisup numeric;

begin
	
	 select limite_inferior ,limite_superior into linf,lisup  from analise_statistica_produtos where filial=p_filial and idproduto=p_produto;
	 
	-- Espaço amostral sai de 365 para 180;
	select coalesce(round(cast(stddev_pop(saidas) as numeric), 2), 0)
	into desvio
	from (
     select * from (	
	  select to_char(emissao, 'YYYYMM') as mes
			,sum(qtde) as saidas
		from consumos c
		where c.filial = p_filial
			and c.idproduto = p_produto
			and c.emissao between (p_dataref - 180)
				and p_dataref
		group by mes) a where a.saidas between linf and lisup
		) com;
	return desvio;
end;$$;


ALTER FUNCTION public.get_stddev_heranca_consumo(p_filial numeric, p_produto character varying, p_dataref date) OWNER TO systock;

--
-- TOC entry 710 (class 1255 OID 53820)
-- Name: get_stddev_ressup_filial(numeric, character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_stddev_ressup_filial(p_filial numeric, idprod character varying) RETURNS double precision
    LANGUAGE plpgsql
    AS $$
declare 
    desvio float;
    filial_matriz int8;
    grupo_matriz int8;
   	compra_matriz varchar;
   	lim_inf numeric;
    lim_sup numeric;
    tot_amostras numeric;
begin 
	
	 select compra_unificada into compra_matriz from cfgsystem c;
  
      if compra_matriz = 'S' then 
              
 
      		select filial,id_grupo into filial_matriz,grupo_matriz  from grupo_filial gf  where matriz ='S';

      	      select floor((q1-(1.5*iqr)))linf ,ceil((q3+(1.5*iqr)))lisup,amostras 
   				into lim_inf,lim_sup,tot_amostras
				   from (     
				   select 
				   avg(saidas) media,
				   percentile_cont(0.25) within group (order by u.saidas) q1,
				   percentile_cont(0.5) within group (order by u.saidas) q2,
				   percentile_cont(0.75) within group (order by u.saidas) q3,
				   percentile_cont(0.75) within group (order by u.saidas) - percentile_cont(0.25) within group (order by u.saidas) iqr,
				   count(*) amostras
				    from(  select tempo_ressuprimento as saidas from analise_requisicoes where filial in (select filial from grupo_filial gf where gf.id_grupo = grupo_matriz) and idproduto = idProd   
     	                     and atraso = 0 and qtde > 0 and data_solicitacao between current_date -180 and current_date)u) r;
     	     
     	    if tot_amostras < 3 then 
     	      lim_inf=0;
     	      lim_sup=0;
     	    end if ;
     	   
     	    if lim_inf < 0 then  lim_inf=0; end if;   
 	        if lim_sup < 0 then  lim_sup=0; end if;                        
      	
     		select coalesce(round(stddev_pop(tempo_ressuprimento)/30,2),0) into desvio from analise_requisicoes where filial in (select filial from grupo_filial gf where gf.id_grupo = grupo_matriz) and idproduto  = idProd 
              and atraso = 0 and qtde > 0 and data_solicitacao between current_date -180 and current_date and tempo_ressuprimento between  lim_inf and lim_sup;
        else
        
             select floor((q1-(1.5*iqr)))linf ,ceil((q3+(1.5*iqr)))lisup,amostras 
   				into lim_inf,lim_sup,tot_amostras
				   from (     
				   select 
				   avg(saidas) media,
				   percentile_cont(0.25) within group (order by u.saidas) q1,
				   percentile_cont(0.5) within group (order by u.saidas) q2,
				   percentile_cont(0.75) within group (order by u.saidas) q3,
				   percentile_cont(0.75) within group (order by u.saidas) - percentile_cont(0.25) within group (order by u.saidas) iqr,
				   count(*) amostras
				    from(  select tempo_ressuprimento as saidas from analise_requisicoes where filial = p_filial and idproduto = idProd   
     	                     and atraso = 0 and qtde > 0 and data_solicitacao between current_date -180 and current_date)u) r;
     	                    
     	    if tot_amostras < 3 then 
     	      lim_inf=0;
     	      lim_sup=0;
     	    end if ;                
     	                    
     	    if lim_inf < 0 then  lim_inf=0; end if;   
 	        if lim_sup < 0 then  lim_sup=0; end if;                  
        
            select coalesce(round(stddev_pop(tempo_ressuprimento)/30,2),0) into desvio from analise_requisicoes where filial = p_filial and idproduto  = idProd 
               and atraso = 0 and qtde > 0 and data_solicitacao between current_date -180 and current_date and tempo_ressuprimento between  lim_inf and lim_sup;
              
       end if;       
    
    return desvio;

end;

$$;


ALTER FUNCTION public.get_stddev_ressup_filial(p_filial numeric, idprod character varying) OWNER TO systock;

--
-- TOC entry 711 (class 1255 OID 53821)
-- Name: get_suavizacao_exponencial_coeficiente(integer, character varying, numeric, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_suavizacao_exponencial_coeficiente(p_idfilial integer, p_idproduto character varying, p_coeficiente numeric, p_data_referencia date DEFAULT CURRENT_DATE) RETURNS double precision[]
    LANGUAGE plpgsql
    AS $$
    declare
        data_referencia_loop date;
        qtde_vendido_mes_anterior float;
        projecoes_mensal float[];
    BEGIN
        FOR data_referencia_loop IN (
            SELECT date_trunc('month', v1.referencia)::date
            FROM generate_series(p_data_referencia - INTERVAL '11 months', p_data_referencia, INTERVAL '1 month') AS v1(referencia)
        )
        LOOP
            SELECT COALESCE(sum(c.qtde), 0) INTO qtde_vendido_mes_anterior
            FROM consumos c
            WHERE
                c.filial = p_idfilial
                AND c.idproduto = p_idproduto
                AND date_part('year', c.emissao) = date_part('year', data_referencia_loop - INTERVAL '1 month')
                AND date_part('month', c.emissao) = date_part('month', data_referencia_loop - INTERVAL '1 month');

            IF array_length(projecoes_mensal, 1) IS NULL THEN
                projecoes_mensal := array_append(projecoes_mensal, qtde_vendido_mes_anterior);
                CONTINUE;
            END IF;

            projecoes_mensal := array_append(
                projecoes_mensal,
                (p_coeficiente * qtde_vendido_mes_anterior) + (1 - p_coeficiente) * projecoes_mensal[array_length(projecoes_mensal, 1)]
            );
        END LOOP;

        RETURN projecoes_mensal;
    END; $$;


ALTER FUNCTION public.get_suavizacao_exponencial_coeficiente(p_idfilial integer, p_idproduto character varying, p_coeficiente numeric, p_data_referencia date) OWNER TO systock;

--
-- TOC entry 712 (class 1255 OID 53822)
-- Name: get_suavizacao_exponencial_filial(integer, character varying, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_suavizacao_exponencial_filial(p_idfilial integer, p_idproduto character varying, p_data_referencia date DEFAULT ('now'::text)::date) RETURNS public.suavizacao_exponencial_type
    LANGUAGE plpgsql
    AS $$
    declare
        qtde_vendido_ultimos_12_meses float;
        coeficiente numeric(3, 2);
        projecoes_coeficiente float[];
        suavizacao_exponencial suavizacao_exponencial_type;
        qtde_diferenca_entre_real_e_projetado float;
    BEGIN

        SELECT COALESCE(sum(c.qtde), 0) INTO qtde_vendido_ultimos_12_meses
        FROM consumos c
        WHERE
            c.filial = p_idfilial
            AND c.idproduto = p_idproduto
            AND c.emissao BETWEEN first_day((p_data_referencia - INTERVAL '11 months')::date) AND last_day(p_data_referencia);

        FOR coeficiente IN (SELECT * FROM generate_series(0.01, 1, .01) AS v1(coeficiente))
        LOOP
            projecoes_coeficiente = get_suavizacao_exponencial_coeficiente(p_idfilial, p_idproduto, coeficiente);

            qtde_diferenca_entre_real_e_projetado = abs(qtde_vendido_ultimos_12_meses - (SELECT COALESCE(SUM(valor), 0) FROM unnest(projecoes_coeficiente) AS v(valor)));

            IF suavizacao_exponencial.qtde_diferenca IS NULL OR qtde_diferenca_entre_real_e_projetado < suavizacao_exponencial.qtde_diferenca THEN
                suavizacao_exponencial.coeficiente := coeficiente;
                suavizacao_exponencial.qtde_diferenca := qtde_diferenca_entre_real_e_projetado;
                suavizacao_exponencial.projecoes := projecoes_coeficiente;
            END IF;

        END LOOP;

        RETURN suavizacao_exponencial;
    END; $$;


ALTER FUNCTION public.get_suavizacao_exponencial_filial(p_idfilial integer, p_idproduto character varying, p_data_referencia date) OWNER TO systock;

--
-- TOC entry 713 (class 1255 OID 53823)
-- Name: get_temp_ressup_filial(numeric, character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_temp_ressup_filial(p_filial numeric, idprod character varying) RETURNS double precision
    LANGUAGE plpgsql
    AS $$
declare 
    tempo_ressuprimento_mes float;
    filial_matriz int8;
    grupo_matriz int8;
    compra_matriz varchar;
    lim_inf numeric;
    lim_sup numeric;
begin 

	       
 --Busca Tempo Pela Matriz
     
  select compra_unificada into compra_matriz from cfgsystem c;
  
      if compra_matriz = 'S' then 
 
      select filial,id_grupo into filial_matriz, grupo_matriz  from grupo_filial gf  where matriz ='S';
     
       select floor((q1-(1.5*iqr)))linf ,ceil((q3+(1.5*iqr)))lisup 
   		 into lim_inf,lim_sup
			   from (     
			   select 
			   avg(saidas) media,
			   percentile_cont(0.25) within group (order by u.saidas) q1,
			   percentile_cont(0.5) within group (order by u.saidas) q2,
			   percentile_cont(0.75) within group (order by u.saidas) q3,
			   percentile_cont(0.75) within group (order by u.saidas) - percentile_cont(0.25) within group (order by u.saidas) iqr
			    from(  select tempo_ressuprimento as saidas from analise_requisicoes where filial in (select filial from grupo_filial gf where gf.id_grupo = grupo_matriz) and idproduto = idProd   
 	                     and atraso = 0 and qtde > 0 and data_solicitacao between current_date -180 and current_date)u) r;
 	                    
 	      if lim_inf < 0 then  lim_inf=0; end if;   
 	      if lim_sup < 0 then  lim_sup=0; end if;     
      
      select coalesce(round(avg(tempo_ressuprimento)/30,2),1.17) into tempo_ressuprimento_mes from analise_requisicoes where filial in (select filial from grupo_filial gf where gf.id_grupo = grupo_matriz) 
        and idproduto = idProd   
     	and atraso = 0 and qtde > 0 and data_solicitacao between current_date -180 and current_date and tempo_ressuprimento between  lim_inf and lim_sup;
     
    else
    
       select floor((q1-(1.5*iqr)))linf ,ceil((q3+(1.5*iqr)))lisup 
   		 into lim_inf,lim_sup
			   from (     
			   select 
			   avg(saidas) media,
			   percentile_cont(0.25) within group (order by u.saidas) q1,
			   percentile_cont(0.5) within group (order by u.saidas) q2,
			   percentile_cont(0.75) within group (order by u.saidas) q3,
			   percentile_cont(0.75) within group (order by u.saidas) - percentile_cont(0.25) within group (order by u.saidas) iqr
			    from(  select tempo_ressuprimento as saidas from analise_requisicoes where filial = p_filial and idproduto = idProd   
 	                     and atraso = 0 and qtde > 0 and data_solicitacao between current_date -180 and current_date)u) r;
 	                    
 	      if lim_inf < 0 then  lim_inf=0; end if;   
 	      if lim_sup < 0 then  lim_sup=0; end if;    
    
    
      select coalesce(round(avg(tempo_ressuprimento)/30,2),1.17) into tempo_ressuprimento_mes from analise_requisicoes where filial = p_filial and idproduto = idProd   
 		and atraso = 0 and qtde > 0 and data_solicitacao between current_date -180 and current_date and tempo_ressuprimento between  lim_inf and lim_sup;
    
    
  end if;  
          
  
 --Tempo Padrão 2 meses caso não tenha comportamento 
 
  tempo_ressuprimento_mes=coalesce(nullif(tempo_ressuprimento_mes,0),1.17); 
      
    
  return tempo_ressuprimento_mes;

end;

$$;


ALTER FUNCTION public.get_temp_ressup_filial(p_filial numeric, idprod character varying) OWNER TO systock;

--
-- TOC entry 714 (class 1255 OID 53824)
-- Name: get_tma_filial(numeric, character varying, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_tma_filial(p_filial numeric, idprod character varying, dataref date DEFAULT ('now'::text)::date) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
declare tma numeric;

--#### Mário Almeida - 26/07/2023 ####  - Ajuste na Função para calcular a frequência em  6 meses

begin
select
	coalesce(sum(saidas)/6, 0)
into
	tma
from
	(
	select
		to_char(emissao, 'YYYYMM') as mes,
		count(*) as saidas
	from
		consumos
	where
		filial = p_filial
		and idproduto = idProd
		and emissao between (dataref - 180) and dataref
	group by
		mes ) saidas;

return tma;
end;

$$;


ALTER FUNCTION public.get_tma_filial(p_filial numeric, idprod character varying, dataref date) OWNER TO systock;

--
-- TOC entry 715 (class 1255 OID 53825)
-- Name: get_tmr_filial(numeric, character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.get_tmr_filial(p_filial numeric, idprod character varying) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
    declare
        tmr numeric;
        ressup_manual varchar;
        ressup_dia numeric;
    begin

        select
            ressuprimento_manual,
            ressuprimento_manual_dias
            into
            ressup_manual,
            ressup_dia
        from produtos_filial pf
        where filial = p_filial and idproduto = idprod;

        if ressup_manual='S' then return ressup_dia;
        else
            select (round(cast(get_temp_ressup_filial(p_filial, idProd) as numeric) + cast(get_stddev_ressup_filial(p_filial, idProd) as numeric), 2) * 30) into tmr;
            return tmr;
        end if;
    end;
    $$;


