BEGIN
    
    IF (SELECT min(aplicado) AS REF FROM tempo_cobertura_compras_geral WHERE tempo_cobertura > 0 AND deleted_at IS NULL) IS NULL THEN
        RETURN;
    END IF;
    
    -- verifica se é pra guardar historico do dia atual
    SELECT MOD(current_date - COALESCE(max(v.DATA), current_date), (SELECT qtde_dias_log_historico_diagnostico FROM cfgsystem)) = 0 INTO guardar_log_historico_diagnostico_data_atual 
    FROM analise_diagnostico_estoque_grupo_diario v;

    -- cancela o log do dia atual
    IF NOT guardar_log_historico_diagnostico_data_atual THEN
        RETURN;
    END IF;
    
    FOR rec_produto IN (SELECT * FROM analise_diagnostico_estoque_grupo)
    LOOP
