ALTER FUNCTION public.processar_analise_diagnostico_estoque_grupo_diario() OWNER TO systock;

--
-- TOC entry 765 (class 1255 OID 53881)
-- Name: processar_analise_movimentacoes_produtos_filial(date, text); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_analise_movimentacoes_produtos_filial(data_inicial date DEFAULT CURRENT_DATE, filtro_sql text DEFAULT ''::text) RETURNS void
    LANGUAGE plpgsql
    AS $_$
    DECLARE
        rec_cruzamento_produtos_tempos record;
        query TEXT;
    BEGIN
        data_inicial = to_char(data_inicial, '01/MM/YYYY')::date;

        query = FORMAT($$
            WITH tempos AS (
                SELECT DISTINCT
                    to_char(day::date, 'YYYY')::int as ano,
                    to_char(day::date, 'MM')::int as mes
                FROM
                    generate_series($1, current_date, '1 day') day
            ),
            cruzamento_produtos_tempos AS (
                SELECT
                    t.mes,
                    t.ano,
                    pf.filial,
                    pf.idproduto
                FROM produtos_filial pf
                    INNER JOIN tempos t ON TRUE
                    INNER JOIN grupo_filial gf ON gf.filial = pf.filial
                    INNER JOIN grupo_compras gc ON gc.id = gf.id_grupo AND gc.grupo_agrega <> 'S'
            ),
            saidas AS (
                SELECT
                    to_char(c.emissao, 'MM')::int AS mes,
                    to_char(c.emissao, 'YYYY')::int AS ano,
                    c.filial,
                    c.idproduto,
                    sum(c.qtde) AS quantidade,
                    sum(c.qtde * c.valor_unit) AS valor
                FROM consumos c
                WHERE
                    c.emissao >= $1
                    AND c.status NOT IN (SELECT scpo.descricao FROM status_consumos_para_ocultar scpo)
                GROUP BY
                    to_char(c.emissao, 'MM')::int,
                    to_char(c.emissao, 'YYYY')::int,
                    c.filial,
                    c.idproduto
            ),
            compras AS (
                SELECT
                    to_char(r.data_solicitacao, 'MM')::int AS mes,
                    to_char(r.data_solicitacao, 'YYYY')::int AS ano,
                    r.idfilial AS filial,
                    r.idproduto,
                    sum(r.qtde) AS quantidade,
                    sum(r.qtde * r.pcompra) AS valor
                FROM requisicoes r
                WHERE r.data_solicitacao >= $1
                GROUP BY
                    to_char(r.data_solicitacao, 'MM')::int,
                    to_char(r.data_solicitacao, 'YYYY')::int,
                    r.idfilial,
                    r.idproduto
            ),
            entradas AS (
                SELECT
                    to_char(e.data_entrada, 'MM')::int AS mes,
                    to_char(e.data_entrada, 'YYYY')::int AS ano,
                    e.idfilial AS filial,
                    e.idproduto,
                    sum(e.qtde) AS quantidade,
                    sum(e.qtde * e.custo_unit) AS valor
                FROM entrada_mercadorias e
                WHERE e.data_entrada >= $1
                GROUP BY
                    to_char(e.data_entrada, 'MM')::int,
                    to_char(e.data_entrada, 'YYYY')::int,
                    e.idfilial,
                    e.idproduto
            ),
            saldos_filial_inicio_mes AS (
                SELECT
                    sf.filial,
                    sf.ano,
                    sf.mes,
                    sf.idproduto,
                    SUM(estoque) AS soma_estoque_inicio
                FROM saldo_filiais sf
                WHERE "data" = to_char("data", '01/mm/yyyy')::date AND sf."data" >= $1
                GROUP BY
                    date_trunc('month', "data"),
                    sf.filial,
                    sf.ano,
                    sf.mes,
                    sf.idproduto
            ),
            saldos_filial_final_mes AS (
                WITH datas AS (
                    SELECT sf.filial, sf.idproduto, max(sf.data) AS data
                    FROM saldo_filiais sf
                    GROUP BY sf.filial, sf.idproduto, sf.ano, sf.mes
                )
                SELECT
                    sf.filial,
                    sf.ano,
                    sf.mes,
                    sf.idproduto,
                    SUM(sf.estoque) AS soma_estoque_final
                FROM saldo_filiais sf
                    INNER JOIN datas d ON (d.filial, d.idproduto, d.data) = (sf.filial, sf.idproduto, sf.data)
                GROUP BY
                    sf.filial,
                    sf.ano,
                    sf.mes,
                    sf.idproduto
            )
            SELECT
                cpt.mes::int,
                cpt.ano::int,
                cpt.filial::int,
                cpt.idproduto::varchar,
                COALESCE(s.quantidade, 0)::NUMERIC AS qtde_saidas,
                COALESCE(s.valor, 0)::NUMERIC AS valor_saidas,
                COALESCE(c.quantidade, 0)::NUMERIC AS qtde_compras,
                COALESCE(c.valor, 0)::NUMERIC AS valor_compras,
                COALESCE(e.quantidade, 0)::NUMERIC AS qtde_entradas,
                COALESCE(e.valor, 0)::NUMERIC AS valor_entradas,
                COALESCE(round((coalesce(im.soma_estoque_inicio,0) + coalesce(fm.soma_estoque_final,0)) / 2, 4), 0)::NUMERIC AS estoque_medio_filial
            FROM cruzamento_produtos_tempos cpt
                LEFT JOIN saidas s ON s.filial = cpt.filial AND s.idproduto = cpt.idproduto AND s.mes = cpt.mes AND s.ano = cpt.ano
                LEFT JOIN compras c ON c.filial = cpt.filial AND c.idproduto = cpt.idproduto AND c.mes = cpt.mes AND c.ano = cpt.ano
                LEFT JOIN entradas e ON e.filial = cpt.filial AND e.idproduto = cpt.idproduto AND e.mes = cpt.mes AND e.ano = cpt.ano
                LEFT JOIN saldos_filial_inicio_mes AS im ON im.ano = cpt.ano AND im.mes = cpt.mes AND im.idproduto = cpt.idproduto AND im.filial = cpt.filial
                LEFT JOIN saldos_filial_final_mes AS fm ON fm.ano = cpt.ano AND fm.mes = cpt.mes AND fm.idproduto = cpt.idproduto AND fm.filial = cpt.filial
            WHERE
                (GREATEST(s.quantidade, c.quantidade, e.quantidade, im.soma_estoque_inicio, fm.soma_estoque_final, 0) > 0 or exists(
                    SELECT ampf.*
                    FROM analise_movimentacoes_produtos_filial ampf
                    WHERE ampf.ano = cpt.ano::int AND ampf.mes = cpt.mes::int AND ampf.filial = cpt.filial::int AND ampf.idproduto = cpt.idproduto::varchar
                ))
                %s
        $$, filtro_sql);

        FOR rec_cruzamento_produtos_tempos IN EXECUTE query USING data_inicial
        LOOP
            UPDATE analise_movimentacoes_produtos_filial
            SET
                mes = rec_cruzamento_produtos_tempos.mes,
                ano = rec_cruzamento_produtos_tempos.ano,
                filial = rec_cruzamento_produtos_tempos.filial,
                idproduto = rec_cruzamento_produtos_tempos.idproduto,
                qtde_saidas = rec_cruzamento_produtos_tempos.qtde_saidas,
                valor_saidas = rec_cruzamento_produtos_tempos.valor_saidas,
                qtde_compras = rec_cruzamento_produtos_tempos.qtde_compras,
                valor_compras = rec_cruzamento_produtos_tempos.valor_compras,
                qtde_entradas = rec_cruzamento_produtos_tempos.qtde_entradas,
                valor_entradas = rec_cruzamento_produtos_tempos.valor_entradas,
                estoque_medio_filial = rec_cruzamento_produtos_tempos.estoque_medio_filial
            WHERE
                mes = rec_cruzamento_produtos_tempos.mes
                AND ano = rec_cruzamento_produtos_tempos.ano
                AND filial = rec_cruzamento_produtos_tempos.filial
                AND idproduto = rec_cruzamento_produtos_tempos.idproduto;

            IF NOT FOUND THEN
                INSERT INTO analise_movimentacoes_produtos_filial (
                    mes,
                    ano,
                    filial,
                    idproduto,
                    qtde_saidas,
                    valor_saidas,
                    qtde_compras,
                    valor_compras,
                    qtde_entradas,
                    valor_entradas,
                    estoque_medio_filial
                )
                VALUES (
                    rec_cruzamento_produtos_tempos.mes,
                    rec_cruzamento_produtos_tempos.ano,
                    rec_cruzamento_produtos_tempos.filial,
                    rec_cruzamento_produtos_tempos.idproduto,
                    rec_cruzamento_produtos_tempos.qtde_saidas,
                    rec_cruzamento_produtos_tempos.valor_saidas,
                    rec_cruzamento_produtos_tempos.qtde_compras,
                    rec_cruzamento_produtos_tempos.valor_compras,
                    rec_cruzamento_produtos_tempos.qtde_entradas,
                    rec_cruzamento_produtos_tempos.valor_entradas,
                    rec_cruzamento_produtos_tempos.estoque_medio_filial
                );
            END IF;
        END LOOP;
    END;
    $_$;


ALTER FUNCTION public.processar_analise_movimentacoes_produtos_filial(data_inicial date, filtro_sql text) OWNER TO systock;

--
-- TOC entry 766 (class 1255 OID 53883)
-- Name: processar_analise_percepcao_compras_grupos(date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_analise_percepcao_compras_grupos(data_inicial date DEFAULT CURRENT_DATE) RETURNS void
    LANGUAGE plpgsql
    AS $$
        DECLARE
            rec_analise record;
        BEGIN
            data_inicial = to_char(data_inicial, '01/MM/YYYY')::date;

            UPDATE analise_percepcao_compras_grupos SET flag = 'D' WHERE data_solicitacao >= data_inicial;

            FOR rec_analise IN (
                SELECT DISTINCT
                    analise.id_grupo,
                    analise.filial,
                    analise.data_solicitacao,
                    analise.ordem_compra,
                    analise.data_entrada,
                    analise.total_entradas,
                    analise.sugestao,
                    analise.idproduto,
                    analise.descricao_produto,
                    analise.descricao_familia_produto,
                    analise.estoque_no_dia_entrada,
                    analise.estoque_seguranca,
                    analise.ponto_pedido,
                    analise.estoque_maximo,
                    analise.tempo_medio_ressuprimento,
                    analise.consumo_medio,
                    analise.estoque_solicitacao,
                    analise.valor_unitario,
                    analise.custo_unitario,
                    analise.nome_comprador,
                    CASE
                        WHEN (
                            SELECT count(*) AS count
                            FROM entrada_mercadorias em
                                INNER JOIN grupo_filial gf ON gf.filial = em.idfilial
                            WHERE
                                gf.id_grupo = analise.id_grupo
                                AND em.idproduto::TEXT = ANY(analise.produtos)
                                AND em.data_entrada < analise.data_solicitacao
                                AND em.data_entrada >= (em.data_entrada - 730)
                                AND em.data_entrada <= 'now'::text::date
                        ) = 0 THEN 'PRIMEIRA COMPRA'::text
                        WHEN analise.consumo_medio = 0::numeric THEN 'SEM COMPORTAMENTO'::TEXT
                        WHEN analise.consumo_medio > 0::numeric AND analise.estoque_solicitacao = 0::numeric THEN 'PERCEPCAO EM RUPTURA'::text
                        WHEN analise.consumo_medio > 0::numeric AND analise.estoque_solicitacao::double precision > analise.ponto_pedido::double precision AND analise.estoque_solicitacao::double precision <= (ceil(analise.estoque_maximo::double precision) * analise.peso::double precision) THEN 'PERCEPCAO EM PONTO DE PEDIDO'::text
                        WHEN analise.consumo_medio > 0::numeric AND analise.estoque_solicitacao::double precision < analise.ponto_pedido::double precision AND analise.estoque_solicitacao > (analise.ponto_pedido - analise.estoque_seguranca) THEN 'PERCEPCAO EM PONTO DE PEDIDO'::text
                        WHEN analise.consumo_medio > 0::numeric AND analise.estoque_solicitacao::double precision > (ceil(analise.estoque_maximo::double precision) * analise.peso::double precision) THEN 'PERCEPCAO COM ELEVADA PREMATURIDADE'::text
                        WHEN analise.consumo_medio > 0::numeric AND analise.estoque_solicitacao::double precision <= analise.ponto_pedido::double precision THEN 'PERCEPCAO COM ELEVADA EXPOSICAO RUPTURA'::text
                        ELSE 'SEM COMPORTAMENTO'::text
                    END AS status_percepcao,
                    CASE
                        WHEN (
                                SELECT count(*) > 0
                                FROM entrada_mercadorias em
                                WHERE
                                    em.idfilial = analise.filial
                                    AND em.idproduto::TEXT = ANY(analise.produtos)
                                    AND em.data_entrada < analise.data_solicitacao
                                    AND em.data_entrada >= (em.data_entrada - 730)
                                    AND em.data_entrada <= 'now'::text::date
                            )
                            AND analise.consumo_medio = 0::numeric
                        THEN (analise.data_solicitacao - (
                                SELECT max(em.data_entrada) AS max
                                FROM entrada_mercadorias em
                                WHERE
                                    em.idfilial = analise.filial
                                    AND em.idproduto::TEXT = ANY(analise.produtos)
                                    AND em.data_entrada < analise.data_solicitacao
                                    AND em.data_entrada >= (em.data_entrada - 730)
                                    AND em.data_entrada <= 'now'::text::date
                            )
                        )::character varying
                        ELSE NULL::character varying
                    END AS qtde_sem_comportamento,
                    analise.fator_conversao,
                    analise.idcomprador,
                    analise.idfornecedor,
                    analise.nivel_servico,
                    analise.produto_eh_combinacao,
                    analise.produto_eh_categoria_mp_pa
                FROM (
                    SELECT
                        gf.id_grupo,
                        requisicoes.idfilial AS filial,
                        requisicoes.data_solicitacao,
                        requisicoes.ordem_compra,
                        entrada_mercadorias.data_entrada,
                        entrada_mercadorias.qtde AS total_entradas,
                        saldos.idproduto,
                        ARRAY[saldos.idproduto] AS produtos,
                        produtos.descricao_produto,
                        familia_produtos.descricao_familia_produto,
                        (
                            SELECT a.estoque
                            FROM saldo_filiais a
                            WHERE a.filial = saldos.filial AND a.idproduto::text = saldos.idproduto::text AND a.data = entrada_mercadorias.data_entrada
                            LIMIT 1
                        ) AS estoque_no_dia_entrada,
                        produtos.tempo_medio_ressuprimento,
                        sg.estoque AS estoque_solicitacao,
                        produtos.valor_unitario,
                        produtos.custo_unitario,
                        comprador.nome_completo AS nome_comprador,
                        sg.esseg AS estoque_seguranca,
                        sg.ppd AS ponto_pedido,
                        sg.emax AS estoque_maximo,
                        saldos.sugestao_compras AS sugestao,
                        sg.cmm AS consumo_medio,
                        produtos.fator_conversao,
                        produtos.idcomprador,
                        produtos.idfornecedor,
                        produtos.nivel_servico,
                        n.peso,
                        FALSE AS produto_eh_combinacao,
                        FALSE AS produto_eh_categoria_mp_pa
                    FROM requisicoes
                        JOIN saldo_filiais saldos ON requisicoes.idfilial = saldos.filial AND requisicoes.idproduto::text = saldos.idproduto::text AND requisicoes.data_solicitacao = saldos.data
                        JOIN produtos_filial produtos ON produtos.filial = saldos.filial AND produtos.idproduto::text = saldos.idproduto::text
                        LEFT JOIN entrada_mercadorias ON entrada_mercadorias.idproduto::text = saldos.idproduto::text AND entrada_mercadorias.ordem_compra = requisicoes.ordem_compra
                        JOIN comprador ON comprador.id = produtos.idcomprador
                        JOIN familia_produtos ON familia_produtos.idfamilia_produto = produtos.idfamilia_produto
                        JOIN nivel_servico n ON n.descricao_nivel_servico::text = produtos.nivel_servico::text
                        JOIN grupo_filial gf ON gf.filial = requisicoes.idfilial
                        JOIN grupo_compras gc ON gc.id = gf.id_grupo
                        JOIN saldo_grupos sg ON sg.id_grupo = gf.id_grupo AND requisicoes.idproduto::text = sg.idproduto::text AND requisicoes.data_solicitacao = sg.data
                    WHERE
                        saldos.data >= data_inicial
                        AND saldos.data <= ('now'::text::date - 1)
                        AND produtos.revenda::text = 'S'::TEXT
                        AND saldos.idproduto NOT IN (
                            SELECT spci.idproduto
                            FROM sys_produtos_combinados spc
                                INNER JOIN sys_produtos_combinados_itens spci ON spci.id_produto_combinado = spc.id AND spc.deleted_at IS NULL
                            GROUP BY spci.idproduto
                        )
                        AND gc.grupo_agrega <> 'S'
                        AND NOT ((requisicoes.idproduto::text, gf.id_grupo) IN (
                            SELECT npb.idproduto, npb.grupo
                            FROM notificacao_produtos_blacklist npb
                            WHERE
                                npb.grupo = gf.id_grupo
                                AND npb.filial IN (0, gf.filial)
                                AND npb.data_limite >= CURRENT_DATE
                                AND npb.deleted_at IS NULL
                        ))

                    UNION ALL

                    SELECT
                        gf.id_grupo,
                        gf.filial,
                        r.data_solicitacao,
                        r.ordem_compra,
                        e.data_entrada,
                        e.qtde AS total_entradas,
                        spc.id AS idproduto,
                        pccf.produtos,
                        spc.descricao AS descricao_produto,
                        '' AS descricao_familia_produto,
                        (
                            SELECT sum(a.estoque)
                            FROM saldo_filiais a
                            WHERE
                                a.filial = gf.filial
                                AND a.idproduto::text IN (SELECT v.idproduto FROM sys_produtos_combinados_itens v WHERE v.id_produto_combinado = spc.id)
                                AND a.data = e.data_entrada
                        ) AS estoque_no_dia_entrada,
                        pccf.tempo_medio_ressuprimento,
                        sg.estoque AS estoque_solicitacao,
                        pccf.valor_unitario,
                        pccf.custo_unitario,
                        ''::TEXT AS nome_comprador,
                        sum(sg.esseg) AS estoque_seguranca,
                        sum(sg.ppd) AS ponto_pedido,
                        sum(sg.emax) AS estoque_maximo,
                        NULL AS sugestao,
                        sum(sg.cmm) AS consumo_medio,
                        pccf.fator_conversao,
                        (
                            SELECT max(pf.idcomprador)
                            FROM produtos_filial pf
                            WHERE pf.filial = gf.filial AND pf.idproduto = ANY(pccf.produtos)
                        ) AS idcomprador,
                        0 AS idfornecedor,
                        pccf.nivel_servico,
                        n.peso,
                        TRUE AS produto_eh_combinacao,
                        FALSE AS produto_eh_categoria_mp_pa
                    FROM requisicoes r
                        INNER JOIN grupo_filial gf ON gf.filial = r.idfilial
                        INNER JOIN grupo_compras gc ON gc.id = gf.id_grupo
                        INNER JOIN sys_produtos_combinados_itens spci ON spci.idproduto = r.idproduto
                        INNER JOIN sys_produtos_combinados spc ON spc.id = spci.id_produto_combinado
                        INNER JOIN produtos_combinados_compras_filial pccf ON pccf.id_grupo = gf.id_grupo AND pccf.filial = gf.filial AND pccf.id_produto_combinado = spc.id
                        INNER JOIN saldo_grupos sg ON sg.id_grupo = gf.id_grupo AND sg.idproduto::text = any(pccf.produtos) AND r.data_solicitacao = sg.DATA
                        INNER JOIN nivel_servico n ON n.descricao_nivel_servico::text = pccf.nivel_servico::text
                        LEFT JOIN entrada_mercadorias e ON e.idproduto::text = r.idproduto::text AND e.ordem_compra = r.ordem_compra
                    WHERE
                        spc.deleted_at IS NULL
                        AND r.data_solicitacao >= data_inicial
                        AND r.data_solicitacao <= (current_date - 1)
                        AND pccf.revenda::text = 'S'::TEXT
                        AND gc.grupo_agrega <> 'S'
                        AND NOT ((spc.id::text, gf.id_grupo) IN (
                            SELECT npb.idproduto, npb.grupo
                            FROM notificacao_produtos_blacklist npb
                            WHERE
                                npb.grupo = gf.id_grupo
                                AND npb.filial IN (0, gf.filial)
                                AND npb.data_limite >= CURRENT_DATE
                                AND npb.deleted_at IS NULL
                        ))
                    GROUP BY
                        gf.id_grupo,
                        gf.filial,
                        r.data_solicitacao,
                        r.ordem_compra,
                        e.data_entrada,
                        e.qtde,
                        spc.id,
                        pccf.produtos,
                        spc.descricao,
                        pccf.tempo_medio_ressuprimento,
                        sg.estoque,
                        pccf.valor_unitario,
                        pccf.custo_unitario,
                        pccf.fator_conversao,
                        pccf.nivel_servico,
                        n.peso

                    UNION ALL

                    (WITH produtos_categoria_mp AS (
                        SELECT DISTINCT mp.id_categoria, mp.id_produto_mp
                        FROM produtos_categoria_mp_pa mp
                    )
                    SELECT
                        gf.id_grupo,
                        requisicoes.idfilial AS filial,
                        requisicoes.data_solicitacao,
                        requisicoes.ordem_compra,
                        NULL AS data_entrada,
                        NULL AS total_entradas,
                        saldos.id_categoria::TEXT AS idproduto,
                        array_agg(id_produto_mp) AS produtos,
                        produtos.descricao_categoria AS descricao_produto,
                        NULL AS descricao_familia_produto,
                        NULL AS estoque_no_dia_entrada,
                        produtos.tempo_medio_ressuprimento,
                        saldos.estoque AS estoque_solicitacao,
                        NULL AS valor_unitario,
                        NULL AS custo_unitario,
                        comprador.nome_completo AS nome_comprador,
                        saldos.estoque_seguranca AS estoque_seguranca,
                        saldos.ponto_pedido AS ponto_pedido,
                        saldos.estoque_maximo AS estoque_maximo,
                        0 AS sugestao,
                        saldos.consumo_medio AS consumo_medio,
                        produtos.fator_conversao,
                        produtos.idcomprador,
                        NULL AS idfornecedor,
                        produtos.nivel_servico,
                        n.peso,
                        FALSE AS produto_eh_combinacao,
                        TRUE AS produto_eh_categoria_mp_pa
                    FROM requisicoes
                        JOIN grupo_filial gf ON gf.filial = requisicoes.idfilial
                        JOIN produtos_categoria_mp pcmp ON pcmp.id_produto_mp = requisicoes.idproduto
                        JOIN saldo_grupos_categorias_mp_pa saldos ON saldos.id_grupo = gf.id_grupo AND saldos.id_categoria = pcmp.id_categoria AND saldos.DATA = requisicoes.data_solicitacao
                        JOIN produtos_compras_categorias_mp_pa produtos ON produtos.id_grupo = gf.id_grupo AND produtos.id_categoria = saldos.id_categoria
                        JOIN comprador ON comprador.id = produtos.idcomprador
                        JOIN nivel_servico n ON n.descricao_nivel_servico::text = produtos.nivel_servico::text
                        JOIN grupo_compras gc ON gc.id = gf.id_grupo
                    WHERE
                        NOT EXISTS (
                            SELECT b.idcategoria
                            FROM notificacao_categorias_mp_pa_blacklist b
                            WHERE
                                b.grupo = produtos.id_grupo
                                AND b.idcategoria = produtos.id_categoria
                                AND b.filial = 0
                                AND b.data_limite >= CURRENT_DATE
                                AND b.deleted_at IS NULL
                        )
                    GROUP BY
                        gf.id_grupo,
                        requisicoes.idfilial,
                        requisicoes.data_solicitacao,
                        requisicoes.ordem_compra,
                        saldos.id_categoria::TEXT,
                        produtos.descricao_categoria,
                        produtos.tempo_medio_ressuprimento,
                        saldos.estoque,
                        comprador.nome_completo,
                        saldos.estoque_seguranca,
                        saldos.ponto_pedido,
                        saldos.estoque_maximo,
                        saldos.consumo_medio,
                        produtos.fator_conversao,
                        produtos.idcomprador,
                        produtos.nivel_servico,
                        n.peso)
                ) analise
            )
            LOOP
                UPDATE analise_percepcao_compras_grupos
                SET
                    id_grupo = rec_analise.id_grupo,
                    filial = rec_analise.filial,
                    data_solicitacao = rec_analise.data_solicitacao,
                    idproduto = rec_analise.idproduto,
                    ordem_compra = rec_analise.ordem_compra,
                    data_entrada = rec_analise.data_entrada,
                    total_entradas = rec_analise.total_entradas,
                    sugestao = rec_analise.sugestao,
                    descricao_produto = rec_analise.descricao_produto,
                    descricao_familia_produto = rec_analise.descricao_familia_produto,
                    estoque_no_dia_entrada = rec_analise.estoque_no_dia_entrada,
                    estoque_seguranca = rec_analise.estoque_seguranca,
                    ponto_pedido = rec_analise.ponto_pedido,
                    estoque_maximo = rec_analise.estoque_maximo,
                    tempo_medio_ressuprimento = rec_analise.tempo_medio_ressuprimento,
                    consumo_medio = rec_analise.consumo_medio,
                    estoque_solicitacao = rec_analise.estoque_solicitacao,
                    valor_unitario = rec_analise.valor_unitario,
                    custo_unitario = rec_analise.custo_unitario,
                    nome_comprador = rec_analise.nome_comprador,
                    status_percepcao = rec_analise.status_percepcao,
                    qtde_sem_comportamento = rec_analise.qtde_sem_comportamento,
                    fator_conversao = rec_analise.fator_conversao,
                    idcomprador = rec_analise.idcomprador,
                    idfornecedor = rec_analise.idfornecedor,
                    nivel_servico = rec_analise.nivel_servico,
                    produto_eh_combinacao = rec_analise.produto_eh_combinacao,
                    produto_eh_categoria_mp_pa = rec_analise.produto_eh_categoria_mp_pa,
                    flag = null
                WHERE
                    id_grupo = rec_analise.id_grupo
                    AND filial = rec_analise.filial
                    AND ordem_compra = rec_analise.ordem_compra
                    AND data_solicitacao = rec_analise.data_solicitacao
                    AND produto_eh_combinacao = rec_analise.produto_eh_combinacao
                    AND produto_eh_categoria_mp_pa = rec_analise.produto_eh_categoria_mp_pa
                    AND idproduto = rec_analise.idproduto;

                IF NOT FOUND THEN
                    INSERT INTO analise_percepcao_compras_grupos (
                        id_grupo,
                        filial,
                        data_solicitacao,
                        ordem_compra,
                        data_entrada,
                        total_entradas,
                        sugestao,
                        idproduto,
                        descricao_produto,
                        descricao_familia_produto,
                        estoque_no_dia_entrada,
                        estoque_seguranca,
                        ponto_pedido,
                        estoque_maximo,
                        tempo_medio_ressuprimento,
                        consumo_medio,
                        estoque_solicitacao,
                        valor_unitario,
                        custo_unitario,
                        nome_comprador,
                        status_percepcao,
                        qtde_sem_comportamento,
                        fator_conversao,
                        idcomprador,
                        idfornecedor,
                        nivel_servico,
                        produto_eh_combinacao,
                        produto_eh_categoria_mp_pa
                    )
                    VALUES (
                        rec_analise.id_grupo,
                        rec_analise.filial,
                        rec_analise.data_solicitacao,
                        rec_analise.ordem_compra,
                        rec_analise.data_entrada,
                        rec_analise.total_entradas,
                        rec_analise.sugestao,
                        rec_analise.idproduto,
                        rec_analise.descricao_produto,
                        rec_analise.descricao_familia_produto,
                        rec_analise.estoque_no_dia_entrada,
                        rec_analise.estoque_seguranca,
                        rec_analise.ponto_pedido,
                        rec_analise.estoque_maximo,
                        rec_analise.tempo_medio_ressuprimento,
                        rec_analise.consumo_medio,
                        rec_analise.estoque_solicitacao,
                        rec_analise.valor_unitario,
                        rec_analise.custo_unitario,
                        rec_analise.nome_comprador,
                        rec_analise.status_percepcao,
                        rec_analise.qtde_sem_comportamento,
                        rec_analise.fator_conversao,
                        rec_analise.idcomprador,
                        rec_analise.idfornecedor,
                        rec_analise.nivel_servico,
                        rec_analise.produto_eh_combinacao,
                        rec_analise.produto_eh_categoria_mp_pa
                    );
                END IF;
            END LOOP;

            DELETE FROM analise_percepcao_compras_grupos WHERE flag = 'D' AND data_solicitacao >= data_inicial;

            DELETE FROM analise_percepcao_compras_grupos WHERE idproduto IN (select idproduto from produtos_para_nao_exibir_nos_indicadores);
        END;
    $$;


ALTER FUNCTION public.processar_analise_percepcao_compras_grupos(data_inicial date) OWNER TO systock;

--
-- TOC entry 767 (class 1255 OID 53885)
-- Name: processar_analise_produtos_comprador_grupo(); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_analise_produtos_comprador_grupo() RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
	max_data_referencia date;
    rec record;
	rec_requisicao record;
   	rec_entregue_em_valor NUMERIC;
	rec_saldos record;
	rec_percepcao_compra record;
	rec_valor_ruptura NUMERIC;
BEGIN
	SELECT max(data_referencia) INTO max_data_referencia FROM analise_produtos_comprador_grupo;
	
	FOR rec IN (
		WITH prod AS (
			SELECT
				gf.id_grupo,
				pf.idfornecedor,
				COALESCE(pf.idcomprador, 0) AS idcomprador
			FROM
				produtos_filial pf
				JOIN grupo_filial gf ON gf.filial = pf.filial
			GROUP BY
				gf.id_grupo,
				pf.idfornecedor,
				pf.idcomprador
		)
		SELECT DISTINCT
		    CASE WHEN last_day(to_char(DAY::date, '01/MM/YYYY')::date) >= (SELECT max(sf.data) FROM saldo_filiais sf WHERE sf.data <= current_date)
		        THEN  (SELECT max(sf.data) FROM saldo_filiais sf WHERE sf.data <= current_date)
		        ELSE last_day(to_char(DAY::date, '01/MM/YYYY')::date)
		    END AS data_referencia,
		    date_part('year', DAY) AS ano,
			date_part('month', DAY) AS mes,
			p.*
		FROM
		    generate_series(current_date - 370, current_date, '1 day') DAY
		    JOIN prod AS p ON TRUE
	    WHERE 
			(max_data_referencia) IS NULL OR (day > (max_data_referencia)) 
	)
	LOOP

		SELECT
			COALESCE(trunc(sum(e.qtde * e.custo_unit)::NUMERIC, 2), 0) INTO rec_entregue_em_valor
		FROM entrada_mercadorias e
			INNER JOIN grupo_filial gf ON gf.filial = e.idfilial
			JOIN produtos_filial pf ON pf.filial = e.idfilial AND pf.idproduto = e.idproduto
		WHERE
			gf.id_grupo = rec.id_grupo
			AND pf.idfornecedor = rec.idfornecedor
			AND pf.idcomprador = rec.idcomprador
			AND date_part('year', e.data_entrada) = rec.ano
			AND date_part('month', e.data_entrada) = rec.mes;


		SELECT
			COALESCE(trunc(sum(r.qtde * r.pcompra)::NUMERIC - sum(r.qtde * r.pcompraant)::NUMERIC, 4), 0) AS valor_saving,
			COALESCE(trunc(sum(r.qtde * r.pcompra)::NUMERIC, 4), 0) AS pedidos_em_valor,
			COALESCE(trunc(sum(r.qtde_pendente * r.pcompra)::NUMERIC, 4), 0) AS pendente_em_valor
			INTO rec_requisicao
		FROM requisicoes r
			INNER JOIN grupo_filial gf ON gf.filial = r.idfilial
			JOIN produtos_filial pf ON pf.filial = r.idfilial AND pf.idproduto = r.idproduto
		WHERE
			gf.id_grupo = rec.id_grupo
			AND pf.idfornecedor = rec.idfornecedor
			AND pf.idcomprador = rec.idcomprador
			AND date_part('year', r.data_solicitacao) = rec.ano
			AND date_part('month', r.data_solicitacao) = rec.mes;

		WITH prod AS (
			SELECT
				gf.id_grupo,
				pf.idproduto,
				pf.idfornecedor,
				pf.idcomprador,
				COALESCE(avg(pf.custo_unitario) FILTER (WHERE pf.estoque > 0), 0) AS custo_unitario
			FROM
				produtos_filial pf
				JOIN grupo_filial gf ON gf.filial = pf.filial
			WHERE gf.id_grupo = rec.id_grupo
			GROUP BY
				gf.id_grupo,
				pf.idproduto,
				pf.idfornecedor,
				pf.idcomprador
		)
		SELECT
			count(sg.idproduto) AS sku_total_saldo,
			count(sg.idproduto) FILTER (WHERE sg.estoque > 0) AS sku_com_estoque,
			COALESCE(sum(sg.estoque * p.custo_unitario), 0) AS valor_estoque,
			count(sg.idproduto) FILTER (WHERE sg.estoque > sg.emax) AS sku_excesso,
			COALESCE(sum(GREATEST(sg.estoque - sg.emax, 0) * p.custo_unitario), 0) AS valor_excesso,
			count(sg.idproduto) FILTER (WHERE sg.estoque = 0) AS sku_zerado
			INTO rec_saldos
		FROM
			saldo_grupos sg
			JOIN prod AS p ON p.id_grupo = sg.id_grupo AND p.idproduto = sg.idproduto
		WHERE
			sg.id_grupo = rec.id_grupo
			AND p.idfornecedor = rec.idfornecedor
			AND p.idcomprador = rec.idcomprador
			AND sg."data" = rec.data_referencia;

       	SELECT
			count(1) FILTER (WHERE trim(upper(apcg.status_percepcao)) = 'PERCEPCAO EM RUPTURA'::TEXT) AS sku_percepcao_compra_com_ruptura,
			count(1) FILTER (WHERE trim(upper(apcg.status_percepcao)) = 'PERCEPCAO COM ELEVADA EXPOSICAO RUPTURA'::TEXT) AS sku_percepcao_compra_exposto_ruptura,
			count(1) FILTER (WHERE trim(upper(apcg.status_percepcao)) = 'PERCEPCAO EM PONTO DE PEDIDO'::TEXT) AS sku_percepcao_compra_ponto_pedido,
			count(1) FILTER (WHERE trim(upper(apcg.status_percepcao)) = 'PERCEPCAO COM ELEVADA PREMATURIDADE'::TEXT) AS sku_percepcao_compra_prematuridade,
			count(1) FILTER (WHERE trim(upper(apcg.status_percepcao)) = 'SEM COMPORTAMENTO'::TEXT) AS sku_percepcao_compra_sem_comportamento
			INTO rec_percepcao_compra
		FROM
			analise_percepcao_compras_grupos apcg
		WHERE
			id_grupo = rec.id_grupo
			AND idfornecedor = rec.idfornecedor
			AND idcomprador = rec.idcomprador
			AND date_part('year', data_solicitacao) = rec.ano
			AND date_part('month', data_solicitacao) = rec.mes;
		
		SELECT
		    sum(arpf.valor_ruptura) AS valor_ruptura
		    INTO rec_valor_ruptura
		FROM
			analise_rupturas_produtos_filial arpf
			JOIN produtos_filial pf ON pf.filial = arpf.filial AND pf.idproduto = arpf.idproduto
			JOIN grupo_filial gf ON gf.filial = arpf.filial
		WHERE 
			gf.id_grupo = rec.id_grupo
			AND arpf.ano = rec.ano
			AND arpf.mes = rec.mes
			AND pf.idfornecedor = rec.idfornecedor
			AND pf.idcomprador = rec.idcomprador;

	   	rec_valor_ruptura = COALESCE(rec_valor_ruptura, 0);

		UPDATE analise_produtos_comprador_grupo
		SET
			pedidos_em_valor = rec_requisicao.pedidos_em_valor,
			entregue_em_valor = rec_entregue_em_valor,
			pendente_em_valor = rec_requisicao.pendente_em_valor,
			sku_total_saldo = rec_saldos.sku_total_saldo,
			sku_com_estoque = rec_saldos.sku_com_estoque,
			valor_estoque = rec_saldos.valor_estoque,
			sku_excesso = rec_saldos.sku_excesso,
			valor_excesso = rec_saldos.valor_excesso,
			valor_ruptura = rec_valor_ruptura,
		    sku_zerado = rec_saldos.sku_zerado,
		    valor_saving = rec_requisicao.valor_saving,
			sku_percepcao_compra_com_ruptura = rec_percepcao_compra.sku_percepcao_compra_com_ruptura,
			sku_percepcao_compra_exposto_ruptura = rec_percepcao_compra.sku_percepcao_compra_exposto_ruptura,
			sku_percepcao_compra_ponto_pedido = rec_percepcao_compra.sku_percepcao_compra_ponto_pedido,
			sku_percepcao_compra_prematuridade = rec_percepcao_compra.sku_percepcao_compra_prematuridade,
			sku_percepcao_compra_sem_comportamento = rec_percepcao_compra.sku_percepcao_compra_sem_comportamento
		WHERE
			id_grupo = rec.id_grupo
			AND idfornecedor = rec.idfornecedor
			AND idcomprador = rec.idcomprador
			AND ano = rec.ano
			AND mes = rec.mes;

	    IF NOT FOUND THEN
         	insert into analise_produtos_comprador_grupo (
         		data_referencia,
				ano,
				mes,
				id_grupo,
				idfornecedor,
				idcomprador,
				pedidos_em_valor,
				entregue_em_valor,
				pendente_em_valor,
				sku_total_saldo,
				sku_com_estoque,
				valor_estoque,
				sku_excesso,
				valor_excesso,
				valor_ruptura,
				sku_zerado,
				valor_saving,
				sku_percepcao_compra_com_ruptura,
				sku_percepcao_compra_exposto_ruptura,
				sku_percepcao_compra_ponto_pedido,
				sku_percepcao_compra_prematuridade,
				sku_percepcao_compra_sem_comportamento
        	)
            values(
           		rec.data_referencia,
				rec.ano,
				rec.mes,
				rec.id_grupo,
				rec.idfornecedor,
				rec.idcomprador,
				rec_requisicao.pedidos_em_valor,
				rec_entregue_em_valor,
				rec_requisicao.pendente_em_valor,
				rec_saldos.sku_total_saldo,
				rec_saldos.sku_com_estoque,
				rec_saldos.valor_estoque,
				rec_saldos.sku_excesso,
				rec_saldos.valor_excesso,
				rec_valor_ruptura,
				rec_saldos.sku_zerado,
				rec_requisicao.valor_saving,
				rec_percepcao_compra.sku_percepcao_compra_com_ruptura,
				rec_percepcao_compra.sku_percepcao_compra_exposto_ruptura,
				rec_percepcao_compra.sku_percepcao_compra_ponto_pedido,
				rec_percepcao_compra.sku_percepcao_compra_prematuridade,
				rec_percepcao_compra.sku_percepcao_compra_sem_comportamento
            );
	    END IF;
	END LOOP;
END $$;


ALTER FUNCTION public.processar_analise_produtos_comprador_grupo() OWNER TO systock;

--
-- TOC entry 768 (class 1255 OID 53887)
-- Name: processar_analise_rupturas_produtos_filial(date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_analise_rupturas_produtos_filial(data_inicial date DEFAULT CURRENT_DATE) RETURNS void
    LANGUAGE plpgsql
    AS $$
        DECLARE
            rec_analise record;
        begin
            data_inicial = to_char(data_inicial, '01/MM/YYYY')::date;

            UPDATE analise_rupturas_produtos_filial SET flag = 'D' WHERE data_ruptura >= data_inicial;

            FOR rec_analise IN (
                SELECT
                    r.ano,
                    r.mes,
                    r.filial,
                    r.idproduto,
                    r.qtde_dias_ruptura,
                    r.venda_diaria_calc,
                    r.qtde_dias_ruptura::numeric * r.venda_diaria_calc AS valor_ruptura,
                    r.tipo_ruptura,
                    COALESCE(NULLIF(trim(r.nivel_servico), ''), 'NIVEL ORDINARIO') AS nivel_servico,
                    r.data_ruptura,
                    r.media_mensal,
                    r.data_ultima_compra,
                    r.data_ultima_venda,
                    r.produto_eh_combinacao
                FROM (
                        SELECT
                            st.filial,
                            st.idproduto,
                            st.ano,
                            st.mes,
                            st.qtde_dias_ruptura,
                            st.venda_diaria_calc,
                            CASE
                                WHEN (SELECT sg.estoque > sg.esseg
                                FROM saldo_grupos sg
                                WHERE sg.id_grupo = st.id_grupo AND sg.idproduto::text = st.idproduto::text AND sg.data = st.data_ruptura) THEN 'DRP'::text
                                ELSE 'COMPRA'::text
                            END AS tipo_ruptura,
                            st.nivel_servico,
                            st.data_ruptura,
                            st.media_mensal,
                            st.ultima_solicitacao AS data_ultima_compra,
                            st.ult_saida AS data_ultima_venda,
                            false AS produto_eh_combinacao
                        FROM status_produto st
                            JOIN grupo_compras gc ON gc.id = st.id_grupo
                            JOIN grupo_filial gf ON st.id_grupo = gf.id_grupo AND gf.filial = st.filial
                        WHERE
                            gc.grupo_agrega::text = 'N'::text
                            AND (gf.subgrupo IS NULL OR gf.subgrupo = gf.filial)
                            AND st.data_referencia >= data_inicial
                            AND st.qtde_dias_ruptura > 0
                            AND st.venda_diaria_calc > 0::numeric
                            AND ((
                                SELECT COALESCE(sum(sg.estoque), 0::numeric) AS "coalesce"
                                FROM saldo_grupos sg
                                WHERE
                                    sg.id_grupo = st.id_grupo
                                    AND (sg.idproduto::text IN (
                                        SELECT s.id_item_filho
                                        FROM similares s
                                        WHERE s.id_item_pai::text = st.idproduto::text AND s.agregar_estoque::text = 'S'::TEXT
                                    ))
                                    AND sg.data = st.data_referencia
                        )) = 0::numeric
                        AND NOT ((st.idproduto::text, st.id_grupo) IN (
                                SELECT npb.idproduto, npb.grupo
                                FROM notificacao_produtos_blacklist npb
                                WHERE
                                    npb.grupo = st.id_grupo
                                    AND npb.filial = 0
                                    AND npb.data_limite >= CURRENT_DATE
                                    AND npb.deleted_at IS NULL
                            ))
                            AND NOT (st.idproduto::text IN (
                                SELECT DISTINCT spci.idproduto
                                FROM sys_produtos_combinados spc
                                    JOIN sys_produtos_combinados_itens spci ON spci.id_produto_combinado::text = spc.id::text
                                WHERE spc.deleted_at IS NULL
                            ))

                        UNION ALL

                        SELECT
                            st.filial,
                            spc.id AS idproduto,
                            st.ano,
                            st.mes,
                            max(st.qtde_dias_ruptura) AS qtde_dias_ruptura,
                            sum(st.venda_diaria_calc) AS venda_diaria_calc,
                            CASE
                                WHEN ( SELECT sum(sg.estoque) > sum(sg.esseg)
                                FROM saldo_grupos sg
                                WHERE sg.id_grupo = st.id_grupo AND (sg.idproduto::text IN ( SELECT v.idproduto
                                        FROM sys_produtos_combinados_itens v
                                        WHERE v.id_produto_combinado::text = spc.id::text)) AND sg.data = st.data_ruptura) THEN 'DRP'::text
                                ELSE 'COMPRA'::text
                            END AS tipo_ruptura,
                            getnivelservico(COALESCE(((min(substring(st.arvore_decisao, 1, 1)::text) || max(substring(st.arvore_decisao, 2, 1)::TEXT)) || min(substring(st.arvore_decisao, 3, 1)::TEXT)) || min(substring(st.arvore_decisao, 4, 1)::text), 'CX2R'::character varying)) AS nivel_servico,
                            st.data_ruptura,
                            sum(st.media_mensal) AS media_mensal,
                            max(st.ultima_solicitacao) AS data_ultima_compra,
                            max(st.ult_saida) AS data_ultima_venda,
                            true AS produto_eh_combinacao
                        FROM status_produto st
                            JOIN grupo_compras gc ON gc.id = st.id_grupo
                            JOIN grupo_filial gf ON st.id_grupo = gf.id_grupo AND gf.filial = st.filial
                            JOIN sys_produtos_combinados_itens spci ON spci.idproduto::text = st.idproduto::text
                            JOIN sys_produtos_combinados spc ON spc.id::text = spci.id_produto_combinado::text
                        WHERE
                            spc.deleted_at IS NULL
                            AND gc.grupo_agrega::text = 'N'::text
                            AND (gf.subgrupo IS NULL OR gf.subgrupo = gf.filial)
                            AND st.data_referencia >= data_inicial
                            AND st.qtde_dias_ruptura > 0
                            AND st.venda_diaria_calc > 0::numeric
                            AND (
                                SELECT COALESCE(sum(sg.estoque), 0::numeric) = 0::numeric
                                FROM saldo_grupos sg
                                WHERE
                                    sg.id_grupo = st.id_grupo
                                    AND (sg.idproduto::text IN (
                                        SELECT v.idproduto
                                        FROM sys_produtos_combinados_itens v
                                        WHERE v.id_produto_combinado::text = spc.id::TEXT
                                    ))
                                    AND sg.data = st.data_referencia
                            )
                            AND NOT ((spc.id::text, st.id_grupo) IN (
                                SELECT npb.idproduto, npb.grupo
                                FROM notificacao_produtos_blacklist npb
                                WHERE
                                    npb.grupo = st.id_grupo
                                    AND npb.filial IN (0, st.filial)
                                    AND npb.data_limite >= CURRENT_DATE
                                    AND npb.deleted_at IS NULL
                            ))
                        GROUP BY st.id_grupo, st.filial, spc.id, st.ano, st.mes, st.data_ruptura
                ) r
            )
            LOOP
                UPDATE analise_rupturas_produtos_filial
                SET
                    ano = rec_analise.ano,
                    mes = rec_analise.mes,
                    filial = rec_analise.filial,
                    idproduto = rec_analise.idproduto,
                    qtde_dias_ruptura = rec_analise.qtde_dias_ruptura,
                    venda_diaria_calc = rec_analise.venda_diaria_calc,
                    valor_ruptura = rec_analise.valor_ruptura,
                    tipo_ruptura = rec_analise.tipo_ruptura,
                    nivel_servico = rec_analise.nivel_servico,
                    data_ruptura = rec_analise.data_ruptura,
                    media_mensal = rec_analise.media_mensal,
                    data_ultima_compra = rec_analise.data_ultima_compra,
                    data_ultima_venda = rec_analise.data_ultima_venda,
                    produto_eh_combinacao = rec_analise.produto_eh_combinacao,
                    flag = null
                WHERE
                    ano = rec_analise.ano
                    AND mes = rec_analise.mes
                    AND filial = rec_analise.filial
                    AND idproduto = rec_analise.idproduto;

                IF NOT FOUND THEN
                    INSERT INTO analise_rupturas_produtos_filial (
                        ano,
                        mes,
                        filial,
                        idproduto,
                        qtde_dias_ruptura,
                        venda_diaria_calc,
                        valor_ruptura,
                        tipo_ruptura,
                        nivel_servico,
                        data_ruptura,
                        media_mensal,
                        data_ultima_compra,
                        data_ultima_venda,
                        produto_eh_combinacao
                    )
                    VALUES (
                        rec_analise.ano,
                        rec_analise.mes,
                        rec_analise.filial,
                        rec_analise.idproduto,
                        rec_analise.qtde_dias_ruptura,
                        rec_analise.venda_diaria_calc,
                        rec_analise.valor_ruptura,
                        rec_analise.tipo_ruptura,
                        rec_analise.nivel_servico,
                        rec_analise.data_ruptura,
                        rec_analise.media_mensal,
                        rec_analise.data_ultima_compra,
                        rec_analise.data_ultima_venda,
                        rec_analise.produto_eh_combinacao
                    );
                END IF;
            END LOOP;

            DELETE FROM analise_rupturas_produtos_filial WHERE flag = 'D' AND data_ruptura >= data_inicial;

            DELETE FROM analise_rupturas_produtos_filial WHERE idproduto IN (select idproduto from produtos_para_nao_exibir_nos_indicadores);

        END;
    $$;


ALTER FUNCTION public.processar_analise_rupturas_produtos_filial(data_inicial date) OWNER TO systock;

--
-- TOC entry 769 (class 1255 OID 53889)
-- Name: processar_analise_statistica(); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_analise_statistica() RETURNS void
    LANGUAGE plpgsql PARALLEL SAFE
    AS $$
    declare
        rec_prod record;
        qt_1 numeric;
        qt_3 numeric;
        vl_iqr numeric;
        lim_inf numeric;
        lim_sup numeric;
    begin

    --Amostra 180 dias

    alter table public.produtos_filial DISABLE TRIGGER all;

    for rec_prod in (select filial,idproduto from produtos_filial pf  order by filial,idproduto)
      loop


       select q1,q3,iqr,coalesce(nullif(floor((q1-(1.5*iqr))),0),media) linf , coalesce(nullif(ceil((q3+(1.5*iqr))),0),media) lisup
        into qt_1,qt_3,vl_iqr,lim_inf,lim_sup
       from (
       select
       avg(saidas) media,
       percentile_cont(0.25) within group (order by u.saidas) q1,
       percentile_cont(0.5) within group (order by u.saidas) q2,
       percentile_cont(0.75) within group (order by u.saidas) q3,
       percentile_cont(0.75) within group (order by u.saidas) - percentile_cont(0.25) within group (order by u.saidas) iqr
        from(


                  with tempo as (
                     select distinct to_char(day :: date, 'YYYYMM') as referencia
                     FROM generate_series(current_date - 180 , current_date, '1 day') day
                     order by to_char(day :: date, 'YYYYMM'))

                    SELECT
                         t.referencia AS mes,
                        coalesce(sum(c.qtde),0) AS saidas
                    from tempo t
                    left join consumos c
                         on c.filial =  rec_prod.filial
                        and c.idproduto = rec_prod.idproduto
                        and to_char(c.emissao , 'YYYYMM') = t.referencia

                    GROUP BY
                        t.referencia

            )u)a;


         if lim_inf < 0 then lim_inf=0; end if;
         if lim_sup < 0 then lim_sup=0; end if;




          UPDATE analise_statistica_produtos
            SET q1=qt_1, q3=qt_3, iqr=vl_iqr, limite_inferior=coalesce(lim_inf,0), limite_superior=lim_sup
            WHERE filial=rec_prod.filial AND idproduto=rec_prod.idproduto;


          if not found then

             INSERT INTO analise_statistica_produtos
                    (filial, idproduto, q1, q3, iqr, limite_inferior, limite_superior)
                    VALUES(rec_prod.filial,rec_prod.idproduto, qt_1,qt_3,vl_iqr,lim_inf,lim_sup);

          end if;

         update produtos_filial set limite_inferior=coalesce(lim_inf,0),limite_superior=coalesce(lim_sup,0) WHERE filial=rec_prod.filial AND idproduto=rec_prod.idproduto;


      end loop;

     alter table public.produtos_filial ENABLE TRIGGER all;

    end
    $$;


ALTER FUNCTION public.processar_analise_statistica() OWNER TO systock;

--
-- TOC entry 770 (class 1255 OID 53890)
-- Name: processar_baixa_pedidos_systock(); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_baixa_pedidos_systock() RETURNS void
    LANGUAGE plpgsql
    AS $$
declare
 
rec_oc record;
rec_pedidos record;

begin
	
for rec_oc in (select * from ( 
            SELECT c.idpedido,i.idproduto,data_emissao,i.qtde_pedido,
            (select coalesce(sum(qtde),0) from requisicoes r where r.idfilial in  (select filial from grupo_filial gf  where gf.id_grupo =c.grupo) and r.idproduto=i.idproduto   and r.data_solicitacao >=c.data_emissao) qtde_atend,
            (select max(id_solicitacao) from requisicoes r where r.idfilial in (select filial from grupo_filial gf  where gf.id_grupo =c.grupo) and r.idproduto=i.idproduto   and r.data_solicitacao >=c.data_emissao) oc_num,
            (select distinct data_solicitacao from requisicoes r where 
               r.id_solicitacao = (select max(id_solicitacao) from requisicoes r where r.idfilial in (select filial from grupo_filial gf  where gf.id_grupo =c.grupo) and r.idproduto=i.idproduto   and r.data_solicitacao >=c.data_emissao)) oc_data
            FROM pedidos_compras c
             inner join pedidos_compras_itens i
              on c.idpedido  = i.idpedido 
            where status='CT' 
            order by idpedido) a  where oc_num is not null)
 loop
	
     update pedidos_compras_itens  set oc_num = rec_oc.oc_num,oc_data = rec_oc.oc_data,oc_qtde = rec_oc.qtde_atend 
        where idpedido = rec_oc.idpedido and idproduto = rec_oc.idproduto and oc_num is null;
    
 
 end loop;	

 --Fechamento dos Pedidos Systock
 
 for rec_pedidos in (select idpedido,oc_data, ((qtde_itens_atend::numeric /qtde_itens::numeric )*100) perc_atendimento from (
  select pc.idpedido,pc.data_emissao,max(pci.oc_data) oc_data,count(pci.idproduto) qtde_itens,count(pci.oc_data) qtde_itens_atend from pedidos_compras pc 
   inner join pedidos_compras_itens pci
   on pci.idpedido  = pc.idpedido 
   where pc.status='CT' group by pc.idpedido,pc.data_emissao order by pc.idpedido) a where a.oc_data is not null)
  loop
      
    if rec_pedidos.perc_atendimento >= 20 then 
  
      update pedidos_compras set status='FN',data_final=rec_pedidos.oc_data where idpedido= rec_pedidos.idpedido;
     
    end if; 
  
  end loop;
	
end
$$;


ALTER FUNCTION public.processar_baixa_pedidos_systock() OWNER TO systock;

--
-- TOC entry 771 (class 1255 OID 53891)
-- Name: processar_compra_mp(); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_compra_mp() RETURNS void
    LANGUAGE plpgsql
    AS $$
declare
 
rec_prod_mp record;
rec_grupo record;
tempo_ressup_mp numeric;
std_tempo_ressup_mp numeric;

begin
	
update produtos_mp set status ='D' where idgrupo in (select id from grupo_compras);

	
for rec_grupo in (select id from grupo_compras gc where id=2)
  loop 
  
     for rec_prod_mp in (
               select 
			    distinct 
				id_fornecedor_materia_prima forn_mp,
				id_produto_materia_prima idproduto_mp,
				descricao_produto,
				round((pf.estoque),2) estoque_mp,
				round((pf.estoque_seguranca),2) estoque_seguranca,
				round((pf.ponto_pedido),2) ponto_pedido,
				round((pf.estoque_maximo),2) emax,
				round((consumo_medio_mensal),2) cmm,
				round((pf.desvio_padrao_consumo),2) std_cmm,
				(select sugestao from vw_lista_compras_dinamica_grupo vlcdg  where id_grupo = rec_grupo.id and idproduto= id_produto_materia_prima) sugestao
				from produtos_pa pp  
				inner join vw_grupo_compras_produtos_mt pf 
				 on pf.idproduto = pp.id_produto_materia_prima 
				where pf.id_grupo= rec_grupo.id
				AND pf.sob_encomenda = 0 
				AND pf.revenda::text = 'S'::text 
				AND pf.revenda::text <> 'FL'::text
				)
				
		 loop 
		 
		   select max(tempo_medio_ressuprimento),sum(desvio_padrao_ressuprimento) into tempo_ressup_mp,std_tempo_ressup_mp 
		        from produtos_filial pf  
		    where pf.filial in (select filial from grupo_filial gf where gf.id_grupo = rec_grupo.id) and pf.idproduto=rec_prod_mp.idproduto_mp;
		 
		 
           UPDATE produtos_mp
			SET estoque=coalesce(rec_prod_mp.estoque_mp,0), emax=rec_prod_mp.emax, cmm=rec_prod_mp.cmm, std_cmm=rec_prod_mp.std_cmm, 
			    tp_ressup=tempo_ressup_mp, std_tp_ressup=std_tempo_ressup_mp,status='', processamento=current_timestamp,sugestao=rec_prod_mp.sugestao
			WHERE idgrupo=rec_grupo.id AND id_fornecedor=rec_prod_mp.forn_mp AND id_produto=rec_prod_mp.idproduto_mp;

		
		   if not found then 
		   
		       
		       INSERT INTO produtos_mp
				(idgrupo, id_fornecedor, id_produto, estoque, emax, cmm, std_cmm, tp_ressup, std_tp_ressup, id_user, data_cadastro, status, processamento,sugestao)
			   VALUES(rec_grupo.id, rec_prod_mp.forn_mp,rec_prod_mp.idproduto_mp,coalesce(rec_prod_mp.estoque_mp,0),rec_prod_mp.emax, rec_prod_mp.cmm,rec_prod_mp.std_cmm,tempo_ressup_mp,
			  std_tempo_ressup_mp,0,current_date,'', current_timestamp,rec_prod_mp.sugestao);
			  
		   
		   end if;

				
	     end loop;
  
  end loop;
 
 delete from  produtos_mp where status ='D';
	
end
$$;


ALTER FUNCTION public.processar_compra_mp() OWNER TO systock;

