--
-- TOC entry 773 (class 1255 OID 53893)
-- Name: processar_filtros_produto(integer, boolean); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_filtros_produto(p_forn integer DEFAULT 0, p_filial boolean DEFAULT false) RETURNS void
    LANGUAGE plpgsql
    AS $$
        declare
    
            produto_rec record;
            f_item_novo bool;
            f_com_movimentacao bool;
            f_sem_movimentacao bool;
            f_similar bool;
            f_heranca bool;
            f_influencia_previsao bool;
            movimentacao numeric;
            existe numeric;
    
        begin
            --filial
            if p_filial then
                for produto_rec in (
                    select
                        (select id_grupo from grupo_filial gf where gf.filial=pf.filial limit 1) as grupo,
                        pf.filial,
                        pf.idfornecedor,
                        pf.idproduto,
                        pf.heranca,
                        pf.fator_atuacao,
                        (pf.estoque > pf.estoque_maximo) AS em_excesso,
                        (pf.estoque > pf.ponto_pedido AND pf.estoque <= pf.estoque_maximo) AS nivel_adequado,
                        (pf.estoque > 0 AND pf.consumo_medio_mensal > 0 AND pf.estoque <= pf.ponto_pedido AND pf.cobertura_estoque >= pf.tempo_medio_ressuprimento) AS baixa_exposicao_ruptura,
                        (pf.estoque > 0 AND pf.consumo_medio_mensal > 0 AND pf.estoque <= pf.ponto_pedido AND pf.cobertura_estoque < pf.tempo_medio_ressuprimento) AS elevada_exposicao_ruptura,
                        (pf.estoque = 0 AND pf.consumo_medio_mensal > 0) AS em_ruptura
                    from produtos_filial pf 
                      inner join grupo_filial gf
                       on gf.id_grupo = pf.grupo_compra 
                    where pf.idfornecedor = p_forn and pf.revenda='S' and pf.status <> 'FL'
                )
                loop
        
                    f_item_novo = false;
                    f_com_movimentacao = false;
                    f_sem_movimentacao = false;
        
                    -- Verificação Movimentos
                    select case when max(emissao) = min(emissao) then 1 else coalesce(max(emissao)-min(emissao),0) end into movimentacao 
                    from consumos c 
                    where c.filial=produto_rec.filial 
                        and c.idproduto=produto_rec.idproduto
                        and c.emissao between (current_date - 180) and current_date;
        
                    if movimentacao > 90 then
                        f_com_movimentacao=true;
                    elsif movimentacao > 0 and movimentacao <= 90  then
                        f_item_novo=true;
                    else
                        f_sem_movimentacao=true;
                        f_item_novo=true;
                    end if;
        
                    -- Verificação Similares
        
                    select (case when (count(*) > 0) then true else false end) into f_similar from similares s where id_item_pai=produto_rec.idproduto;
        
                    -- Verificação Herança
        
                    if produto_rec.heranca notnull and produto_rec.heranca not in ('', ' ') then
                        f_heranca = true;
                    else
                        f_heranca = false;
                    end if;
        
                    -- Verifcação Fator de Atuação
        
                    if produto_rec.fator_atuacao <> 1 then
                        f_influencia_previsao = true;
                    else
                        f_influencia_previsao = false;
                    end if;
        
                    select count(*) into existe
                    from filtros_produto fp
                    where fp.idgrupo = produto_rec.grupo
                        and fp.idfilial = produto_rec.filial
                        and fp.idfornecedor = produto_rec.idfornecedor
                        and fp.idproduto = produto_rec.idproduto;
                    
                        --insert ou update
                    if existe > 0 then

                        update filtros_produto
                            set (item_novo, com_movimentacao, sem_movimentacao, "similar", heranca, ciclo_vida, sazonalidade, evento, influencia_previsao, excesso, adequado, baixa_exposicao_ruptura, elevada_exposicao_ruptura, ruptura)
                            =
                            (f_item_novo, f_com_movimentacao, f_sem_movimentacao, f_similar, f_heranca, false, false, false, f_influencia_previsao,produto_rec.em_excesso, produto_rec.nivel_adequado, produto_rec.baixa_exposicao_ruptura, produto_rec.elevada_exposicao_ruptura, produto_rec.em_ruptura)
                        where idgrupo=produto_rec.grupo
                            and idfilial=produto_rec.filial
                            and idfornecedor=produto_rec.idfornecedor
                            and idproduto=produto_rec.idproduto;

                    else

                        insert into filtros_produto
                        values (produto_rec.grupo, produto_rec.filial, produto_rec.idfornecedor, produto_rec.idproduto, f_item_novo, f_com_movimentacao, f_sem_movimentacao, f_similar, f_heranca, false, false, false, f_influencia_previsao, produto_rec.em_excesso, produto_rec.nivel_adequado, produto_rec.baixa_exposicao_ruptura, produto_rec.elevada_exposicao_ruptura, produto_rec.em_ruptura);

                    end if;
        
                end loop;
            -- grupo
            else
            
                for produto_rec in (
                   
                    with heranca_grupo as (
                  
                        select gf.id_grupo ,pf.idproduto, max(heranca) as heranca 
                         from produtos_filial pf 
                          inner join grupo_filial gf
                           on gf.filial = pf.filial 
                         where  pf.idfornecedor =  p_forn
                         group by gf.id_grupo ,pf.idproduto
                   )
                
                    select 
                        vg.id_grupo as grupo,
                        0 as filial,
                        vg.idfornecedor,
                        vg.idproduto,
                        hg.heranca,
                        vg.fator_atuacao,
                        (vg.estoque = 0 AND vg.consumo_medio_mensal > 0) AS em_ruptura,
                        (vg.estoque > vg.estoque_maximo) AS em_excesso,
                        (vg.estoque > vg.ponto_pedido AND vg.estoque <= vg.estoque_maximo) AS nivel_adequado,
                        (vg.estoque > 0 AND vg.consumo_medio_mensal > 0 AND vg.estoque <= vg.ponto_pedido AND vg.cobertura_estoque >= vg.tempo_medio_ressuprimento) AS baixa_exposicao_ruptura,
                        (vg.estoque > 0 AND vg.consumo_medio_mensal > 0 AND vg.estoque <= vg.ponto_pedido AND vg.cobertura_estoque < vg.tempo_medio_ressuprimento) AS elevada_exposicao_ruptura
                    from vw_grupo_compras_produtos_mt vg
                      left join heranca_grupo hg 
                       on hg.id_grupo = vg.id_grupo 
                       and hg.idproduto = vg.idproduto 
                    where vg.idfornecedor = p_forn and vg.revenda='S' and vg.status <> 'FL'

                )
                loop
        
                    f_item_novo = false;
                    f_com_movimentacao = false;
                    f_sem_movimentacao = false;
        
                    -- Verificação Movimentos
                    select case when max(emissao) = min(emissao) then 1 else coalesce(max(emissao)-min(emissao),0) end into movimentacao  
                    from consumos c 
                    where c.filial in (select filial from grupo_filial gf where gf.id_grupo=produto_rec.grupo) 
                        and c.idproduto=produto_rec.idproduto
                        and c.emissao between (current_date - 180) and current_date;
        
                    if movimentacao > 90 then
                        f_com_movimentacao=true;
                    elsif movimentacao > 0 and movimentacao <= 90  then
                        f_item_novo=true;
                    else
                        f_sem_movimentacao=true;
                        f_item_novo=true;
                    end if;
        
                    -- Verificação Similares
        
                    select (case when (count(*) > 0) then true else false end) into f_similar from similares s where id_item_pai=produto_rec.idproduto;
        
                    -- Verificação Herança
        
                    if produto_rec.heranca notnull and produto_rec.heranca not in ('', ' ') then
                        f_heranca = true;
                    else
                        f_heranca = false;
                    end if;
        
                    -- Verifcação Fator de Atuação
        
                    if produto_rec.fator_atuacao <> 1 then
                        f_influencia_previsao = true;
                    else
                        f_influencia_previsao = false;
                    end if;
        
                    select count(*) into existe
                    from filtros_produto fp
                    where fp.idgrupo = produto_rec.grupo
                        and fp.idfilial = produto_rec.filial
                        and fp.idfornecedor = produto_rec.idfornecedor
                        and fp.idproduto = produto_rec.idproduto;
                    
                    
                    
                    --insert ou update
                    if existe > 0 then

                        update filtros_produto
                            set (item_novo, com_movimentacao, sem_movimentacao, "similar", heranca, ciclo_vida, sazonalidade, evento, influencia_previsao, excesso, adequado, baixa_exposicao_ruptura, elevada_exposicao_ruptura, ruptura)
                            =
                            (f_item_novo, f_com_movimentacao, f_sem_movimentacao, f_similar, f_heranca, false, false, false, f_influencia_previsao, produto_rec.em_excesso, produto_rec.nivel_adequado, produto_rec.baixa_exposicao_ruptura, produto_rec.elevada_exposicao_ruptura, produto_rec.em_ruptura)
                        where idgrupo=produto_rec.grupo
                            and idfilial=produto_rec.filial
                            and idfornecedor=produto_rec.idfornecedor
                            and idproduto=produto_rec.idproduto;

                    else

                        insert into filtros_produto
                        values (produto_rec.grupo, produto_rec.filial, produto_rec.idfornecedor, produto_rec.idproduto, f_item_novo, f_com_movimentacao, f_sem_movimentacao, f_similar, f_heranca, false, false, false, f_influencia_previsao, produto_rec.em_excesso, produto_rec.nivel_adequado, produto_rec.baixa_exposicao_ruptura, produto_rec.elevada_exposicao_ruptura, produto_rec.em_ruptura);

                    end if;
        
                end loop;
            
            end if;
        end
    $$;


ALTER FUNCTION public.processar_filtros_produto(p_forn integer, p_filial boolean) OWNER TO systock;

--
-- TOC entry 774 (class 1255 OID 53895)
-- Name: processar_forecast(bigint); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_forecast(p_fornecedor bigint DEFAULT 0) RETURNS void
    LANGUAGE plpgsql
    AS $$
declare
rec_forecast record;
    
begin
	
if p_fornecedor = 0 then 

update produtos_forecast set flag ='D' where id_grupo in (select id from grupo_compras);

for rec_forecast in(
  SELECT a.id_grupo,
    a.idfornecedor,
    a.fornecedor,
    a.idcomprador,
    a.comprador,
    a.idproduto,
    a.descricao_produto,
    a.iddepartamento,
    a.departamento,
    a.ponto_pedido::double precision * a.fator_conversao::double precision AS ponto_pedido,
    a.estoque_futuro::double precision * a.fator_conversao::double precision AS estoque_futuro,
    a.estoque_maximo::double precision * a.fator_conversao::double precision AS estoque_maximo,
    a.estoque::double precision * a.fator_conversao::double precision AS estoque,
    a.tempo_ressuprimento,
    a.desvio_padrao_ressuprimento,
    a.consumo_medio_mensal::double precision * a.fator_conversao::double precision AS consumo_medio_mensal,
    gerar_lote_embalagem(LEAST(a.lote_compras, a.estoque_maximo) * a.fator_conversao::numeric, a.lote_minimo * a.fator_conversao::numeric) AS lote_compras,
    a.lote_compras * a.fator_conversao::numeric AS lote_compras_bruto,
    a.fator_conversao,
    a.unidade_compra,
    a.lote_minimo,
    a.nivel_servico,
    a.peso_compras
   FROM ( SELECT previsao.idfornecedor,
            previsao.fornecedor,
            previsao.idcomprador,
            previsao.comprador,
            previsao.idproduto,
            previsao.descricao_produto,
            previsao.ponto_pedido,
            previsao.estoque_futuro,
            previsao.estoque_maximo,
            previsao.estoque,
            previsao.tempo_ressuprimento,
            previsao.desvio_padrao_ressuprimento,
            previsao.consumo_medio_mensal,
            round((previsao.estoque_maximo::double precision + (previsao.consumo_medio_mensal * (previsao.tempo_ressuprimento + previsao.desvio_padrao_ressuprimento))::double precision - previsao.estoque::double precision)::numeric, 2) AS lote_compras,
            previsao.fator_conversao,
            previsao.unidade_compra,
            previsao.lote_minimo,
            previsao.id_grupo,
            previsao.iddepartamento,
            previsao.descricao_departamento AS departamento,
            previsao.nivel_servico,
            previsao.peso_compras
           FROM ( SELECT p.id_grupo,
                    p.idfornecedor,
                    f.razao_social AS fornecedor,
                    p.idcomprador,
                    c.nome_completo AS comprador,
                    p.idproduto,
                    p.descricao_produto,
                    dep.iddepartamento,
                    dep.descricao_departamento,
                    p.ponto_pedido,
					get_forecast_grupo(
						p.id_grupo::numeric, 
						p.idproduto, 
						coalesce(
							nullif((SELECT pfi.tempo_forecast FROM produtos_forecast_itens pfi WHERE pfi.idproduto = p.idproduto), 0), 
							(SELECT f_1.tempo_forecast FROM fornecedor f_1 WHERE f_1.id = p.idfornecedor)
						)::NUMERIC
					) AS estoque_futuro,
                    p.estoque_maximo,
                    p.estoque,
                    p.tempo_ressuprimento,
                    p.desvio_padrao_ressuprimento,
                    p.consumo_medio_mensal,
                    p.unidade_compra,
                    p.lote_minimo,
                    1 AS fator_conversao,
                    get_arvore_decisao_grupo(p.id_grupo::numeric, p.idproduto)::text AS arvore_decisao,
                    getnivelservico(get_arvore_decisao_grupo(p.id_grupo::numeric, p.idproduto)) AS nivel_servico,
                    getpesocompras(get_arvore_decisao_grupo(p.id_grupo::numeric, p.idproduto), "substring"(get_arvore_decisao_grupo(p.id_grupo::numeric, p.idproduto)::text, 3, 1)::numeric) AS peso_compras
                   FROM produtos_compras_grupo p
                     JOIN fornecedor f ON f.id = p.idfornecedor
                     JOIN comprador c ON c.id = p.idcomprador
                     JOIN departamentos dep ON dep.iddepartamento = p.idfamilia_produto
                  WHERE p.lote_compras = 0::numeric AND p.consumo_medio_mensal > 0::numeric AND p.compra_transito = 0::numeric AND p.revenda::text = 'S'::text AND p.status::text <> 'FL'::text) previsao
          WHERE previsao.estoque_futuro::double precision <= previsao.ponto_pedido::double precision) a
  WHERE gerar_lote_embalagem(a.lote_compras * a.fator_conversao::numeric, a.lote_minimo) > 0::numeric)
  loop 
  
  
    --Update 
    
	  update
