-- Name: processar_forecast_filial(bigint); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_forecast_filial(p_fornecedor bigint DEFAULT 0) RETURNS void
    LANGUAGE plpgsql
    AS $$
declare
 
rec_forecast record;
    
begin
	
if p_fornecedor = 0 then 

update produtos_forecast_filial set flag ='D' where id_grupo in (select id from grupo_compras);

for rec_forecast in(
  SELECT a.id_grupo,
    a.idfornecedor,
    a.fornecedor,
    a.idcomprador,
    a.comprador,
    a.filial,
    a.idproduto,
    a.descricao_produto,
    a.iddepartamento,
    a.departamento,
    a.ponto_pedido::double precision * a.fator_conversao::double precision AS ponto_pedido,
    a.estoque_futuro::double precision * a.fator_conversao::double precision AS estoque_futuro,
    a.estoque_maximo::double precision * a.fator_conversao::double precision AS estoque_maximo,
    a.estoque::double precision * a.fator_conversao::double precision AS estoque,
    a.tempo_ressuprimento,
    a.desvio_padrao_ressuprimento,
    a.consumo_medio_mensal::double precision * a.fator_conversao::double precision AS consumo_medio_mensal,
    gerar_lote_embalagem(LEAST(a.lote_compras, a.estoque_maximo) * a.fator_conversao::numeric, a.lote_minimo * a.fator_conversao::numeric) AS lote_compras,
    a.lote_compras * a.fator_conversao::numeric AS lote_compras_bruto,
    a.fator_conversao,
    a.unidade_compra,
    a.lote_minimo,
    a.nivel_servico,
    a.peso_compras
   FROM ( SELECT previsao.idfornecedor,
            previsao.fornecedor,
            previsao.idcomprador,
            previsao.comprador,
            previsao.filial,
            previsao.idproduto,
            previsao.descricao_produto,
            previsao.ponto_pedido,
            previsao.estoque_futuro,
            previsao.estoque_maximo,
            previsao.estoque,
            previsao.tempo_ressuprimento,
            previsao.desvio_padrao_ressuprimento,
            previsao.consumo_medio_mensal,
            round((previsao.estoque_maximo::double precision + (previsao.consumo_medio_mensal * (previsao.tempo_ressuprimento + previsao.desvio_padrao_ressuprimento))::double precision - previsao.estoque::double precision)::numeric, 2) AS lote_compras,
            previsao.fator_conversao,
            previsao.unidade_compra,
            previsao.lote_minimo,
            previsao.id_grupo,
            previsao.iddepartamento,
            previsao.descricao_departamento AS departamento,
            previsao.nivel_servico,
            previsao.peso_compras
           FROM ( SELECT p.filial,
                    p.id_grupo,
                    p.idfornecedor,
                    f.razao_social AS fornecedor,
                    p.idcomprador,
                    c.nome_completo AS comprador,
                    p.idproduto,
                    p.descricao_produto,
                    dep.iddepartamento,
                    dep.descricao_departamento,
                    p.ponto_pedido,
					get_forecast_filial(
					 	p.filial::numeric, 
					 	p.idproduto,
					 	coalesce(
							nullif((SELECT pfi.tempo_forecast FROM produtos_forecast_itens pfi WHERE pfi.idproduto = p.idproduto), 0), 
					 		(SELECT f_1.tempo_forecast FROM fornecedor f_1 WHERE f_1.id = p.idfornecedor)
						)::NUMERIC 		
					) AS estoque_futuro,
                    p.estoque_maximo,
                    p.estoque,
                    p.tempo_ressuprimento,
                    p.desvio_padrao_ressuprimento,
                    p.consumo_medio_mensal,
                    p.unidade_compra,
                    p.lote_minimo,
                    1 AS fator_conversao,
                    p.arvore_decisao,
                    p.nivel_servico,
                    p.peso_compras
                   FROM produtos_compras_filial p
                     JOIN fornecedor f ON f.id = p.idfornecedor
                     JOIN comprador c ON c.id = p.idcomprador
                     JOIN departamentos dep ON dep.iddepartamento = p.idfamilia_produto
                  WHERE p.lote_compras = 0::numeric AND p.consumo_medio_mensal > 0::numeric AND p.compra_transito = 0::numeric AND p.revenda::text = 'S'::text AND p.status::text <> 'FL'::text) previsao
          WHERE previsao.estoque_futuro::double precision <= previsao.ponto_pedido::double precision) a
  WHERE gerar_lote_embalagem(a.lote_compras * a.fator_conversao::numeric, a.lote_minimo) > 0::numeric)
  loop 
  
  
    --Update 
    
	  update
		produtos_forecast_filial 
	set
		idfornecedor = rec_forecast.idfornecedor,
		fornecedor = rec_forecast.fornecedor,
		idcomprador = rec_forecast.idcomprador,
		comprador = rec_forecast.comprador,
		descricao_produto = rec_forecast.descricao_produto,
		iddepartamento = rec_forecast.iddepartamento,
		departamento = rec_forecast.departamento,
		ponto_pedido = rec_forecast.ponto_pedido,
		estoque_futuro = rec_forecast.estoque_futuro,
		estoque_maximo = rec_forecast.estoque_maximo,
		estoque = rec_forecast.estoque,
		tempo_ressuprimento = rec_forecast.tempo_ressuprimento,
		desvio_padrao_ressuprimento = rec_forecast.desvio_padrao_ressuprimento,
		consumo_medio_mensal = rec_forecast.consumo_medio_mensal,
		lote_compras = rec_forecast.lote_compras,
		lote_compras_bruto = rec_forecast.lote_compras_bruto,
		fator_conversao = rec_forecast.fator_conversao,
		unidade_compra = rec_forecast.unidade_compra,
		lote_minimo = rec_forecast.lote_minimo,
		nivel_servico = rec_forecast.nivel_servico,
		peso_compras = rec_forecast.peso_compras,
		flag = null,
		processamento = current_timestamp 
	where
		id_grupo = rec_forecast.id_grupo
		and filial = rec_forecast.filial
		and idproduto = rec_forecast.idproduto;
	
	if not found then 
	
	  --Insert 
    
		 insert
			into
			produtos_forecast_filial (
			id_grupo,
			idfornecedor,
			fornecedor,
			idcomprador,
			comprador,
			filial,
			idproduto,
			descricao_produto,
			iddepartamento,
			departamento,
			ponto_pedido,
			estoque_futuro,
			estoque_maximo,
			estoque,
			tempo_ressuprimento,
			desvio_padrao_ressuprimento,
			consumo_medio_mensal,
			lote_compras,
			lote_compras_bruto,
			fator_conversao,
			unidade_compra,
			lote_minimo,
			nivel_servico,
			peso_compras,
			flag,
			processamento)
		values(
			rec_forecast.id_grupo,
			rec_forecast.idfornecedor,
			rec_forecast.fornecedor,
			rec_forecast.idcomprador,
			rec_forecast.comprador,
			rec_forecast.filial,
			rec_forecast.idproduto,
			rec_forecast.descricao_produto,
			rec_forecast.iddepartamento,
			rec_forecast.departamento,
			rec_forecast.ponto_pedido,
			rec_forecast.estoque_futuro,
			rec_forecast.estoque_maximo,
			rec_forecast.estoque,
			rec_forecast.tempo_ressuprimento,
			rec_forecast.desvio_padrao_ressuprimento,
			rec_forecast.consumo_medio_mensal,
			rec_forecast.lote_compras,
			rec_forecast.lote_compras_bruto,
			rec_forecast.fator_conversao,
			rec_forecast.unidade_compra,
			rec_forecast.lote_minimo,
			rec_forecast.nivel_servico,
			rec_forecast.peso_compras,
			null,
			current_timestamp
			);
		
       end if;		
		
	 end loop;	
		
	else
	
	 update produtos_forecast_filial set flag ='D' where id_grupo in (select id from grupo_compras) and produtos_forecast_filial.idfornecedor = p_fornecedor;

		for rec_forecast in(
		  SELECT a.id_grupo,
		    a.idfornecedor,
		    a.fornecedor,
		    a.idcomprador,
		    a.comprador,
		    a.filial,
		    a.idproduto,
		    a.descricao_produto,
		    a.iddepartamento,
		    a.departamento,
		    a.ponto_pedido::double precision * a.fator_conversao::double precision AS ponto_pedido,
		    a.estoque_futuro::double precision * a.fator_conversao::double precision AS estoque_futuro,
		    a.estoque_maximo::double precision * a.fator_conversao::double precision AS estoque_maximo,
		    a.estoque::double precision * a.fator_conversao::double precision AS estoque,
		    a.tempo_ressuprimento,
		    a.desvio_padrao_ressuprimento,
		    a.consumo_medio_mensal::double precision * a.fator_conversao::double precision AS consumo_medio_mensal,
		    gerar_lote_embalagem(a.lote_compras * a.fator_conversao::numeric, a.lote_minimo * a.fator_conversao::numeric) AS lote_compras,
		    a.lote_compras * a.fator_conversao::numeric AS lote_compras_bruto,
		    a.fator_conversao,
		    a.unidade_compra,
		    a.lote_minimo,
		    a.nivel_servico,
		    a.peso_compras
		   FROM ( SELECT previsao.idfornecedor,
		            previsao.fornecedor,
		            previsao.idcomprador,
		            previsao.comprador,
		            previsao.filial,
		            previsao.idproduto,
		            previsao.descricao_produto,
		            previsao.ponto_pedido,
		            previsao.estoque_futuro,
		            previsao.estoque_maximo,
		            previsao.estoque,
		            previsao.tempo_ressuprimento,
		            previsao.desvio_padrao_ressuprimento,
		            previsao.consumo_medio_mensal,
		            round((previsao.estoque_maximo::double precision + (previsao.consumo_medio_mensal * (previsao.tempo_ressuprimento + previsao.desvio_padrao_ressuprimento))::double precision - previsao.estoque::double precision)::numeric, 2) AS lote_compras,
		            previsao.fator_conversao,
		            previsao.unidade_compra,
		            previsao.lote_minimo,
		            previsao.id_grupo,
		            previsao.iddepartamento,
		            previsao.descricao_departamento AS departamento,
		            previsao.nivel_servico,
		            previsao.peso_compras
		           FROM ( SELECT p.filial,
		                    p.id_grupo,
		                    p.idfornecedor,
		                    f.razao_social AS fornecedor,
		                    p.idcomprador,
		                    c.nome_completo AS comprador,
		                    p.idproduto,
		                    p.descricao_produto,
		                    dep.iddepartamento,
		                    dep.descricao_departamento,
		                    p.ponto_pedido,
		                    get_forecast_filial(p.filial::numeric, p.idproduto,(( SELECT f_1.tempo_forecast
		                           FROM fornecedor f_1
		                          WHERE f_1.id = p.idfornecedor))::numeric) AS estoque_futuro,
		                    p.estoque_maximo,
		                    p.estoque,
		                    p.tempo_ressuprimento,
		                    p.desvio_padrao_ressuprimento,
		                    p.consumo_medio_mensal,
		                    p.unidade_compra,
		                    p.lote_minimo,
		                    1 AS fator_conversao,
		                    p.arvore_decisao,
		                    p.nivel_servico,
		                    p.peso_compras
		                   FROM produtos_compras_filial p
		                     JOIN fornecedor f ON f.id = p.idfornecedor
		                     JOIN comprador c ON c.id = p.idcomprador
		                     JOIN departamentos dep ON dep.iddepartamento = p.idfamilia_produto
		                  WHERE p.idfornecedor = p_fornecedor and p.lote_compras = 0::numeric AND p.consumo_medio_mensal > 0::numeric AND p.compra_transito = 0::numeric AND p.revenda::text = 'S'::text AND p.status::text <> 'FL'::text) previsao
		          WHERE previsao.estoque_futuro::double precision <= previsao.ponto_pedido::double precision) a
		  WHERE gerar_lote_embalagem(a.lote_compras * a.fator_conversao::numeric, a.lote_minimo) > 0::numeric)
		  loop 
		  
		  
		    --Update 
		    
			  update
				produtos_forecast_filial
			   set
				idfornecedor = rec_forecast.idfornecedor,
				fornecedor = rec_forecast.fornecedor,
				idcomprador = rec_forecast.idcomprador,
				comprador = rec_forecast.comprador,
				descricao_produto = rec_forecast.descricao_produto,
				iddepartamento = rec_forecast.iddepartamento,
				departamento = rec_forecast.departamento,
				ponto_pedido = rec_forecast.ponto_pedido,
				estoque_futuro = rec_forecast.estoque_futuro,
				estoque_maximo = rec_forecast.estoque_maximo,
				estoque = rec_forecast.estoque,
				tempo_ressuprimento = rec_forecast.tempo_ressuprimento,
				desvio_padrao_ressuprimento = rec_forecast.desvio_padrao_ressuprimento,
				consumo_medio_mensal = rec_forecast.consumo_medio_mensal,
				lote_compras = rec_forecast.lote_compras,
				lote_compras_bruto = rec_forecast.lote_compras_bruto,
				fator_conversao = rec_forecast.fator_conversao,
				unidade_compra = rec_forecast.unidade_compra,
				lote_minimo = rec_forecast.lote_minimo,
				nivel_servico = rec_forecast.nivel_servico,
				peso_compras = rec_forecast.peso_compras,
				flag = null,
				processamento = current_timestamp 
			where
				id_grupo = rec_forecast.id_grupo
				and filial = rec_forecast.filial
				and idproduto = rec_forecast.idproduto;
			
			if not found then 
			
			  --Insert 
		    
				 insert
					into
					produtos_forecast_filial (
					id_grupo,
					idfornecedor,
					fornecedor,
					idcomprador,
					comprador,
					filial,
					idproduto,
					descricao_produto,
					iddepartamento,
					departamento,
					ponto_pedido,
					estoque_futuro,
					estoque_maximo,
					estoque,
					tempo_ressuprimento,
					desvio_padrao_ressuprimento,
					consumo_medio_mensal,
					lote_compras,
					lote_compras_bruto,
					fator_conversao,
					unidade_compra,
					lote_minimo,
					nivel_servico,
					peso_compras,
					flag,
					processamento)
				values(
					rec_forecast.id_grupo,
					rec_forecast.idfornecedor,
					rec_forecast.fornecedor,
					rec_forecast.idcomprador,
					rec_forecast.comprador,
					rec_forecast.filial,
					rec_forecast.idproduto,
					rec_forecast.descricao_produto,
					rec_forecast.iddepartamento,
					rec_forecast.departamento,
					rec_forecast.ponto_pedido,
					rec_forecast.estoque_futuro,
					rec_forecast.estoque_maximo,
					rec_forecast.estoque,
					rec_forecast.tempo_ressuprimento,
					rec_forecast.desvio_padrao_ressuprimento,
					rec_forecast.consumo_medio_mensal,
					rec_forecast.lote_compras,
					rec_forecast.lote_compras_bruto,
					rec_forecast.fator_conversao,
					rec_forecast.unidade_compra,
					rec_forecast.lote_minimo,
					rec_forecast.nivel_servico,
					rec_forecast.peso_compras,
					null,
					current_timestamp
					);
			 
			end if;
		
	 end loop;
   
end if;
	     
delete from  produtos_forecast_filial  where  flag ='D';

end
$$;


ALTER FUNCTION public.processar_forecast_filial(p_fornecedor bigint) OWNER TO systock;

--
-- TOC entry 777 (class 1255 OID 53900)
-- Name: processar_historico_compras(integer); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_historico_compras(prazo integer DEFAULT 30) RETURNS void
    LANGUAGE plpgsql
    AS $$
declare

requisoes record;
arv_decisao varchar;
eseg numeric;
ppd  numeric;
emax numeric;
existe numeric;
cmm numeric;
sugest numeric;

begin
		
  
  for requisoes in (select distinct r.idproduto::varchar,r.data_solicitacao from requisicoes r
       inner join produtos p 
        on p.idproduto::varchar = r.idproduto::varchar
       inner join entrada_mercadorias e ON r.ordem_compra = e.ordem_compra AND r.idproduto = e.idproduto  
      where  data_solicitacao between current_date - prazo and current_date 
          /* and not exists (select 'x' from hist_analise_compras h 
                                            where h.idproduto::varchar = r.idproduto::varchar 
                                            and h.data_solicitacao = r.data_solicitacao )*/                 
           and p.revenda='S' 
           and p.status <>'FL'
          order by r.data_solicitacao)
     loop
                
           
          select count(*),arvore_decisao  into existe,arv_decisao from hist_analise_compras where idproduto = requisoes.idproduto 
            and data_solicitacao = requisoes.data_solicitacao group by arvore_decisao;
         
          if existe = 0 then
          
             arv_decisao = (select get_prismas_analise(requisoes.idproduto,requisoes.data_solicitacao));
         
             select estoque_seguranca,ponto_pedido,estoque_maximo,consumo_medio,sugestao into eseg,ppd,emax,cmm,sugest from get_calculo_dimensoes_estoque(requisoes.idproduto,arv_decisao,requisoes.data_solicitacao);

             INSERT INTO public.hist_analise_compras
               (idproduto, data_solicitacao,arvore_decisao,estoque_seguranca, ponto_pedido, estoque_maximo,consumo_medio,sugestao)
             VALUES(requisoes.idproduto, requisoes.data_solicitacao,arv_decisao,eseg,ppd,emax,cmm,sugest);


             else
             
             select estoque_seguranca,ponto_pedido,estoque_maximo,consumo_medio,sugestao into eseg,ppd,emax,cmm,sugest from get_calculo_dimensoes_estoque(requisoes.idproduto,arv_decisao,requisoes.data_solicitacao);
             
             
             UPDATE public.hist_analise_compras
                 SET estoque_seguranca=eseg, ponto_pedido=ppd, estoque_maximo=emax, consumo_medio=cmm, sugestao=sugest
             WHERE filial=0 AND idproduto= requisoes.idproduto  AND data_solicitacao=requisoes.data_solicitacao;

          end if;
         
     
     end loop;


end;

$$;


ALTER FUNCTION public.processar_historico_compras(prazo integer) OWNER TO systock;

--
-- TOC entry 778 (class 1255 OID 53901)
-- Name: processar_historico_compras_saldos(integer); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_historico_compras_saldos(prazo integer DEFAULT 30) RETURNS void
    LANGUAGE plpgsql
    AS $$
declare

rec_prod record;
arv_decisao varchar;
eseg numeric;
ppd  numeric;
emax numeric;
existe numeric;
cmm numeric;
sugest numeric;
est numeric;

begin
		
  
  for rec_prod in (select idproduto,"data",arvore_decisao from saldos where "data" between current_date-prazo and current_date and arvore_decisao is not null order by "data",idproduto)
     loop
                
           
          select count(*) into existe from hist_analise_compras where idproduto = rec_prod.idproduto and data_solicitacao = rec_prod.data;
         
          if existe = 0 then
          
             select estoque_seguranca,ponto_pedido,estoque_maximo,consumo_medio,sugestao,estoque into eseg,ppd,emax,cmm,sugest,est from get_calculo_dimensoes_estoque(rec_prod.idproduto,rec_prod.arvore_decisao,rec_prod.data);

             INSERT INTO public.hist_analise_compras
               (idproduto, data_solicitacao,arvore_decisao,estoque_seguranca, ponto_pedido, estoque_maximo,consumo_medio,sugestao,estoque)
             VALUES(rec_prod.idproduto, rec_prod.data,rec_prod.arvore_decisao,eseg,ppd,emax,cmm,sugest,est);


             else
             
             select estoque_seguranca,ponto_pedido,estoque_maximo,consumo_medio,sugestao,estoque into eseg,ppd,emax,cmm,sugest,est from get_calculo_dimensoes_estoque(rec_prod.idproduto,rec_prod.arvore_decisao,rec_prod.data);
             
             
             UPDATE public.hist_analise_compras
                 SET estoque_seguranca=eseg, ponto_pedido=ppd, estoque_maximo=emax, consumo_medio=cmm, 
                 sugestao=sugest,arvore_decisao=rec_prod.arvore_decisao,processamento=current_timestamp,
                 estoque=est
             WHERE filial=0 AND idproduto= rec_prod.idproduto  AND data_solicitacao=rec_prod.data;

          end if;
         
     
     end loop;


end;

$$;


ALTER FUNCTION public.processar_historico_compras_saldos(prazo integer) OWNER TO systock;

--
-- TOC entry 779 (class 1255 OID 53902)
-- Name: processar_historico_compras_saldos_filial(integer); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_historico_compras_saldos_filial(prazo integer DEFAULT 30) RETURNS void
    LANGUAGE plpgsql
    AS $$

declare



rec_prod record;

arv_decisao varchar;

eseg numeric;

ppd  numeric;

emax numeric;

existe numeric;

cmm numeric;

sugest numeric;

est numeric;



begin

		

  

  for rec_prod in (select filial,idproduto,"data",arvore_decisao from saldo_filiais sf where "data" between current_date-prazo and current_date and arvore_decisao is not null order by "data",idproduto,filial)

     loop

                

           

          select count(*) into existe from hist_analise_compras_filial where filial= rec_prod.filial and idproduto = rec_prod.idproduto and data_solicitacao = rec_prod.data;

         

          if existe = 0 then

          

             select coalesce(estoque_seguranca,0),coalesce(ponto_pedido,0),coalesce(estoque_maximo,0),coalesce(consumo_medio,0),coalesce(sugestao,0),coalesce(estoque,0) into eseg,ppd,emax,cmm,sugest,est from get_calculo_dimensoes_estoque_filial(rec_prod.filial,rec_prod.idproduto,rec_prod.arvore_decisao,rec_prod.data);



             INSERT INTO public.hist_analise_compras_filial

               (filial,idproduto, data_solicitacao,arvore_decisao,estoque_seguranca, ponto_pedido, estoque_maximo,consumo_medio,sugestao,estoque)

             VALUES(rec_prod.filial,rec_prod.idproduto, rec_prod.data,rec_prod.arvore_decisao,eseg,ppd,emax,cmm,sugest,est);





             else

             

             select coalesce(estoque_seguranca,0),coalesce(ponto_pedido,0),coalesce(estoque_maximo,0),coalesce(consumo_medio,0),coalesce(sugestao,0),coalesce(estoque,0) into eseg,ppd,emax,cmm,sugest,est  from get_calculo_dimensoes_estoque_filial(rec_prod.filial,rec_prod.idproduto,rec_prod.arvore_decisao,rec_prod.data);

             

             

             UPDATE public.hist_analise_compras_filial

                 SET estoque_seguranca=eseg, ponto_pedido=ppd, estoque_maximo=emax, consumo_medio=cmm, 

                 sugestao=sugest,arvore_decisao=rec_prod.arvore_decisao,processamento=current_timestamp,

                 estoque=est

             WHERE filial=rec_prod.filial AND idproduto= rec_prod.idproduto  AND data_solicitacao=rec_prod.data;



          end if;

         

     

     end loop;





end;



$$;


