CREATE FUNCTION public.processar_historico_compras_saldos_filial_data(p_data date) RETURNS void
    LANGUAGE plpgsql
    AS $$

declare



rec_prod record;

arv_decisao varchar;

eseg numeric;

ppd  numeric;

emax numeric;

existe numeric;

cmm numeric;

sugest numeric;

est numeric;



begin

		

  

  for rec_prod in (select filial,idproduto,"data",arvore_decisao from saldo_filiais sf where "data" = p_data and arvore_decisao is not null order by "data",idproduto,filial)

     loop

                

           

          select count(*) into existe from hist_analise_compras_filial where filial= rec_prod.filial and idproduto = rec_prod.idproduto and data_solicitacao = rec_prod.data;

         

          if existe = 0 then

          

             select coalesce(estoque_seguranca,0),coalesce(ponto_pedido,0),coalesce(estoque_maximo,0),coalesce(consumo_medio,0),coalesce(sugestao,0),coalesce(estoque,0) into eseg,ppd,emax,cmm,sugest,est from get_calculo_dimensoes_estoque_filial(rec_prod.filial,rec_prod.idproduto,rec_prod.arvore_decisao,rec_prod.data);



             INSERT INTO public.hist_analise_compras_filial

               (filial,idproduto, data_solicitacao,arvore_decisao,estoque_seguranca, ponto_pedido, estoque_maximo,consumo_medio,sugestao,estoque)

             VALUES(rec_prod.filial,rec_prod.idproduto, rec_prod.data,rec_prod.arvore_decisao,eseg,ppd,emax,cmm,sugest,est);





             else

             

             select coalesce(estoque_seguranca,0),coalesce(ponto_pedido,0),coalesce(estoque_maximo,0),coalesce(consumo_medio,0),coalesce(sugestao,0),coalesce(estoque,0) into eseg,ppd,emax,cmm,sugest,est  from get_calculo_dimensoes_estoque_filial(rec_prod.filial,rec_prod.idproduto,rec_prod.arvore_decisao,rec_prod.data);

             

             

             UPDATE public.hist_analise_compras_filial

                 SET estoque_seguranca=eseg, ponto_pedido=ppd, estoque_maximo=emax, consumo_medio=cmm, 

                 sugestao=sugest,arvore_decisao=rec_prod.arvore_decisao,processamento=current_timestamp,

                 estoque=est

             WHERE filial=rec_prod.filial AND idproduto= rec_prod.idproduto  AND data_solicitacao=rec_prod.data;



          end if;

         

     

     end loop;





end;



$$;


ALTER FUNCTION public.processar_historico_compras_saldos_filial_data(p_data date) OWNER TO systock;

--
-- TOC entry 781 (class 1255 OID 53904)
-- Name: processar_historico_compras_saldos_filial_prod(numeric, character varying, date, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_historico_compras_saldos_filial_prod(p_filial numeric, p_produto character varying, p_dataini date, p_datafim date) RETURNS void
    LANGUAGE plpgsql PARALLEL SAFE
    AS $$

declare

rec_prod record;
arv_decisao varchar;
eseg numeric;
ppd  numeric;
emax numeric;
existe numeric;
cmm numeric;
sugest numeric;
est numeric;

begin

		

for rec_prod in (select filial,idproduto,"data",arvore_decisao from saldo_filiais sf where filial = p_filial and idproduto =p_produto and "data" between p_dataini and p_datafim and  arvore_decisao is not null order by "data")

     loop

        
       select coalesce(estoque_seguranca,0),coalesce(ponto_pedido,0),coalesce(estoque_maximo,0),coalesce(consumo_medio,0),coalesce(sugestao,0),coalesce(estoque,0) into eseg,ppd,emax,cmm,sugest,est  from get_calculo_dimensoes_estoque_filial(rec_prod.filial,rec_prod.idproduto,rec_prod.arvore_decisao,rec_prod.data);

            
	     UPDATE public.hist_analise_compras_filial
	
	         SET estoque_seguranca=eseg, ponto_pedido=ppd, estoque_maximo=emax, consumo_medio=cmm, 
	
	         sugestao=sugest,arvore_decisao=rec_prod.arvore_decisao,processamento=current_timestamp,
	
	         estoque=est
	
	     WHERE filial=rec_prod.filial AND idproduto= rec_prod.idproduto  AND data_solicitacao=rec_prod.data;
    
         
	    if not found then 
	    
	    	 INSERT INTO public.hist_analise_compras_filial

               (filial,idproduto, data_solicitacao,arvore_decisao,estoque_seguranca, ponto_pedido, estoque_maximo,consumo_medio,sugestao,estoque)

             VALUES(rec_prod.filial,rec_prod.idproduto, rec_prod.data,rec_prod.arvore_decisao,eseg,ppd,emax,cmm,sugest,est);
	    
	    end if;
	   
   
     end loop;


end;


$$;


ALTER FUNCTION public.processar_historico_compras_saldos_filial_prod(p_filial numeric, p_produto character varying, p_dataini date, p_datafim date) OWNER TO systock;

--
-- TOC entry 782 (class 1255 OID 53905)
-- Name: processar_indicadores(integer); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_indicadores(qtd_meses integer DEFAULT 13) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE 
	item_rec record;
BEGIN 
	-- Prismas
	FOR item_rec IN (
		SELECT LEAST(last_day(day::date), current_date) as data
		FROM generate_series(current_date - make_interval(months => qtd_meses), current_date, '1 month') day
	)
	LOOP 
		PERFORM processar_prismas_filiais(item_rec.data);
	END LOOP;

	-- Saldos diário
	FOR item_rec IN (
		SELECT gf.filial, day::date as data
		FROM generate_series(current_date - make_interval(months => qtd_meses), current_date, '1 day') day
		    CROSS JOIN grupo_filial gf  
		ORDER BY day, gf.filial
	)
	LOOP
		PERFORM gerar_saldos_diario(item_rec.filial::integer, item_rec.data::date, item_rec.data::date, 0::numeric);
	END LOOP;
	
	REFRESH MATERIALIZED VIEW saldo_grupos;
          
	-- Status Produto
	FOR item_rec IN (
		SELECT LEAST(last_day(day::date), current_date) as data
		FROM generate_series(current_date - make_interval(months => qtd_meses), current_date, '1 month') day
	)
	LOOP 
		PERFORM processar_status_produto(item_rec.data);
	END LOOP;
	
	PERFORM processar_analise_rupturas_produtos_filial(current_date - 400);
	PERFORM processar_analise_percepcao_compras_grupos(current_date - 400);
END; $$;


ALTER FUNCTION public.processar_indicadores(qtd_meses integer) OWNER TO systock;

--
-- TOC entry 783 (class 1255 OID 53906)
-- Name: processar_prismas_filiais(date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_prismas_filiais(p_dataref date DEFAULT ('now'::text)::date) RETURNS void
    LANGUAGE plpgsql
    AS $$
declare
rec_dados record;
rec_filiais record;	
begin 

    ALTER TABLE public.produtos_filial DISABLE TRIGGER produtos_filial_trg;

    for rec_filiais in (select distinct filial from produtos_filial pf )
    loop 
   
       
      	 for rec_dados in (select produto as idproduto, arvore as arv_decisao  from gerar_prismas_filiais_3(rec_filiais.filial,p_dataref))
         loop
          
            UPDATE prismas_filiais pf
			SET arvore_decisao=rec_dados.arv_decisao
			WHERE pf.filial=rec_filiais.filial AND pf.idproduto=rec_dados.idproduto and pf.data_ref = first_day(p_dataref);

	       
            if not found then
		   
   	            INSERT INTO prismas_filiais (filial, idproduto, arvore_decisao,data_ref )
				VALUES(rec_filiais.filial,rec_dados.idproduto,rec_dados.arv_decisao,first_day(p_dataref));
		   
            end if;
          
        end loop;
         
        
        -- classificação de rentabilidade     
        FOR rec_dados IN (SELECT * FROM gerar_prismas_rentabilidade_filiais(rec_filiais.filial))
        LOOP
            
            UPDATE prismas_filiais pf
            SET classificacao_rentabilidade = rec_dados.classificacao_rentabilidade
            WHERE pf.filial = rec_filiais.filial AND pf.idproduto = rec_dados.idproduto AND pf.data_ref = to_char(current_date, 'YYYY-MM-01')::date;
       
            UPDATE produtos_filial pf
            SET classificacao_rentabilidade = rec_dados.classificacao_rentabilidade
            WHERE pf.filial = rec_filiais.filial AND pf.idproduto = rec_dados.idproduto;
        
        END LOOP;
   
    end loop;
  
    ALTER TABLE public.produtos_filial ENABLE TRIGGER produtos_filial_trg;

    perform  processar_prismas_grupo(p_dataref);
end;$$;


ALTER FUNCTION public.processar_prismas_filiais(p_dataref date) OWNER TO systock;

--
-- TOC entry 784 (class 1255 OID 53907)
-- Name: processar_prismas_grupo(date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_prismas_grupo(p_dataref date DEFAULT ('now'::text)::date) RETURNS void
    LANGUAGE plpgsql
    AS $$
declare
rec_dados record;

begin 


       
  	for rec_dados in (
  	     select gf.id_grupo,idproduto,data_ref,min(substring(arvore_decisao,1,1))||max(substring(arvore_decisao,2,1))||min(substring(arvore_decisao,3,1))||min(substring(arvore_decisao,4,1)) arv_decisao_grupo,
		   getFes(min(substring(arvore_decisao,1,1))||max(substring(arvore_decisao,2,1))||min(substring(arvore_decisao,3,1))||min(substring(arvore_decisao,4,1))) as fes_grupo,
		   getnivelservico(min(substring(arvore_decisao,1,1))||max(substring(arvore_decisao,2,1))||min(substring(arvore_decisao,3,1))||min(substring(arvore_decisao,4,1))) nivel_servico
		   from prismas_filiais pf
		   inner join grupo_filial gf 
		   on gf.filial = pf.filial 
		   where data_ref=first_day(p_dataref)
		   group by gf.id_grupo,idproduto,data_ref
  	)
      loop
      
        UPDATE prismas_grupos pf
		SET arvore_decisao=rec_dados.arv_decisao_grupo,fes=rec_dados.fes_grupo,nivel_servico=rec_dados.nivel_servico
		WHERE pf.id_grupo=rec_dados.id_grupo AND pf.idproduto=rec_dados.idproduto and pf.data_ref = first_day(p_dataref);

	   if not found then
	   
	   	 INSERT INTO prismas_grupos
			(id_grupo, idproduto, arvore_decisao,data_ref,fes,nivel_servico )
			VALUES(rec_dados.id_grupo,rec_dados.idproduto,rec_dados.arv_decisao_grupo,first_day(p_dataref),rec_dados.fes_grupo,rec_dados.nivel_servico);
	   
	   
	   end if;
      
      
      end loop;
       


end;$$;


ALTER FUNCTION public.processar_prismas_grupo(p_dataref date) OWNER TO systock;

--
-- TOC entry 785 (class 1255 OID 53908)
-- Name: processar_produtos_combinados_compras_filial(character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_produtos_combinados_compras_filial(f_id_produto_combinado character varying DEFAULT NULL::character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
        DECLARE rec_forecast record;
    BEGIN
        IF trim(f_id_produto_combinado) = '' THEN
            f_id_produto_combinado = NULL;
        END IF;

        UPDATE produtos_combinados_compras_filial SET flag = 'D' WHERE (f_id_produto_combinado = id_produto_combinado OR f_id_produto_combinado IS NULL);

        FOR rec_forecast IN (
            SELECT
                id_grupo,
                filial,
                id_produto_combinado,
                descricao_produto,
                produtos,
                compradores,
                fornecedores,
                familias_produtos,
                secoes,
                revenda,
                status,
                estoque,
                COALESCE(round(estoque / NULLIF(consumo_medio_mensal, 0::numeric), 4), 0::numeric) AS cobertura_estoque,
                estoque_seguranca,
                ponto_pedido,
                estoque_maximo,
                consumo_medio_mensal,
                desvio_padrao_consumo,
                tempo_medio_ressuprimento,
                tempo_ressuprimento,
                desvio_padrao_ressuprimento,
                coeficiente_variacao,
                compra_transito,
                lote_minimo,
                lote_compras_bruto,
                arvore_decisao,
                nivel_servico,
                peso_compras,
                unidade_compra,
                lote_embalagem,
                CASE
                    WHEN flag_sob_encomenda = 'S'::text THEN 1
                    -- WHEN lote_compras_bruto > 0::numeric AND lote_embalagem = 0::numeric THEN 1 -- OCTADESK99905315
                    ELSE 0
                END AS sob_encomenda,
                CASE
                    WHEN lote_embalagem > 0::numeric AND COALESCE(round(estoque / NULLIF(consumo_medio_mensal, 0::numeric), 4), 0::numeric) < tempo_ressuprimento AND compra_transito = 0::numeric THEN gerar_lote_embalagem(estoque_maximo, COALESCE(lote_minimo, 1::numeric))
                    ELSE lote_embalagem
                END AS lote_compras,
                preco_compra,
                custo_unitario,
                valor_unitario,
				valor_liquido,
                estoque_bloqueado,
                CASE
                    WHEN coeficiente_variacao::numeric >= 0::numeric AND coeficiente_variacao::numeric <= 200::numeric THEN 'REPETITIVO'::text
                    WHEN coeficiente_variacao::numeric > 200::numeric AND coeficiente_variacao::numeric <= 600::numeric THEN 'ESTATISTICO'::text
                    ELSE 'OCASIONAL'::text
                END AS perfil_demanda,
                tempo_medio_apanhe,
                embalagem,
                idunidade_medida,
                ressuprimento_manual,
                ressuprimento_manual_dias,
                cod_produto,
                codigo_barras,
                fator_conversao,
                fator_atuacao,
                projecao_rentabilidade,
                estoque_avaria,
                peso,
                altura,
                largura,
				litragem,
                comprimento,
                (
                    SELECT max(r.data_solicitacao) AS max
                    FROM requisicoes r
                    WHERE
                        (r.idproduto::text = ANY (lote.produtos::text[]))
                        AND (r.idfilial IN (SELECT gf.filial FROM grupo_filial gf WHERE gf.id_grupo = lote.id_grupo))
                ) AS data_ultima_requisicao,
                estoque_reservado,
                multiplo_compra::numeric(12,6) AS multiplo_compra,
                unidade_master,
                tipo_fator_conversao,
                compra_transito_entregue,
                detalhamento_tecnico,
                estoque_minimo,
                classificacao_rentabilidade,
                estoque_seguranca_estetico,
                ponto_pedido_estetico,
                ponto_pedido_estetico + consumo_medio_mensal AS estoque_maximo_estetico
            FROM (
                SELECT
                    a.id_grupo,
                    a.filial,
                    a.id_produto_combinado,
                    a.descricao_produto,
                    a.produtos,
                    a.compradores,
                    a.fornecedores,
                    a.familias_produtos,
                    a.secoes,
                    a.revenda,
                    a.status,
                    a.estoque,
                    a.cobertura_estoque,
                    a.estoque_seguranca,
                    a.ponto_pedido,
                    a.estoque_maximo,
                    a.consumo_medio_mensal,
                    a.desvio_padrao_consumo,
                    a.tempo_medio_ressuprimento,
                    a.tempo_ressuprimento,
                    a.desvio_padrao_ressuprimento,
                    a.coeficiente_variacao,
                    a.compra_transito,
                    a.lote_minimo,
                    CASE
                        WHEN a.coeficiente_variacao::numeric >= 0::numeric AND a.compra_transito = 0::numeric AND a.estoque <= a.ponto_pedido AND a.revenda = 'S'::text AND a.status <> 'FL'::text THEN round(a.estoque_maximo + a.consumo_medio_mensal * (a.tempo_ressuprimento + a.desvio_padrao_ressuprimento) - a.estoque, 2)
                        WHEN a.coeficiente_variacao::numeric = 0::numeric AND a.compra_transito = 0::numeric AND a.estoque <= a.ponto_pedido AND a.revenda = 'S'::text AND a.status <> 'FL'::text THEN ceil(a.consumo_medio_mensal / 2::numeric)
                        ELSE 0::numeric
                    END AS lote_compras_bruto,
                    a.arvore_decisao,
                    a.nivel_servico,
                    a.peso_compras,
                    a.unidade_compra,
                    gerar_lote_embalagem(
                        CASE
                            WHEN a.coeficiente_variacao::numeric >= 0::numeric AND a.compra_transito = 0::numeric AND a.estoque <= a.ponto_pedido AND a.revenda = 'S'::text AND a.status <> 'FL'::text THEN round(a.estoque_maximo + a.consumo_medio_mensal * (a.tempo_ressuprimento + a.desvio_padrao_ressuprimento) - a.estoque, 2)
                            WHEN a.coeficiente_variacao::numeric = 0::numeric AND a.compra_transito = 0::numeric AND a.estoque <= a.ponto_pedido AND a.revenda = 'S'::text AND a.status <> 'FL'::text THEN ceil(a.consumo_medio_mensal / 2::numeric)
                            ELSE 0::numeric
                        END, COALESCE(a.lote_minimo, 1::numeric)
                    ) AS lote_embalagem,
                    a.preco_compra,
                    a.custo_unitario,
                    a.valor_unitario,
					a.valor_liquido,
                    a.estoque_bloqueado,
                    a.tempo_medio_apanhe,
                    a.embalagem,
                    a.idunidade_medida,
                    a.ressuprimento_manual,
                    a.ressuprimento_manual_dias,
                    a.cod_produto,
                    a.codigo_barras,
                    a.fator_conversao,
                    a.fator_atuacao,
                    a.projecao_rentabilidade,
                    a.estoque_avaria,
                    a.peso,
                    a.altura,
                    a.largura,
					a.litragem,
                    a.comprimento,
                    a.flag_sob_encomenda,
                    a.estoque_reservado,
                    a.multiplo_compra,
                    a.unidade_master,
                    a.tipo_fator_conversao,
                    a.compra_transito_entregue,
                    a.detalhamento_tecnico,
                    a.estoque_minimo,
                    a.classificacao_rentabilidade,
                    a.estoque_seguranca_estetico,
                    a.estoque_seguranca_estetico + a.consumo_medio_mensal / 30::numeric * a.tempo_medio_ressuprimento AS ponto_pedido_estetico
                    FROM (
                        SELECT
                            v.id_grupo,
                            v.filial,
                            v.id_produto_combinado,
                            v.descricao_produto,
                            v.produtos,
                            v.compradores,
                            v.fornecedores,
                            v.familias_produtos,
                            v.secoes,
                            v.revenda,
                            v.status,
                            v.unidade_compra,
                            v.estoque,
                            v.cobertura_estoque,
                            CASE
                                WHEN v.qtde_dias_cobertura_eseg > 0::numeric THEN v.consumo_medio_mensal / 30::numeric * v.qtde_dias_cobertura_eseg
                                ELSE v.estoque_seguranca
                            END AS estoque_seguranca,
                            CASE
                                WHEN v.qtde_dias_cobertura_eseg > 0::numeric THEN round(v.consumo_medio_mensal / 30::numeric * v.qtde_dias_cobertura_eseg + v.consumo_medio_mensal * (v.tempo_ressuprimento + v.desvio_padrao_ressuprimento), 2)
                                ELSE v.ponto_pedido
                            END AS ponto_pedido,
                            CASE
                                WHEN v.qtde_dias_cobertura_emax > 0::numeric THEN v.consumo_medio_mensal / 30::numeric * v.qtde_dias_cobertura_emax
                                ELSE v.estoque_maximo
                            END AS estoque_maximo,
                            v.consumo_medio_mensal,
                            v.desvio_padrao_consumo,
                            v.tempo_medio_ressuprimento,
                            v.tempo_ressuprimento,
                            v.desvio_padrao_ressuprimento,
                            v.coeficiente_variacao,
                            v.compra_transito,
                            v.lote_minimo,
                            v.arvore_decisao,
                            v.nivel_servico,
                            v.peso_compras,
                            v.preco_compra,
                            v.custo_unitario,
                            v.valor_unitario,
							v.valor_liquido,
                            v.estoque_bloqueado,
                            v.tempo_medio_apanhe,
                            v.embalagem,
                            v.idunidade_medida,
                            v.ressuprimento_manual,
                            v.ressuprimento_manual_dias,
                            v.cod_produto,
                            v.codigo_barras,
                            v.fator_conversao,
                            v.fator_atuacao,
                            v.projecao_rentabilidade,
                            v.estoque_avaria,
                            v.peso,
                            v.altura,
                            v.largura,
							v.litragem,
                            v.comprimento,
                            v.flag_sob_encomenda,
                            v.estoque_reservado,
                            v.multiplo_compra,
                            v.unidade_master,
                            v.tipo_fator_conversao,
                            v.compra_transito_entregue,
                            v.detalhamento_tecnico,
                            v.estoque_minimo,
                            v.classificacao_rentabilidade,
                            v.estoque_seguranca_estetico
                        FROM (
                            WITH prismas AS (
                                SELECT
                                    gf.id_grupo,
                                    gf.filial,
                                    spci_1.id_produto_combinado,
                                    (
                                        (min(pf.classificacao_financeira::text) || max(pf.classificacao_criticidade::text))
                                        || min(pf.classificacao_comprabilidade))
                                        || min(pf.classificacao_popularidade::TEXT
                                    ) AS arvore_decisao
                                FROM produtos_filial pf
                                    JOIN grupo_filial gf ON gf.filial = pf.filial
                                    JOIN sys_produtos_combinados_itens spci_1 ON spci_1.idproduto::text = pf.idproduto::text
                                WHERE pf.processar_analise::text = 'S'::text
                                GROUP BY gf.id_grupo, gf.filial, spci_1.id_produto_combinado
                            ),
                            compras_pendentes_com_entrega AS (
                                SELECT
                                    gf.id_grupo,
                                    gf.filial,
                                    spci_1.id_produto_combinado,
                                    sum(r.qtde_entregue / spci_1.fator_conversao::double precision) AS compra_transito_entregue
                                FROM requisicoes r
                                    JOIN grupo_filial gf ON gf.filial = r.idfilial
                                    JOIN sys_produtos_combinados_itens spci_1 ON spci_1.idproduto::text = r.idproduto::text
                                WHERE r.qtde_pendente > 0::double precision AND r.qtde_entregue > 0::double precision
                                GROUP BY gf.id_grupo, gf.filial, spci_1.id_produto_combinado
                            )
                            SELECT
                                g.id_grupo,
                                g.filial,
                                spci.id_produto_combinado,
                                spc.descricao AS descricao_produto,
                                array_agg(DISTINCT p.idproduto) AS produtos,
                                array_agg(DISTINCT p.idcomprador) AS compradores,
                                array_agg(DISTINCT p.idfornecedor) AS fornecedores,
                                array_agg(DISTINCT p.idfamilia_produto) AS familias_produtos,
                                array_agg(DISTINCT p.idsecao) AS secoes,
                                max(p.revenda::text) AS revenda,
                                min(p.status::text) AS status,
                                max(p.unidade_compra::text) AS unidade_compra,
                                (sum((p.estoque - COALESCE(p.estoque_similar, 0)) / spci.fator_conversao) + get_estoque_similar_produto_combinado(g.id_grupo::int, g.filial::int, spci.id_produto_combinado)) AS estoque,
                                avg(NULLIF(p.cobertura_estoque, 0::numeric)) AS cobertura_estoque,
                                sum(p.estoque_seguranca / spci.fator_conversao) AS estoque_seguranca,
                                sum(p.ponto_pedido / spci.fator_conversao) AS ponto_pedido,
                                sum(p.estoque_maximo / spci.fator_conversao) AS estoque_maximo,
                                (sum(p.consumo_medio_mensal / spci.fator_conversao) + (get_cmm_heranca_produto_combinado(g.id_grupo::int, spci.id_produto_combinado, g.filial::int) * avg(p.fator_atuacao))) AS consumo_medio_mensal,
                                sum(p.desvio_padrao_consumo / spci.fator_conversao) AS desvio_padrao_consumo,
                                avg(p.tempo_medio_ressuprimento) AS tempo_medio_ressuprimento,
                                avg(p.tempo_ressuprimento) AS tempo_ressuprimento,
                                avg(p.desvio_padrao_ressuprimento) AS desvio_padrao_ressuprimento,
                                COALESCE(sum(p.desvio_padrao_consumo / spci.fator_conversao) / NULLIF((sum(p.consumo_medio_mensal / spci.fator_conversao) + (get_cmm_heranca_produto_combinado(g.id_grupo::int, spci.id_produto_combinado, g.filial::int) * avg(p.fator_atuacao))), 0::numeric) * 100::numeric, 0::numeric)::text AS coeficiente_variacao,
                                sum(getcompra_transito_filial(g.filial::numeric, p.idproduto) / spci.fator_conversao) AS compra_transito,
                                trunc(max(p.lote_minimo / spci.fator_conversao), 4) AS lote_minimo,
                                COALESCE(pm.arvore_decisao, 'CX2R'::text) AS arvore_decisao,
                                getnivelservico(COALESCE(pm.arvore_decisao::character varying, 'CX2R'::character varying)) AS nivel_servico,
                                getpesocompras(COALESCE(pm.arvore_decisao::character varying, 'CX2R'::character varying), "substring"(COALESCE(pm.arvore_decisao::character varying, 'CX2R'::character varying)::text, 3, 1)::numeric) AS peso_compras,
                                COALESCE(avg(NULLIF(p.preco_compra, 0::numeric) * spci.fator_conversao), 0::numeric) AS preco_compra,
                                COALESCE(avg(NULLIF(p.custo_unitario, 0::numeric) * spci.fator_conversao), 0::numeric) AS custo_unitario,
                                COALESCE(avg(NULLIF(p.valor_unitario, 0::numeric) * spci.fator_conversao), 0::numeric) AS valor_unitario,
								COALESCE(avg(NULLIF(p.valor_liquido, 0::numeric) * spci.fator_conversao), 0::numeric) AS valor_liquido,
                                sum(p.estoque_bloqueado / spci.fator_conversao) AS estoque_bloqueado,
                                sum(p.tempo_medio_apanhe) AS tempo_medio_apanhe,
                                max(p.embalagem::text) AS embalagem,
                                max(p.idunidade_medida::text) AS idunidade_medida,
                                max(p.ressuprimento_manual::text)::character varying(1) AS ressuprimento_manual,
                                max(COALESCE(p.ressuprimento_manual_dias, 0::numeric)) AS ressuprimento_manual_dias,
                                ''::text AS cod_produto,
                                max(p.codigo_barras::text)::character varying(25) AS codigo_barras,
                                1 AS fator_conversao,
                                avg(p.fator_atuacao) AS fator_atuacao,
                                sum(p.projecao_rentabilidade) AS projecao_rentabilidade,
                                sum(p.estoque_avaria / spci.fator_conversao) AS estoque_avaria,
                                max(p.peso / spci.fator_conversao) AS peso,
                                max(p.altura / spci.fator_conversao) AS altura,
                                max(p.largura / spci.fator_conversao) AS largura,
								max(p.litragem / spci.fator_conversao) AS litragem,
                                max(p.comprimento / spci.fator_conversao) AS comprimento,
                                max(p.flag_sob_encomenda::text) AS flag_sob_encomenda,
                                sum(COALESCE(p.estoque_reservado, 0::numeric) / spci.fator_conversao) AS estoque_reservado,
                                max(p.multiplo_compra) AS multiplo_compra,
                                max(p.unidade_master::text) AS unidade_master,
                                'D'::text AS tipo_fator_conversao,
                                COALESCE(cpce.compra_transito_entregue, 0::double precision) AS compra_transito_entregue,
                                max(p.detalhamento_tecnico) AS detalhamento_tecnico,
                                sum(p.estoque_minimo / spci.fator_conversao) AS estoque_minimo,
                                min(p.classificacao_rentabilidade::text) AS classificacao_rentabilidade,
                                sum(p.estoque_minimo / spci.fator_conversao) AS estoque_seguranca_estetico,
                                COALESCE(
                                    (
                                        SELECT NULLIF(tccp.tempo_cobertura_esseg, 0) AS x
                                        FROM tempo_cobertura_compras_produtos tccp
                                        WHERE tccp.idproduto::text = spc.id::TEXT
                                    ), (
                                        SELECT NULLIF(tcc.tempo_cobertura_esseg, 0) AS x
                                        FROM tempo_cobertura_compras tcc
                                        WHERE tcc.id_grupo = g.id_grupo AND tcc.pqr::text = min("substring"(p.arvore_decisao::text, 4, 1)) AND tcc.xyz::text = min("substring"(p.arvore_decisao::text, 2, 1))
                                        LIMIT 1
                                    ), 0
                                )::numeric AS qtde_dias_cobertura_eseg,
                                COALESCE(
                                    (
                                        SELECT NULLIF(tccp.tempo_cobertura, 0) AS x
                                        FROM tempo_cobertura_compras_produtos tccp
                                        WHERE tccp.idproduto::text = spc.id::TEXT
                                    ), (
                                        SELECT NULLIF(tcc.tempo_cobertura, 0) AS x
                                        FROM tempo_cobertura_compras tcc
                                        WHERE tcc.id_grupo = g.id_grupo AND tcc.pqr::text = min("substring"(p.arvore_decisao::text, 4, 1)) AND tcc.xyz::text = min("substring"(p.arvore_decisao::text, 2, 1))
                                        LIMIT 1
                                    ), 0::bigint
                                )::numeric AS qtde_dias_cobertura_emax
                                FROM produtos_filial p
                                    JOIN grupo_filial g ON p.filial = g.filial
                                    JOIN sys_produtos_combinados_itens spci ON spci.idproduto::text = p.idproduto::text
                                    JOIN sys_produtos_combinados spc ON spc.id::text = spci.id_produto_combinado::text
                                    LEFT JOIN prismas pm ON pm.id_grupo = g.id_grupo AND pm.filial = g.filial AND pm.id_produto_combinado::text = spci.id_produto_combinado::text
                                    LEFT JOIN compras_pendentes_com_entrega cpce ON cpce.id_grupo = g.id_grupo AND cpce.filial = p.filial AND cpce.id_produto_combinado::text = spci.id_produto_combinado::text
                                WHERE
                                    spc.deleted_at IS NULL
                                    AND p.revenda::text = 'S'::text
                                    AND p.processar_analise::text = 'S'::TEXT
                                    AND (f_id_produto_combinado = spc.id OR f_id_produto_combinado IS NULL)
                                GROUP BY g.id_grupo, g.filial, spc.id, spci.id_produto_combinado, pm.arvore_decisao, cpce.compra_transito_entregue
                            ) v
                        ) a
                    ) lote
        )
        LOOP
            -- UPDATE
            UPDATE produtos_combinados_compras_filial
            SET
                id_grupo = rec_forecast.id_grupo,
                filial = rec_forecast.filial,
                id_produto_combinado = rec_forecast.id_produto_combinado,
                descricao_produto = rec_forecast.descricao_produto,
                produtos = rec_forecast.produtos,
                compradores = rec_forecast.compradores,
                fornecedores = rec_forecast.fornecedores,
                familias_produtos = rec_forecast.familias_produtos,
                secoes = rec_forecast.secoes,
                revenda = rec_forecast.revenda,
                status = rec_forecast.status,
                estoque = rec_forecast.estoque,
                cobertura_estoque = rec_forecast.cobertura_estoque,
                estoque_seguranca = rec_forecast.estoque_seguranca,
                ponto_pedido = rec_forecast.ponto_pedido,
                estoque_maximo = rec_forecast.estoque_maximo,
                consumo_medio_mensal = rec_forecast.consumo_medio_mensal,
                desvio_padrao_consumo = rec_forecast.desvio_padrao_consumo,
                tempo_medio_ressuprimento = rec_forecast.tempo_medio_ressuprimento,
                tempo_ressuprimento = rec_forecast.tempo_ressuprimento,
                desvio_padrao_ressuprimento = rec_forecast.desvio_padrao_ressuprimento,
                coeficiente_variacao = rec_forecast.coeficiente_variacao,
                compra_transito = rec_forecast.compra_transito,
                lote_minimo = rec_forecast.lote_minimo,
                lote_compras_bruto = rec_forecast.lote_compras_bruto,
                arvore_decisao = rec_forecast.arvore_decisao,
                nivel_servico = rec_forecast.nivel_servico,
                peso_compras = rec_forecast.peso_compras,
                unidade_compra = rec_forecast.unidade_compra,
                lote_embalagem = rec_forecast.lote_embalagem,
                sob_encomenda = rec_forecast.sob_encomenda,
                lote_compras = rec_forecast.lote_compras,
                preco_compra = rec_forecast.preco_compra,
                custo_unitario = rec_forecast.custo_unitario,
                valor_unitario = rec_forecast.valor_unitario,
				valor_liquido= rec_forecast.valor_liquido,
                estoque_bloqueado = rec_forecast.estoque_bloqueado,
                perfil_demanda = rec_forecast.perfil_demanda,
                tempo_medio_apanhe = rec_forecast.tempo_medio_apanhe,
                embalagem = rec_forecast.embalagem,
                idunidade_medida = rec_forecast.idunidade_medida,
                ressuprimento_manual = rec_forecast.ressuprimento_manual,
                ressuprimento_manual_dias = rec_forecast.ressuprimento_manual_dias,
                cod_produto = rec_forecast.cod_produto,
                codigo_barras = rec_forecast.codigo_barras,
                fator_conversao = rec_forecast.fator_conversao,
                fator_atuacao = rec_forecast.fator_atuacao,
                projecao_rentabilidade = rec_forecast.projecao_rentabilidade,
                estoque_avaria = rec_forecast.estoque_avaria,
                peso = rec_forecast.peso,
                altura = rec_forecast.altura,
                largura = rec_forecast.largura,
				litragem = rec_forecast.litragem,
                comprimento = rec_forecast.comprimento,
                data_ultima_requisicao = rec_forecast.data_ultima_requisicao,
                estoque_reservado = rec_forecast.estoque_reservado,
                multiplo_compra = rec_forecast.multiplo_compra,
                unidade_master = rec_forecast.unidade_master,
                tipo_fator_conversao = rec_forecast.tipo_fator_conversao,
                compra_transito_entregue = rec_forecast.compra_transito_entregue,
                detalhamento_tecnico = rec_forecast.detalhamento_tecnico,
                estoque_minimo = rec_forecast.estoque_minimo,
                classificacao_rentabilidade = rec_forecast.classificacao_rentabilidade,
                estoque_seguranca_estetico = rec_forecast.estoque_seguranca_estetico,
                ponto_pedido_estetico = rec_forecast.ponto_pedido_estetico,
                estoque_maximo_estetico = rec_forecast.estoque_maximo_estetico,
                flag = NULL
            WHERE
                id_grupo = rec_forecast.id_grupo
                AND filial = rec_forecast.filial
                AND id_produto_combinado = rec_forecast.id_produto_combinado;

            -- INSERT
            IF NOT FOUND THEN
                INSERT INTO produtos_combinados_compras_filial (
                    id_grupo,
                    filial,
                    id_produto_combinado,
                    descricao_produto,
                    produtos,
                    compradores,
                    fornecedores,
                    familias_produtos,
                    secoes,
                    revenda,
                    status,
                    estoque,
                    cobertura_estoque,
                    estoque_seguranca,
                    ponto_pedido,
                    estoque_maximo,
                    consumo_medio_mensal,
                    desvio_padrao_consumo,
                    tempo_medio_ressuprimento,
                    tempo_ressuprimento,
                    desvio_padrao_ressuprimento,
                    coeficiente_variacao,
                    compra_transito,
                    lote_minimo,
                    lote_compras_bruto,
                    arvore_decisao,
                    nivel_servico,
                    peso_compras,
                    unidade_compra,
                    lote_embalagem,
                    sob_encomenda,
                    lote_compras,
                    preco_compra,
                    custo_unitario,
                    valor_unitario,
					valor_liquido,
                    estoque_bloqueado,
                    perfil_demanda,
                    tempo_medio_apanhe,
                    embalagem,
                    idunidade_medida,
                    ressuprimento_manual,
                    ressuprimento_manual_dias,
                    cod_produto,
                    codigo_barras,
                    fator_conversao,
                    fator_atuacao,
                    projecao_rentabilidade,
                    estoque_avaria,
                    peso,
                    altura,
                    largura,
					litragem,
                    comprimento,
                    data_ultima_requisicao,
                    estoque_reservado,
                    multiplo_compra,
                    unidade_master,
                    tipo_fator_conversao,
                    compra_transito_entregue,
                    detalhamento_tecnico,
                    estoque_minimo,
                    classificacao_rentabilidade,
                    estoque_seguranca_estetico,
                    ponto_pedido_estetico,
                    estoque_maximo_estetico,
                    flag
                ) VALUES (
                    rec_forecast.id_grupo,
                    rec_forecast.filial,
                    rec_forecast.id_produto_combinado,
                    rec_forecast.descricao_produto,
                    rec_forecast.produtos,
                    rec_forecast.compradores,
                    rec_forecast.fornecedores,
                    rec_forecast.familias_produtos,
                    rec_forecast.secoes,
                    rec_forecast.revenda,
                    rec_forecast.status,
                    rec_forecast.estoque,
                    rec_forecast.cobertura_estoque,
                    rec_forecast.estoque_seguranca,
                    rec_forecast.ponto_pedido,
                    rec_forecast.estoque_maximo,
                    rec_forecast.consumo_medio_mensal,
                    rec_forecast.desvio_padrao_consumo,
                    rec_forecast.tempo_medio_ressuprimento,
                    rec_forecast.tempo_ressuprimento,
                    rec_forecast.desvio_padrao_ressuprimento,
                    rec_forecast.coeficiente_variacao,
                    rec_forecast.compra_transito,
                    rec_forecast.lote_minimo,
                    rec_forecast.lote_compras_bruto,
                    rec_forecast.arvore_decisao,
                    rec_forecast.nivel_servico,
                    rec_forecast.peso_compras,
                    rec_forecast.unidade_compra,
                    rec_forecast.lote_embalagem,
                    rec_forecast.sob_encomenda,
                    rec_forecast.lote_compras,
                    rec_forecast.preco_compra,
                    rec_forecast.custo_unitario,
                    rec_forecast.valor_unitario,
					rec_forecast.valor_liquido,
                    rec_forecast.estoque_bloqueado,
                    rec_forecast.perfil_demanda,
                    rec_forecast.tempo_medio_apanhe,
                    rec_forecast.embalagem,
                    rec_forecast.idunidade_medida,
                    rec_forecast.ressuprimento_manual,
                    rec_forecast.ressuprimento_manual_dias,
                    rec_forecast.cod_produto,
                    rec_forecast.codigo_barras,
                    rec_forecast.fator_conversao,
                    rec_forecast.fator_atuacao,
                    rec_forecast.projecao_rentabilidade,
                    rec_forecast.estoque_avaria,
                    rec_forecast.peso,
                    rec_forecast.altura,
                    rec_forecast.largura,
					rec_forecast.litragem,
                    rec_forecast.comprimento,
                    rec_forecast.data_ultima_requisicao,
                    rec_forecast.estoque_reservado,
                    rec_forecast.multiplo_compra,
                    rec_forecast.unidade_master,
                    rec_forecast.tipo_fator_conversao,
                    rec_forecast.compra_transito_entregue,
                    rec_forecast.detalhamento_tecnico,
                    rec_forecast.estoque_minimo,
                    rec_forecast.classificacao_rentabilidade,
                    rec_forecast.estoque_seguranca_estetico,
                    rec_forecast.ponto_pedido_estetico,
                    rec_forecast.estoque_maximo_estetico,
                    NULL
                );
            END IF;
        END LOOP;

        DELETE FROM produtos_combinados_compras_filial WHERE flag = 'D';
    END $$;


ALTER FUNCTION public.processar_produtos_combinados_compras_filial(f_id_produto_combinado character varying) OWNER TO systock;

--
-- TOC entry 786 (class 1255 OID 53910)
-- Name: processar_produtos_combinados_compras_grupo(character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_produtos_combinados_compras_grupo(f_id_produto_combinado character varying DEFAULT NULL::character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
        DECLARE rec_forecast record;
    BEGIN
        IF trim(f_id_produto_combinado) = '' THEN
            f_id_produto_combinado = NULL;
        END IF;


        UPDATE produtos_combinados_compras_grupo SET flag = 'D' WHERE (f_id_produto_combinado = id_produto_combinado OR f_id_produto_combinado IS NULL);

        FOR rec_forecast IN (
            SELECT
                lote.id_grupo,
                lote.id_produto_combinado,
                lote.descricao_produto,
                lote.produtos,
                lote.compradores,
                lote.fornecedores,
                lote.familias_produtos,
                lote.secoes,
                lote.revenda,
                lote.status,
                lote.estoque,
                COALESCE(round(lote.estoque / NULLIF(lote.consumo_medio_mensal, 0::numeric) * 30::numeric, 4), 0::numeric) AS cobertura_estoque,
                lote.estoque_seguranca,
                lote.ponto_pedido,
                lote.estoque_maximo,
                lote.consumo_medio_mensal,
                lote.desvio_padrao_consumo,
                lote.tempo_medio_ressuprimento,
                lote.tempo_ressuprimento,
                lote.desvio_padrao_ressuprimento,
                lote.coeficiente_variacao,
                lote.compra_transito,
                lote.lote_minimo,
                lote.lote_compras_bruto,
                lote.arvore_decisao,
                lote.nivel_servico,
                lote.peso_compras,
                lote.unidade_compra,
                lote.lote_embalagem,
                CASE
                    WHEN lote.flag_sob_encomenda = 'S'::text THEN 1
                    -- WHEN lote.lote_compras_bruto > 0::numeric AND lote.lote_embalagem = 0::numeric THEN 1 -- OCTADESK99905315
                    ELSE 0
                END AS sob_encomenda,
                CASE
                    WHEN lote.lote_embalagem > 0::numeric AND COALESCE(round(lote.estoque / NULLIF(lote.consumo_medio_mensal, 0::numeric), 4), 0::numeric) < lote.tempo_ressuprimento AND lote.compra_transito = 0::numeric THEN gerar_lote_embalagem(lote.estoque_maximo, COALESCE(lote.lote_minimo, 1::numeric))
                    ELSE lote.lote_embalagem
                END AS lote_compras,
                lote.preco_compra,
                lote.custo_unitario,
                lote.valor_unitario,
                lote.estoque_bloqueado,
                CASE
                    WHEN lote.coeficiente_variacao::numeric >= 0::numeric AND lote.coeficiente_variacao::numeric <= 200::numeric THEN 'REPETITIVO'::text
                    WHEN lote.coeficiente_variacao::numeric > 200::numeric AND lote.coeficiente_variacao::numeric <= 600::numeric THEN 'ESTATISTICO'::text
                    ELSE 'OCASIONAL'::text
                END AS perfil_demanda,
                lote.tempo_medio_apanhe,
                lote.embalagem,
                lote.idunidade_medida,
                lote.ressuprimento_manual,
                lote.ressuprimento_manual_dias,
                lote.cod_produto,
                lote.codigo_barras,
                lote.fator_conversao,
                lote.fator_atuacao,
                lote.projecao_rentabilidade,
                lote.estoque_avaria,
                lote.peso,
                lote.altura,
                lote.largura,
                lote.comprimento,
                (
                    SELECT max(r.data_solicitacao) AS max
                    FROM requisicoes r
                    WHERE
                        (r.idproduto::text = ANY (lote.produtos::text[]))
                        AND (r.idfilial IN (SELECT gf.filial FROM grupo_filial gf WHERE gf.id_grupo = lote.id_grupo))
                ) AS data_ultima_requisicao,
                lote.estoque_reservado,
                lote.multiplo_compra::numeric(12,6) AS multiplo_compra,
                lote.unidade_master,
                lote.tipo_fator_conversao,
                lote.compra_transito_entregue,
                lote.detalhamento_tecnico,
                lote.estoque_minimo,
                lote.classificacao_rentabilidade,
                lote.estoque_seguranca_estetico,
                lote.ponto_pedido_estetico,
                lote.ponto_pedido_estetico + lote.consumo_medio_mensal AS estoque_maximo_estetico
                FROM (
                    SELECT
                        a.id_grupo,
                        a.id_produto_combinado,
                        a.descricao_produto,
                        a.produtos,
                        a.compradores,
                        a.fornecedores,
                        a.familias_produtos,
                        a.secoes,
                        a.revenda,
                        a.status,
                        a.estoque,
                        a.estoque_seguranca,
                        a.ponto_pedido,
                        a.estoque_maximo,
                        a.consumo_medio_mensal,
                        a.desvio_padrao_consumo,
                        a.tempo_medio_ressuprimento,
                        a.tempo_ressuprimento,
                        a.desvio_padrao_ressuprimento,
                        a.coeficiente_variacao,
                        a.compra_transito,
                        a.lote_minimo,
                        CASE
                            WHEN a.coeficiente_variacao::numeric >= 0::numeric AND a.compra_transito = 0::numeric AND a.estoque <= a.ponto_pedido AND a.revenda = 'S'::text AND a.status <> 'FL'::text THEN round(a.estoque_maximo + a.consumo_medio_mensal * (a.tempo_ressuprimento + a.desvio_padrao_ressuprimento) - a.estoque, 2)
                            WHEN a.coeficiente_variacao::numeric = 0::numeric AND a.compra_transito = 0::numeric AND a.estoque <= a.ponto_pedido AND a.revenda = 'S'::text AND a.status <> 'FL'::text THEN ceil(a.consumo_medio_mensal / 2::numeric)
                            ELSE 0::numeric
                        END AS lote_compras_bruto,
                        a.arvore_decisao,
                        a.nivel_servico,
                        a.peso_compras,
                        a.unidade_compra,
                        gerar_lote_embalagem(
                        CASE
                            WHEN a.coeficiente_variacao::numeric >= 0::numeric AND a.compra_transito = 0::numeric AND a.estoque <= a.ponto_pedido AND a.revenda = 'S'::text AND a.status <> 'FL'::text THEN round(a.estoque_maximo + a.consumo_medio_mensal * (a.tempo_ressuprimento + a.desvio_padrao_ressuprimento) - a.estoque, 2)
                            WHEN a.coeficiente_variacao::numeric = 0::numeric AND a.compra_transito = 0::numeric AND a.estoque <= a.ponto_pedido AND a.revenda = 'S'::text AND a.status <> 'FL'::text THEN ceil(a.consumo_medio_mensal / 2::numeric)
                            ELSE 0::numeric
                        END, COALESCE(a.lote_minimo, 1::numeric)) AS lote_embalagem,
                        a.preco_compra,
                        a.custo_unitario,
                        a.valor_unitario,
                        a.estoque_bloqueado,
                        a.tempo_medio_apanhe,
                        a.embalagem,
                        a.idunidade_medida,
                        a.ressuprimento_manual,
                        a.ressuprimento_manual_dias,
                        a.cod_produto,
                        a.codigo_barras,
                        a.fator_conversao,
                        a.fator_atuacao,
                        a.projecao_rentabilidade,
                        a.estoque_avaria,
                        a.peso,
                        a.altura,
                        a.largura,
                        a.comprimento,
                        a.flag_sob_encomenda,
                        a.estoque_reservado,
                        a.multiplo_compra,
                        a.unidade_master,
                        a.tipo_fator_conversao,
                        a.compra_transito_entregue,
                        a.detalhamento_tecnico,
                        a.estoque_minimo,
                        a.classificacao_rentabilidade,
                        a.estoque_seguranca_estetico,
                        a.estoque_seguranca_estetico + a.consumo_medio_mensal / 30::numeric * a.tempo_medio_ressuprimento AS ponto_pedido_estetico
                    FROM (
                        SELECT
                            v.id_grupo,
                            v.id_produto_combinado,
                            v.descricao_produto,
                            v.produtos,
                            v.compradores,
                            v.fornecedores,
                            v.familias_produtos,
                            v.secoes,
                            v.revenda,
                            v.status,
                            v.unidade_compra,
                            v.estoque,
                            CASE
                                WHEN v.qtde_dias_cobertura_eseg > 0::numeric THEN v.consumo_medio_mensal / 30::numeric * v.qtde_dias_cobertura_eseg
                                ELSE v.estoque_seguranca
                            END AS estoque_seguranca,
                            CASE
                                WHEN v.qtde_dias_cobertura_eseg > 0::numeric THEN round(v.consumo_medio_mensal / 30::numeric * v.qtde_dias_cobertura_eseg + v.consumo_medio_mensal * (v.tempo_ressuprimento + v.desvio_padrao_ressuprimento), 2)
                                ELSE v.ponto_pedido
                            END AS ponto_pedido,
                            CASE
                                WHEN v.qtde_dias_cobertura_emax > 0::numeric THEN v.consumo_medio_mensal / 30::numeric * v.qtde_dias_cobertura_emax
                                ELSE v.estoque_maximo
                            END AS estoque_maximo,
                            v.consumo_medio_mensal,
                            v.desvio_padrao_consumo,
                            v.tempo_medio_ressuprimento,
                            v.tempo_ressuprimento,
                            v.desvio_padrao_ressuprimento,
                            v.coeficiente_variacao,
                            v.compra_transito,
                            v.lote_minimo,
                            v.arvore_decisao,
                            v.nivel_servico,
                            v.peso_compras,
                            v.preco_compra,
                            v.custo_unitario,
                            v.valor_unitario,
                            v.estoque_bloqueado,
                            v.tempo_medio_apanhe,
                            v.embalagem,
                            v.idunidade_medida,
                            v.ressuprimento_manual,
                            v.ressuprimento_manual_dias,
                            v.cod_produto,
                            v.codigo_barras,
                            v.fator_conversao,
                            v.fator_atuacao,
                            v.projecao_rentabilidade,
                            v.estoque_avaria,
                            v.peso,
                            v.altura,
                            v.largura,
                            v.comprimento,
                            v.flag_sob_encomenda,
                            v.estoque_reservado,
                            v.multiplo_compra,
                            v.unidade_master,
                            v.tipo_fator_conversao,
                            v.compra_transito_entregue,
                            v.detalhamento_tecnico,
                            v.estoque_minimo,
                            v.classificacao_rentabilidade,
                            v.estoque_seguranca_estetico
                        FROM (
                            WITH prismas AS (
                                SELECT
                                    gf.id_grupo,
                                    spci_1.id_produto_combinado,
                                    (
                                        (
                                            min(pf.classificacao_financeira::text) || max(pf.classificacao_criticidade::text)
                                        ) || min(pf.classificacao_comprabilidade)
                                    ) || min(pf.classificacao_popularidade::text) AS arvore_decisao
                                FROM produtos_filial pf
                                    JOIN grupo_filial gf ON gf.filial = pf.filial
                                    JOIN sys_produtos_combinados_itens spci_1 ON spci_1.idproduto::text = pf.idproduto::text
                                WHERE pf.processar_analise::text = 'S'::text
                                GROUP BY gf.id_grupo, spci_1.id_produto_combinado
                            ),
                            compras_pendentes_com_entrega AS (
                                SELECT
                                    gf.id_grupo,
                                    spci_1.id_produto_combinado,
                                    sum(r.qtde_entregue / spci_1.fator_conversao::double precision) AS compra_transito_entregue
                                FROM requisicoes r
                                    JOIN grupo_filial gf ON gf.filial = r.idfilial
                                    JOIN sys_produtos_combinados_itens spci_1 ON spci_1.idproduto::text = r.idproduto::text
                                WHERE r.qtde_pendente > 0::double precision AND r.qtde_entregue > 0::double precision
                                GROUP BY gf.id_grupo, spci_1.id_produto_combinado
                            )
                            SELECT
                                g.id_grupo,
                                spci.id_produto_combinado,
                                spc.descricao AS descricao_produto,
                                array_agg(DISTINCT p.idproduto) AS produtos,
                                array_agg(DISTINCT p.idcomprador) AS compradores,
                                array_agg(DISTINCT p.idfornecedor) AS fornecedores,
                                array_agg(DISTINCT p.idfamilia_produto) AS familias_produtos,
                                array_agg(DISTINCT p.idsecao) AS secoes,
                                max(p.revenda::text) AS revenda,
                                min(p.status::text) AS status,
                                max(p.unidade_compra::text) AS unidade_compra,
                                (sum((p.estoque - COALESCE(p.estoque_similar, 0)) / spci.fator_conversao) + get_estoque_similar_produto_combinado(g.id_grupo::int, 0, spci.id_produto_combinado)) AS estoque,
                                sum(p.estoque_seguranca / spci.fator_conversao) AS estoque_seguranca,
                                sum(p.ponto_pedido / spci.fator_conversao) AS ponto_pedido,
                                sum(p.estoque_maximo / spci.fator_conversao) AS estoque_maximo,
                                (sum(p.consumo_medio_mensal / spci.fator_conversao) + (get_cmm_heranca_produto_combinado(g.id_grupo::int, spci.id_produto_combinado) * avg(p.fator_atuacao))) AS consumo_medio_mensal,
                                sum(p.desvio_padrao_consumo / spci.fator_conversao) AS desvio_padrao_consumo,
                                avg(p.tempo_medio_ressuprimento) AS tempo_medio_ressuprimento,
                                avg(p.tempo_ressuprimento) AS tempo_ressuprimento,
                                avg(p.desvio_padrao_ressuprimento) AS desvio_padrao_ressuprimento,
                                COALESCE(sum(p.desvio_padrao_consumo / spci.fator_conversao) / NULLIF((sum(p.consumo_medio_mensal / spci.fator_conversao) + (get_cmm_heranca_produto_combinado(g.id_grupo::int, spci.id_produto_combinado) * avg(p.fator_atuacao))), 0::numeric) * 100::numeric, 0::numeric)::text AS coeficiente_variacao,
                                sum(getcompra_transito_filial(p.filial::numeric, p.idproduto) / spci.fator_conversao) AS compra_transito,
                                trunc(max(p.lote_minimo / spci.fator_conversao), 4) AS lote_minimo,
                                COALESCE(pm.arvore_decisao, 'CX2R'::text) AS arvore_decisao,
                                getnivelservico(COALESCE(pm.arvore_decisao::character varying, 'CX2R'::character varying)) AS nivel_servico,
                                getpesocompras(COALESCE(pm.arvore_decisao::character varying, 'CX2R'::character varying), "substring"(COALESCE(pm.arvore_decisao::character varying, 'CX2R'::character varying)::text, 3, 1)::numeric) AS peso_compras,
                                COALESCE(avg(NULLIF(p.preco_compra, 0::numeric) * spci.fator_conversao), 0::numeric) AS preco_compra,
                                COALESCE(avg(NULLIF(p.custo_unitario, 0::numeric) * spci.fator_conversao), 0::numeric) AS custo_unitario,
                                COALESCE(avg(NULLIF(p.valor_unitario, 0::numeric) * spci.fator_conversao), 0::numeric) AS valor_unitario,
                                sum(p.estoque_bloqueado / spci.fator_conversao) AS estoque_bloqueado,
                                sum(p.tempo_medio_apanhe) AS tempo_medio_apanhe,
                                max(p.embalagem::text) AS embalagem,
                                max(p.idunidade_medida::text) AS idunidade_medida,
                                max(p.ressuprimento_manual::text)::character varying(1) AS ressuprimento_manual,
                                max(COALESCE(p.ressuprimento_manual_dias, 0::numeric)) AS ressuprimento_manual_dias,
                                ''::text AS cod_produto,
                                max(p.codigo_barras::text)::character varying(25) AS codigo_barras,
                                1 AS fator_conversao,
                                avg(p.fator_atuacao) AS fator_atuacao,
                                sum(p.projecao_rentabilidade) AS projecao_rentabilidade,
                                sum(p.estoque_avaria / spci.fator_conversao) AS estoque_avaria,
                                max(p.peso / spci.fator_conversao) AS peso,
                                max(p.altura / spci.fator_conversao) AS altura,
                                max(p.largura / spci.fator_conversao) AS largura,
                                max(p.comprimento / spci.fator_conversao) AS comprimento,
                                max(p.flag_sob_encomenda::text) AS flag_sob_encomenda,
                                sum(COALESCE(p.estoque_reservado, 0::numeric) / spci.fator_conversao) AS estoque_reservado,
                                max(p.multiplo_compra) AS multiplo_compra,
                                max(p.unidade_master::text) AS unidade_master,
                                'D'::text AS tipo_fator_conversao,
                                COALESCE(cpce.compra_transito_entregue, 0::double precision) AS compra_transito_entregue,
                                max(p.detalhamento_tecnico) AS detalhamento_tecnico,
                                sum(p.estoque_minimo / spci.fator_conversao) AS estoque_minimo,
                                min(p.classificacao_rentabilidade::text) AS classificacao_rentabilidade,
                                sum(p.estoque_minimo / spci.fator_conversao) AS estoque_seguranca_estetico,
                                COALESCE(
                                    (
                                        SELECT NULLIF(tccp.tempo_cobertura_esseg, 0) AS x
                                        FROM tempo_cobertura_compras_produtos tccp
                                        WHERE tccp.idproduto::text = spc.id::TEXT
                                    ), (
                                        SELECT NULLIF(tcc.tempo_cobertura_esseg, 0) AS x
                                        FROM tempo_cobertura_compras tcc
                                        WHERE
                                            tcc.id_grupo = g.id_grupo
                                            AND tcc.pqr::text = min("substring"(p.arvore_decisao::text, 4, 1))
                                            AND tcc.xyz::text = min("substring"(p.arvore_decisao::text, 2, 1))
                                        LIMIT 1
                                    ), 0
                                )::numeric AS qtde_dias_cobertura_eseg,
                                COALESCE(
                                    (
                                        SELECT NULLIF(tccp.tempo_cobertura, 0) AS x
                                        FROM tempo_cobertura_compras_produtos tccp
                                        WHERE tccp.idproduto::text = spc.id::TEXT
                                    ), (
                                        SELECT NULLIF(tcc.tempo_cobertura, 0) AS x
                                        FROM tempo_cobertura_compras tcc
                                        WHERE
                                            tcc.id_grupo = g.id_grupo
                                            AND tcc.pqr::text = min("substring"(p.arvore_decisao::text, 4, 1))
                                            AND tcc.xyz::text = min("substring"(p.arvore_decisao::text, 2, 1))
                                        LIMIT 1
                                    ), 0::bigint
                               )::numeric AS qtde_dias_cobertura_emax
                            FROM produtos_filial p
                                JOIN grupo_filial g ON p.filial = g.filial
                                JOIN sys_produtos_combinados_itens spci ON spci.idproduto::text = p.idproduto::text
                                JOIN sys_produtos_combinados spc ON spc.id::text = spci.id_produto_combinado::text
                                LEFT JOIN prismas pm ON pm.id_grupo = g.id_grupo AND pm.id_produto_combinado::text = spci.id_produto_combinado::text
                                LEFT JOIN compras_pendentes_com_entrega cpce ON cpce.id_grupo = g.id_grupo AND cpce.id_produto_combinado::text = spci.id_produto_combinado::text
                            WHERE
                                spc.deleted_at IS NULL
                                AND p.revenda::text = 'S'::text
                                AND p.processar_analise::text = 'S'::TEXT
                                AND (f_id_produto_combinado = spc.id OR f_id_produto_combinado IS NULL)
                            GROUP BY g.id_grupo, spc.id, spci.id_produto_combinado, pm.arvore_decisao, cpce.compra_transito_entregue
                        ) v
                    ) a
                ) lote
        )
        LOOP
            -- UPDATE
            UPDATE produtos_combinados_compras_grupo
            SET
                id_grupo = rec_forecast.id_grupo,
                id_produto_combinado = rec_forecast.id_produto_combinado,
                descricao_produto = rec_forecast.descricao_produto,
                produtos = rec_forecast.produtos,
                compradores = rec_forecast.compradores,
                fornecedores = rec_forecast.fornecedores,
                familias_produtos = rec_forecast.familias_produtos,
                secoes = rec_forecast.secoes,
                revenda = rec_forecast.revenda,
                status = rec_forecast.status,
                estoque = rec_forecast.estoque,
                cobertura_estoque = rec_forecast.cobertura_estoque,
                estoque_seguranca = rec_forecast.estoque_seguranca,
                ponto_pedido = rec_forecast.ponto_pedido,
                estoque_maximo = rec_forecast.estoque_maximo,
                consumo_medio_mensal = rec_forecast.consumo_medio_mensal,
                desvio_padrao_consumo = rec_forecast.desvio_padrao_consumo,
                tempo_medio_ressuprimento = rec_forecast.tempo_medio_ressuprimento,
                tempo_ressuprimento = rec_forecast.tempo_ressuprimento,
                desvio_padrao_ressuprimento = rec_forecast.desvio_padrao_ressuprimento,
                coeficiente_variacao = rec_forecast.coeficiente_variacao,
                compra_transito = rec_forecast.compra_transito,
                lote_minimo = rec_forecast.lote_minimo,
                lote_compras_bruto = rec_forecast.lote_compras_bruto,
                arvore_decisao = rec_forecast.arvore_decisao,
                nivel_servico = rec_forecast.nivel_servico,
                peso_compras = rec_forecast.peso_compras,
                unidade_compra = rec_forecast.unidade_compra,
                lote_embalagem = rec_forecast.lote_embalagem,
                sob_encomenda = rec_forecast.sob_encomenda,
                lote_compras = rec_forecast.lote_compras,
                preco_compra = rec_forecast.preco_compra,
                custo_unitario = rec_forecast.custo_unitario,
                valor_unitario = rec_forecast.valor_unitario,
                estoque_bloqueado = rec_forecast.estoque_bloqueado,
                perfil_demanda = rec_forecast.perfil_demanda,
                tempo_medio_apanhe = rec_forecast.tempo_medio_apanhe,
                embalagem = rec_forecast.embalagem,
                idunidade_medida = rec_forecast.idunidade_medida,
                ressuprimento_manual = rec_forecast.ressuprimento_manual,
                ressuprimento_manual_dias = rec_forecast.ressuprimento_manual_dias,
                cod_produto = rec_forecast.cod_produto,
                codigo_barras = rec_forecast.codigo_barras,
                fator_conversao = rec_forecast.fator_conversao,
                fator_atuacao = rec_forecast.fator_atuacao,
                projecao_rentabilidade = rec_forecast.projecao_rentabilidade,
                estoque_avaria = rec_forecast.estoque_avaria,
                peso = rec_forecast.peso,
                altura = rec_forecast.altura,
                largura = rec_forecast.largura,
                comprimento = rec_forecast.comprimento,
                data_ultima_requisicao = rec_forecast.data_ultima_requisicao,
                estoque_reservado = rec_forecast.estoque_reservado,
                multiplo_compra = rec_forecast.multiplo_compra,
                unidade_master = rec_forecast.unidade_master,
                tipo_fator_conversao = rec_forecast.tipo_fator_conversao,
                compra_transito_entregue = rec_forecast.compra_transito_entregue,
                detalhamento_tecnico = rec_forecast.detalhamento_tecnico,
                estoque_minimo = rec_forecast.estoque_minimo,
                classificacao_rentabilidade = rec_forecast.classificacao_rentabilidade,
                estoque_seguranca_estetico = rec_forecast.estoque_seguranca_estetico,
                ponto_pedido_estetico = rec_forecast.ponto_pedido_estetico,
                estoque_maximo_estetico = rec_forecast.estoque_maximo_estetico,
                flag = NULL
            WHERE
                id_grupo = rec_forecast.id_grupo
                AND id_produto_combinado = rec_forecast.id_produto_combinado;

            IF NOT FOUND THEN
                INSERT INTO produtos_combinados_compras_grupo (
                    id_grupo,
                    id_produto_combinado,
                    descricao_produto,
                    produtos,
                    compradores,
                    fornecedores,
                    familias_produtos,
                    secoes,
                    revenda,
                    status,
                    estoque,
                    cobertura_estoque,
                    estoque_seguranca,
                    ponto_pedido,
                    estoque_maximo,
                    consumo_medio_mensal,
                    desvio_padrao_consumo,
                    tempo_medio_ressuprimento,
                    tempo_ressuprimento,
                    desvio_padrao_ressuprimento,
                    coeficiente_variacao,
                    compra_transito,
                    lote_minimo,
                    lote_compras_bruto,
                    arvore_decisao,
                    nivel_servico,
                    peso_compras,
                    unidade_compra,
                    lote_embalagem,
                    sob_encomenda,
                    lote_compras,
                    preco_compra,
                    custo_unitario,
                    valor_unitario,
                    estoque_bloqueado,
                    perfil_demanda,
                    tempo_medio_apanhe,
                    embalagem,
                    idunidade_medida,
                    ressuprimento_manual,
                    ressuprimento_manual_dias,
                    cod_produto,
                    codigo_barras,
                    fator_conversao,
                    fator_atuacao,
                    projecao_rentabilidade,
                    estoque_avaria,
                    peso,
                    altura,
                    largura,
                    comprimento,
                    data_ultima_requisicao,
                    estoque_reservado,
                    multiplo_compra,
                    unidade_master,
                    tipo_fator_conversao,
                    compra_transito_entregue,
                    detalhamento_tecnico,
                    estoque_minimo,
                    classificacao_rentabilidade,
                    estoque_seguranca_estetico,
                    ponto_pedido_estetico,
                    estoque_maximo_estetico,
                    flag
                ) VALUES (
                    rec_forecast.id_grupo,
                    rec_forecast.id_produto_combinado,
                    rec_forecast.descricao_produto,
                    rec_forecast.produtos,
                    rec_forecast.compradores,
                    rec_forecast.fornecedores,
                    rec_forecast.familias_produtos,
                    rec_forecast.secoes,
                    rec_forecast.revenda,
                    rec_forecast.status,
                    rec_forecast.estoque,
                    rec_forecast.cobertura_estoque,
                    rec_forecast.estoque_seguranca,
                    rec_forecast.ponto_pedido,
                    rec_forecast.estoque_maximo,
                    rec_forecast.consumo_medio_mensal,
                    rec_forecast.desvio_padrao_consumo,
                    rec_forecast.tempo_medio_ressuprimento,
                    rec_forecast.tempo_ressuprimento,
                    rec_forecast.desvio_padrao_ressuprimento,
                    rec_forecast.coeficiente_variacao,
                    rec_forecast.compra_transito,
                    rec_forecast.lote_minimo,
                    rec_forecast.lote_compras_bruto,
                    rec_forecast.arvore_decisao,
                    rec_forecast.nivel_servico,
                    rec_forecast.peso_compras,
                    rec_forecast.unidade_compra,
                    rec_forecast.lote_embalagem,
                    rec_forecast.sob_encomenda,
                    rec_forecast.lote_compras,
                    rec_forecast.preco_compra,
                    rec_forecast.custo_unitario,
                    rec_forecast.valor_unitario,
                    rec_forecast.estoque_bloqueado,
                    rec_forecast.perfil_demanda,
                    rec_forecast.tempo_medio_apanhe,
                    rec_forecast.embalagem,
                    rec_forecast.idunidade_medida,
                    rec_forecast.ressuprimento_manual,
                    rec_forecast.ressuprimento_manual_dias,
                    rec_forecast.cod_produto,
                    rec_forecast.codigo_barras,
                    rec_forecast.fator_conversao,
                    rec_forecast.fator_atuacao,
                    rec_forecast.projecao_rentabilidade,
                    rec_forecast.estoque_avaria,
                    rec_forecast.peso,
                    rec_forecast.altura,
                    rec_forecast.largura,
                    rec_forecast.comprimento,
                    rec_forecast.data_ultima_requisicao,
                    rec_forecast.estoque_reservado,
                    rec_forecast.multiplo_compra,
                    rec_forecast.unidade_master,
                    rec_forecast.tipo_fator_conversao,
                    rec_forecast.compra_transito_entregue,
                    rec_forecast.detalhamento_tecnico,
                    rec_forecast.estoque_minimo,
                    rec_forecast.classificacao_rentabilidade,
                    rec_forecast.estoque_seguranca_estetico,
                    rec_forecast.ponto_pedido_estetico,
                    rec_forecast.estoque_maximo_estetico,
                    NULL
                );
            END IF;
        END LOOP;

        DELETE FROM produtos_combinados_compras_grupo WHERE flag = 'D';
    END $$;


ALTER FUNCTION public.processar_produtos_combinados_compras_grupo(f_id_produto_combinado character varying) OWNER TO systock;

--
-- TOC entry 787 (class 1255 OID 53912)
-- Name: processar_produtos_combinados_forecast_filial(character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_produtos_combinados_forecast_filial(f_id_produto_combinado character varying DEFAULT NULL::character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
        DECLARE rec_forecast record;
    BEGIN
        IF trim(f_id_produto_combinado) = '' THEN
            f_id_produto_combinado = NULL;
        END IF;

        UPDATE produtos_combinados_forecast_filial SET flag = 'D' WHERE (f_id_produto_combinado = id_produto_combinado OR f_id_produto_combinado IS NULL);

        FOR rec_forecast IN (
            SELECT
                b.id_grupo,
                b.filial,
                b.id_produto_combinado,
                b.estoque_futuro::double precision AS estoque_futuro,
                gerar_lote_embalagem(b.lote_compras, b.lote_minimo) AS lote_compras,
                b.lote_compras AS lote_compras_bruto
            FROM (
                SELECT
                    a.id_grupo,
                    a.filial,
                    a.id_produto_combinado,
                    a.estoque_futuro,
                    round((a.estoque_maximo::double precision + (a.consumo_medio_mensal * (a.tempo_ressuprimento + a.desvio_padrao_ressuprimento))::double precision - a.estoque::double precision)::numeric, 2) AS lote_compras,
                    a.lote_minimo
                FROM (
                    SELECT DISTINCT p.id_grupo,
                        p.filial,
                        p.id_produto_combinado,
                        p.ponto_pedido,
                        sum(
                            get_forecast_filial(p.filial::numeric, spci.idproduto, COALESCE(( SELECT avg(f.tempo_forecast) AS avg
                                FROM fornecedor f
                                WHERE f.id = ANY (p.fornecedores)), 15::numeric)) / spci.fator_conversao
                        ) AS estoque_futuro,
                        p.estoque_maximo,
                        p.estoque,
                        p.tempo_ressuprimento,
                        p.desvio_padrao_ressuprimento,
                        p.consumo_medio_mensal,
                        p.lote_minimo,
                        1 AS fator_conversao
                    FROM produtos_combinados_compras_filial p
                    JOIN sys_produtos_combinados_itens spci ON spci.id_produto_combinado::text = p.id_produto_combinado::text
                    WHERE
                        p.lote_compras = 0::numeric
                        AND p.consumo_medio_mensal > 0::numeric
                        AND p.compra_transito = 0::numeric
                        AND p.revenda = 'S'::text
                        AND p.status <> 'FL'::TEXT
                        AND (f_id_produto_combinado = p.id_produto_combinado OR f_id_produto_combinado IS NULL)
                    GROUP BY p.id_grupo, p.filial, p.id_produto_combinado, p.ponto_pedido, p.estoque_maximo, p.estoque, p.tempo_ressuprimento, p.desvio_padrao_ressuprimento, p.consumo_medio_mensal, p.lote_minimo
                ) a
                WHERE a.estoque_futuro::double precision <= a.ponto_pedido::double PRECISION
            ) b
            WHERE gerar_lote_embalagem(b.lote_compras, b.lote_minimo) > 0::numeric
        )
        LOOP
            -- UPDATE
            UPDATE produtos_combinados_forecast_filial
            SET
                id_grupo = rec_forecast.id_grupo,
                filial = rec_forecast.filial,
                id_produto_combinado = rec_forecast.id_produto_combinado,
                estoque_futuro = rec_forecast.estoque_futuro,
                lote_compras = rec_forecast.lote_compras,
                lote_compras_bruto = rec_forecast.lote_compras_bruto,
                flag = NULL
            WHERE
                id_grupo = rec_forecast.id_grupo
                AND filial = rec_forecast.filial
                AND id_produto_combinado = rec_forecast.id_produto_combinado;

            -- INSERT
            IF NOT FOUND THEN
                INSERT INTO produtos_combinados_forecast_filial (
                    id_grupo,
                    filial,
                    id_produto_combinado,
                    estoque_futuro,
                    lote_compras,
                    lote_compras_bruto,
                    flag
                ) VALUES (
                    rec_forecast.id_grupo,
                    rec_forecast.filial,
                    rec_forecast.id_produto_combinado,
                    rec_forecast.estoque_futuro,
                    rec_forecast.lote_compras,
                    rec_forecast.lote_compras_bruto,
                    NULL
                );
            END IF;
        END LOOP;

        DELETE FROM produtos_combinados_forecast_filial WHERE flag = 'D';
    END $$;


ALTER FUNCTION public.processar_produtos_combinados_forecast_filial(f_id_produto_combinado character varying) OWNER TO systock;

--
-- TOC entry 788 (class 1255 OID 53913)
-- Name: processar_produtos_combinados_forecast_grupo(character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_produtos_combinados_forecast_grupo(f_id_produto_combinado character varying DEFAULT NULL::character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
        DECLARE rec_forecast record;
    BEGIN
        IF trim(f_id_produto_combinado) = '' THEN
            f_id_produto_combinado = NULL;
        END IF;

        UPDATE produtos_combinados_forecast_grupo SET flag = 'D' WHERE (f_id_produto_combinado = id_produto_combinado OR f_id_produto_combinado IS NULL);

        FOR rec_forecast IN (
            SELECT a.id_grupo,
                a.id_produto_combinado,
                a.estoque_futuro::double precision AS estoque_futuro,
                gerar_lote_embalagem(a.lote_compras, a.lote_minimo) AS lote_compras,
                a.lote_compras AS lote_compras_bruto
            FROM (
                SELECT a_1.id_grupo,
                    a_1.id_produto_combinado,
                    a_1.estoque_futuro,
                    round((a_1.estoque_maximo::double precision + (a_1.consumo_medio_mensal * (a_1.tempo_ressuprimento + a_1.desvio_padrao_ressuprimento))::double precision - a_1.estoque::double precision)::numeric, 2) AS lote_compras,
                    a_1.lote_minimo
                FROM (
                    SELECT DISTINCT p.id_grupo,
                        p.id_produto_combinado,
                        p.ponto_pedido,
                        sum(
                            get_forecast_grupo(p.id_grupo::numeric, spci.idproduto, COALESCE((SELECT avg(f.tempo_forecast) AS avg FROM fornecedor f WHERE f.id = ANY (p.fornecedores)), 15::numeric)
                        ) / spci.fator_conversao) AS estoque_futuro,
                        p.estoque_maximo,
                        p.estoque,
                        p.tempo_ressuprimento,
                        p.desvio_padrao_ressuprimento,
                        p.consumo_medio_mensal,
                        p.lote_minimo,
                        p.fator_conversao
                    FROM produtos_combinados_compras_grupo p
                        JOIN sys_produtos_combinados_itens spci ON spci.id_produto_combinado::text = p.id_produto_combinado::text
                    WHERE
                        p.lote_compras = 0::numeric
                        AND p.consumo_medio_mensal > 0::numeric
                        AND p.compra_transito = 0::numeric
                        AND p.revenda = 'S'::text
                        AND p.status <> 'FL'::TEXT
                        AND (f_id_produto_combinado = p.id_produto_combinado OR f_id_produto_combinado IS NULL)
                    GROUP BY p.id_grupo, p.id_produto_combinado, p.ponto_pedido, p.estoque_maximo, p.estoque, p.tempo_ressuprimento, p.desvio_padrao_ressuprimento, p.consumo_medio_mensal, p.lote_minimo, p.fator_conversao
                ) a_1
                WHERE a_1.estoque_futuro::double precision <= a_1.ponto_pedido::double PRECISION
            ) a
            WHERE gerar_lote_embalagem(a.lote_compras, a.lote_minimo) > 0::numeric
        )
        LOOP
            -- UPDATE
            UPDATE produtos_combinados_forecast_grupo
            SET
                id_grupo = rec_forecast.id_grupo,
                id_produto_combinado = rec_forecast.id_produto_combinado,
                estoque_futuro = rec_forecast.estoque_futuro,
                lote_compras = rec_forecast.lote_compras,
                lote_compras_bruto = rec_forecast.lote_compras_bruto,
                flag = NULL
            WHERE
                id_grupo = rec_forecast.id_grupo
                AND id_produto_combinado = rec_forecast.id_produto_combinado;

            -- INSERT
            IF NOT FOUND THEN
                INSERT INTO produtos_combinados_forecast_grupo (
                    id_grupo,
                    id_produto_combinado,
                    estoque_futuro,
                    lote_compras,
                    lote_compras_bruto,
                    flag
                ) VALUES (
                    rec_forecast.id_grupo,
                    rec_forecast.id_produto_combinado,
                    rec_forecast.estoque_futuro,
                    rec_forecast.lote_compras,
                    rec_forecast.lote_compras_bruto,
                    NULL
                );
            END IF;
        END LOOP;

        DELETE FROM produtos_combinados_forecast_grupo WHERE flag = 'D';
    END $$;


ALTER FUNCTION public.processar_produtos_combinados_forecast_grupo(f_id_produto_combinado character varying) OWNER TO systock;

--
-- TOC entry 789 (class 1255 OID 53914)
-- Name: processar_produtos_combinados_transito_filial(character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_produtos_combinados_transito_filial(f_id_produto_combinado character varying DEFAULT NULL::character varying) RETURNS void
    LANGUAGE plpgsql PARALLEL SAFE
    AS $$
    declare
    rec_transito record;
    qtde_dias_delay int;
    BEGIN

    IF trim(f_id_produto_combinado) = '' THEN
        f_id_produto_combinado = NULL;
    END IF;

    qtde_dias_delay = 2;

    update produtos_combinados_transito_filial set flag = 'D' WHERE (f_id_produto_combinado = id_produto_combinado OR f_id_produto_combinado IS NULL);

    for rec_transito in(
         SELECT
            b.id_grupo,
            b.filial,
            b.id_produto_combinado,
            b.compra_transito * b.fator_conversao AS compra_transito,
            b.consumo_transito * b.fator_conversao AS consumo_transito,
            b.saldo_futuro * b.fator_conversao AS saldo_futuro,
            b.status,
            CASE
                WHEN b.status = 'PREVISÃO FUTURA EM EXCESSO'::text AND abs(b.lote_compras) > b.compra_transito::double precision THEN (b.compra_transito * b.fator_conversao * '-1'::integer::numeric)::double precision
                ELSE gerar_lote_embalagem((b.lote_compras * b.fator_conversao::double precision)::numeric, b.lote_minimo::numeric * b.fator_conversao)::double precision
            END AS lote_compras,
            b.data_ultima_requisicao,
            'now'::text::date - b.data_ultima_requisicao AS tempo_pedido,
            CASE
                WHEN ('now'::text::date - b.data_ultima_requisicao - qtde_dias_delay) < 0 THEN NULL::integer
                ELSE 'now'::text::date - b.data_ultima_requisicao - qtde_dias_delay
            END AS gatilho_transito
        FROM (
            SELECT
                a.id_grupo,
                a.filial,
                a.id_produto_combinado,
                a.compra_transito,
                a.consumo_transito,
                a.saldo_futuro,
                a.fator_conversao,
                a.lote_minimo,
                a.data_ultima_requisicao,
                CASE
                    WHEN a.status_compra::numeric = 0::numeric AND ('now'::text::date - a.data_ultima_requisicao) > qtde_dias_delay AND a.saldo_futuro::double precision > a.estoque_maximo THEN 'PREVISÃO FUTURA EM EXCESSO'::text
                    WHEN a.status_compra::numeric = 0::numeric AND ('now'::text::date - a.data_ultima_requisicao) > qtde_dias_delay AND a.saldo_futuro::double precision > a.ponto_pedido AND a.saldo_futuro::double precision <= a.estoque_maximo AND (a.saldo_futuro::double precision - a.consumo_medio_mensal * 0.5::double precision) > a.ponto_pedido THEN 'PREVISÃO FUTURA ADEQUADA'::text
                    WHEN a.status_compra::numeric = 0::numeric AND ('now'::text::date - a.data_ultima_requisicao) > qtde_dias_delay AND a.saldo_futuro::double precision > a.ponto_pedido AND a.saldo_futuro::double precision <= a.estoque_maximo AND (a.saldo_futuro::double precision - a.consumo_medio_mensal * 0.5::double precision) <= a.ponto_pedido THEN 'PREVISÃO COM SUTIL EXPOSIÇÃO A RUPTURA'::text
                    WHEN a.status_compra::numeric = 0::numeric AND ('now'::text::date - a.data_ultima_requisicao) > qtde_dias_delay AND a.saldo_futuro::double precision <= a.ponto_pedido THEN 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA'::text
                    WHEN a.status_compra::numeric = 0::numeric AND ('now'::text::date - a.data_ultima_requisicao) < qtde_dias_delay THEN 'PRODUTO EM TRANSITO'::text
                    ELSE 'PRIMEIRA COMPRA'::text
                END AS status,
                CASE
                    WHEN a.status_compra::numeric = 0::numeric AND ('now'::text::date - a.data_ultima_requisicao) > qtde_dias_delay AND a.saldo_futuro::double precision > a.estoque_maximo THEN a.estoque_maximo - a.saldo_futuro::double precision
                    WHEN a.status_compra::numeric = 0::numeric AND ('now'::text::date - a.data_ultima_requisicao) > qtde_dias_delay AND a.saldo_futuro::double precision > a.ponto_pedido AND a.saldo_futuro::double precision <= a.estoque_maximo AND (a.saldo_futuro::double precision - a.consumo_medio_mensal * 0.5::double precision) > a.ponto_pedido THEN 0::double precision
                    WHEN a.status_compra::numeric = 0::numeric AND ('now'::text::date - a.data_ultima_requisicao) > qtde_dias_delay AND a.saldo_futuro::double precision > a.ponto_pedido AND a.saldo_futuro::double precision <= a.estoque_maximo AND (a.saldo_futuro::double precision - a.consumo_medio_mensal * 0.5::double precision) <= a.ponto_pedido THEN round((a.estoque_maximo - a.saldo_futuro::double precision)::numeric, 2)::double precision
                    WHEN a.status_compra::numeric = 0::numeric AND ('now'::text::date - a.data_ultima_requisicao) > qtde_dias_delay AND a.saldo_futuro::double precision <= a.ponto_pedido THEN round((a.estoque_maximo - a.saldo_futuro::double precision)::numeric, 2)::double precision
                    ELSE 0::double precision
                END AS lote_compras
            FROM (
                SELECT
                    p.id_grupo,
                    p.filial,
                    p.id_produto_combinado,
                    p.compra_transito,
                    sum(getconsumo_transito_filial(p.filial::numeric, spci.idproduto) / spci.fator_conversao) AS consumo_transito,
                    sum(getsaldohorizontefuturo_projetado_filial(p.filial::numeric, spci.idproduto, p.id_grupo::numeric) / spci.fator_conversao) AS saldo_futuro,
                    sum(amplitude_transito_atual_filial(p.filial::numeric, spci.idproduto)) AS amplitude_atual,
                    COALESCE(p.estoque_maximo::double precision, 0::double precision) AS estoque_maximo,
                    COALESCE(p.ponto_pedido::double precision, 0::double precision) AS ponto_pedido,
                    CASE
                        WHEN p.perfil_demanda::text = 'OCASIONAL'::text THEN p.consumo_medio_mensal::double precision / 2::double precision
                        ELSE p.consumo_medio_mensal::double precision
                    END AS consumo_medio_mensal,
                    (
                        SELECT CASE WHEN count(*) > 0 THEN 0 ELSE 1 END
                        FROM entrada_mercadorias
                        WHERE entrada_mercadorias.data_entrada <= 'now'::text::date AND entrada_mercadorias.idproduto::text = ANY (p.produtos) AND entrada_mercadorias.qtde > 0::double PRECISION
                    ) AS status_compra,
                    p.fator_conversao,
                    COALESCE(p.lote_minimo::double precision, 1::double precision) AS lote_minimo,
                    p.data_ultima_requisicao,
                    p.arvore_decisao
                FROM produtos_combinados_compras_filial p
                    INNER JOIN sys_produtos_combinados_itens spci ON spci.id_produto_combinado = p.id_produto_combinado
                WHERE
                    p.compra_transito > 0
                    AND (f_id_produto_combinado = spci.id_produto_combinado OR f_id_produto_combinado IS NULL)
                GROUP BY
                    p.id_grupo,
                    p.filial,
                    p.id_produto_combinado,
                    p.compra_transito,
                    p.estoque_maximo,
                    p.ponto_pedido,
                    p.perfil_demanda,
                    p.consumo_medio_mensal,
                    p.produtos,
                    p.fator_conversao,
                    p.lote_minimo,
                    p.data_ultima_requisicao,
                    p.arvore_decisao
            ) a
            WHERE a.compra_transito > 0::NUMERIC
        ) b
    )
    loop

        update produtos_combinados_transito_filial
        set
            compra_transito = rec_transito.compra_transito,
            consumo_transito = rec_transito.consumo_transito,
            saldo_futuro = rec_transito.saldo_futuro,
            status = rec_transito.status,
            lote_compras = rec_transito.lote_compras,
            data_ultima_requisicao = rec_transito.data_ultima_requisicao,
            tempo_pedido = rec_transito.tempo_pedido,
            gatilho_transito = rec_transito.gatilho_transito,
            flag = NULL,
            processamento = current_timestamp
        where
            id_grupo = rec_transito.id_grupo
            and filial = rec_transito.filial
            and id_produto_combinado = rec_transito.id_produto_combinado;


        if not found then

             insert into produtos_combinados_transito_filial (
                    id_grupo,
                    filial,
                    id_produto_combinado,
                    compra_transito,
                    consumo_transito,
                    saldo_futuro,
                    status,
                    lote_compras,
                    data_ultima_requisicao,
                    tempo_pedido,
                    gatilho_transito,
                    flag,
                    processamento
                )
                values(
                    rec_transito.id_grupo,
                    rec_transito.filial,
                    rec_transito.id_produto_combinado,
                    rec_transito.compra_transito,
                    rec_transito.consumo_transito,
                    rec_transito.saldo_futuro,
                    rec_transito.status,
                    rec_transito.lote_compras,
                    rec_transito.data_ultima_requisicao,
                    rec_transito.tempo_pedido,
                    rec_transito.gatilho_transito,
                    null,
                    current_timestamp
                );

            end if;

        end loop;

    DELETE FROM produtos_combinados_transito_filial WHERE flag ='D';

    end $$;


ALTER FUNCTION public.processar_produtos_combinados_transito_filial(f_id_produto_combinado character varying) OWNER TO systock;

--
-- TOC entry 790 (class 1255 OID 53916)
-- Name: processar_produtos_combinados_transito_grupo(character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_produtos_combinados_transito_grupo(f_id_produto_combinado character varying DEFAULT NULL::character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
    declare
        rec_transito record;
        rec_pedidos record;
        p_atraso int4;
        qtde_transito_atraso numeric;
        qtde_transito numeric;
        qtde_estoque numeric;
        qtde_saldo  numeric;
        p_ponto_pedido numeric;
        p_sugestao numeric;
        p_emax numeric;
        p_cmm numeric;
        p_tr numeric;
        p_consumo_transito numeric;
        p_consumo_transito2 numeric;
        qtde_saldo_futuro numeric;
        qtde_saldo_residual numeric;
        p_status_transito varchar;
        qtde_lote_minimo  numeric;
        qtde_cobertura_futura numeric;
        qtde_dias numeric;
        cont_ped numeric;
        consumo_transito_cal numeric;
        data_temp date;
    BEGIN

    IF trim(f_id_produto_combinado) = '' THEN
        f_id_produto_combinado = NULL;
    END IF;

    UPDATE produtos_combinados_transito_grupo SET flag ='D' WHERE (f_id_produto_combinado = id_produto_combinado OR f_id_produto_combinado IS NULL);

    for rec_transito in(
        SELECT
            a.id_grupo,
            a.id_produto_combinado,
            a.produtos,
            a.compra_transito,
            a.consumo_transito * a.fator_conversao AS consumo_transito,
            a.saldo_futuro * a.fator_conversao AS saldo_futuro,
            a.estoque_maximo * a.fator_conversao::double precision AS estoque_maximo,
            a.ponto_pedido * a.fator_conversao::double precision AS ponto_pedido,
            a.consumo_medio_mensal::double precision * a.fator_conversao::double precision AS consumo_medio_mensal,
            a.tempo_ressuprimento,
            a.estoque::double precision * a.fator_conversao::double precision AS estoque,
            a.status,
            CASE
                WHEN a.status = 'PREVISÃO FUTURA EM EXCESSO'::text AND abs(a.lote_compras * a.fator_conversao::double precision) > a.compra_transito::double precision THEN (a.compra_transito * '-1'::integer::numeric)::double precision
                ELSE gerar_lote_embalagem((a.lote_compras * a.fator_conversao::double precision)::numeric, a.lote_minimo::numeric * a.fator_conversao)::double precision
            END AS lote_compras,
            a.fator_conversao,
            a.unidade_compra,
            a.data_ultima_requisicao,
            'now'::text::date - a.data_ultima_requisicao AS tempo_pedido,
            a.nivel_servico,
            a.peso_compras,
            CASE
                WHEN ('now'::text::date - a.data_ultima_requisicao - 1) < 0 THEN NULL::integer
                ELSE 'now'::text::date - a.data_ultima_requisicao - 1
            END AS gatilho_transito,
            a.lote_minimo
        FROM (
            SELECT
                analise_entrada.id_grupo,
                analise_entrada.id_produto_combinado,
                analise_entrada.produtos,
                analise_entrada.compra_transito,
                analise_entrada.consumo_transito,
                analise_entrada.saldo_futuro,
                analise_entrada.estoque_maximo,
                analise_entrada.ponto_pedido,
                analise_entrada.consumo_medio_mensal,
                analise_entrada.tempo_ressuprimento,
                analise_entrada.estoque,
                analise_entrada.fator_conversao,
                analise_entrada.unidade_compra,
                analise_entrada.lote_minimo,
                analise_entrada.data_ultima_requisicao,
                analise_entrada.nivel_servico,
                analise_entrada.peso_compras,
                case
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_requisicao) <= 1 THEN 'PRODUTO EM TRANSITO'::text
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_requisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.estoque_maximo THEN 'PREVISÃO FUTURA EM EXCESSO'::text
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_requisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.ponto_pedido AND analise_entrada.saldo_futuro::double precision <= analise_entrada.estoque_maximo AND (analise_entrada.saldo_futuro::double precision - analise_entrada.consumo_medio_mensal::double precision * 0.3::double precision) > analise_entrada.ponto_pedido THEN 'PREVISÃO FUTURA ADEQUADA'::text
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_requisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.ponto_pedido AND analise_entrada.saldo_futuro::double precision <= analise_entrada.estoque_maximo AND (analise_entrada.saldo_futuro::double precision - analise_entrada.consumo_medio_mensal::double precision * 0.3::double precision) <= analise_entrada.ponto_pedido THEN 'PREVISÃO COM SUTIL EXPOSIÇÃO A RUPTURA'::text
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_requisicao) > 1 AND analise_entrada.saldo_futuro::double precision <= analise_entrada.ponto_pedido THEN 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA'::text
                    ELSE 'PRIMEIRA COMPRA'::text
                END AS status,
                CASE
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_requisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.estoque_maximo THEN analise_entrada.estoque_maximo - analise_entrada.saldo_futuro::double precision
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_requisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.ponto_pedido AND analise_entrada.saldo_futuro::double precision <= analise_entrada.estoque_maximo AND (analise_entrada.saldo_futuro::double precision - analise_entrada.consumo_medio_mensal::double precision * 0.3::double precision) > analise_entrada.ponto_pedido THEN 0::double precision
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_requisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.ponto_pedido AND analise_entrada.saldo_futuro::double precision <= analise_entrada.estoque_maximo AND (analise_entrada.saldo_futuro::double precision - analise_entrada.consumo_medio_mensal::double precision * 0.3::double precision) <= analise_entrada.ponto_pedido THEN round((analise_entrada.estoque_maximo - (analise_entrada.saldo_futuro::double PRECISION - analise_entrada.consumo_transito_grupo_entre_pedidos))::numeric, 2)::double precision
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_requisicao) > 1 AND analise_entrada.saldo_futuro::double precision <= analise_entrada.ponto_pedido THEN round((analise_entrada.estoque_maximo - (analise_entrada.saldo_futuro::double precision - analise_entrada.consumo_transito_grupo_entre_pedidos))::numeric, 2)::double precision
                    ELSE 0::double precision
                END AS lote_compras
            FROM (
                SELECT
                    b.id_grupo,
                    b.id_produto_combinado,
                    b.produtos,
                    b.fator_conversao,
                    b.unidade_compra,
                    max(b.lote_minimo) AS lote_minimo,
                    max(b.data_ultima_requisicao) AS data_ultima_requisicao,
                    b.nivel_servico,
                    b.peso_compras,
                    avg(b.compra_transito) AS compra_transito,
                    sum(b.consumo_transito) AS consumo_transito,
                    CASE
                        WHEN (greatest((avg(b.estoque) - sum(b.consumo_transito)),0) + avg(b.compra_transito)) < 0::numeric THEN 0::numeric
                        ELSE greatest((avg(b.estoque) - sum(b.consumo_transito)),0) + avg(b.compra_transito)
                    END AS saldo_futuro,
                    avg(b.amplitude_atual) AS amplitude_atual,
                    avg(b.estoque_maximo) AS estoque_maximo,
                    avg(b.ponto_pedido) AS ponto_pedido,
                    avg(b.consumo_medio_mensal) AS consumo_medio_mensal,
                    avg(b.tempo_ressuprimento) AS tempo_ressuprimento,
                    avg(b.desvio_padrao_ressuprimento) AS desvio_padrao_ressuprimento,
                    avg(b.estoque) AS estoque,
                    avg(b.status_compra) AS status_compra,
                    b.consumo_transito_grupo_entre_pedidos
                FROM (
                    SELECT
                        g.id_grupo,
                        p.filial,
                        vp.id_produto_combinado,
                        vp.produtos,
                        vp.compra_transito AS compra_transito,
                        case
                            when ((
                                select count(*)
                                from analise_requisicoes ar
                                where filial in(select filial from grupo_filial gf where gf.id_grupo=g.id_grupo::numeric) and idproduto = ANY (vp.produtos) and atraso  > 0
                            ) > 0)
                            then sum(getconsumo_transito_grupo_new(g.id_grupo::numeric, p.idproduto)) +  round(coalesce((vp.tempo_medio_ressuprimento / 30) * vp.consumo_medio_mensal, 0), 2)
                            else sum(getconsumo_transito_grupo_new(g.id_grupo::numeric, p.idproduto))
                        END as consumo_transito,
                        round(coalesce((vp.tempo_medio_ressuprimento / 30) * vp.consumo_medio_mensal, 0), 2) AS consumo_transito_2,
                        case
                            when ((select count(*) from analise_requisicoes ar
                                where filial in(select filial from grupo_filial gf where gf.id_grupo=g.id_grupo::numeric)
                                and idproduto = ANY (vp.produtos) and atraso  > 0) > 0)  then 1
                            else 0
                        end as atraso,
                        sum(amplitude_transito_atual_filial(p.filial::numeric, p.idproduto)) AS amplitude_atual,
                        COALESCE(vp.estoque_maximo::double precision, 0::double precision) AS estoque_maximo,
                        COALESCE(vp.ponto_pedido::double precision, 0::double precision) AS ponto_pedido,
                        vp.consumo_medio_mensal,
                        vp.tempo_ressuprimento,
                        vp.desvio_padrao_ressuprimento,
                        vp.estoque,
                        (
                            SELECT CASE WHEN count(*) > 0 THEN 0 ELSE 1 END
                            FROM entrada_mercadorias
                            WHERE
                                entrada_mercadorias.data_entrada <= 'now'::text::date
                                AND entrada_mercadorias.idproduto::text = ANY (vp.produtos)
                                AND entrada_mercadorias.qtde > 0::double PRECISION
                        ) AS status_compra,
                        vp.fator_conversao,
                        vp.unidade_compra,
                        vp.lote_minimo,
                        vp.data_ultima_requisicao,
                        vp.arvore_decisao,
                        vp.nivel_servico,
                        vp.peso_compras,
                        sum(getconsumo_transito_grupo_entre_pedidos(g.id_grupo::numeric, p.idproduto)) AS consumo_transito_grupo_entre_pedidos
                    FROM produtos_filial p
                        INNER JOIN sys_produtos_combinados_itens spci ON spci.idproduto = p.idproduto
                        JOIN grupo_filial g ON g.filial = p.filial
                        JOIN produtos_combinados_compras_grupo vp ON vp.id_grupo = g.id_grupo AND vp.id_produto_combinado = spci.id_produto_combinado
                    where
                        p.revenda::text = 'S'::text
                        AND p.status::text <> 'FL'::text
                        AND p.status_suprimento_sku::text ~~ '%AGUARDANDO%'::text
                        AND getcompra_transito_grupo(g.id_grupo::numeric, p.idproduto) > 0::NUMERIC
                        AND (f_id_produto_combinado = spci.id_produto_combinado OR f_id_produto_combinado IS NULL)
                    GROUP BY
                        g.id_grupo,
                        p.filial,
                        vp.id_produto_combinado,
                        vp.descricao_produto,
                        vp.compra_transito,
                        vp.produtos,
                        vp.tempo_medio_ressuprimento,
                        vp.consumo_medio_mensal,
                        vp.estoque_maximo,
                        vp.ponto_pedido,
                        vp.tempo_ressuprimento,
                        vp.desvio_padrao_ressuprimento,
                        vp.estoque,
                        vp.fator_conversao,
                        vp.unidade_compra,
                        vp.lote_minimo,
                        vp.data_ultima_requisicao,
                        vp.arvore_decisao,
                        vp.nivel_servico,
                        vp.peso_compras
                ) b
                GROUP BY b.id_grupo, b.id_produto_combinado, b.produtos, b.fator_conversao, b.unidade_compra, b.arvore_decisao, b.nivel_servico, b.peso_compras, b.consumo_transito_grupo_entre_pedidos
            ) analise_entrada
            WHERE analise_entrada.compra_transito > 0::NUMERIC
        ) a
    )
    loop

          p_atraso=0;
          qtde_transito_atraso =0;
          qtde_transito=0;
          qtde_estoque=0;
          p_sugestao= 0;
          p_consumo_transito =0;
          p_consumo_transito2 = 0;
          qtde_saldo_futuro = 0;
          qtde_lote_minimo =  coalesce(rec_transito.lote_minimo,1);
          qtde_cobertura_futura=0;
          consumo_transito_cal = 0;


            --Identificar se o produto tem compra em atraso
            select count(*) into p_atraso
            from analise_requisicoes ar
            where filial in(select filial from grupo_filial gf where gf.id_grupo = rec_transito.id_grupo)
            and idproduto = ANY (rec_transito.produtos) and atraso >= 0 and qtde_pendente > 0;


            -- Pedidos em atraso;
            select  sum(qtde_pendente / spci.fator_conversao) into qtde_transito_atraso
            from analise_requisicoes r
                INNER JOIN sys_produtos_combinados_itens spci ON spci.idproduto = r.idproduto
            where
                spci.id_produto_combinado = rec_transito.id_produto_combinado
                and qtde_pendente > 0
                and atraso >= 0
                and r.filial in (select filial from grupo_filial where id_grupo = rec_transito.id_grupo);

            qtde_transito_atraso = coalesce(qtde_transito_atraso,0);

            --Pedidos em Transito Aberto;
            select  sum(qtde_pendente / spci.fator_conversao) into qtde_transito
            from analise_requisicoes r
                INNER JOIN sys_produtos_combinados_itens spci ON spci.idproduto = r.idproduto
            where
                spci.id_produto_combinado = rec_transito.id_produto_combinado
                and qtde_pendente > 0
                and atraso < 0
                and r.filial in (select filial from grupo_filial where id_grupo= rec_transito.id_grupo);

            qtde_transito = coalesce(qtde_transito, 0);


            -- Parâmetros do Estoque;
            qtde_estoque = rec_transito.estoque;
            p_ponto_pedido = rec_transito.ponto_pedido;
            p_emax = rec_transito.estoque_maximo;
            p_cmm = rec_transito.consumo_medio_mensal;
            p_tr =  rec_transito.tempo_ressuprimento;

            SELECT sum(getconsumo_transito_grupo_new(rec_transito.id_grupo, idproduto) / spci.fator_conversao) INTO p_consumo_transito
            FROM sys_produtos_combinados_itens spci
            WHERE spci.id_produto_combinado = rec_transito.id_produto_combinado;

            --Somente itens atrasados
            if p_atraso > 0 and qtde_transito = 0 then


                qtde_transito = greatest(qtde_transito,0);

                qtde_saldo = qtde_estoque + qtde_transito_atraso + qtde_transito;

                qtde_saldo_residual =  qtde_saldo - p_consumo_transito ;


                if qtde_saldo_residual > p_emax then -- Excesso


                  p_sugestao =  p_emax - qtde_saldo_residual;


                 if abs(p_sugestao) > qtde_transito_atraso then


                    p_sugestao = qtde_transito_atraso *(-1);

                 end if;


                elseif qtde_saldo_residual > p_ponto_pedido AND qtde_saldo_residual <= p_emax AND (qtde_saldo_residual - (p_cmm * 0.30)) > p_ponto_pedido then  -- Adequado


                  p_sugestao = 0;
                  p_status_transito = 'PREVISÃO ADEQUADA';


                elseif qtde_saldo_residual > p_ponto_pedido AND qtde_saldo_residual <= p_emax AND (qtde_saldo_residual - (p_cmm * 0.30)) <= p_ponto_pedido  then

                    SELECT sum(getconsumo_transito_grupo_2(rec_transito.id_grupo, idproduto) / spci.fator_conversao) INTO p_consumo_transito2
                    FROM sys_produtos_combinados_itens spci
                    WHERE spci.id_produto_combinado = rec_transito.id_produto_combinado;

                    p_sugestao =  (p_emax - greatest(qtde_saldo_residual-p_consumo_transito2, 0));



                      qtde_cobertura_futura =  round(qtde_saldo_residual/ greatest(p_cmm, 1),2);

                      if qtde_cobertura_futura < p_tr then


                        p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';


                        else


                        p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';

                      end if;


                elseif  ( qtde_saldo_residual  <= p_ponto_pedido) then

                  SELECT sum(getconsumo_transito_grupo_2(rec_transito.id_grupo, idproduto) / spci.fator_conversao) INTO p_consumo_transito2
                  FROM sys_produtos_combinados_itens spci
                  WHERE spci.id_produto_combinado = rec_transito.id_produto_combinado;

                  p_sugestao =  (p_emax - greatest(qtde_saldo_residual-p_consumo_transito2, 0)); --
                  qtde_cobertura_futura =  round(qtde_saldo_residual/ greatest(p_cmm, 1),2);


                  if qtde_cobertura_futura < p_tr then


                    p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';


                    else


                    p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';

                  end if;


                else

                  p_sugestao = 0;
                  p_status_transito = 'PRODUTO EM TRÂNSITO';


                end if;


                p_sugestao = gerar_lote_embalagem(p_sugestao,qtde_lote_minimo);



            elseif p_atraso = 0 and  qtde_transito > 0  then --Somente itens Abertos



                qtde_transito = greatest(qtde_transito,0);

                qtde_saldo = qtde_estoque;


                -- Quantidade de Pedidos Abertos


                cont_ped = 1;

                qtde_saldo_futuro= 0;


                for rec_pedidos in (
                    SELECT data_prevista_cal, sum(qtde / spci.fator_conversao) qtde
                    from analise_requisicoes r
                        INNER JOIN sys_produtos_combinados_itens spci ON spci.idproduto = r.idproduto
                    where
                        spci.id_produto_combinado = rec_transito.id_produto_combinado
                        and qtde_pendente > 0
                        and atraso < 0
                        and r.filial in (select filial from grupo_filial where id_grupo = rec_transito.id_grupo)
                    group by data_prevista_cal
                    order by data_prevista_cal
                )
                 loop


                      if cont_ped = 1 then

                          data_temp= rec_pedidos.data_prevista_cal;
                          qtde_dias =  rec_pedidos.data_prevista_cal - current_date ;
                          p_tr = (qtde_dias/30);


                        else


                         qtde_dias = ((rec_pedidos.data_prevista_cal)  - data_temp) ;
                         p_tr = (qtde_dias/30);
                         data_temp= rec_pedidos.data_prevista_cal;


                     end if;


                     consumo_transito_cal = round((p_cmm * (qtde_dias/30)),2);


                     if  consumo_transito_cal > qtde_saldo then


                         consumo_transito_cal = qtde_saldo;

                         qtde_saldo_residual = qtde_saldo - consumo_transito_cal;


                     else

                        qtde_saldo_residual = qtde_saldo - consumo_transito_cal;

                     end if;


                     qtde_saldo_futuro = qtde_saldo_residual + rec_pedidos.qtde;

                     qtde_saldo = qtde_saldo_futuro;


                     cont_ped = cont_ped + 1;


                 end loop;

                if qtde_saldo_futuro > p_emax then


                  p_sugestao =  p_emax - qtde_saldo_futuro;
                  p_status_transito = 'PREVISÃO EM EXCESSO';



                  if abs(p_sugestao) > rec_transito.compra_transito then


                    p_sugestao = rec_transito.compra_transito *(-1);

                 end if;


                elseif qtde_saldo_futuro > p_ponto_pedido AND qtde_saldo_futuro <= p_emax AND (qtde_saldo_futuro - (p_cmm * 0.30)) > p_ponto_pedido then

                 p_sugestao = 0;
                 p_status_transito = 'PREVISÃO ADEQUADA';


                elseif qtde_saldo_futuro > p_ponto_pedido AND qtde_saldo_futuro <= p_emax AND (qtde_saldo_futuro - (p_cmm * 0.30)) <= p_ponto_pedido  then

                 if qtde_transito > 0 then

                        select ((current_date + (produtos.tempo_medio_ressuprimento::int4)) - ((current_date + ((vw_requisicoes.data_solicitacao+produtos.tempo_medio_ressuprimento::int4) - current_date)) - current_date) - current_date)::numeric/30  into p_tr
                        FROM vw_requisicoes
                            inner join produtos_filial as produtos ON produtos.filial = vw_requisicoes.filial and produtos.idproduto = vw_requisicoes.idproduto::varchar
                        where
                            vw_requisicoes.idproduto::varchar = ANY (rec_transito.produtos)
                            and vw_requisicoes.filial in (select filial from grupo_filial gf where id_grupo= rec_transito.id_grupo )
                            and data_entrada isnull
                        order by data_solicitacao desc
                        limit 1;
                  end if;


                  p_sugestao = (p_emax - (greatest(qtde_saldo_futuro-(p_cmm *p_tr),0)));



                  qtde_cobertura_futura =  round(qtde_saldo_futuro/ greatest(p_cmm, 1),2);

                  if qtde_cobertura_futura < p_tr then


                    p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';


                    else


                    p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';

                  end if;


                elseif  ( qtde_saldo_futuro  <= p_ponto_pedido) then



                    if qtde_transito > 0 then

                            select ((current_date + (produtos.tempo_medio_ressuprimento::int4)) - ((current_date + ((vw_requisicoes.data_solicitacao+produtos.tempo_medio_ressuprimento::int4) - current_date)) - current_date) - current_date)::numeric/30  into p_tr
                            from vw_requisicoes
                                inner join produtos_filial  as produtos on  produtos.filial =vw_requisicoes.filial and  produtos.idproduto = vw_requisicoes.idproduto::varchar
                            where
                                vw_requisicoes.idproduto::varchar = ANY (rec_transito.produtos)
                                and vw_requisicoes.filial in (select filial from grupo_filial gf where id_grupo= rec_transito.id_grupo )
                                and data_entrada isnull
                            order by data_solicitacao desc
                            limit 1;

                      end if;


                     p_sugestao = (p_emax - (greatest(qtde_saldo_futuro-(p_cmm *p_tr),0)));


                      qtde_cobertura_futura =  round(qtde_saldo_futuro/ greatest(p_cmm, 1),2);

                      if qtde_cobertura_futura < p_tr then


                        p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';


                        else


                        p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';

                      end if;



                else

                  p_sugestao = 0;

                  p_status_transito = 'PRODUTO EM TRÂNSITO';


                end if;


             else    -- COMPRAS HIBRIDAS



                qtde_transito = greatest(qtde_transito,0);

                qtde_saldo = qtde_estoque +  qtde_transito_atraso;


                cont_ped = 1;


                qtde_saldo_futuro= 0;


                for rec_pedidos in (
                    select data_prevista_cal, sum(qtde / spci.fator_conversao) qtde
                    from analise_requisicoes r
                        INNER JOIN sys_produtos_combinados_itens spci ON spci.idproduto = r.idproduto
                    where
                        spci.id_produto_combinado = rec_transito.id_produto_combinado
                        and qtde_pendente > 0
                        and atraso < 0
                        and r.filial  in (select filial from grupo_filial where id_grupo= rec_transito.id_grupo )
                    group by data_prevista_cal
                    order by data_prevista_cal
                )

                 loop


                    if cont_ped = 1 then

                          data_temp= rec_pedidos.data_prevista_cal;
                          qtde_dias =  rec_pedidos.data_prevista_cal - current_date ;
                          p_tr = (qtde_dias/30);


                        else


                         qtde_dias = ((rec_pedidos.data_prevista_cal)  - data_temp) ;
                         p_tr = (qtde_dias/30);
                         data_temp= rec_pedidos.data_prevista_cal;


                     end if;



                     consumo_transito_cal = round((p_cmm * (qtde_dias/30)),2);


                     if  consumo_transito_cal > qtde_saldo then


                         consumo_transito_cal = qtde_saldo;

                         qtde_saldo_residual = qtde_saldo - consumo_transito_cal;


                     else

                        qtde_saldo_residual = qtde_saldo - consumo_transito_cal;

                     end if;


                     qtde_saldo_futuro = qtde_saldo_residual + rec_pedidos.qtde;

                     qtde_saldo = qtde_saldo_futuro;


                     cont_ped = cont_ped + 1;


                 end loop;



                if qtde_saldo_futuro > p_emax then


                  p_sugestao =  p_emax - qtde_saldo_futuro;
                  p_status_transito = 'PREVISÃO EM EXCESSO';



                  if abs(p_sugestao) > rec_transito.compra_transito then


                    p_sugestao = rec_transito.compra_transito *(-1);

                 end if;


                elseif qtde_saldo_futuro > p_ponto_pedido AND qtde_saldo_futuro <= p_emax AND (qtde_saldo_futuro - (p_cmm * 0.30)) > p_ponto_pedido then

                 p_sugestao = 0;
                 p_status_transito = 'PREVISÃO ADEQUADA';


                elseif qtde_saldo_futuro > p_ponto_pedido AND qtde_saldo_futuro <= p_emax AND (qtde_saldo_futuro - (p_cmm * 0.30)) <= p_ponto_pedido  then

                 if qtde_transito > 0 then

                        select ((current_date + (produtos.tempo_medio_ressuprimento::int4)) - ((current_date + ((vw_requisicoes.data_solicitacao+produtos.tempo_medio_ressuprimento::int4) - current_date)) - current_date) - current_date)::numeric/30  into p_tr
                        from vw_requisicoes
                            inner join produtos_filial  as produtos on  produtos.filial =vw_requisicoes.filial and  produtos.idproduto = vw_requisicoes.idproduto::varchar
                        where
                            vw_requisicoes.idproduto::varchar = ANY (rec_transito.produtos)
                            and vw_requisicoes.filial in (select filial from grupo_filial gf where id_grupo= rec_transito.id_grupo )
                            and data_entrada isnull  order by data_solicitacao desc
                        limit 1;

                  end if;


                  p_sugestao = (p_emax - (greatest(qtde_saldo_futuro-(p_cmm *p_tr),0)));


                  qtde_cobertura_futura =  round(qtde_saldo_futuro/ greatest(p_cmm, 1),2);

                  if qtde_cobertura_futura < p_tr then


                    p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';


                    else


                    p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';

                  end if;


                elseif  ( qtde_saldo_futuro  <= p_ponto_pedido) then



                    if qtde_transito > 0 then

                        select ((current_date + (produtos.tempo_medio_ressuprimento::int4)) - ((current_date + ((vw_requisicoes.data_solicitacao+produtos.tempo_medio_ressuprimento::int4) - current_date)) - current_date) - current_date)::numeric/30  into p_tr
                        from vw_requisicoes
                            inner join produtos_filial  as produtos on  produtos.filial =vw_requisicoes.filial and  produtos.idproduto = vw_requisicoes.idproduto::varchar
                        where
                            vw_requisicoes.idproduto::varchar = ANY (rec_transito.produtos)
                            and vw_requisicoes.filial in (select filial from grupo_filial gf where id_grupo= rec_transito.id_grupo )
                            and data_entrada isnull
                        order by data_solicitacao desc
                        limit 1;

                    end if;

                     p_sugestao = (p_emax - (greatest(qtde_saldo_futuro-(p_cmm *p_tr),0)));

                      qtde_cobertura_futura =  round(qtde_saldo_futuro/ greatest(p_cmm, 1),2);

                      if qtde_cobertura_futura < p_tr then


                        p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';


                        else


                        p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';

                      end if;



                else

                  p_sugestao = 0;

                  p_status_transito = 'PRODUTO EM TRÂNSITO';


                end if;


            end if;


               p_sugestao = gerar_lote_embalagem(p_sugestao,qtde_lote_minimo);

            -- Ajuste para Analisar os pedidos em compras após 15 dias
              if rec_transito.tempo_pedido  <= 2  then
                  p_sugestao = 0;
                  p_status_transito = 'PREVISÃO ADEQUADA';
              end if;

          IF p_status_transito IS NULL THEN
              p_status_transito = 'PRODUTO EM TRÂNSITO';
          END IF;

          update
            produtos_combinados_transito_grupo
            set
                compra_transito = rec_transito.compra_transito,
                consumo_transito = rec_transito.consumo_transito,
                saldo_futuro = rec_transito.saldo_futuro,
                status = p_status_transito,
                lote_compras = p_sugestao,
                data_ultima_requisicao = rec_transito.data_ultima_requisicao,
                tempo_pedido = rec_transito.tempo_pedido,
                gatilho_transito = rec_transito.gatilho_transito,
                flag = null,
                processamento = current_timestamp
            where
                id_grupo = rec_transito.id_grupo
                and id_produto_combinado = rec_transito.id_produto_combinado;


        if not found then

             insert into produtos_combinados_transito_grupo (
                    id_grupo,
                    id_produto_combinado,
                    compra_transito,
                    consumo_transito,
                    saldo_futuro,
                    status,
                    lote_compras,
                    data_ultima_requisicao,
                    tempo_pedido,
                    gatilho_transito,
                    flag,
                    processamento
                )
                values(
                    rec_transito.id_grupo,
                    rec_transito.id_produto_combinado,
                    rec_transito.compra_transito,
                    rec_transito.consumo_transito,
                    rec_transito.saldo_futuro,
                    p_status_transito,
                    p_sugestao,
                    rec_transito.data_ultima_requisicao,
                    rec_transito.tempo_pedido,
                    rec_transito.gatilho_transito,
                    null,
                    current_timestamp
                );

            end if;

        end loop;

        delete from  produtos_combinados_transito_grupo  where  flag ='D';

    end $$;


ALTER FUNCTION public.processar_produtos_combinados_transito_grupo(f_id_produto_combinado character varying) OWNER TO systock;

--
-- TOC entry 791 (class 1255 OID 53918)
-- Name: processar_produtos_comprador(); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_produtos_comprador() RETURNS void
    LANGUAGE plpgsql
    AS $$
    DECLARE
        ult_data_referencia date;
        max_data_saldo date;
        existe boolean;
        rec record;
    BEGIN
        SELECT max(data_referencia) IS NULL INTO existe FROM analise_produtos_comprador apc;
        SELECT max(apc.data_referencia) INTO ult_data_referencia::date FROM analise_produtos_comprador apc;
        SELECT max(sf.data) INTO max_data_saldo::date FROM saldo_filiais sf;

        IF existe THEN
            FOR rec IN (
                WITH ult_data_mes AS (
                    SELECT
                        DISTINCT
                        CASE WHEN last_day(to_char(DAY::date, '01/MM/YYYY')::date) > '2022-07-20'::date - 1
                            THEN '2022-07-20'::date - 1
                            ELSE last_day(to_char(DAY::date, '01/MM/YYYY')::date)
                        END AS data_referencia
                    FROM
                        generate_series('2022-07-20'::date - 365, '2022-07-20'::date, '1 day') DAY
                    ORDER BY
                        data_referencia
                ),
                produtos_ressuprimento AS (
                    SELECT
                        '2022-07-20'::date - 1 AS data_referencia,
                        w.filial,
                        w.idfornecedor,
                        w.idcomprador,
                        count(*) AS qtde_itens_ressuprir,
                        COALESCE(round(sum(w.sugestao * pf.preco_compra)::NUMERIC, 2), 0) AS tot_ressuprir
                    FROM
                        vw_lista_compras_dinamica_grupo_filial w
                    JOIN produtos_filial AS pf ON pf.filial = w.filial AND pf.idproduto = w.idproduto
                    WHERE
                        (w.idfornecedor, w.idproduto) NOT IN (
                            SELECT
                                npb.idfornecedor ,
                                npb.idproduto
                            FROM
                                notificacao_produtos_blacklist npb
                            WHERE
                                data_limite >= '2022-07-20'::date
                                AND deleted_at IS NULL
                        )
                    GROUP BY
                        w.filial,
                        w.idfornecedor,
                        w.idcomprador
                )
                SELECT
                    udms.data_referencia,
                    sf.ano,
                    sf.mes,
                    gf.id_grupo,
                    sf.filial,
                    f.id AS idfornecedor,
                    c.id AS idcomprador,
                    COALESCE(sum(sf.emax * pf.custo_unitario), 0) AS  custo_emax,
                    COALESCE(sum(sf.estoque * pf.custo_unitario), 0) AS  custo_estoque,
                    COALESCE(count(DISTINCT sf.idproduto), 0) AS  qtde_total_produto,
                    COALESCE(count(1) FILTER (WHERE sf.estoque > sf.emax), 0) AS qtde_produtos_excesso,
                    COALESCE(sum(sf.estoque * pf.custo_unitario) FILTER (WHERE sf.estoque > sf.emax AND pf.consumo_medio_mensal > 0), 0) AS valor_excesso,
                    COALESCE(count(1) FILTER (WHERE sf.estoque > sf.ppd AND sf.estoque < sf.emax), 0) AS qtde_produtos_adequado,
                    COALESCE(count(1) FILTER (WHERE pf.consumo_medio_mensal > 0 AND sf.estoque < sf.ppd), 0) AS qtde_produtos_a_comprar,
                    COALESCE(count(1) FILTER (WHERE sf.estoque = 0), 0) AS qtde_produtos_zerados,
                    COALESCE(count(pr.qtde_itens_ressuprir), 0) AS qtde_produtos_transito,
                    COALESCE(sum(pr.tot_ressuprir), 0) AS compra_prevista,
                    COALESCE(sum(sf.estoque * pf.custo_unitario), 0) AS total_estoque_periodo
                FROM
                    saldo_filiais AS sf
                    JOIN ult_data_mes AS udms ON udms.data_referencia = sf.DATA
                    LEFT JOIN requisicoes r ON r.idfilial = sf.filial
                        AND r.idproduto = sf.idproduto
                        AND to_char(r.data_solicitacao, '01/MM/YYYY')::date = first_day(udms.data_referencia)
                        AND r.qtde <> r.qtde_entregue
                        AND r.qtde_pendente > 0
                    JOIN produtos_filial AS pf ON pf.filial = sf.filial
                        AND pf.idproduto = sf.idproduto
                    LEFT JOIN produtos_ressuprimento pr ON pr.filial = pf.filial
                        AND pr.idfornecedor = pf.idfornecedor
                        AND pr.idcomprador = pf.idcomprador
                        AND pr.data_referencia = udms.data_referencia
                    JOIN grupo_filial AS gf ON gf.filial = sf.filial
                    JOIN comprador AS c ON c.id = pf.idcomprador
                    JOIN fornecedor AS f ON f.id = pf.idfornecedor
                GROUP BY
                    udms.data_referencia,
                    sf.ano,
                    sf.mes,
                    gf.id_grupo,
                    sf.filial,
                    f.id,
                    c.id
            )
            LOOP
                INSERT INTO analise_produtos_comprador (
                    data_referencia,
                    ano,
                    mes,
                    id_grupo,
                    filial,
                    idfornecedor,
                    idcomprador,
                    qtde_total_produto,
                    qtde_produtos_excesso,
                    valor_excesso,
                    excesso_toleravel,
                    diferenca_dinheiro,
                    excesso_realizado,
                    qtde_produtos_adequado,
                    qtde_produtos_a_comprar,
                    qtde_produtos_zerados,
                    qtde_produtos_transito,
                    compra_prevista,
                    total_estoque_periodo
                ) VALUES (
                    rec.data_referencia,
                    rec.ano,
                    rec.mes,
                    rec.id_grupo,
                    rec.filial,
                    rec.idfornecedor,
                    rec.idcomprador,
                    rec.qtde_total_produto,
                    rec.qtde_produtos_excesso,
                    rec.valor_excesso,
                    rec.custo_emax * 0.18,
                    GREATEST(rec.custo_estoque -    (rec.custo_emax + rec.custo_emax * 0.18), 0),
                    GREATEST(COALESCE((rec.custo_emax - rec.custo_estoque) / NULLIF(rec.custo_estoque, 0)) * 100, 0),
                    rec.qtde_produtos_adequado,
                    rec.qtde_produtos_a_comprar,
                    rec.qtde_produtos_zerados,
                    rec.qtde_produtos_transito,
                    rec.compra_prevista,
                    rec.total_estoque_periodo
                );
            END LOOP;
        ELSE
            FOR rec IN (
                WITH produtos_ressuprimento AS (
                    SELECT
                        '2022-07-20'::date - 1 AS data_referencia,
                        w.filial,
                        w.idfornecedor,
                        w.idcomprador,
                        count(DISTINCT w.idproduto) AS qtde_itens_ressuprir,
                        COALESCE(round(sum(w.sugestao * pf.preco_compra)::NUMERIC, 2), 0) AS tot_ressuprir
                    FROM
                        vw_lista_compras_dinamica_grupo_filial w
                    JOIN produtos_filial AS pf ON pf.filial = w.filial AND pf.idproduto = w.idproduto
                    WHERE
                        (w.idfornecedor, w.idproduto) NOT IN (
                            SELECT
                                npb.idfornecedor ,
                                npb.idproduto
                            FROM
                                notificacao_produtos_blacklist npb
                            WHERE
                                data_limite >= '2022-07-20'::date - 1
                                AND deleted_at IS NULL
                        )
                    GROUP BY
                        data_referencia,
                        w.filial,
                        w.idfornecedor,
                        w.idcomprador
                ),
                dados AS (
                    SELECT
                        '2022-07-20'::date - 1 AS data_referencia,
                        sf.ano,
                        sf.mes,
                        gf.id_grupo,
                        sf.filial,
                        f.id AS idfornecedor,
                        c.id AS idcomprador,
                        COALESCE(sum(sf.emax * pf.custo_unitario), 0) AS  custo_emax,
                        COALESCE(sum(sf.estoque * pf.custo_unitario), 0) AS  custo_estoque,
                        COALESCE(count(DISTINCT sf.idproduto), 0) AS  qtde_total_produto,
                        COALESCE(count(1) FILTER (WHERE sf.estoque > sf.emax), 0) AS qtde_produtos_excesso,
                        COALESCE(sum(sf.estoque * pf.custo_unitario) FILTER (WHERE sf.estoque > sf.emax AND pf.consumo_medio_mensal > 0), 0) AS valor_excesso,
                        COALESCE(count(1) FILTER (WHERE sf.estoque > sf.ppd AND sf.estoque < sf.emax), 0) AS qtde_produtos_adequado,
                        COALESCE(count(1) FILTER (WHERE pf.consumo_medio_mensal > 0 AND sf.estoque < sf.ppd), 0) AS qtde_produtos_a_comprar,
                        COALESCE(count(1) FILTER (WHERE sf.estoque = 0), 0) AS qtde_produtos_zerados,
                        COALESCE(sum(sf.estoque * pf.custo_unitario), 0) AS total_estoque_periodo
                    FROM
                        saldo_filiais AS sf
                    JOIN produtos_filial AS pf ON pf.filial = sf.filial
                        AND pf.idproduto = sf.idproduto
                    JOIN grupo_filial AS gf ON gf.filial = pf.filial
                    JOIN comprador AS c ON c.id = pf.idcomprador
                    JOIN fornecedor AS f ON f.id = pf.idfornecedor
                    WHERE
                        sf."data" = '2022-07-20'::date - 1
                    GROUP BY
                        sf.ano,
                        sf.mes,
                        gf.id_grupo,
                        sf.filial,
                        f.id,
                        c.id
                )
                SELECT
                    d.*,
                    COALESCE((pr.qtde_itens_ressuprir), 0) AS qtde_produtos_transito,
                    COALESCE((pr.tot_ressuprir), 0) AS compra_prevista
                FROM
                    dados AS d
                LEFT JOIN produtos_ressuprimento pr ON pr.filial = d.filial
                    AND pr.idfornecedor = d.idfornecedor
                    AND pr.idcomprador = d.idcomprador
            )
            LOOP
                IF max_data_saldo = last_day('2022-07-20'::date) THEN
                    INSERT INTO analise_produtos_comprador (
                        data_referencia,
                        ano,
                        mes,
                        id_grupo,
                        filial,
                        idfornecedor,
                        idcomprador,
                        qtde_total_produto,
                        qtde_produtos_excesso,
                        valor_excesso,
                        excesso_toleravel,
                        diferenca_dinheiro,
                        excesso_realizado,
                        qtde_produtos_adequado,
                        qtde_produtos_a_comprar,
                        qtde_produtos_zerados,
                        total_estoque_periodo,
                        compra_prevista,
                        qtde_produtos_transito
                    ) VALUES (
                        rec.data_referencia,
                        rec.ano,
                        rec.mes,
                        rec.id_grupo,
                        rec.filial,
                        rec.idfornecedor,
                        rec.idcomprador,
                        rec.qtde_total_produto,
                        rec.qtde_produtos_excesso,
                        rec.valor_excesso,
                        rec.custo_emax * 0.18,
                        GREATEST(rec.custo_estoque -    (rec.custo_emax + rec.custo_emax * 0.18), 0),
                        GREATEST(COALESCE((rec.custo_emax - rec.custo_estoque) / NULLIF(rec.custo_estoque, 0)) * 100, 0),
                        rec.qtde_produtos_adequado,
                        rec.qtde_produtos_a_comprar,
                        rec.qtde_produtos_zerados,
                        rec.total_estoque_periodo,
                        rec.compra_prevista,
                        rec.qtde_produtos_transito
                    );
                ELSE
                    UPDATE analise_produtos_comprador
                    SET
                        data_referencia = rec.data_referencia,
                        ano = rec.ano,
                        mes = rec.mes,
                        id_grupo = rec.id_grupo,
                        filial = rec.filial,
                        idfornecedor = rec.idfornecedor,
                        idcomprador = rec.idcomprador,
                        qtde_total_produto = rec.qtde_total_produto,
                        qtde_produtos_excesso = rec.qtde_produtos_excesso,
                        valor_excesso = rec.valor_excesso,
                        excesso_toleravel = rec.custo_emax * 0.18,
                        qtde_produtos_adequado = rec.qtde_produtos_adequado,
                        qtde_produtos_a_comprar = rec.qtde_produtos_a_comprar,
                        qtde_produtos_zerados = rec.qtde_produtos_zerados,
                        total_estoque_periodo = rec.total_estoque_periodo,
                        qtde_produtos_transito = rec.qtde_produtos_transito,
                        compra_prevista = rec.compra_prevista
                    WHERE data_referencia = max_data_saldo - 1;

                    IF NOT FOUND THEN
                        INSERT INTO analise_produtos_comprador (
                            data_referencia,
                            ano,
                            mes,
                            id_grupo,
                            filial,
                            idfornecedor,
                            idcomprador,
                            qtde_total_produto,
                            qtde_produtos_excesso,
                            valor_excesso,
                            excesso_toleravel,
                            diferenca_dinheiro,
                            excesso_realizado,
                            qtde_produtos_adequado,
                            qtde_produtos_a_comprar,
                            qtde_produtos_zerados,
                            total_estoque_periodo,
                            compra_prevista,
                            qtde_produtos_transito
                        ) VALUES (
                            rec.data_referencia,
                            rec.ano,
                            rec.mes,
                            rec.id_grupo,
                            rec.filial,
                            rec.idfornecedor,
                            rec.idcomprador,
                            rec.qtde_total_produto,
                            rec.qtde_produtos_excesso,
                            rec.valor_excesso,
                            rec.custo_emax * 0.18,
                            GREATEST(rec.custo_estoque -    (rec.custo_emax + rec.custo_emax * 0.18), 0),
                            GREATEST(COALESCE((rec.custo_emax - rec.custo_estoque) / NULLIF(rec.custo_estoque, 0)) * 100, 0),
                            rec.qtde_produtos_adequado,
                            rec.qtde_produtos_a_comprar,
                            rec.qtde_produtos_zerados,
                            rec.total_estoque_periodo,
                            rec.compra_prevista,
                            rec.qtde_produtos_transito
                        );
                    END IF;
                END IF;
            END LOOP;
        END IF;
    END;
$$;


ALTER FUNCTION public.processar_produtos_comprador() OWNER TO systock;

--
-- TOC entry 792 (class 1255 OID 53920)
-- Name: processar_produtos_compras_categorias(integer, character varying, character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_produtos_compras_categorias(filtro_id_grupo integer DEFAULT 0, filtro_id_departamento character varying DEFAULT '0'::character varying, filtro_id_categoria character varying DEFAULT '0'::character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
	rec_produto_grupo record;
    p_estoque_seguranca numeric(12,4);
	p_ponto_pedido numeric(12,4);
	p_estoque_maximo numeric(12,4);
	p_tempo_medio_ressuprimento numeric(12,4);
	p_tempo_ressuprimento numeric(12,4);
	p_desvio_padrao_ressuprimento numeric(12,4);
	p_compra_transito numeric(12,4);
	p_lote_compras_bruto numeric(12,4);
	p_lote_compras numeric(12,4);
    p_lote_minimo numeric(12,4);

BEGIN

	FOR rec_produto_grupo IN (
		select
			a.*,
			CASE
				WHEN a.coeficiente_variacao::numeric > 0::numeric AND a.coeficiente_variacao::numeric <= 200::numeric THEN 'REPETITIVO'::text
				WHEN a.coeficiente_variacao::numeric > 200::numeric AND a.coeficiente_variacao::numeric <= 600::numeric THEN 'ESTATISTICO'::text
				ELSE 'OCASIONAL'::text
			END AS perfil_demanda,
			0  as idcomprador,
		    35 as tempo_medio_ressuprimento,
			1.17 as tempo_ressuprimento,
			(
				SELECT r.pcompra
				FROM requisicoes r
					INNER JOIN grupo_filial gf ON gf.filial = r.idfilial
					INNER JOIN produtos_filial pf ON pf.filial = r.idfilial AND pf.idproduto = r.idproduto
				WHERE pf.idcategoria = a.idcategoria AND gf.id_grupo = a.id_grupo
				ORDER BY r.id_solicitacao DESC, r.data_solicitacao DESC
				LIMIT 1
			) AS ultimo_preco_compra
		from (
			WITH prismas AS (
				SELECT
					gf.id_grupo,
			   		pf.idcategoria,
			    	((min(pf.classificacao_financeira::text) || max(pf.classificacao_criticidade::text)) || min(pf.classificacao_comprabilidade)) || min(pf.classificacao_popularidade::text) AS arvore_decisao,
			    	 min(pf.classificacao_comprabilidade) as classificacao_comprabilidade
			   	FROM produtos_filial pf
			    	JOIN grupo_filial gf ON gf.filial = pf.filial
			  	GROUP BY gf.id_grupo, pf.idcategoria
			)
			select
				gf.id_grupo,
				pf.iddepartamento,
				pf.idsecao,
				pf.idcategoria,
				c.descricao_categoria,
				max(pf.idunidade_medida) AS idunidade_medida,
				sum(pf.estoque) as estoque,
				sum(pf.estoque_bloqueado) as estoque_bloqueado,
				sum(pf.estoque_avaria) as estoque_avaria,
				sum(pf.estoque_reservado) as estoque_reservado,
				sum(pf.estoque_similar) as estoque_similar,
				sum(pf.consumo_medio_mensal) as consumo_medio_mensal,
				sum(pf.desvio_padrao_consumo) as desvio_padrao_consumo,
				round(coalesce((sum(pf.estoque)/nullif(sum(pf.consumo_medio_mensal),0)),0),2) cobertura_estoque,
				round(coalesce((sum(pf.desvio_padrao_consumo * pf.fator_conversao)/nullif(sum(pf.consumo_medio_mensal * pf.fator_conversao),0)*100),0),2)::text AS coeficiente_variacao,
				round(avg(pf.tempo_medio_apanhe),2) as tempo_medio_apanhe,
				p.arvore_decisao,
				getNivelServico(p.arvore_decisao) as nivel_servico,
				getFes(p.arvore_decisao) as fes,
				getPesoCompras(p.arvore_decisao,coalesce(p.classificacao_comprabilidade,0)) as peso_compras,
				max(pf.unidade_compra) AS unidade_compra,
				max(pf.idunidade_medida) AS idunidade_medida,
				COALESCE(max(pcc.cobertura_manual_categoria), 0) AS cobertura_manual_categoria,
				avg(pf.custo_unitario) AS custo_unitario,
				avg(NULLIF(preco_compra, 0)) AS preco_medio_compra
			from categorias c
				inner join produtos_filial pf on pf.idcategoria = c.idcategoria::text
				inner join grupo_filial gf on gf.filial = pf.filial
				inner join prismas p on p.id_grupo = gf.id_grupo and p.idcategoria = pf.idcategoria
				LEFT JOIN produtos_compras_categorias pcc ON pcc.id_grupo = gf.id_grupo AND pcc.idcategoria = pf.idcategoria
			where pf.revenda='S' and pf.status<>'FL'
				and (gf.id_grupo  = filtro_id_grupo  or  filtro_id_grupo = 0)
				and (pf.iddepartamento = filtro_id_departamento or filtro_id_departamento = '0')
				and (pf.idcategoria = filtro_id_categoria or filtro_id_categoria = '0')
			group by gf.id_grupo,pf.iddepartamento,pf.idsecao,pf.idcategoria ,c.descricao_categoria,p.arvore_decisao,p.classificacao_comprabilidade
		) a
	)

	LOOP


		p_estoque_seguranca  = 0;
	    p_ponto_pedido  = 0;
		p_estoque_maximo  = 0;
		p_compra_transito  = 0;
		p_lote_compras_bruto  = 0;
		p_lote_compras  = 0;
		p_lote_minimo = 1;
		p_tempo_medio_ressuprimento  = 35;
		p_tempo_ressuprimento  = 1.17;
		p_desvio_padrao_ressuprimento  = 0;



	    select lote_minimo,tempo_medio_ressuprimento,tempo_ressuprimento,desvio_padrao_ressuprimento into
	    	p_lote_minimo,
		    p_tempo_medio_ressuprimento,
		    p_tempo_ressuprimento,
		    p_desvio_padrao_ressuprimento
		    from produtos_compras_categorias pcc
		    where id_grupo = rec_produto_grupo.id_grupo
			and idcategoria::text = rec_produto_grupo.idcategoria;


			p_lote_minimo = coalesce(p_lote_minimo,1);
		    p_tempo_medio_ressuprimento  = coalesce(p_tempo_medio_ressuprimento,35);
		    p_tempo_ressuprimento  = coalesce(p_tempo_ressuprimento,1.17);
		    p_desvio_padrao_ressuprimento  = coalesce(p_desvio_padrao_ressuprimento,0);






	    -- Estoque Segurança;


	      p_estoque_seguranca = ( round(cast( rec_produto_grupo.desvio_padrao_consumo * rec_produto_grupo.fes as numeric),2));


    	  if rec_produto_grupo.desvio_padrao_consumo = 0 then

       		p_estoque_seguranca = ( round(cast( rec_produto_grupo.consumo_medio_mensal * rec_produto_grupo.fes as numeric),2));

    	 end if;



   		 if rec_produto_grupo.perfil_demanda ='OCASIONAL' then

         	p_estoque_seguranca = ( round(cast((rec_produto_grupo.consumo_medio_mensal/2) * rec_produto_grupo.fes as numeric),2));

         end if;

	    -- Cobertura Manual
	    if (rec_produto_grupo.cobertura_manual_categoria > 0) then
	     	p_estoque_seguranca = ((rec_produto_grupo.consumo_medio_mensal/30)*rec_produto_grupo.cobertura_manual_categoria) * 0.30;
	    end if;

        -- Ponto de Pedido
        p_ponto_pedido = round(cast(p_estoque_seguranca + (rec_produto_grupo.consumo_medio_mensal * (p_tempo_ressuprimento+p_desvio_padrao_ressuprimento))as numeric),2) ;



        --  Estoque Máximo

        p_estoque_maximo = (p_ponto_pedido+rec_produto_grupo.consumo_medio_mensal);


	  	--Cobertura Manual
	    if rec_produto_grupo.cobertura_manual_categoria > 0 THEN

    		if  ((rec_produto_grupo.consumo_medio_mensal/30) * rec_produto_grupo.cobertura_manual_categoria) > p_ponto_pedido then
    	    	p_estoque_maximo = ((rec_produto_grupo.consumo_medio_mensal / 30) * rec_produto_grupo.cobertura_manual_categoria);
    	   	else
	    	   -- Cobertura Máxima atribuida ao item e inferior ao tempo de reposição do mesmo;
	    	   p_estoque_maximo = (p_ponto_pedido + rec_produto_grupo.consumo_medio_mensal);
	    	end if;

      	else
	       p_estoque_maximo = (p_ponto_pedido + rec_produto_grupo.consumo_medio_mensal);
		end if;


       -- Validação Perfil OCASIONAL
       	 if rec_produto_grupo.perfil_demanda ='OCASIONAL' THEN

         	p_ponto_pedido = round(cast(p_estoque_seguranca + ((rec_produto_grupo.consumo_medio_mensal/2) * (p_tempo_ressuprimento+p_desvio_padrao_ressuprimento)) as numeric),2);

   			if (rec_produto_grupo.cobertura_manual_categoria > 0) AND (((rec_produto_grupo.consumo_medio_mensal/30) * rec_produto_grupo.cobertura_manual_categoria) > p_ponto_pedido) THEN
	    	    p_estoque_maximo = (((rec_produto_grupo.consumo_medio_mensal/2) / 30) * rec_produto_grupo.cobertura_manual_categoria);
   			ELSE
	         	p_estoque_maximo = (p_ponto_pedido+(rec_produto_grupo.consumo_medio_mensal/2));
	         END IF;
         end if;



         -- Compra em Trânsito;


          select coalesce(sum(r.qtde_pendente),0) into p_compra_transito from requisicoes r
			inner join produtos_filial pf
			 on r.idfilial = pf.filial
			 and r.idproduto = pf.idproduto
			 where pf.idcategoria= rec_produto_grupo.idcategoria  and qtde_pendente > 0;


			p_compra_transito = coalesce(p_compra_transito,0);


        --Lote de Compras



		 if  p_compra_transito = 0 and  rec_produto_grupo.perfil_demanda ='OCASIONAL' and  rec_produto_grupo.estoque <  p_ponto_pedido then

		        p_lote_compras_bruto =  ((rec_produto_grupo.consumo_medio_mensal/2));
		        p_lote_compras= gerar_lote_embalagem(p_lote_compras_bruto,p_lote_minimo);


		 elseif  p_compra_transito = 0 and  rec_produto_grupo.perfil_demanda <> 'OCASIONAL' and  rec_produto_grupo.estoque <  p_ponto_pedido then


		       p_lote_compras_bruto = (round(cast((p_estoque_maximo+(rec_produto_grupo.consumo_medio_mensal*(p_tempo_ressuprimento+p_desvio_padrao_ressuprimento))-rec_produto_grupo.estoque) as numeric),2));
		       p_lote_compras= gerar_lote_embalagem(p_lote_compras_bruto,p_lote_minimo);
		 else

		       p_lote_compras_bruto = 0;
		       p_lote_compras  = 0;

		 end if;

		-- cobertura estoque menor que o tempo de ressuprimento: comprar emax
		if (p_lote_compras_bruto > 0 and rec_produto_grupo.cobertura_estoque < p_tempo_ressuprimento) then
		       p_lote_compras_bruto = p_estoque_maximo;
		       p_lote_compras  = gerar_lote_embalagem(p_lote_compras_bruto, p_lote_minimo);
		end if;



		update
			produtos_compras_categorias
		SET
			iddepartamento = rec_produto_grupo.iddepartamento,
			idsecao = rec_produto_grupo.idsecao,
			descricao_categoria = rec_produto_grupo.descricao_categoria,
			estoque = rec_produto_grupo.estoque,
			estoque_bloqueado = rec_produto_grupo.estoque_bloqueado,
			estoque_avaria = rec_produto_grupo.estoque_avaria,
			estoque_reservado = rec_produto_grupo.estoque_reservado,
			cobertura_estoque = rec_produto_grupo.cobertura_estoque,
			estoque_seguranca = p_estoque_seguranca,
			ponto_pedido = p_ponto_pedido,
			estoque_maximo = p_estoque_maximo,
			consumo_medio_mensal = rec_produto_grupo.consumo_medio_mensal,
			desvio_padrao_consumo = rec_produto_grupo.desvio_padrao_consumo,
			tempo_medio_ressuprimento = p_tempo_medio_ressuprimento,
			tempo_ressuprimento = p_tempo_ressuprimento,
			desvio_padrao_ressuprimento = 0,
			coeficiente_variacao = rec_produto_grupo.coeficiente_variacao,
			compra_transito = p_compra_transito,
			arvore_decisao = rec_produto_grupo.arvore_decisao,
			nivel_servico = rec_produto_grupo.nivel_servico,
			peso_compras = rec_produto_grupo.peso_compras,
			lote_compras_bruto = p_lote_compras_bruto ,
			lote_compras = p_lote_compras,
			perfil_demanda = rec_produto_grupo.perfil_demanda,
			tempo_medio_apanhe = rec_produto_grupo.tempo_medio_apanhe,
			unidade_compra = rec_produto_grupo.unidade_compra,
			idunidade_medida = rec_produto_grupo.idunidade_medida,
			custo_unitario = rec_produto_grupo.custo_unitario,
			preco_medio_compra = rec_produto_grupo.preco_medio_compra,
			ultimo_preco_compra = rec_produto_grupo.ultimo_preco_compra,
			processamento = current_timestamp
		where
			id_grupo = rec_produto_grupo.id_grupo
			and idcategoria::text = rec_produto_grupo.idcategoria;

		IF NOT FOUND then

		      insert
					into
					produtos_compras_categorias (
					id_grupo,
					iddepartamento,
					idsecao,
					idcategoria,
					descricao_categoria,
					idcomprador,
					estoque,
					estoque_bloqueado,
					estoque_avaria,
					estoque_reservado,
					cobertura_estoque,
					estoque_seguranca,
					ponto_pedido,
					estoque_maximo,
					consumo_medio_mensal,
					desvio_padrao_consumo,
					tempo_medio_ressuprimento,
					tempo_ressuprimento,
					desvio_padrao_ressuprimento,
					coeficiente_variacao,
					compra_transito,
					arvore_decisao,
					nivel_servico,
					peso_compras,
					lote_minimo,
					lote_compras_bruto,
					lote_compras,
					perfil_demanda,
					tempo_medio_apanhe,
					unidade_compra,
					idunidade_medida,
					custo_unitario,
					preco_medio_compra,
					ultimo_preco_compra,
					processamento)
				values( rec_produto_grupo.id_grupo,
						rec_produto_grupo.iddepartamento,
						rec_produto_grupo.idsecao,
						rec_produto_grupo.idcategoria::int8,
						rec_produto_grupo.descricao_categoria,
						rec_produto_grupo.idcomprador,
						rec_produto_grupo.estoque,
						rec_produto_grupo.estoque_bloqueado,
						rec_produto_grupo.estoque_avaria,
						rec_produto_grupo.estoque_reservado,
						rec_produto_grupo.cobertura_estoque,
						p_estoque_seguranca,
						p_ponto_pedido,
						p_estoque_maximo,
						rec_produto_grupo.consumo_medio_mensal,
						rec_produto_grupo.desvio_padrao_consumo,
						p_tempo_medio_ressuprimento,
						p_tempo_ressuprimento,
						p_desvio_padrao_ressuprimento,
						rec_produto_grupo.coeficiente_variacao,
						p_compra_transito,
						rec_produto_grupo.arvore_decisao,
						rec_produto_grupo.nivel_servico,
						rec_produto_grupo.peso_compras,
						p_lote_minimo,
						p_lote_compras_bruto,
						p_lote_compras,
						rec_produto_grupo.perfil_demanda,
						rec_produto_grupo.tempo_medio_apanhe,
						rec_produto_grupo.unidade_compra,
						rec_produto_grupo.idunidade_medida,
						rec_produto_grupo.custo_unitario,
						rec_produto_grupo.preco_medio_compra,
						rec_produto_grupo.ultimo_preco_compra,
						current_timestamp);
		END IF;
	END LOOP;
END;
$$;


ALTER FUNCTION public.processar_produtos_compras_categorias(filtro_id_grupo integer, filtro_id_departamento character varying, filtro_id_categoria character varying) OWNER TO systock;

--
-- TOC entry 793 (class 1255 OID 53922)
-- Name: processar_produtos_compras_categorias_mp_pa(integer, integer); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_produtos_compras_categorias_mp_pa(f_grupo integer DEFAULT 0, f_categoria integer DEFAULT 0) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE 
    rec_categoria record;
    p_estoque_seguranca numeric(12,4);
    p_ponto_pedido numeric(12,4);
    p_estoque_maximo numeric(12,4);
    p_tempo_medio_ressuprimento numeric(12,4);
    p_tempo_ressuprimento numeric(12,4);
    p_lote_compras_bruto numeric(12,4);
    p_lote_compras numeric(12,4);
BEGIN
    UPDATE produtos_compras_categorias_mp_pa SET flag = 'D';

    FOR rec_categoria IN (
        WITH produtos_categoria_mp AS (
            SELECT DISTINCT 
                mp.id_categoria,
                mp.id_produto_mp
            FROM produtos_categoria_mp_pa mp
        ),
        produtos_categoria_pa AS (
            SELECT DISTINCT 
                pa.id_categoria,
                pa.id_produto_pa
            FROM produtos_categoria_mp_pa pa
        ),
        produtos_acabado AS (
            SELECT 
                gf.id_grupo,
                cmp.id AS id_categoria,
                cmp.nome AS descricao_categoria,
                sum(pa.estoque) AS estoque,
                sum(pa.estoque * pa.peso) AS estoque_peso,
                sum(pa.estoque_bloqueado * pa.peso) AS estoque_bloqueado_peso,
                sum(pa.estoque_avaria * pa.peso) AS estoque_avaria_peso,
                sum(pa.estoque_reservado * pa.peso) AS estoque_reservado_peso,
                sum(pa.estoque_similar * pa.peso) AS estoque_similar_peso,
                sum(pa.consumo_medio_mensal * pa.peso) AS consumo_medio_mensal_peso,
                sum(pa.consumo_medio_mensal) AS consumo_medio_mensal,
                COALESCE(sum(pa.desvio_padrao_consumo * pa.peso), 0::numeric) AS desvio_padrao_consumo_peso,
                min(pa.classificacao_financeira::text) AS classificacao_financeira,
                max(pa.classificacao_criticidade::text) AS classificacao_criticidade,
                min(pa.classificacao_comprabilidade) AS classificacao_comprabilidade,
                min(pa.classificacao_popularidade::text) AS classificacao_popularidade
            FROM categorias_mp_pa cmp
                JOIN produtos_categoria_pa pcmp ON pcmp.id_categoria = cmp.id
                JOIN produtos_filial pa ON pa.idproduto::text = pcmp.id_produto_pa::text
                JOIN grupo_filial gf ON gf.filial = pa.filial
            WHERE 
                pa.revenda = 'S'
                AND pa.status <> 'FL'
            GROUP BY gf.id_grupo, cmp.id
        ),
        materia_prima AS (
            SELECT gf.id_grupo,
                cmp.id AS id_categoria,
                cmp.nome AS descricao_categoria,
                sum(mp.estoque) AS estoque,
                (sum(mp.estoque_bloqueado)) AS estoque_bloqueado,
                (sum(mp.estoque_avaria)) AS estoque_avaria,
                (sum(mp.estoque_reservado)) AS estoque_reservado,
                (sum(mp.estoque_similar)) AS estoque_similar,
                (sum(mp.consumo_medio_mensal)) AS consumo_medio_mensal,
                sum(mp.desvio_padrao_consumo) AS desvio_padrao_consumo,
                COALESCE(max(mp.fator_conversao), 1) AS fator_conversao,
                COALESCE(avg(NULLIF(mp.tempo_medio_apanhe, 0::numeric)), 0::numeric) AS tempo_medio_apanhe,
                min(mp.unidade_compra::text) AS unidade_compra,
                min(mp.idunidade_medida::text) AS idunidade_medida,
                COALESCE(avg(NULLIF(mp.tempo_medio_ressuprimento, 0)), 0) AS prazo_medio_recebimento,
                 COALESCE(NULLIF(cmp.tempo_medio_ressuprimento, 0), 35) AS tempo_medio_ressuprimento,
                COALESCE(NULLIF(cmp.tempo_ressuprimento, 0::numeric), 1.17) AS tempo_ressuprimento,
                COALESCE(avg(NULLIF(mp.custo_unitario, 0::numeric)), 0) AS custo_medio_unitario,
                COALESCE(avg(NULLIF(mp.preco_compra, 0::numeric)), 0) AS preco_medio_compra,
                max(mp.idcomprador) AS idcomprador,
                COALESCE(NULLIF(cmp.lote_minimo, 0), 1) AS lote_minimo,
                COALESCE(cmp.desvio_padrao_ressuprimento, 0) AS desvio_padrao_ressuprimento,
                min(mp.classificacao_financeira::text) AS classificacao_financeira,
                max(mp.classificacao_criticidade::text) AS classificacao_criticidade,
                min(mp.classificacao_comprabilidade) AS classificacao_comprabilidade,
                min(mp.classificacao_popularidade::text) AS classificacao_popularidade
            FROM categorias_mp_pa cmp
                JOIN produtos_categoria_mp pcmp ON pcmp.id_categoria = cmp.id
                JOIN produtos_filial mp ON mp.idproduto::text = pcmp.id_produto_mp::text
                JOIN grupo_filial gf ON gf.filial = mp.filial
            GROUP BY 
                gf.id_grupo, 
                cmp.id
        ),
        categorias_grupos AS (
            SELECT
                gc.id AS id_grupo,
                cmp.id AS id_categoria,
                cmp.nome AS descricao_categoria,
                COALESCE(cmp.cobertura_manual_categoria, 0) AS cobertura_manual_categoria,
                COALESCE(NULLIF(cmp.tempo_ressuprimento, 0::numeric), 1.17) AS tempo_ressuprimento,
                COALESCE(NULLIF(cmp.lote_minimo, 0), 1) AS lote_minimo,
                COALESCE(cmp.desvio_padrao_ressuprimento, 0) AS desvio_padrao_ressuprimento
            FROM categorias_mp_pa cmp
                INNER JOIN grupo_compras gc ON 1 = 1
        ),
        produtos_consolidados AS (
            SELECT
                cg.id_grupo,
                cg.id_categoria,
                cg.descricao_categoria,
                COALESCE(mp.estoque + pa.estoque_peso, 0) AS estoque_peso,
                COALESCE(mp.estoque, 0) AS estoque_mp_peso,
                COALESCE(pa.estoque, 0) AS estoque_pa,
                COALESCE(pa.estoque_peso, 0) AS estoque_pa_peso,
                COALESCE(mp.estoque_bloqueado + pa.estoque_bloqueado_peso, 0) AS estoque_bloqueado_peso,
                COALESCE(mp.estoque_avaria + pa.estoque_avaria_peso, 0) AS estoque_avaria_peso,
                COALESCE(mp.estoque_reservado + pa.estoque_reservado_peso, 0) AS estoque_reservado_peso,
                COALESCE(mp.estoque_similar + pa.estoque_similar_peso, 0) AS estoque_similar_peso,
                COALESCE(pa.consumo_medio_mensal_peso, 0) AS cmm_peso,
                COALESCE(pa.consumo_medio_mensal_peso, 0) AS cmm_pa_peso,
                COALESCE(pa.consumo_medio_mensal, 0) AS cmm_pa,
                COALESCE(mp.desvio_padrao_consumo + pa.desvio_padrao_consumo_peso, 0) AS desvio_padrao_consumo_peso,
                COALESCE(mp.fator_conversao, 1) AS fator_conversao,
                COALESCE(mp.tempo_medio_apanhe), 0 AS tempo_medio_apanhe,
                COALESCE(mp.unidade_compra, 'KG') AS unidade_compra,
                COALESCE(mp.idunidade_medida, 'KG') AS idunidade_medida,
                COALESCE(cg.cobertura_manual_categoria, 0) AS cobertura_manual_categoria,
                COALESCE(mp.prazo_medio_recebimento, 0) AS prazo_medio_recebimento,
                COALESCE(mp.tempo_medio_ressuprimento, 0) AS tempo_medio_ressuprimento,
                COALESCE(cg.tempo_ressuprimento, 0) AS tempo_ressuprimento,
                COALESCE(mp.custo_medio_unitario, 0) AS custo_medio_unitario,
                COALESCE(mp.preco_medio_compra, 0) AS preco_medio_compra,
                COALESCE(mp.idcomprador, 0) AS idcomprador,
                cg.lote_minimo,
                COALESCE(cg.desvio_padrao_ressuprimento, 0) AS desvio_padrao_ressuprimento,
                COALESCE(pa.classificacao_financeira::TEXT, mp.classificacao_financeira::text) AS classificacao_financeira,
                COALESCE(pa.classificacao_criticidade::TEXT, mp.classificacao_criticidade::text) AS classificacao_criticidade,
                COALESCE(pa.classificacao_comprabilidade, mp.classificacao_comprabilidade) AS classificacao_comprabilidade,
                COALESCE(pa.classificacao_popularidade::TEXT, mp.classificacao_popularidade::text) AS classificacao_popularidade
            FROM categorias_grupos cg
                LEFT JOIN materia_prima mp ON mp.id_grupo = cg.id_grupo AND mp.id_categoria = cg.id_categoria
                LEFT JOIN produtos_acabado pa ON pa.id_grupo = cg.id_grupo AND pa.id_categoria = cg.id_categoria
        ),
        prismas AS (
            SELECT 
                pc.id_grupo,
                pc.id_categoria,
                (pc.classificacao_financeira::text || pc.classificacao_criticidade::text || pc.classificacao_comprabilidade || pc.classificacao_popularidade::text) AS arvore_decisao
            FROM produtos_consolidados pc
        )
        SELECT 
            pc.*,
            round(COALESCE(pc.desvio_padrao_consumo_peso * pc.fator_conversao / NULLIF(pc.cmm_peso * pc.fator_conversao, 0::numeric) * 100::numeric, 0::numeric), 2) AS coeficiente_variacao,
            p.arvore_decisao,
            getNivelServico(p.arvore_decisao) as nivel_servico,
            getFes(p.arvore_decisao) as fes,
            getPesoCompras(p.arvore_decisao, coalesce(pc.classificacao_comprabilidade, 0)) as peso_compras,
            0.0 AS estoque_transito_peso,
            coalesce(trunc(pc.estoque_peso / NULLIF(pc.cmm_peso, 0), 4), 0) AS cobertura_estoque_peso,
            '' AS perfil_demanda,
            COALESCE((
                SELECT r.pcompra 
                FROM requisicoes r 
                    --INNER JOIN grupo_filial gf ON gf.filial = r.idfilial 
                    INNER JOIN produtos_categoria_mp mp ON mp.id_produto_mp = r.idproduto 
                WHERE mp.id_categoria = pc.id_categoria --AND gf.id_grupo = pc.id_grupo
                ORDER BY r.id_solicitacao DESC, r.data_solicitacao DESC
                LIMIT 1
            ), 0) AS ultimo_preco_compra
        FROM produtos_consolidados pc
            INNER JOIN prismas p ON p.id_grupo = pc.id_grupo AND p.id_categoria = pc.id_categoria
    )
    LOOP    
        -- define o perfil de demanda
        IF (rec_categoria.coeficiente_variacao >= 0 AND rec_categoria.coeficiente_variacao <= 200) then
            rec_categoria.perfil_demanda = 'REPETITIVO'::TEXT;
        ELSIF (rec_categoria.coeficiente_variacao <= 600) THEN 
            rec_categoria.perfil_demanda = 'ESTATISTICO'::TEXT;
        ELSE 
            rec_categoria.perfil_demanda = 'OCASIONAL'::TEXT;
        END IF;
        
        -- estoque de segurança
        if (rec_categoria.cobertura_manual_categoria > 0) THEN 
        
            p_estoque_seguranca = round(((rec_categoria.cmm_peso / 30) * rec_categoria.cobertura_manual_categoria) * 0.30, 4);
        
        ELSEIF (rec_categoria.perfil_demanda = 'OCASIONAL') THEN 
        
            p_estoque_seguranca = round(cast((rec_categoria.cmm_peso / 2) * rec_categoria.fes AS NUMERIC), 4);
        
        ELSEIF (rec_categoria.desvio_padrao_consumo_peso = 0) THEN 
        
            p_estoque_seguranca = round(cast(rec_categoria.cmm_peso * rec_categoria.fes AS NUMERIC), 4);
        
        ELSE 
        
            p_estoque_seguranca = round(cast(rec_categoria.desvio_padrao_consumo_peso * rec_categoria.fes AS NUMERIC), 4); 
        
        END IF;
     
    
        -- Ponto de Pedido 
        IF rec_categoria.perfil_demanda = 'OCASIONAL' THEN
            p_ponto_pedido = round(cast(p_estoque_seguranca + ((rec_categoria.cmm_peso / 2) * (rec_categoria.tempo_ressuprimento + rec_categoria.desvio_padrao_ressuprimento)) AS NUMERIC), 2);
        ELSE 
            p_ponto_pedido = round(cast(p_estoque_seguranca + (rec_categoria.cmm_peso * (rec_categoria.tempo_ressuprimento + rec_categoria.desvio_padrao_ressuprimento)) AS NUMERIC), 2);
        END IF;
    
    
        -- estoque maximo
        IF rec_categoria.perfil_demanda = 'OCASIONAL' THEN
        
            IF (rec_categoria.cobertura_manual_categoria > 0) AND (((rec_categoria.cmm_peso / 30) * rec_categoria.cobertura_manual_categoria) > p_ponto_pedido) THEN
                p_estoque_maximo = (((rec_categoria.cmm_peso / 2) / 30) * rec_categoria.cobertura_manual_categoria); 
            ELSE 
                p_estoque_maximo = (p_ponto_pedido + (rec_categoria.cmm_peso / 2));
            END IF;
         
        ELSEIF (rec_categoria.cobertura_manual_categoria > 0) THEN 
        
            IF ((rec_categoria.cmm_peso / 30) * rec_categoria.cobertura_manual_categoria) > p_ponto_pedido THEN
                p_estoque_maximo = ((rec_categoria.cmm_peso / 30) * rec_categoria.cobertura_manual_categoria); 
            ELSE
               -- Cobertura Máxima atribuida ao item e inferior ao tempo de reposição do mesmo;
               p_estoque_maximo = (p_ponto_pedido + rec_categoria.cmm_peso);
            END IF;
        
        ELSE 
            p_estoque_maximo = (p_ponto_pedido + rec_categoria.cmm_peso);
        END IF;
    
        -- estoque em transito        
        SELECT sum(compra_transito) INTO rec_categoria.estoque_transito_peso
        FROM (
            SELECT COALESCE(sum(qtde_pendente), 0) AS compra_transito
            FROM requisicoes r  
                INNER JOIN produtos_filial pf ON pf.filial = r.idfilial AND pf.idproduto = r.idproduto 
                INNER JOIN grupo_filial gf ON gf.filial = pf.filial 
            WHERE 
                r.qtde_pendente  > 0
                AND gf.id_grupo = rec_categoria.id_grupo
                AND pf.idproduto IN (
                    SELECT DISTINCT id_produto_mp 
                    FROM produtos_categoria_mp_pa pc
                    WHERE pc.id_categoria = rec_categoria.id_categoria
                )
        
            UNION 
        
            SELECT COALESCE(sum(qtde_pendente * pf.peso), 0) AS compra_transito
            FROM requisicoes r  
                INNER JOIN produtos_filial pf ON pf.filial = r.idfilial AND pf.idproduto = r.idproduto 
                INNER JOIN grupo_filial gf ON gf.filial = pf.filial 
            WHERE 
                r.qtde_pendente  > 0
                AND gf.id_grupo = rec_categoria.id_grupo
                AND pf.idproduto IN (
                    SELECT DISTINCT id_produto_pa 
                    FROM produtos_categoria_mp_pa pc
                    WHERE pc.id_categoria = rec_categoria.id_categoria
                )
        ) t;
           
    
        -- calcula a sugestao de compra para itens que nao estão em transito
        IF (rec_categoria.estoque_transito_peso = 0 AND rec_categoria.perfil_demanda = 'OCASIONAL' AND rec_categoria.estoque_peso <  p_ponto_pedido) THEN 
        
            p_lote_compras_bruto =  (rec_categoria.cmm_peso / 2);
            p_lote_compras = gerar_lote_embalagem(p_lote_compras_bruto, rec_categoria.lote_minimo);
        
         ELSEIF (rec_categoria.estoque_transito_peso = 0 AND rec_categoria.perfil_demanda <> 'OCASIONAL' AND rec_categoria.estoque_peso <  p_ponto_pedido) THEN 
         
            p_lote_compras_bruto = round(cast((p_estoque_maximo + (rec_categoria.cmm_peso * (rec_categoria.tempo_ressuprimento + rec_categoria.desvio_padrao_ressuprimento)) - rec_categoria.estoque_peso) AS NUMERIC), 2);
            p_lote_compras = gerar_lote_embalagem(p_lote_compras_bruto, rec_categoria.lote_minimo);
        
         ELSE
         
            p_lote_compras_bruto = 0;
            p_lote_compras  = 0;
        
         END IF;
    
        -- se cobertura de estoque for menor que o tempo de ressuprimento então compre o emax
        IF (p_lote_compras_bruto > 0 AND rec_categoria.cobertura_estoque_peso < rec_categoria.tempo_ressuprimento) THEN 
               p_lote_compras_bruto = p_estoque_maximo;
               p_lote_compras  = gerar_lote_embalagem(p_lote_compras_bruto, rec_categoria.lote_minimo);
        END IF;
       
        UPDATE produtos_compras_categorias_mp_pa
        SET
            descricao_categoria = rec_categoria.descricao_categoria,
            estoque_peso = rec_categoria.estoque_peso,
            estoque_mp_peso = rec_categoria.estoque_mp_peso,
            estoque_pa = rec_categoria.estoque_pa,
            estoque_pa_peso = rec_categoria.estoque_pa_peso,
            estoque_bloqueado_peso = rec_categoria.estoque_bloqueado_peso,
            estoque_avaria_peso = rec_categoria.estoque_avaria_peso,
            estoque_reservado_peso = rec_categoria.estoque_reservado_peso,
            estoque_similar_peso = rec_categoria.estoque_similar_peso,
            cobertura_estoque_peso = rec_categoria.cobertura_estoque_peso,
            estoque_seguranca = p_estoque_seguranca,
            ponto_pedido = p_ponto_pedido,
            estoque_maximo = p_estoque_maximo,
            cmm_peso = rec_categoria.cmm_peso,
            cmm_pa_peso = rec_categoria.cmm_pa_peso,
            cmm_pa = rec_categoria.cmm_pa,
            desvio_padrao_consumo_peso = rec_categoria.desvio_padrao_consumo_peso,
            tempo_medio_ressuprimento = rec_categoria.tempo_medio_ressuprimento,
            prazo_medio_recebimento = rec_categoria.prazo_medio_recebimento,
            tempo_ressuprimento = rec_categoria.tempo_ressuprimento,
            desvio_padrao_ressuprimento = rec_categoria.desvio_padrao_ressuprimento,
            coeficiente_variacao = rec_categoria.coeficiente_variacao,
            estoque_transito_peso = rec_categoria.estoque_transito_peso,
            arvore_decisao = rec_categoria.arvore_decisao,
            nivel_servico = rec_categoria.nivel_servico,
            peso_compras = rec_categoria.peso_compras,
            lote_minimo = rec_categoria.lote_minimo,
            lote_compras_bruto = p_lote_compras_bruto ,
            lote_compras = p_lote_compras,
            perfil_demanda = rec_categoria.perfil_demanda,
            tempo_medio_apanhe = rec_categoria.tempo_medio_apanhe,
            unidade_compra = rec_categoria.unidade_compra,
            cobertura_manual_categoria = rec_categoria.cobertura_manual_categoria,
            custo_medio_unitario = rec_categoria.custo_medio_unitario,
            preco_medio_compra = rec_categoria.preco_medio_compra,
            idunidade_medida = rec_categoria.idunidade_medida,
            fator_conversao = rec_categoria.fator_conversao,
            fes = rec_categoria.fes,
            classificacao_financeira = rec_categoria.classificacao_financeira,
            classificacao_criticidade = rec_categoria.classificacao_criticidade,
            classificacao_comprabilidade = rec_categoria.classificacao_comprabilidade,
            classificacao_popularidade = rec_categoria.classificacao_popularidade,
            ultimo_preco_compra = rec_categoria.ultimo_preco_compra,
            processamento = current_timestamp,
            flag = NULL 
        WHERE 
            id_grupo = rec_categoria.id_grupo
            AND id_categoria = rec_categoria.id_categoria;
        
        IF NOT FOUND then
            INSERT INTO produtos_compras_categorias_mp_pa (
                id_grupo,
                id_categoria,
                descricao_categoria,
                idcomprador,
                estoque_peso,
                estoque_mp_peso,
                estoque_pa,
                estoque_pa_peso,
                estoque_bloqueado_peso,
                estoque_avaria_peso,
                estoque_reservado_peso,
                estoque_similar_peso,
                cobertura_estoque_peso,
                estoque_seguranca,
                ponto_pedido,
                estoque_maximo,
                cmm_peso,
                cmm_pa_peso,
                cmm_pa,
                desvio_padrao_consumo_peso,
                tempo_medio_ressuprimento,
                prazo_medio_recebimento,
                tempo_ressuprimento,
                desvio_padrao_ressuprimento,
                coeficiente_variacao,
                estoque_transito_peso,
                arvore_decisao,
                nivel_servico,
                peso_compras,
                lote_minimo,
                lote_compras_bruto,
                lote_compras,
                perfil_demanda,
                tempo_medio_apanhe,
                unidade_compra,
                cobertura_manual_categoria,
                custo_medio_unitario,
                preco_medio_compra,
                idunidade_medida,
                fator_conversao,
                fes,
                classificacao_financeira,
                classificacao_criticidade,
                classificacao_comprabilidade,
                classificacao_popularidade,
                ultimo_preco_compra,
                processamento,
                flag
            )
            VALUES (
                rec_categoria.id_grupo,
                rec_categoria.id_categoria,
                rec_categoria.descricao_categoria,
                rec_categoria.idcomprador,
                rec_categoria.estoque_peso,
                rec_categoria.estoque_mp_peso,
                rec_categoria.estoque_pa,
                rec_categoria.estoque_pa_peso,
                rec_categoria.estoque_bloqueado_peso,
                rec_categoria.estoque_avaria_peso,
                rec_categoria.estoque_reservado_peso,
                rec_categoria.estoque_similar_peso,
                rec_categoria.cobertura_estoque_peso,
                p_estoque_seguranca,
                p_ponto_pedido,
                p_estoque_maximo,
                rec_categoria.cmm_peso,
                rec_categoria.cmm_pa_peso,
                rec_categoria.cmm_pa,
                rec_categoria.desvio_padrao_consumo_peso,
                rec_categoria.tempo_medio_ressuprimento,
                rec_categoria.prazo_medio_recebimento,
                rec_categoria.tempo_ressuprimento,
                rec_categoria.desvio_padrao_ressuprimento,
                rec_categoria.coeficiente_variacao,
                rec_categoria.estoque_transito_peso,
                rec_categoria.arvore_decisao,
                rec_categoria.nivel_servico,
                rec_categoria.peso_compras,
                rec_categoria.lote_minimo,
                p_lote_compras_bruto,
                p_lote_compras,
                rec_categoria.perfil_demanda,
                rec_categoria.tempo_medio_apanhe,
                rec_categoria.unidade_compra,
                rec_categoria.cobertura_manual_categoria,
                rec_categoria.custo_medio_unitario,
                rec_categoria.preco_medio_compra,
                rec_categoria.idunidade_medida,
                rec_categoria.fator_conversao,
                rec_categoria.fes,
                rec_categoria.classificacao_financeira,
                rec_categoria.classificacao_criticidade,
                rec_categoria.classificacao_comprabilidade,
                rec_categoria.classificacao_popularidade,
                rec_categoria.ultimo_preco_compra,
                current_timestamp,
                NULL
            );
        END IF;
        
    END LOOP;

    DELETE FROM produtos_compras_categorias_mp_pa WHERE flag = 'D';
END;
$$;


ALTER FUNCTION public.processar_produtos_compras_categorias_mp_pa(f_grupo integer, f_categoria integer) OWNER TO systock;

--
-- TOC entry 794 (class 1255 OID 53924)
-- Name: processar_produtos_compras_filial(integer, bigint); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_produtos_compras_filial(filtro_filial integer DEFAULT 0, filtro_id_fornecedor bigint DEFAULT 0) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE 
	rec_produto_filial record;
BEGIN 
    
    update produtos_compras_filial 
    set flag='D' 
    where 
        (produtos_compras_filial.filial = filtro_filial OR filtro_filial = 0)
        AND (produtos_compras_filial.idfornecedor  = filtro_id_fornecedor OR filtro_id_fornecedor = 0);
    
	FOR rec_produto_filial IN (
		SELECT 
			lote.id_grupo,
			lote.filial,
			lote.idproduto,
			lote.descricao_produto,
			lote.idcomprador,
			lote.idfornecedor,
			lote.idfamilia_produto,
			lote.revenda,
			lote.status,
			lote.estoque,
			lote.cobertura_estoque,
			lote.estoque_seguranca,
			lote.ponto_pedido,
			lote.estoque_maximo,
			lote.consumo_medio_mensal,
			lote.desvio_padrao_consumo,
			lote.tempo_medio_ressuprimento,
			lote.tempo_ressuprimento,
			lote.desvio_padrao_ressuprimento,
			lote.coeficiente_variacao,
			lote.compra_transito,
			lote.lote_minimo,
			lote.lote_compras_bruto,
			lote.arvore_decisao,
			lote.nivel_servico,
			lote.peso_compras,
			lote.unidade_compra,
			lote.lote_embalagem,
			CASE
				WHEN lote.lote_compras_bruto > 0::numeric AND lote.lote_embalagem = 0::numeric THEN 1
				ELSE 0
			END AS sob_encomenda,
			--lote.lote_embalagem AS lote_compras,
			CASE
			    WHEN lote.lote_embalagem > 0::numeric AND COALESCE(round(lote.estoque / NULLIF(lote.consumo_medio_mensal, 0::numeric), 4), 0::numeric) < lote.tempo_ressuprimento AND lote.compra_transito = 0::numeric THEN gerar_lote_embalagem(lote.estoque_maximo, COALESCE(lote.lote_minimo, 1::numeric))
			    ELSE lote.lote_embalagem
			END AS lote_compras,
			lote.preco_compra,
			lote.custo_unitario,
			lote.valor_unitario,
			lote.estoque_bloqueado,
			CASE
				WHEN lote.coeficiente_variacao::numeric >= 0::numeric AND lote.coeficiente_variacao::numeric <= 200::numeric THEN 'REPETITIVO'::text
				WHEN lote.coeficiente_variacao::numeric > 200::numeric AND lote.coeficiente_variacao::numeric <= 600::numeric THEN 'ESTATISTICO'::text
				ELSE 'OCASIONAL'::text
			END AS perfil_demanda,
			lote.tempo_medio_apanhe,
			lote.embalagem,
			lote.idunidade_medida,
			lote.ressuprimento_manual,
			lote.ressuprimento_manual_dias,
			lote.cod_produto,
			lote.codigo_barras,
			lote.fator_atuacao,
			lote.estoque_avaria,
			lote.estoque_reservado,
			lote.multiplo_compra,
			lote.unidade_master,
			lote.tipo_fator_conversao,
			lote.compra_transito_entregue,
            lote.estoque_minimo,
            lote.classificacao_rentabilidade,
            lote.estoque_seguranca_estetico,
            lote.ponto_pedido_estetico,
            (lote.ponto_pedido_estetico + lote.consumo_medio_mensal) AS estoque_maximo_estetico,
			lote.estoque_pendente,
			lote.idsecao,
			lote.idcategoria
		FROM (
			SELECT 
				a.id_grupo,
				a.filial,
				a.idproduto,
				a.descricao_produto,
				a.idcomprador,
				a.idfornecedor,
				a.idfamilia_produto,
				a.revenda,
				a.status,
				a.estoque,
				a.cobertura_estoque,
				a.estoque_seguranca,
				a.ponto_pedido,
				a.estoque_maximo,
				a.consumo_medio_mensal,
				a.desvio_padrao_consumo,
				a.tempo_medio_ressuprimento,
				a.tempo_ressuprimento,
				a.desvio_padrao_ressuprimento,
				a.coeficiente_variacao,
				a.compra_transito,
				a.lote_minimo,
				CASE
					WHEN a.coeficiente_variacao::numeric >= 0::numeric AND a.compra_transito = 0::numeric AND a.estoque <= a.ponto_pedido AND a.revenda::text = 'S'::text AND a.status::text <> 'FL'::text THEN round(a.estoque_maximo + a.consumo_medio_mensal * (a.tempo_ressuprimento + a.desvio_padrao_ressuprimento) - a.estoque, 2)
					WHEN a.coeficiente_variacao::numeric = 0::numeric AND a.compra_transito = 0::numeric AND a.estoque <= a.ponto_pedido AND a.revenda::text = 'S'::text AND a.status::text <> 'FL'::text THEN ceil(a.consumo_medio_mensal / 2::numeric)
					ELSE 0::numeric
				END AS lote_compras_bruto,
				a.arvore_decisao,
				a.nivel_servico,
				a.peso_compras,
				a.unidade_compra,
				gerar_lote_embalagem(
					CASE
						WHEN a.coeficiente_variacao::numeric >= 0::numeric AND a.compra_transito = 0::numeric AND a.estoque <= a.ponto_pedido AND a.revenda::text = 'S'::text AND a.status::text <> 'FL'::text THEN round(a.estoque_maximo + a.consumo_medio_mensal * (a.tempo_ressuprimento + a.desvio_padrao_ressuprimento) - a.estoque, 2)
						WHEN a.coeficiente_variacao::numeric = 0::numeric AND a.compra_transito = 0::numeric AND a.estoque <= a.ponto_pedido AND a.revenda::text = 'S'::text AND a.status::text <> 'FL'::text THEN ceil(a.consumo_medio_mensal / 2::numeric)
						ELSE 0::numeric
					END, 
					COALESCE(a.lote_minimo, 1::numeric)
				) AS lote_embalagem,
				a.preco_compra,
				a.custo_unitario,
				a.valor_unitario,
				a.estoque_bloqueado,
				a.tempo_medio_apanhe,
				a.embalagem,
				a.idunidade_medida,
				a.ressuprimento_manual,
				a.ressuprimento_manual_dias,
				a.cod_produto,
				a.codigo_barras,
				a.fator_atuacao,
				a.estoque_avaria,
				a.estoque_reservado,
				a.multiplo_compra,
				a.unidade_master,
				a.tipo_fator_conversao,
				a.compra_transito_entregue,
				a.estoque_minimo,
				a.classificacao_rentabilidade,
                a.estoque_seguranca_estetico,
                (a.estoque_seguranca_estetico + ((a.consumo_medio_mensal / 30) * a.tempo_medio_ressuprimento)) AS ponto_pedido_estetico,
				a.estoque_pendente,
				a.idsecao,
				a.idcategoria
			FROM (
			    WITH compras_pendentes_com_entrega AS (
                    SELECT 
                        gf.id_grupo,
                        r.idfilial AS filial,
                        r.idproduto,
                        sum(r.qtde_entregue) AS compra_transito_entregue
                    FROM requisicoes r 
                        INNER JOIN grupo_filial gf ON gf.filial = r.idfilial 
                    WHERE 
                        r.qtde_pendente > 0
                        AND r.qtde_entregue > 0
                    GROUP BY 
                        r.idfilial,
                        gf.id_grupo,
                        r.idproduto 
                )
				SELECT 
					p.filial,
					g.id_grupo,
					p.idproduto,
					p.descricao_produto,
					p.idcomprador,
					p.idfornecedor,
					p.idfamilia_produto,
					p.revenda,
					p.status,
					p.unidade_compra,
					p.estoque * p.fator_conversao AS estoque,
					NULLIF(p.cobertura_estoque, 0::numeric) AS cobertura_estoque,
					p.estoque_seguranca * p.fator_conversao AS estoque_seguranca,
					p.ponto_pedido * p.fator_conversao AS ponto_pedido,
					p.estoque_maximo * p.fator_conversao AS estoque_maximo,
					p.consumo_medio_mensal * p.fator_conversao AS consumo_medio_mensal,
					p.desvio_padrao_consumo * p.fator_conversao AS desvio_padrao_consumo,
					p.tempo_medio_ressuprimento,
					p.tempo_ressuprimento,
					p.desvio_padrao_ressuprimento,
					p.coeficiente_variacao::text AS coeficiente_variacao,
					getcompra_transito_filial(p.filial::numeric, p.idproduto) AS compra_transito,
					p.lote_minimo * p.fator_conversao AS lote_minimo,
					p.arvore_decisao,
					p.nivel_servico,
					p.peso_compras,
					p.preco_compra,
					p.custo_unitario,
					p.valor_unitario,
					p.estoque_bloqueado * p.fator_conversao AS estoque_bloqueado,
					p.tempo_medio_apanhe,
					p.embalagem,
					p.idunidade_medida,
					p.ressuprimento_manual,
					COALESCE(p.ressuprimento_manual_dias, 0::numeric) AS ressuprimento_manual_dias,
					p.cod_produto,
					p.codigo_barras,
					p.fator_atuacao,
					p.estoque_avaria,
					COALESCE(p.estoque_reservado) AS estoque_reservado,
					p.multiplo_compra,
					p.unidade_master,
					p.tipo_fator_conversao,
                    COALESCE(cpce.compra_transito_entregue, 0) AS compra_transito_entregue,
                    p.estoque_minimo,
                    p.classificacao_rentabilidade,
                    p.estoque_minimo AS estoque_seguranca_estetico,
					p.estoque_pendente,
					p.idsecao,
					p.idcategoria
				FROM produtos_filial p
					JOIN grupo_filial g ON p.filial = g.filial
                    LEFT JOIN compras_pendentes_com_entrega cpce ON cpce.id_grupo = g.id_grupo AND  cpce.filial = p.filial AND  cpce.idproduto = p.idproduto
				WHERE 
					p.processar_analise::text = 'S'::text 
					AND p.revenda::text = 'S'::text
					AND p.status::text <> 'FL'::text 
					AND p.processar_analise::text = 'S'::TEXT
		    		AND (g.filial = filtro_filial OR filtro_filial = 0)
		    		AND (p.idfornecedor = filtro_id_fornecedor OR filtro_id_fornecedor = 0)
				ORDER BY p.idproduto, g.id_grupo, p.filial
			) a
		) lote
	)
	LOOP 
		UPDATE
		  public.produtos_compras_filial
		SET
		  id_grupo = rec_produto_filial.id_grupo,
		  descricao_produto = rec_produto_filial.descricao_produto,
		  idcomprador = rec_produto_filial.idcomprador,
		  idfornecedor = rec_produto_filial.idfornecedor,
          idfamilia_produto = rec_produto_filial.idfamilia_produto,
          iddepartamento = rec_produto_filial.idfamilia_produto,
		  revenda = rec_produto_filial.revenda,
		  status = rec_produto_filial.status,
		  estoque = rec_produto_filial.estoque,
		  cobertura_estoque = rec_produto_filial.cobertura_estoque,
		  estoque_seguranca = rec_produto_filial.estoque_seguranca,
		  ponto_pedido = rec_produto_filial.ponto_pedido,
		  estoque_maximo = rec_produto_filial.estoque_maximo,
		  consumo_medio_mensal = rec_produto_filial.consumo_medio_mensal,
		  desvio_padrao_consumo = rec_produto_filial.desvio_padrao_consumo,
		  tempo_medio_ressuprimento = rec_produto_filial.tempo_medio_ressuprimento,
		  tempo_ressuprimento = rec_produto_filial.tempo_ressuprimento,
		  desvio_padrao_ressuprimento = rec_produto_filial.desvio_padrao_ressuprimento,
		  coeficiente_variacao = rec_produto_filial.coeficiente_variacao,
		  compra_transito = rec_produto_filial.compra_transito,
		  lote_minimo = rec_produto_filial.lote_minimo,
		  lote_compras_bruto = rec_produto_filial.lote_compras_bruto,
		  arvore_decisao = rec_produto_filial.arvore_decisao,
		  nivel_servico = rec_produto_filial.nivel_servico,
		  peso_compras = rec_produto_filial.peso_compras,
		  unidade_compra = rec_produto_filial.unidade_compra,
		  lote_embalagem = rec_produto_filial.lote_embalagem,
		  sob_encomenda = rec_produto_filial.sob_encomenda,
		  lote_compras = rec_produto_filial.lote_compras,
		  preco_compra = rec_produto_filial.preco_compra,
		  custo_unitario = rec_produto_filial.custo_unitario,
		  valor_unitario = rec_produto_filial.valor_unitario,
		  estoque_bloqueado = rec_produto_filial.estoque_bloqueado,
		  perfil_demanda = rec_produto_filial.perfil_demanda,
		  tempo_medio_apanhe = rec_produto_filial.tempo_medio_apanhe,
		  embalagem = rec_produto_filial.embalagem,
		  idunidade_medida = rec_produto_filial.idunidade_medida,
		  ressuprimento_manual = rec_produto_filial.ressuprimento_manual,
		  ressuprimento_manual_dias = rec_produto_filial.ressuprimento_manual_dias,
		  cod_produto = rec_produto_filial.cod_produto,
		  codigo_barras = rec_produto_filial.codigo_barras,
		  fator_atuacao = rec_produto_filial.fator_atuacao,
		  estoque_avaria = rec_produto_filial.estoque_avaria,
		  estoque_reservado = rec_produto_filial.estoque_reservado,
		  multiplo_compra = rec_produto_filial.multiplo_compra,
		  unidade_master = rec_produto_filial.unidade_master,
		  tipo_fator_conversao = rec_produto_filial.tipo_fator_conversao,
		  compra_transito_entregue = rec_produto_filial.compra_transito_entregue,
		  estoque_minimo = rec_produto_filial.estoque_minimo,
		  processamento = current_timestamp,
          flag=NULL,
          classificacao_rentabilidade = rec_produto_filial.classificacao_rentabilidade,
          estoque_seguranca_estetico = rec_produto_filial.estoque_seguranca_estetico,
          ponto_pedido_estetico = rec_produto_filial.ponto_pedido_estetico,
          estoque_maximo_estetico = rec_produto_filial.estoque_maximo_estetico,
		  estoque_pendente = rec_produto_filial.estoque_pendente,
          idsecao = rec_produto_filial.idsecao,
		  idcategoria = rec_produto_filial.idcategoria
		WHERE
		  id_grupo = rec_produto_filial.id_grupo
		  and filial = rec_produto_filial.filial
		  AND idproduto = rec_produto_filial.idproduto;

		IF NOT FOUND THEN
			INSERT INTO public.produtos_compras_filial(
			    id_grupo, 
			    filial, 
			    idproduto, 
			    descricao_produto, 
			    idcomprador, 
			    idfornecedor, 
			    idfamilia_produto,
			    iddepartamento,
			    revenda, 
			    status, 
			    estoque, 
			    cobertura_estoque, 
			    estoque_seguranca, 
			    ponto_pedido,
			    estoque_maximo,
			    consumo_medio_mensal,
			    desvio_padrao_consumo,
			    tempo_medio_ressuprimento,
			    tempo_ressuprimento,
			    desvio_padrao_ressuprimento,
			    coeficiente_variacao,
			    compra_transito,
			    lote_minimo,
			    lote_compras_bruto,
			    arvore_decisao, 
			    nivel_servico, 
			    peso_compras, 
			    unidade_compra, 
			    lote_embalagem, 
			    sob_encomenda, 
			    lote_compras, 
			    preco_compra, 
			    custo_unitario, 
			    valor_unitario, 
			    estoque_bloqueado, 
			    perfil_demanda, 
			    tempo_medio_apanhe, 
			    embalagem, 
			    idunidade_medida, 
			    ressuprimento_manual, 
			    ressuprimento_manual_dias, 
			    cod_produto, 
			    codigo_barras, 
			    fator_atuacao, 
			    estoque_avaria, 
			    estoque_reservado, 
			    multiplo_compra, 
			    unidade_master,
				tipo_fator_conversao,
				compra_transito_entregue,
				estoque_minimo,
			    processamento,
			    classificacao_rentabilidade,
                estoque_seguranca_estetico,
                ponto_pedido_estetico,
                estoque_maximo_estetico,
				estoque_pendente,
	            idsecao,
				idcategoria
			)
			VALUES(
			    rec_produto_filial.id_grupo, 
			    rec_produto_filial.filial, 
			    rec_produto_filial.idproduto, 
			    rec_produto_filial.descricao_produto, 
			    rec_produto_filial.idcomprador, 
			    rec_produto_filial.idfornecedor, 
                rec_produto_filial.idfamilia_produto, 
                rec_produto_filial.idfamilia_produto, 
			    rec_produto_filial.revenda, 
			    rec_produto_filial.status, 
			    rec_produto_filial.estoque, 
			    rec_produto_filial.cobertura_estoque, 
			    rec_produto_filial.estoque_seguranca, 
			    rec_produto_filial.ponto_pedido,
			    rec_produto_filial.estoque_maximo,
			    rec_produto_filial.consumo_medio_mensal,
			    rec_produto_filial.desvio_padrao_consumo,
			    rec_produto_filial.tempo_medio_ressuprimento,
			    rec_produto_filial.tempo_ressuprimento,
			    rec_produto_filial.desvio_padrao_ressuprimento,
			    rec_produto_filial.coeficiente_variacao,
			    rec_produto_filial.compra_transito,
			    rec_produto_filial.lote_minimo,
			    rec_produto_filial.lote_compras_bruto,
			    rec_produto_filial.arvore_decisao, 
			    rec_produto_filial.nivel_servico, 
			    rec_produto_filial.peso_compras, 
			    rec_produto_filial.unidade_compra, 
			    rec_produto_filial.lote_embalagem, 
			    rec_produto_filial.sob_encomenda, 
			    rec_produto_filial.lote_compras, 
			    rec_produto_filial.preco_compra, 
			    rec_produto_filial.custo_unitario, 
			    rec_produto_filial.valor_unitario, 
			    rec_produto_filial.estoque_bloqueado, 
			    rec_produto_filial.perfil_demanda, 
			    rec_produto_filial.tempo_medio_apanhe, 
			    rec_produto_filial.embalagem, 
			    rec_produto_filial.idunidade_medida, 
			    rec_produto_filial.ressuprimento_manual, 
			    rec_produto_filial.ressuprimento_manual_dias, 
			    rec_produto_filial.cod_produto, 
			    rec_produto_filial.codigo_barras, 
			    rec_produto_filial.fator_atuacao, 
			    rec_produto_filial.estoque_avaria, 
			    rec_produto_filial.estoque_reservado, 
			    rec_produto_filial.multiplo_compra, 
			    rec_produto_filial.unidade_master,
		  		rec_produto_filial.tipo_fator_conversao,
		  		rec_produto_filial.compra_transito_entregue,
		  		rec_produto_filial.estoque_minimo,
			    current_timestamp,
			    rec_produto_filial.classificacao_rentabilidade,
                rec_produto_filial.estoque_seguranca_estetico,
                rec_produto_filial.ponto_pedido_estetico,
                rec_produto_filial.estoque_maximo_estetico,
				rec_produto_filial.estoque_pendente,
            	rec_produto_filial.idsecao,
				rec_produto_filial.idcategoria
			);
		END IF;
	END LOOP;
    
    delete from produtos_compras_filial 
    where
        flag='D' 
        and (produtos_compras_filial.filial = filtro_filial OR filtro_filial = 0)
        AND (produtos_compras_filial.idfornecedor  = filtro_id_fornecedor OR filtro_id_fornecedor = 0);
    
END;
$$;


ALTER FUNCTION public.processar_produtos_compras_filial(filtro_filial integer, filtro_id_fornecedor bigint) OWNER TO systock;

--
-- TOC entry 795 (class 1255 OID 53926)
-- Name: processar_produtos_compras_grupo(integer, bigint); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_produtos_compras_grupo(filtro_id_grupo integer DEFAULT 0, filtro_id_fornecedor bigint DEFAULT 0) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE 
	rec_produto_grupo record;
BEGIN 
    
    update produtos_compras_grupo  
    set flag='D' 
    where  
        (produtos_compras_grupo.id_grupo  = filtro_id_grupo OR filtro_id_grupo = 0)
        AND (produtos_compras_grupo.idfornecedor  = filtro_id_fornecedor OR filtro_id_fornecedor = 0);
    
	FOR rec_produto_grupo IN (
		SELECT 
			lote.id_grupo,
			lote.idproduto,
			lote.descricao_produto,
			lote.idcomprador,
			lote.idfornecedor,
			lote.idfamilia_produto,
			lote.revenda,
			lote.status,
			lote.estoque,
			COALESCE(round(lote.estoque / NULLIF(lote.consumo_medio_mensal, 0::numeric), 4), 0::numeric) AS cobertura_estoque,
			lote.estoque_seguranca,
			lote.ponto_pedido,
			lote.estoque_maximo,
			lote.consumo_medio_mensal,
			lote.desvio_padrao_consumo,
			lote.tempo_medio_ressuprimento,
			lote.tempo_ressuprimento,
			lote.desvio_padrao_ressuprimento,
			lote.coeficiente_variacao,
			lote.compra_transito,
			lote.lote_minimo,
			lote.lote_compras_bruto,
			lote.arvore_decisao,
			lote.nivel_servico,
			lote.peso_compras,
			lote.unidade_compra,
			lote.lote_embalagem,
			CASE
			    WHEN lote.flag_sob_encomenda::text = 'S'::text THEN 1
			    -- WHEN lote.lote_compras_bruto > 0::numeric AND lote.lote_embalagem = 0::numeric THEN 1 -- OCTADESK99905315
			    ELSE 0
			END AS sob_encomenda,
			CASE
			    WHEN lote.lote_embalagem > 0::numeric AND COALESCE(round(lote.estoque / NULLIF(lote.consumo_medio_mensal, 0::numeric), 4), 0::numeric) < lote.tempo_ressuprimento AND lote.compra_transito = 0::numeric THEN gerar_lote_embalagem(lote.estoque_maximo, COALESCE(lote.lote_minimo, 1::numeric))
			    ELSE lote.lote_embalagem
			END AS lote_compras,
			lote.preco_compra,
			lote.custo_unitario,
			lote.valor_unitario,
			lote.valor_liquido,
			lote.estoque_bloqueado,
			CASE 
				WHEN lote.coeficiente_variacao::numeric >= 0::numeric AND lote.coeficiente_variacao::numeric <= 200::numeric THEN 'REPETITIVO'::text
				WHEN lote.coeficiente_variacao::numeric > 200::numeric AND lote.coeficiente_variacao::numeric <= 600::numeric THEN 'ESTATISTICO'::text
				ELSE 'OCASIONAL'::text
			END AS perfil_demanda,
			lote.tempo_medio_apanhe,
			lote.embalagem,
			lote.idunidade_medida,
			lote.ressuprimento_manual,
			lote.ressuprimento_manual_dias,
			lote.cod_produto,
			lote.codigo_barras,
			lote.fator_conversao,
			lote.fator_atuacao,
			lote.projecao_rentabilidade,
			lote.estoque_avaria,
			lote.peso,
			lote.altura,
			lote.largura,
			lote.comprimento,
			(
				SELECT max(r.data_solicitacao) AS max
				FROM requisicoes r
			    WHERE r.idproduto::text = lote.idproduto::text AND (r.idfilial IN ( SELECT gf.filial FROM grupo_filial gf WHERE gf.id_grupo = lote.id_grupo))
			) AS data_ultima_requisicao,
			lote.estoque_reservado,
			lote.multiplo_compra::numeric(12,6) AS multiplo_compra,
			lote.unidade_master,
			lote.tipo_fator_conversao,
            lote.compra_transito_entregue,
            lote.detalhamento_tecnico,
            lote.estoque_minimo,
            lote.classificacao_rentabilidade,
            lote.estoque_seguranca_estetico,
            lote.ponto_pedido_estetico,
            (lote.ponto_pedido_estetico + lote.consumo_medio_mensal) AS estoque_maximo_estetico,
			lote.estoque_pendente,
			lote.idsecao,
			lote.idcategoria
		FROM (
			SELECT 
				a.id_grupo,
				a.idproduto,
				a.descricao_produto,
				a.idcomprador,
				a.idfornecedor,
				a.idfamilia_produto,
				a.revenda,
				a.status,
				a.estoque,
				a.cobertura_estoque,
				a.estoque_seguranca,
				a.ponto_pedido,
				a.estoque_maximo,
				a.consumo_medio_mensal,
				a.desvio_padrao_consumo,
				a.tempo_medio_ressuprimento,
				a.tempo_ressuprimento,
				a.desvio_padrao_ressuprimento,
				a.coeficiente_variacao,
				a.compra_transito,
				a.lote_minimo,
				CASE
					WHEN a.coeficiente_variacao::numeric >= 0::numeric AND a.compra_transito = 0::numeric AND a.estoque <= a.ponto_pedido AND a.revenda::text = 'S'::text AND a.status::text <> 'FL'::text THEN round(a.estoque_maximo + a.consumo_medio_mensal * (a.tempo_ressuprimento + a.desvio_padrao_ressuprimento) - a.estoque, 2)
					WHEN a.coeficiente_variacao::numeric = 0::numeric AND a.compra_transito = 0::numeric AND a.estoque <= a.ponto_pedido AND a.revenda::text = 'S'::text AND a.status::text <> 'FL'::text THEN ceil(a.consumo_medio_mensal / 2::numeric)
					ELSE 0::numeric
				END AS lote_compras_bruto,
				a.arvore_decisao,
				a.nivel_servico,
				a.peso_compras,
				a.unidade_compra,
				gerar_lote_embalagem(
				CASE
					WHEN a.coeficiente_variacao::numeric >= 0::numeric AND a.compra_transito = 0::numeric AND a.estoque <= a.ponto_pedido AND a.revenda::text = 'S'::text AND a.status::text <> 'FL'::text THEN round(a.estoque_maximo + a.consumo_medio_mensal * (a.tempo_ressuprimento + a.desvio_padrao_ressuprimento) - a.estoque, 2)
					WHEN a.coeficiente_variacao::numeric = 0::numeric AND a.compra_transito = 0::numeric AND a.estoque <= a.ponto_pedido AND a.revenda::text = 'S'::text AND a.status::text <> 'FL'::text THEN ceil(a.consumo_medio_mensal / 2::numeric)
				    ELSE 0::numeric
				END, 
				COALESCE(a.lote_minimo, 1::numeric)) AS lote_embalagem,
				a.preco_compra,
				a.custo_unitario,
				a.valor_unitario,
				a.valor_liquido,
				a.estoque_bloqueado,
				a.tempo_medio_apanhe,
				a.embalagem,
				a.idunidade_medida,
				a.ressuprimento_manual,
				a.ressuprimento_manual_dias,
				a.cod_produto,
				a.codigo_barras,
				a.fator_conversao,
				a.fator_atuacao,
				a.projecao_rentabilidade,
				a.estoque_avaria,
				a.peso,
				a.altura,
				a.largura,
				a.comprimento,
				a.flag_sob_encomenda,
				a.estoque_reservado,
				a.multiplo_compra,
				a.unidade_master,
				a.tipo_fator_conversao,
                a.compra_transito_entregue,
                a.detalhamento_tecnico,
                a.estoque_minimo,
                a.classificacao_rentabilidade,
                a.estoque_seguranca_estetico,
                (a.estoque_seguranca_estetico + ((a.consumo_medio_mensal / 30) * a.tempo_medio_ressuprimento)) AS ponto_pedido_estetico,
				a.estoque_pendente,
				a.idsecao,
				a.idcategoria
			FROM (
				WITH prismas AS (
					SELECT 
						gf.id_grupo,
				   		pf.idproduto,
				    	((min(pf.classificacao_financeira::text) || max(pf.classificacao_criticidade::text)) || min(pf.classificacao_comprabilidade)) || min(pf.classificacao_popularidade::text) AS arvore_decisao
				   	FROM produtos_filial pf
				    	JOIN grupo_filial gf ON gf.filial = pf.filial
				  	WHERE pf.processar_analise::text = 'S'::text
				  	GROUP BY gf.id_grupo, pf.idproduto
				),
                compras_pendentes_com_entrega AS (
                    SELECT 
                        gf.id_grupo,
                        r.idproduto,
                        sum(r.qtde_entregue) AS compra_transito_entregue
                    FROM requisicoes r 
                        INNER JOIN grupo_filial gf ON gf.filial = r.idfilial 
                    WHERE 
                        r.qtde_pendente > 0
                        AND r.qtde_entregue > 0
                    GROUP BY 
                        gf.id_grupo,
                        r.idproduto 
                )
				SELECT 
					g.id_grupo,
				    p.idproduto,
				    max(TRIM(BOTH FROM p.descricao_produto::text))::character varying(60) AS descricao_produto,
				    max(p.idcomprador) AS idcomprador,
				    max(p.idfornecedor) AS idfornecedor,
				    max(p.idfamilia_produto) AS idfamilia_produto,
				    max(p.revenda) as revenda,
				    min(p.status) as status,
				    p.unidade_compra,
				    sum(p.estoque * p.fator_conversao) AS estoque,
				    avg(NULLIF(p.cobertura_estoque, 0::numeric)) AS cobertura_estoque,
				    sum(p.estoque_seguranca * p.fator_conversao) AS estoque_seguranca,
				    sum(p.ponto_pedido * p.fator_conversao) AS ponto_pedido,
				    sum(p.estoque_maximo * p.fator_conversao) AS estoque_maximo,
				    sum(p.consumo_medio_mensal * p.fator_conversao) AS consumo_medio_mensal,
				    sum(p.desvio_padrao_consumo * p.fator_conversao) AS desvio_padrao_consumo,
				    avg(p.tempo_medio_ressuprimento) AS tempo_medio_ressuprimento,
				    avg(p.tempo_ressuprimento) AS tempo_ressuprimento,
				    avg(p.desvio_padrao_ressuprimento) AS desvio_padrao_ressuprimento,
				    coalesce((sum(p.desvio_padrao_consumo * p.fator_conversao)/nullif(sum(p.consumo_medio_mensal * p.fator_conversao),0)*100),0)::text AS coeficiente_variacao,
				    getcompra_transito_grupo(g.id_grupo::numeric, p.idproduto) AS compra_transito,
				    max(p.lote_minimo * p.fator_conversao) AS lote_minimo,
				    COALESCE(pm.arvore_decisao, 'CX2R'::text) AS arvore_decisao,
					getnivelservico(COALESCE(pm.arvore_decisao::character varying, 'CX2R'::character varying)) AS nivel_servico,
					getpesocompras(COALESCE(pm.arvore_decisao::character varying, 'CX2R'::character varying), "substring"(COALESCE(pm.arvore_decisao::character varying, 'CX2R'::character varying)::text, 3, 1)::numeric) AS peso_compras,
				    COALESCE(avg(NULLIF(p.preco_compra, 0::numeric)), 0::numeric) AS preco_compra,
				    COALESCE(avg(NULLIF(p.custo_unitario, 0::numeric)), 0::numeric) AS custo_unitario,
				    COALESCE(avg(NULLIF(p.valor_unitario, 0::numeric)), 0::numeric) AS valor_unitario,
					COALESCE(avg(NULLIF(p.valor_liquido, 0::numeric)), 0::numeric) AS valor_liquido,
				    sum(p.estoque_bloqueado * p.fator_conversao) AS estoque_bloqueado,
				    sum(p.tempo_medio_apanhe) AS tempo_medio_apanhe,
				    p.embalagem,
				    p.idunidade_medida,
				    max(p.ressuprimento_manual::text)::character varying(1) AS ressuprimento_manual,
				    max(COALESCE(p.ressuprimento_manual_dias, 0::numeric)) AS ressuprimento_manual_dias,
				    max(p.cod_produto::text)::character varying(30) AS cod_produto,
				    max(p.codigo_barras::text)::character varying(25) AS codigo_barras,
				    avg(p.fator_conversao) AS fator_conversao,
				    avg(p.fator_atuacao) AS fator_atuacao,
				    sum(p.projecao_rentabilidade) AS projecao_rentabilidade,
				    sum(p.estoque_avaria) AS estoque_avaria,
				    max(p.peso) AS peso,
				    max(p.altura) AS altura,
				    max(p.largura) AS largura,
				    max(p.comprimento) AS comprimento,
				    p.flag_sob_encomenda,
				    sum(COALESCE(p.estoque_reservado, 0::numeric)) AS estoque_reservado,
				    max(p.multiplo_compra) AS multiplo_compra,
				    max(p.unidade_master::text) AS unidade_master,
				    p.tipo_fator_conversao,
                    coalesce(cpce.compra_transito_entregue, 0) AS compra_transito_entregue,
                    max(p.detalhamento_tecnico) AS detalhamento_tecnico,
                    sum(p.estoque_minimo) as estoque_minimo,
                    min(p.classificacao_rentabilidade) AS classificacao_rentabilidade,
                    sum(p.estoque_minimo) AS estoque_seguranca_estetico,
					sum(p.estoque_pendente) as estoque_pendente,
					max(p.idsecao) as idsecao,
					max(p.idcategoria) as idcategoria
				FROM produtos_filial p
					INNER JOIN grupo_filial g ON p.filial = g.filial
			    	LEFT JOIN prismas pm ON pm.id_grupo = g.id_grupo AND pm.idproduto::text = p.idproduto::TEXT
                    LEFT JOIN compras_pendentes_com_entrega cpce ON cpce.id_grupo = g.id_grupo AND  cpce.idproduto = p.idproduto
		    	WHERE 
		    		(g.id_grupo = filtro_id_grupo OR filtro_id_grupo = 0)
		    		AND (p.idfornecedor = filtro_id_fornecedor OR filtro_id_fornecedor = 0)
                    AND p.revenda::text = 'S'::text 
					AND p.status::text <> 'FL'::text
                    AND p.processar_analise::text = 'S'::TEXT
			  	GROUP BY g.id_grupo, p.idproduto, p.unidade_compra, p.embalagem, p.idunidade_medida, p.flag_sob_encomenda, pm.arvore_decisao, p.tipo_fator_conversao, cpce.compra_transito_entregue
			) AS a	
		) AS lote
	)
	LOOP 
		UPDATE public.produtos_compras_grupo
		SET 
			descricao_produto = rec_produto_grupo.descricao_produto,
			idcomprador = rec_produto_grupo.idcomprador,
			idfornecedor = rec_produto_grupo.idfornecedor,
			idfamilia_produto = rec_produto_grupo.idfamilia_produto,
            iddepartamento = rec_produto_grupo.idfamilia_produto,
			revenda = rec_produto_grupo.revenda,
			status = rec_produto_grupo.status,
			estoque = rec_produto_grupo.estoque,
			cobertura_estoque = rec_produto_grupo.cobertura_estoque,
			estoque_seguranca = rec_produto_grupo.estoque_seguranca,
			ponto_pedido = rec_produto_grupo.ponto_pedido,
			estoque_maximo = rec_produto_grupo.estoque_maximo,
			consumo_medio_mensal = rec_produto_grupo.consumo_medio_mensal,
			desvio_padrao_consumo = rec_produto_grupo.desvio_padrao_consumo,
			tempo_medio_ressuprimento = rec_produto_grupo.tempo_medio_ressuprimento,
			tempo_ressuprimento = rec_produto_grupo.tempo_ressuprimento,
			desvio_padrao_ressuprimento = rec_produto_grupo.desvio_padrao_ressuprimento,
			coeficiente_variacao = rec_produto_grupo.coeficiente_variacao,
			compra_transito = rec_produto_grupo.compra_transito,
			lote_minimo = rec_produto_grupo.lote_minimo,
			lote_compras_bruto = rec_produto_grupo.lote_compras_bruto,
			arvore_decisao = rec_produto_grupo.arvore_decisao,
			nivel_servico = rec_produto_grupo.nivel_servico,
			peso_compras = rec_produto_grupo.peso_compras,
			unidade_compra = rec_produto_grupo.unidade_compra,
			lote_embalagem = rec_produto_grupo.lote_embalagem,
			sob_encomenda = rec_produto_grupo.sob_encomenda,
			lote_compras = rec_produto_grupo.lote_compras,
			preco_compra = rec_produto_grupo.preco_compra,
			custo_unitario = rec_produto_grupo.custo_unitario,
			valor_unitario = rec_produto_grupo.valor_unitario,
			valor_liquido = rec_produto_grupo.valor_liquido,
			estoque_bloqueado = rec_produto_grupo.estoque_bloqueado,
			perfil_demanda = rec_produto_grupo.perfil_demanda,
			tempo_medio_apanhe = rec_produto_grupo.tempo_medio_apanhe,
			embalagem = rec_produto_grupo.embalagem,
			idunidade_medida = rec_produto_grupo.idunidade_medida,
			ressuprimento_manual = rec_produto_grupo.ressuprimento_manual,
			ressuprimento_manual_dias = rec_produto_grupo.ressuprimento_manual_dias,
			cod_produto = rec_produto_grupo.cod_produto,
			codigo_barras = rec_produto_grupo.codigo_barras,
			fator_conversao = rec_produto_grupo.fator_conversao,
			fator_atuacao = rec_produto_grupo.fator_atuacao,
			projecao_rentabilidade = rec_produto_grupo.projecao_rentabilidade,
			estoque_avaria = rec_produto_grupo.estoque_avaria,
			peso = rec_produto_grupo.peso,
			altura = rec_produto_grupo.altura,
			largura = rec_produto_grupo.largura,
			comprimento = rec_produto_grupo.comprimento,
			data_ultima_requisicao = rec_produto_grupo.data_ultima_requisicao,
			estoque_reservado = rec_produto_grupo.estoque_reservado,
			multiplo_compra = rec_produto_grupo.multiplo_compra,
			unidade_master = rec_produto_grupo.unidade_master,
			tipo_fator_conversao = rec_produto_grupo.tipo_fator_conversao,
			processamento = current_timestamp,
            compra_transito_entregue = rec_produto_grupo.compra_transito_entregue,
            detalhamento_tecnico = rec_produto_grupo.detalhamento_tecnico,
            estoque_minimo = rec_produto_grupo.estoque_minimo,
            flag=NULL,
            classificacao_rentabilidade = rec_produto_grupo.classificacao_rentabilidade,
            estoque_seguranca_estetico = rec_produto_grupo.estoque_seguranca_estetico,
            ponto_pedido_estetico = rec_produto_grupo.ponto_pedido_estetico,
            estoque_maximo_estetico = rec_produto_grupo.estoque_maximo_estetico,
			estoque_pendente = rec_produto_grupo.estoque_pendente,
            idsecao = rec_produto_grupo.idsecao,
			idcategoria = rec_produto_grupo.idcategoria
		WHERE id_grupo = rec_produto_grupo.id_grupo AND idproduto = rec_produto_grupo.idproduto;

		IF NOT FOUND THEN
			INSERT INTO produtos_compras_grupo (
			    id_grupo,
			    idproduto,
			    descricao_produto,
			    idcomprador,
			    idfornecedor,
			    idfamilia_produto,
                iddepartamento,
			    revenda,
			    status,
			    estoque,
			    cobertura_estoque,
			    estoque_seguranca,
			    ponto_pedido,
			    estoque_maximo,
			    consumo_medio_mensal,
			    desvio_padrao_consumo,
			    tempo_medio_ressuprimento,
			    tempo_ressuprimento,
			    desvio_padrao_ressuprimento,
			    coeficiente_variacao,
			    compra_transito,
			    lote_minimo,
			    lote_compras_bruto,
			    arvore_decisao,
			    nivel_servico,
			    peso_compras,
			    unidade_compra,
			    lote_embalagem,
			    sob_encomenda,
			    lote_compras,
			    preco_compra,
			    custo_unitario,
			    valor_unitario,
				valor_liquido,
			    estoque_bloqueado,
			    perfil_demanda,
			    tempo_medio_apanhe,
			    embalagem,
			    idunidade_medida,
			    ressuprimento_manual,
			    ressuprimento_manual_dias,
			    cod_produto,
			    codigo_barras,
			    fator_conversao,
			    fator_atuacao,
			    projecao_rentabilidade,
			    estoque_avaria,
			    peso,
			    altura,
			    largura,
			    comprimento,
			    data_ultima_requisicao,
			    estoque_reservado,
			    multiplo_compra,
			    unidade_master,
				tipo_fator_conversao,
				compra_transito_entregue,
                detalhamento_tecnico,
			    processamento,
			    estoque_minimo,
			    classificacao_rentabilidade,
                estoque_seguranca_estetico,
                ponto_pedido_estetico,
                estoque_maximo_estetico,
				estoque_pendente,
	            idsecao,
				idcategoria
			)
			VALUES(
			    rec_produto_grupo.id_grupo,
			    rec_produto_grupo.idproduto,
			    rec_produto_grupo.descricao_produto,
			    rec_produto_grupo.idcomprador,
			    rec_produto_grupo.idfornecedor,
                rec_produto_grupo.idfamilia_produto,
                rec_produto_grupo.idfamilia_produto,
			    rec_produto_grupo.revenda,
			    rec_produto_grupo.status,
			    rec_produto_grupo.estoque,
			    rec_produto_grupo.cobertura_estoque,
			    rec_produto_grupo.estoque_seguranca,
			    rec_produto_grupo.ponto_pedido,
			    rec_produto_grupo.estoque_maximo,
			    rec_produto_grupo.consumo_medio_mensal,
			    rec_produto_grupo.desvio_padrao_consumo,
			    rec_produto_grupo.tempo_medio_ressuprimento,
			    rec_produto_grupo.tempo_ressuprimento,
			    rec_produto_grupo.desvio_padrao_ressuprimento,
			    rec_produto_grupo.coeficiente_variacao,
			    rec_produto_grupo.compra_transito,
			    rec_produto_grupo.lote_minimo,
			    rec_produto_grupo.lote_compras_bruto,
			    rec_produto_grupo.arvore_decisao,
			    rec_produto_grupo.nivel_servico,
			    rec_produto_grupo.peso_compras,
			    rec_produto_grupo.unidade_compra,
			    rec_produto_grupo.lote_embalagem,
			    rec_produto_grupo.sob_encomenda,
			    rec_produto_grupo.lote_compras,
			    rec_produto_grupo.preco_compra,
			    rec_produto_grupo.custo_unitario,
			    rec_produto_grupo.valor_unitario,
				rec_produto_grupo.valor_liquido,
			    rec_produto_grupo.estoque_bloqueado,
			    rec_produto_grupo.perfil_demanda,
			    rec_produto_grupo.tempo_medio_apanhe,
			    rec_produto_grupo.embalagem,
			    rec_produto_grupo.idunidade_medida,
			    rec_produto_grupo.ressuprimento_manual,
			    rec_produto_grupo.ressuprimento_manual_dias,
			    rec_produto_grupo.cod_produto,
			    rec_produto_grupo.codigo_barras,
			    rec_produto_grupo.fator_conversao,
			    rec_produto_grupo.fator_atuacao,
			    rec_produto_grupo.projecao_rentabilidade,
			    rec_produto_grupo.estoque_avaria,
			    rec_produto_grupo.peso,
			    rec_produto_grupo.altura,
			    rec_produto_grupo.largura,
			    rec_produto_grupo.comprimento,
			    rec_produto_grupo.data_ultima_requisicao,
			    rec_produto_grupo.estoque_reservado,
			    rec_produto_grupo.multiplo_compra,
			    rec_produto_grupo.unidade_master,
			    rec_produto_grupo.tipo_fator_conversao,
                rec_produto_grupo.compra_transito_entregue,
                rec_produto_grupo.detalhamento_tecnico,
			    current_timestamp,
			    rec_produto_grupo.estoque_minimo,
			    rec_produto_grupo.classificacao_rentabilidade,
                rec_produto_grupo.estoque_seguranca_estetico,
                rec_produto_grupo.ponto_pedido_estetico,
                rec_produto_grupo.estoque_maximo_estetico,
				rec_produto_grupo.estoque_pendente,
            	rec_produto_grupo.idsecao,
				rec_produto_grupo.idcategoria
			);
		END IF;
	END LOOP;
	
    
   delete from produtos_compras_grupo 
   where 
        flag='D' 
        and (produtos_compras_grupo.id_grupo  = filtro_id_grupo OR filtro_id_grupo = 0)
        AND (produtos_compras_grupo.idfornecedor  = filtro_id_fornecedor OR filtro_id_fornecedor = 0);
          
END;
$$;


ALTER FUNCTION public.processar_produtos_compras_grupo(filtro_id_grupo integer, filtro_id_fornecedor bigint) OWNER TO systock;

--
-- TOC entry 796 (class 1255 OID 53928)
-- Name: processar_produtos_forecast_categoria(integer, character varying, character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_produtos_forecast_categoria(p_grupo integer DEFAULT 0, p_departamento character varying DEFAULT '0'::character varying, p_idcategoria character varying DEFAULT '0'::character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
declare

rec_forecast record;

begin

update produtos_forecast_categorias
set flag ='D'
WHERE
	(id_grupo = p_grupo or p_grupo = 0)
	and (iddepartamento = p_departamento or p_departamento = '0')
	and (idcategoria = p_idcategoria or p_idcategoria = '0');

for rec_forecast in(
	select
		*,
		gerar_lote_embalagem(a.lote_compras_bruto, a.lote_minimo) AS lote_compras
	from
		(
		select
			pcc.id_grupo,
			pcc.iddepartamento,
			pcc.idsecao,
			pcc.idcategoria,
			pcc.descricao_categoria,
			pcc.consumo_medio_mensal,
			pcc.desvio_padrao_consumo ,
			pcc.estoque,
			pcc.ponto_pedido,
			pcc.estoque_maximo,
			(pcc.estoque - (((pcc.consumo_medio_mensal)/ 30) * COALESCE(c.tempo_forecast, d.tempo_forecast))) AS saldo_futuro,
			pcc.processamento,
			round((pcc.estoque_maximo + (pcc.consumo_medio_mensal * (pcc.tempo_ressuprimento  + pcc.desvio_padrao_ressuprimento) - pcc.estoque)), 2) AS lote_compras_bruto,
			pcc.tempo_ressuprimento,
			pcc.tempo_medio_ressuprimento,
			pcc.lote_minimo,
			pcc.nivel_servico
		from
			produtos_compras_categorias pcc
			INNER JOIN departamentos d ON d.iddepartamento::TEXT = pcc.iddepartamento
	        INNER JOIN categorias c ON c.idcategoria::TEXT = pcc.idcategoria
		where
			pcc.lote_compras = 0
			and pcc.compra_transito = 0
			and pcc.consumo_medio_mensal > 0
			and (pcc.id_grupo = p_grupo or p_grupo = 0)
			and (pcc.iddepartamento = p_departamento or p_departamento = '0')
			and (pcc.idcategoria = p_idcategoria or p_idcategoria = '0')
		) a
	where
		saldo_futuro <= ponto_pedido
  )
  loop


	update
		produtos_forecast_categorias
	set
		iddepartamento = rec_forecast.iddepartamento,
		idsecao = rec_forecast.idsecao,
		descricao_categoria = rec_forecast.descricao_categoria,
		consumo_medio_mensal = rec_forecast.consumo_medio_mensal,
		desvio_padrao_consumo = rec_forecast.desvio_padrao_consumo,
		estoque = rec_forecast.estoque,
		ponto_pedido = rec_forecast.ponto_pedido,
		estoque_maximo = rec_forecast.estoque_maximo,
		saldo_futuro = rec_forecast.saldo_futuro,
		lote_compras = rec_forecast.lote_compras,
		flag = null,
		tempo_ressuprimento = rec_forecast.tempo_ressuprimento,
		tempo_medio_ressuprimento = rec_forecast.tempo_medio_ressuprimento,
		lote_minimo = rec_forecast.lote_minimo,
		nivel_servico = rec_forecast.nivel_servico,
		processamento = current_timestamp
	where
		id_grupo = rec_forecast.id_grupo
		and idcategoria = rec_forecast.idcategoria;


	if not found then

		insert
			into
			produtos_forecast_categorias (
				id_grupo,
				iddepartamento,
				idsecao,
				idcategoria,
				descricao_categoria,
				consumo_medio_mensal,
				desvio_padrao_consumo,
				estoque,
				ponto_pedido,
				estoque_maximo,
				saldo_futuro,
				lote_compras,
				tempo_ressuprimento,
				tempo_medio_ressuprimento,
				lote_minimo,
				nivel_servico,
				processamento
			)
			values(
			    rec_forecast.id_grupo,
				rec_forecast.iddepartamento,
				rec_forecast.idsecao,
				rec_forecast.idcategoria,
				rec_forecast.descricao_categoria,
				rec_forecast.consumo_medio_mensal,
				rec_forecast.desvio_padrao_consumo,
				rec_forecast.estoque,
				rec_forecast.ponto_pedido,
				rec_forecast.estoque_maximo,
				rec_forecast.saldo_futuro,
				rec_forecast.lote_compras,
				rec_forecast.tempo_ressuprimento,
				rec_forecast.tempo_medio_ressuprimento,
				rec_forecast.lote_minimo,
				rec_forecast.nivel_servico,
				rec_forecast.processamento
			);

       end if;

	 end loop;


 delete
 from  produtos_forecast_categorias
 where  flag ='D'
	and (id_grupo = p_grupo or p_grupo = 0)
	and (iddepartamento = p_departamento or p_departamento = '0')
	and (idcategoria = p_idcategoria or p_idcategoria = '0');

end
$$;


ALTER FUNCTION public.processar_produtos_forecast_categoria(p_grupo integer, p_departamento character varying, p_idcategoria character varying) OWNER TO systock;

--
-- TOC entry 797 (class 1255 OID 53929)
-- Name: processar_produtos_transito(bigint); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_produtos_transito(p_fornecedor bigint DEFAULT 0) RETURNS void
    LANGUAGE plpgsql
    AS $$
declare
 
rec_transito record;
rec_pedidos record;

p_atraso int4;
qtde_transito_atraso numeric;
qtde_transito numeric;
qtde_estoque numeric;
qtde_saldo  numeric;
p_ponto_pedido numeric;
p_sugestao numeric;
p_emax numeric;
p_cmm numeric;
p_tr numeric;
p_consumo_transito numeric;
p_consumo_transito2 numeric;
qtde_saldo_futuro numeric;
qtde_saldo_residual numeric;
p_status_transito varchar;
qtde_lote_minimo  numeric;
qtde_cobertura_futura numeric;
qtde_dias numeric;
cont_ped numeric;
consumo_transito_cal numeric;
data_temp date;
begin
    
--p_fornecedor = 0;   
    
    
if p_fornecedor = 0 then 

update produtos_transito set flag ='D' where id_grupo in (select id from grupo_compras);

for rec_transito in(
SELECT a.id_grupo,
    a.idfornecedor,
    a.fornecedor,
    a.idcomprador,
    a.comprador,
    a.idproduto,
    a.descricao_produto,
    a.iddepartamento,
    a.departamento,
    a.compra_transito,
    a.consumo_transito * a.fator_conversao AS consumo_transito,
    a.saldo_futuro * a.fator_conversao AS saldo_futuro,
    a.estoque_maximo * a.fator_conversao::double precision AS estoque_maximo,
    a.ponto_pedido * a.fator_conversao::double precision AS ponto_pedido,
    a.consumo_medio_mensal::double precision * a.fator_conversao::double precision AS consumo_medio_mensal,
    a.tempo_ressuprimento,
    a.desvio_padrao_ressuprimento,
    a.estoque::double precision * a.fator_conversao::double precision AS estoque,
    a.status,
        CASE
            WHEN a.status = 'PREVISÃO FUTURA EM EXCESSO'::text AND abs(a.lote_compras * a.fator_conversao::double precision) > a.compra_transito::double precision THEN (a.compra_transito * '-1'::integer::numeric)::double precision
            ELSE gerar_lote_embalagem((a.lote_compras * a.fator_conversao::double precision)::numeric, a.lote_minimo::numeric * a.fator_conversao)::double precision
        END AS lote_compras,
    a.fator_conversao,
    a.unidade_compra,
    a.data_ultima_riquisicao,
    'now'::text::date - a.data_ultima_riquisicao AS tempo_pedido,
    a.nivel_servico,
    a.peso_compras,
        CASE
            WHEN ('now'::text::date - a.data_ultima_riquisicao - 1) < 0 THEN NULL::integer
            ELSE 'now'::text::date - a.data_ultima_riquisicao - 1
        END AS gatilho_transito,
     a.lote_minimo    
   FROM ( SELECT analise_entrada.idfornecedor,
            analise_entrada.fornecedor,
            analise_entrada.idcomprador,
            analise_entrada.comprador,
            analise_entrada.idproduto,
            analise_entrada.descricao_produto,
            analise_entrada.compra_transito,
            analise_entrada.consumo_transito,
            analise_entrada.saldo_futuro,
            analise_entrada.estoque_maximo,
            analise_entrada.ponto_pedido,
            analise_entrada.consumo_medio_mensal,
            analise_entrada.tempo_ressuprimento,
            analise_entrada.desvio_padrao_ressuprimento,
            analise_entrada.estoque,
            analise_entrada.fator_conversao,
            analise_entrada.unidade_compra,
            analise_entrada.lote_minimo,
            analise_entrada.data_ultima_riquisicao,
            analise_entrada.id_grupo,
            analise_entrada.iddepartamento,
            analise_entrada.descricao_departamento AS departamento,
            analise_entrada.nivel_servico,
            analise_entrada.peso_compras,
                case
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) <= 1 THEN 'PRODUTO EM TRANSITO'::text
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.estoque_maximo THEN 'PREVISÃO FUTURA EM EXCESSO'::text
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.ponto_pedido AND analise_entrada.saldo_futuro::double precision <= analise_entrada.estoque_maximo AND (analise_entrada.saldo_futuro::double precision - analise_entrada.consumo_medio_mensal::double precision * 0.3::double precision) > analise_entrada.ponto_pedido THEN 'PREVISÃO FUTURA ADEQUADA'::text
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.ponto_pedido AND analise_entrada.saldo_futuro::double precision <= analise_entrada.estoque_maximo AND (analise_entrada.saldo_futuro::double precision - analise_entrada.consumo_medio_mensal::double precision * 0.3::double precision) <= analise_entrada.ponto_pedido THEN 'PREVISÃO COM SUTIL EXPOSIÇÃO A RUPTURA'::text
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision <= analise_entrada.ponto_pedido THEN 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA'::text
                    ELSE 'PRIMEIRA COMPRA'::text
                END AS status,
                CASE
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.estoque_maximo THEN analise_entrada.estoque_maximo - analise_entrada.saldo_futuro::double precision
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.ponto_pedido AND analise_entrada.saldo_futuro::double precision <= analise_entrada.estoque_maximo AND (analise_entrada.saldo_futuro::double precision - analise_entrada.consumo_medio_mensal::double precision * 0.3::double precision) > analise_entrada.ponto_pedido THEN 0::double precision
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.ponto_pedido AND analise_entrada.saldo_futuro::double precision <= analise_entrada.estoque_maximo AND (analise_entrada.saldo_futuro::double precision - analise_entrada.consumo_medio_mensal::double precision * 0.3::double precision) <= analise_entrada.ponto_pedido THEN round((analise_entrada.estoque_maximo - (analise_entrada.saldo_futuro::double precision- getconsumo_transito_grupo_entre_pedidos(analise_entrada.id_grupo::numeric, analise_entrada.idproduto)))::numeric, 2)::double precision
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision <= analise_entrada.ponto_pedido THEN round((analise_entrada.estoque_maximo - (analise_entrada.saldo_futuro::double precision - getconsumo_transito_grupo_entre_pedidos(analise_entrada.id_grupo::numeric, analise_entrada.idproduto)))::numeric, 2)::double precision
                    ELSE 0::double precision
                END AS lote_compras
           FROM ( SELECT b.id_grupo,
                    b.idfornecedor,
                    b.fornecedor,
                    b.idcomprador,
                    b.comprador,
                    b.idproduto,
                    max(b.descricao_produto::text) AS descricao_produto,
                    b.iddepartamento,
                    b.descricao_departamento,
                    b.fator_conversao,
                    b.unidade_compra,
                    max(b.lote_minimo) AS lote_minimo,
                    max(b.data_ultima_riquisicao) AS data_ultima_riquisicao,
                    b.arvore_decisao,
                    b.nivel_servico,
                    b.peso_compras,
                    avg(b.compra_transito) AS compra_transito,
                    sum(b.consumo_transito) AS consumo_transito,
                        CASE
                            WHEN (greatest((avg(b.estoque) - sum(b.consumo_transito)),0) + avg(b.compra_transito)) < 0::numeric THEN 0::numeric
                            ELSE greatest((avg(b.estoque) - sum(b.consumo_transito)),0) + avg(b.compra_transito)
                        END AS saldo_futuro,
                    avg(b.amplitude_atual) AS amplitude_atual,
                    avg(b.estoque_maximo) AS estoque_maximo,
                    avg(b.ponto_pedido) AS ponto_pedido,
                    avg(b.consumo_medio_mensal) AS consumo_medio_mensal,
                    avg(b.tempo_ressuprimento) AS tempo_ressuprimento,
                    avg(b.desvio_padrao_ressuprimento) AS desvio_padrao_ressuprimento,
                    avg(b.estoque) AS estoque,
                    avg(b.status_compra) AS status_compra
                   FROM ( SELECT g.id_grupo,
                            p.filial,
                            fornecedor.id AS idfornecedor,
                            fornecedor.razao_social AS fornecedor,
                            comprador.id AS idcomprador,
                            comprador.nome_completo AS comprador,
                            p.idproduto,
                            p.descricao_produto,
                            dep.iddepartamento,
                            dep.descricao_departamento,
                            getcompra_transito_grupo(g.id_grupo::numeric, p.idproduto) AS compra_transito,
                             case when ((select count(*) from analise_requisicoes ar  
                                        where filial in(select filial from grupo_filial gf where gf.id_grupo=g.id_grupo::numeric)  
                                        and idproduto=p.idproduto and atraso  > 0) > 0)  then 
                                        
                                     getconsumo_transito_grupo_new(g.id_grupo::numeric, p.idproduto) +  getconsumo_transito_grupo_2(g.id_grupo::numeric, p.idproduto)
                                        
                               else 
                               
                                 getconsumo_transito_grupo_new(g.id_grupo::numeric, p.idproduto)
                               
                             end  as consumo_transito,
                            getconsumo_transito_grupo_2(g.id_grupo::numeric, p.idproduto)  AS consumo_transito_2,
                              case when ((select count(*) from analise_requisicoes ar  
                                        where filial in(select filial from grupo_filial gf where gf.id_grupo=g.id_grupo::numeric)  
                                        and idproduto=p.idproduto and atraso  > 0) > 0)  then 
                                   1 else 0 end as atraso,     
                            amplitude_transito_atual_filial(p.filial::numeric, p.idproduto) AS amplitude_atual,
                            COALESCE(vp.estoque_maximo::double precision, 0::double precision) AS estoque_maximo,
                            COALESCE(vp.ponto_pedido::double precision, 0::double precision) AS ponto_pedido,
                            vp.consumo_medio_mensal,
                            p.tempo_ressuprimento,
                            p.desvio_padrao_ressuprimento,
                            get_estoque_grupo(g.id_grupo::numeric, p.idproduto) AS estoque,
                            ( SELECT
                                    CASE
                                     WHEN count(*) > 0 THEN 0
                                     ELSE 1
                                    END AS "case"
                                   FROM entrada_mercadorias
                                  WHERE entrada_mercadorias.data_entrada <= 'now'::text::date AND entrada_mercadorias.idproduto::text = p.idproduto::text AND entrada_mercadorias.qtde > 0::double precision) AS status_compra,
                            p.fator_conversao,
                            p.unidade_compra,
                            COALESCE(p.lote_minimo::double precision, 1::double precision) AS lote_minimo,
                            p.data_ultima_riquisicao,
                            get_arvore_decisao_grupo(g.id_grupo::numeric, p.idproduto)::text AS arvore_decisao,
                            getnivelservico(get_arvore_decisao_grupo(g.id_grupo::numeric, p.idproduto)) AS nivel_servico,
                            getpesocompras(get_arvore_decisao_grupo(g.id_grupo::numeric, p.idproduto), "substring"(get_arvore_decisao_grupo(g.id_grupo::numeric, p.idproduto)::text, 3, 1)::numeric) AS peso_compras
                           FROM produtos_filial p
                             LEFT JOIN comprador ON comprador.id = p.idcomprador
                             JOIN grupo_filial g ON g.filial = p.filial
                             JOIN departamentos dep ON dep.iddepartamento = p.idfamilia_produto
                             JOIN vw_grupo_compras_produtos_mt vp ON vp.id_grupo = g.id_grupo AND vp.idproduto::text = p.idproduto::text
                             LEFT JOIN fornecedor ON fornecedor.id = vp.idfornecedor
                          where p.revenda::text = 'S'::text AND p.status::text <> 'FL'::text 
                          AND getcompra_transito_grupo(g.id_grupo::numeric, p.idproduto) > 0::numeric
                          
                          ) b
                  GROUP BY b.id_grupo, b.idfornecedor, b.fornecedor, b.idcomprador, b.comprador, b.idproduto, b.descricao_departamento, b.fator_conversao,
                   b.unidade_compra, b.arvore_decisao, b.nivel_servico, b.peso_compras, b.iddepartamento) analise_entrada
          WHERE analise_entrada.compra_transito > 0::numeric) a
)
  loop 
      
      
      p_atraso=0;
      qtde_transito_atraso =0;
      qtde_transito=0;
      qtde_estoque=0;
      p_sugestao= 0;
      p_consumo_transito =0;
      p_consumo_transito2 = 0;
      qtde_saldo_futuro = 0;
      qtde_lote_minimo =  coalesce(rec_transito.lote_minimo,1);
      qtde_cobertura_futura=0;
      consumo_transito_cal = 0;
      
      
        --Identificar se o produto tem compra em atraso
      
        select count(*) into p_atraso  from analise_requisicoes ar  
        where filial in(select filial from grupo_filial gf where gf.id_grupo=rec_transito.id_grupo)  
        and idproduto=rec_transito.idproduto and atraso  >= 0  and qtde_pendente > 0;
       
       
        -- Pedidos em atraso;
       
        select  sum(qtde_pendente)  into qtde_transito_atraso 
          from analise_requisicoes r inner join produtos_filial pf on r.filial  = pf.filial and r.idproduto = pf.idproduto 
          where r.idproduto = rec_transito.idproduto and qtde_pendente > 0 and atraso >=0
        and r.filial  in (select filial from grupo_filial where id_grupo= rec_transito.id_grupo) ;  
       
        qtde_transito_atraso = coalesce(qtde_transito_atraso,0);
       
        --Pedidos em Transito Aberto;
      
          select  sum(qtde_pendente)  into qtde_transito 
          from analise_requisicoes r inner join produtos_filial pf on r.filial  = pf.filial and r.idproduto = pf.idproduto 
          where r.idproduto = rec_transito.idproduto and qtde_pendente > 0 and atraso < 0
        and r.filial  in (select filial from grupo_filial where id_grupo= rec_transito.id_grupo) ; 
         
        qtde_transito = coalesce(qtde_transito,0);

       
        -- Parâmetros do Estoque;
       
        qtde_estoque = rec_transito.estoque;
        p_ponto_pedido = rec_transito.ponto_pedido;
        p_emax = rec_transito.estoque_maximo;
        p_cmm = rec_transito.consumo_medio_mensal;
        p_tr =  rec_transito.tempo_ressuprimento;
       
        p_consumo_transito = getconsumo_transito_grupo_new(rec_transito.id_grupo,rec_transito.idproduto);
        
       
        --Somente itens atrasados
       
        if p_atraso > 0 and qtde_transito = 0 then   
        
        
            qtde_transito = greatest(qtde_transito,0);
           
            qtde_saldo = qtde_estoque + qtde_transito_atraso + qtde_transito;
        
            qtde_saldo_residual =  qtde_saldo - p_consumo_transito ;
           
           
            if qtde_saldo_residual > p_emax then -- Excesso
            
             
              p_sugestao =  p_emax - qtde_saldo_residual;
            
             
             if abs(p_sugestao) > qtde_transito_atraso then
             
              
                p_sugestao = qtde_transito_atraso *(-1);
             
             end if;
             
            
            elseif qtde_saldo_residual > p_ponto_pedido AND qtde_saldo_residual <= p_emax AND (qtde_saldo_residual - (p_cmm * 0.30)) > p_ponto_pedido then  -- Adequado
              
            
              p_sugestao = 0;
              p_status_transito = 'PREVISÃO ADEQUADA';
             
             
            elseif qtde_saldo_residual > p_ponto_pedido AND qtde_saldo_residual <= p_emax AND (qtde_saldo_residual - (p_cmm * 0.30)) <= p_ponto_pedido  then 
           
            
            
                p_consumo_transito2 = getconsumo_transito_grupo_2(rec_transito.id_grupo,rec_transito.idproduto);
          
     
                p_sugestao =  (p_emax - greatest(qtde_saldo_residual-p_consumo_transito2, 0));  
           

            
                  qtde_cobertura_futura =  round(qtde_saldo_residual/ greatest(p_cmm, 1),2);
                 
                  if qtde_cobertura_futura < p_tr then
                  
                    
                    p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';
                    
                  
                    else
                    
                    
                    p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';
                  
                  end if;
             
             
            elseif  ( qtde_saldo_residual  <= p_ponto_pedido) then
            
           
                        
              p_consumo_transito2 = getconsumo_transito_grupo_2(rec_transito.id_grupo,rec_transito.idproduto);
              
             
              p_sugestao =  (p_emax - greatest(qtde_saldo_residual-p_consumo_transito2, 0)); --
              qtde_cobertura_futura =  round(qtde_saldo_residual/ greatest(p_cmm, 1),2);
             
             
              if qtde_cobertura_futura < p_tr then
              
                
                p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';
                
              
                else
                
                
                p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';
              
              end if;
                      
            
            else
            
              p_sugestao = 0;
              p_status_transito = 'PRODUTO EM TRÂNSITO';
             
            
            end if;
            
          
            p_sugestao = gerar_lote_embalagem(p_sugestao,qtde_lote_minimo);
           
           
           
        elseif p_atraso = 0 and  qtde_transito > 0  then --Somente itens Abertos
        
        
        
            qtde_transito = greatest(qtde_transito,0);
        
            qtde_saldo = qtde_estoque;
        
        
            -- Quantidade de Pedidos Abertos 
        
        
            cont_ped = 1;
                          
            qtde_saldo_futuro= 0;
            
          
            for rec_pedidos in ( select  data_prevista_cal,sum(qtde) qtde
                    from analise_requisicoes r inner join produtos_filial pf on r.filial  = pf.filial and r.idproduto = pf.idproduto 
                where r.idproduto = rec_transito.idproduto and qtde_pendente > 0 and atraso < 0
              and r.filial  in (select filial from grupo_filial where id_grupo= rec_transito.id_grupo ) group by data_prevista_cal order by data_prevista_cal)
              
             loop 
                 
                 
                  if cont_ped = 1 then 
                 
                      data_temp= rec_pedidos.data_prevista_cal;
                      qtde_dias =  rec_pedidos.data_prevista_cal - current_date ;
                      p_tr = (qtde_dias/30);
                     
                 
                    else
                   
                    
                     qtde_dias = ((rec_pedidos.data_prevista_cal)  - data_temp) ;
                     p_tr = (qtde_dias/30);
                     data_temp= rec_pedidos.data_prevista_cal;
                    
                    
                 end if;       
                         
                
                 consumo_transito_cal = round((p_cmm * (qtde_dias/30)),2);
                
                 
                 if  consumo_transito_cal > qtde_saldo then 
                 
                 
                     consumo_transito_cal = qtde_saldo;
                    
                     qtde_saldo_residual = qtde_saldo - consumo_transito_cal;
                 
                 
                 else
                 
                    qtde_saldo_residual = qtde_saldo - consumo_transito_cal; 
                 
                 end if;
                 
                
                 qtde_saldo_futuro = qtde_saldo_residual + rec_pedidos.qtde;
                   
                 qtde_saldo = qtde_saldo_futuro;    
                        
                                 
                 cont_ped = cont_ped + 1;
                 
                
             end loop;
             
                   
           
            if qtde_saldo_futuro > p_emax then
            
          
              p_sugestao =  p_emax - qtde_saldo_futuro;
              p_status_transito = 'PREVISÃO EM EXCESSO';
             
              
             
              if abs(p_sugestao) > rec_transito.compra_transito then
             
              
                p_sugestao = rec_transito.compra_transito *(-1);
             
             end if;
             
            
            elseif qtde_saldo_futuro > p_ponto_pedido AND qtde_saldo_futuro <= p_emax AND (qtde_saldo_futuro - (p_cmm * 0.30)) > p_ponto_pedido then 
              
             p_sugestao = 0;
             p_status_transito = 'PREVISÃO ADEQUADA';
             
             
            elseif qtde_saldo_futuro > p_ponto_pedido AND qtde_saldo_futuro <= p_emax AND (qtde_saldo_futuro - (p_cmm * 0.30)) <= p_ponto_pedido  then 
           
             if qtde_transito > 0 then
            
                        select
    
                                --((current_date + (produtos.tempo_medio_ressuprimento::int4)) - ((current_date + ((vw_requisicoes.data_solicitacao+produtos.tempo_medio_ressuprimento::int4) - current_date)) - current_date) - current_date)::numeric/30  into p_tr
                           		GREATEST((current_date + produtos.tempo_medio_ressuprimento::int4) - COALESCE(vw_requisicoes.data_prevista_cal, vw_requisicoes.data_previsao), 0) / 30.0 into p_tr -- Lucas: tempo entre a ultima entrada prevista e a entrada da sugestão de compra
                        from
                    
                            vw_requisicoes
                    
                         inner join produtos_filial  as produtos
                    
                       on  produtos.filial =vw_requisicoes.filial and  produtos.idproduto = vw_requisicoes.idproduto::varchar
                    
                        where
                    
                            vw_requisicoes.idproduto::varchar = rec_transito.idproduto  
                            and vw_requisicoes.filial in (select filial from grupo_filial gf where id_grupo= rec_transito.id_grupo )
                    
                            and data_entrada isnull  order by COALESCE(vw_requisicoes.data_prevista_cal, vw_requisicoes.data_previsao, vw_requisicoes.data_solicitacao) desc limit 1;
                
                  end if;   
                 
                 
              p_sugestao = (p_emax - (greatest(qtde_saldo_futuro-(p_cmm *p_tr),0))); 
             
             
              qtde_cobertura_futura =  round(qtde_saldo_futuro/ greatest(p_cmm, 1),2);
             
              if qtde_cobertura_futura < p_tr then
              
                
                p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';
                
              
                else
                
                
                p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';
              
              end if;
             
             
            elseif  ( qtde_saldo_futuro  <= p_ponto_pedido) then
            
               
               
                if qtde_transito > 0 then
            
                        select
    
                                --((current_date + (produtos.tempo_medio_ressuprimento::int4)) - ((current_date + ((vw_requisicoes.data_solicitacao+produtos.tempo_medio_ressuprimento::int4) - current_date)) - current_date) - current_date)::numeric/30  into p_tr
                           		GREATEST((current_date + produtos.tempo_medio_ressuprimento::int4) - COALESCE(vw_requisicoes.data_prevista_cal, vw_requisicoes.data_previsao), 0) / 30.0 into p_tr -- Lucas: tempo entre a ultima entrada prevista e a entrada da sugestão de compra
                           
                        from
                    
                            vw_requisicoes
                    
                         inner join produtos_filial  as produtos
                    
                       on  produtos.filial =vw_requisicoes.filial and  produtos.idproduto = vw_requisicoes.idproduto::varchar
                    
                        where
                    
                            vw_requisicoes.idproduto::varchar = rec_transito.idproduto  
                            and vw_requisicoes.filial in (select filial from grupo_filial gf where id_grupo= rec_transito.id_grupo )
                    
                            and data_entrada isnull  order by COALESCE(vw_requisicoes.data_prevista_cal, vw_requisicoes.data_previsao, vw_requisicoes.data_solicitacao) desc limit 1;
                
                  end if;   
                 
                
                 p_sugestao = (p_emax - (greatest(qtde_saldo_futuro-(p_cmm *p_tr),0)));
			  
                  qtde_cobertura_futura =  round(qtde_saldo_futuro/ greatest(p_cmm, 1),2);
             
                  if qtde_cobertura_futura < p_tr then
                  
                    
                    p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';
                    
                  
                    else
                    
                    
                    p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';
                  
                  end if;
             
            
            
            else
            
              p_sugestao = 0;
             
              p_status_transito = 'PRODUTO EM TRÂNSITO';
             
            
            end if;
           
           
         else    -- COMPRAS HIBRIDAS
            
      
        
            qtde_transito = greatest(qtde_transito,0);
        
            qtde_saldo = qtde_estoque +  qtde_transito_atraso;

        
            cont_ped = 1;
           
          
            qtde_saldo_futuro= 0;
           
           
           
          
            for rec_pedidos in (select  data_prevista_cal,sum(qtde) qtde
                    from analise_requisicoes r inner join produtos_filial pf on r.filial  = pf.filial and r.idproduto = pf.idproduto 
                where r.idproduto = rec_transito.idproduto and qtde_pendente > 0 and atraso < 0
              and r.filial  in (select filial from grupo_filial where id_grupo= rec_transito.id_grupo ) group by data_prevista_cal order by data_prevista_cal)
              
             loop 
                 
                 
                if cont_ped = 1 then 
                 
                      data_temp= rec_pedidos.data_prevista_cal;
                      qtde_dias =  rec_pedidos.data_prevista_cal - current_date ;
                      p_tr = (qtde_dias/30);
                     
                 
                    else
                   
                    
                     qtde_dias = ((rec_pedidos.data_prevista_cal)  - data_temp) ;
                     p_tr = (qtde_dias/30);
                     data_temp= rec_pedidos.data_prevista_cal;
                    
                    
                 end if;    
                
                 
                
                 consumo_transito_cal = round((p_cmm * (qtde_dias/30)),2);
                
                 
                 if  consumo_transito_cal > qtde_saldo then 
                 
                 
                     consumo_transito_cal = qtde_saldo;
                    
                     qtde_saldo_residual = qtde_saldo - consumo_transito_cal;
                 
                 
                 else
                 
                    qtde_saldo_residual = qtde_saldo - consumo_transito_cal; 
                 
                 end if;
                 
                
                 qtde_saldo_futuro = qtde_saldo_residual + rec_pedidos.qtde;
                   
                 qtde_saldo = qtde_saldo_futuro;    
        
                 
                 cont_ped = cont_ped + 1;
                 
                
             end loop;
             
         
           
            if qtde_saldo_futuro > p_emax then
            
            
              p_sugestao =  p_emax - qtde_saldo_futuro;
              p_status_transito = 'PREVISÃO EM EXCESSO';
             
           
             
              if abs(p_sugestao) > rec_transito.compra_transito then
             
              
                p_sugestao = rec_transito.compra_transito *(-1);
             
             end if;
             
            
            elseif qtde_saldo_futuro > p_ponto_pedido AND qtde_saldo_futuro <= p_emax AND (qtde_saldo_futuro - (p_cmm * 0.30)) > p_ponto_pedido then 
              
             p_sugestao = 0;
             p_status_transito = 'PREVISÃO ADEQUADA';
             
             
            elseif qtde_saldo_futuro > p_ponto_pedido AND qtde_saldo_futuro <= p_emax AND (qtde_saldo_futuro - (p_cmm * 0.30)) <= p_ponto_pedido  then 
           
             if qtde_transito > 0 then
            
                        select
    
                                --((current_date + (produtos.tempo_medio_ressuprimento::int4)) - ((current_date + ((vw_requisicoes.data_solicitacao+produtos.tempo_medio_ressuprimento::int4) - current_date)) - current_date) - current_date)::numeric/30  into p_tr
                           		GREATEST((current_date + produtos.tempo_medio_ressuprimento::int4) - COALESCE(vw_requisicoes.data_prevista_cal, vw_requisicoes.data_previsao), 0) / 30.0 into p_tr -- Lucas: tempo entre a ultima entrada prevista e a entrada da sugestão de compra
                           
                        from
                    
                            vw_requisicoes
                    
                         inner join produtos_filial  as produtos
                    
                       on  produtos.filial =vw_requisicoes.filial and  produtos.idproduto = vw_requisicoes.idproduto::varchar
                    
                        where
                    
                            vw_requisicoes.idproduto::varchar = rec_transito.idproduto  
                            and vw_requisicoes.filial in (select filial from grupo_filial gf where id_grupo= rec_transito.id_grupo )
                    
                            and data_entrada isnull  order by COALESCE(vw_requisicoes.data_prevista_cal, vw_requisicoes.data_previsao, vw_requisicoes.data_solicitacao) desc limit 1;
                
                  end if;   
                 
                 
              p_sugestao = (p_emax - (greatest(qtde_saldo_futuro-(p_cmm *p_tr),0)));    
			  
             
              qtde_cobertura_futura =  round(qtde_saldo_futuro/ greatest(p_cmm, 1),2);
             
              if qtde_cobertura_futura < p_tr then
              
                
                p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';
                
              
                else
                
                
                p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';
              
              end if;
             
             
            elseif  ( qtde_saldo_futuro  <= p_ponto_pedido) then
            
               
               
                if qtde_transito > 0 then
            
                        select
    
                                --((current_date + (produtos.tempo_medio_ressuprimento::int4)) - ((current_date + ((vw_requisicoes.data_solicitacao+produtos.tempo_medio_ressuprimento::int4) - current_date)) - current_date) - current_date)::numeric/30  into p_tr
                           		GREATEST((current_date + produtos.tempo_medio_ressuprimento::int4) - COALESCE(vw_requisicoes.data_prevista_cal, vw_requisicoes.data_previsao), 0) / 30.0 into p_tr -- Lucas: tempo entre a ultima entrada prevista e a entrada da sugestão de compra
                           
                        from
                    
                            vw_requisicoes
                    
                         inner join produtos_filial  as produtos
                    
                       on  produtos.filial =vw_requisicoes.filial and  produtos.idproduto = vw_requisicoes.idproduto::varchar
                    
                        where
                    
                            vw_requisicoes.idproduto::varchar = rec_transito.idproduto  
                            and vw_requisicoes.filial in (select filial from grupo_filial gf where id_grupo= rec_transito.id_grupo )
                    
                            and data_entrada isnull  order by COALESCE(vw_requisicoes.data_prevista_cal, vw_requisicoes.data_previsao, vw_requisicoes.data_solicitacao) desc limit 1;
                
                  end if;   
                 
                
                 p_sugestao = (p_emax - (greatest(qtde_saldo_futuro-(p_cmm *p_tr),0)));
			  
                
                  qtde_cobertura_futura =  round(qtde_saldo_futuro/ greatest(p_cmm, 1),2);
             
                  if qtde_cobertura_futura < p_tr then
                  
                    
                    p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';
                    
                  
                    else
                    
                    
                    p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';
                  
                  end if;
             
            
            
            else
            
              p_sugestao = 0;
             
              p_status_transito = 'PRODUTO EM TRÂNSITO';
             
            
            end if;
        
       
        end if;
       
       
           p_sugestao = gerar_lote_embalagem(p_sugestao,qtde_lote_minimo);
          
          
          
            -- Ajuste para Analisar os pedidos em compras após 15 dias 
          
          if rec_transito.tempo_pedido  <= 2  then 
          
      
              p_sugestao = 0;
             
              p_status_transito = 'PREVISÃO ADEQUADA';
           
          
          end if;
          
          
  
    --Update 
    
      update
        produtos_transito
        set
            idfornecedor = rec_transito.idfornecedor,
            fornecedor = rec_transito.fornecedor,
            idcomprador = rec_transito.idcomprador,
            comprador = rec_transito.comprador,
            descricao_produto = rec_transito.descricao_produto,
            iddepartamento = rec_transito.iddepartamento,
            departamento = rec_transito.departamento,
            compra_transito = rec_transito.compra_transito,
            consumo_transito = rec_transito.consumo_transito,
            saldo_futuro = qtde_saldo_futuro,
            estoque_maximo = rec_transito.estoque_maximo,
            ponto_pedido = rec_transito.ponto_pedido,
            consumo_medio_mensal = rec_transito.consumo_medio_mensal,
            tempo_ressuprimento = rec_transito.tempo_ressuprimento,
            desvio_padrao_ressuprimento = rec_transito.desvio_padrao_ressuprimento,
            estoque = rec_transito.estoque,
            status = p_status_transito,
            lote_compras = p_sugestao,
            fator_conversao = rec_transito.fator_conversao,
            unidade_compra = rec_transito.unidade_compra,
            data_ultima_riquisicao = rec_transito.data_ultima_riquisicao,
            tempo_pedido = rec_transito.tempo_pedido,
            nivel_servico = rec_transito.nivel_servico,
            peso_compras = rec_transito.peso_compras,
            gatilho_transito = rec_transito.gatilho_transito,
            flag = null,
            processamento = current_timestamp 
        where
            id_grupo = rec_transito.id_grupo 
            and idproduto = rec_transito.idproduto;

    
    if not found then 
    
      --Insert 
    
         insert
            into
            produtos_transito (
            id_grupo,
            idfornecedor,
            fornecedor,
            idcomprador,
            comprador,
            idproduto,
            descricao_produto,
            iddepartamento,
            departamento,
            compra_transito,
            consumo_transito,
            saldo_futuro,
            estoque_maximo,
            ponto_pedido,
            consumo_medio_mensal,
            tempo_ressuprimento,
            desvio_padrao_ressuprimento,
            estoque,
            status,
            lote_compras,
            fator_conversao,
            unidade_compra,
            data_ultima_riquisicao,
            tempo_pedido,
            nivel_servico,
            peso_compras,
            gatilho_transito,
            flag,
            processamento
            )
            values(
            rec_transito.id_grupo,
            rec_transito.idfornecedor,
            rec_transito.fornecedor,
            rec_transito.idcomprador,
            rec_transito.comprador,
            rec_transito.idproduto,
            rec_transito.descricao_produto,
            rec_transito.iddepartamento,
            rec_transito.departamento,
            rec_transito.compra_transito,
            rec_transito.consumo_transito,
            qtde_saldo_futuro,
            rec_transito.estoque_maximo,
            rec_transito.ponto_pedido,
            rec_transito.consumo_medio_mensal,
            rec_transito.tempo_ressuprimento,
            rec_transito.desvio_padrao_ressuprimento,
            rec_transito.estoque,
            p_status_transito,
            p_sugestao,
            rec_transito.fator_conversao,
            rec_transito.unidade_compra,
            rec_transito.data_ultima_riquisicao,
            rec_transito.tempo_pedido,
            rec_transito.nivel_servico,
            rec_transito.peso_compras,
            rec_transito.gatilho_transito,
            null,
            current_timestamp
            );
        
       end if;      
        
     end loop;  
        
    else
    
     update produtos_transito set flag ='D' where id_grupo in (select id from grupo_compras) and produtos_transito.idfornecedor = p_fornecedor;

     for rec_transito in(
           SELECT a.id_grupo,
    a.idfornecedor,
    a.fornecedor,
    a.idcomprador,
    a.comprador,
    a.idproduto,
    a.descricao_produto,
    a.iddepartamento,
    a.departamento,
    a.compra_transito,
    a.consumo_transito * a.fator_conversao AS consumo_transito,
    a.saldo_futuro * a.fator_conversao AS saldo_futuro,
    a.estoque_maximo * a.fator_conversao::double precision AS estoque_maximo,
    a.ponto_pedido * a.fator_conversao::double precision AS ponto_pedido,
    a.consumo_medio_mensal::double precision * a.fator_conversao::double precision AS consumo_medio_mensal,
    a.tempo_ressuprimento,
    a.desvio_padrao_ressuprimento,
    a.estoque::double precision * a.fator_conversao::double precision AS estoque,
    a.status,
        CASE
            WHEN a.status = 'PREVISÃO FUTURA EM EXCESSO'::text AND abs(a.lote_compras * a.fator_conversao::double precision) > a.compra_transito::double precision THEN (a.compra_transito * '-1'::integer::numeric)::double precision
            ELSE gerar_lote_embalagem((a.lote_compras * a.fator_conversao::double precision)::numeric, a.lote_minimo::numeric * a.fator_conversao)::double precision
        END AS lote_compras,
    a.fator_conversao,
    a.unidade_compra,
    a.data_ultima_riquisicao,
    'now'::text::date - a.data_ultima_riquisicao AS tempo_pedido,
    a.nivel_servico,
    a.peso_compras,
        CASE
            WHEN ('now'::text::date - a.data_ultima_riquisicao - 1) < 0 THEN NULL::integer
            ELSE 'now'::text::date - a.data_ultima_riquisicao - 1
        END AS gatilho_transito,
     a.lote_minimo        
   FROM ( SELECT analise_entrada.idfornecedor,
            analise_entrada.fornecedor,
            analise_entrada.idcomprador,
            analise_entrada.comprador,
            analise_entrada.idproduto,
            analise_entrada.descricao_produto,
            analise_entrada.compra_transito,
            analise_entrada.consumo_transito,
            analise_entrada.saldo_futuro,
            analise_entrada.estoque_maximo,
            analise_entrada.ponto_pedido,
            analise_entrada.consumo_medio_mensal,
            analise_entrada.tempo_ressuprimento,
            analise_entrada.desvio_padrao_ressuprimento,
            analise_entrada.estoque,
            analise_entrada.fator_conversao,
            analise_entrada.unidade_compra,
            analise_entrada.lote_minimo,
            analise_entrada.data_ultima_riquisicao,
            analise_entrada.id_grupo,
            analise_entrada.iddepartamento,
            analise_entrada.descricao_departamento AS departamento,
            analise_entrada.nivel_servico,
            analise_entrada.peso_compras,
                CASE
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.estoque_maximo THEN 'PREVISÃO FUTURA EM EXCESSO'::text
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.ponto_pedido AND analise_entrada.saldo_futuro::double precision <= analise_entrada.estoque_maximo AND (analise_entrada.saldo_futuro::double precision - analise_entrada.consumo_medio_mensal::double precision * 0.3::double precision) > analise_entrada.ponto_pedido THEN 'PREVISÃO FUTURA ADEQUADA'::text
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.ponto_pedido AND analise_entrada.saldo_futuro::double precision <= analise_entrada.estoque_maximo AND (analise_entrada.saldo_futuro::double precision - analise_entrada.consumo_medio_mensal::double precision * 0.3::double precision) <= analise_entrada.ponto_pedido THEN 'PREVISÃO COM SUTIL EXPOSIÇÃO A RUPTURA'::text
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision <= analise_entrada.ponto_pedido THEN 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA'::text
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) <= 1 THEN 'PRODUTO EM TRANSITO'::text
                    ELSE 'PRIMEIRA COMPRA'::text
                END AS status,
                CASE
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.estoque_maximo THEN analise_entrada.estoque_maximo - analise_entrada.saldo_futuro::double precision
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.ponto_pedido AND analise_entrada.saldo_futuro::double precision <= analise_entrada.estoque_maximo AND (analise_entrada.saldo_futuro::double precision - analise_entrada.consumo_medio_mensal::double precision * 0.3::double precision) > analise_entrada.ponto_pedido THEN 0::double precision
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.ponto_pedido AND analise_entrada.saldo_futuro::double precision <= analise_entrada.estoque_maximo AND (analise_entrada.saldo_futuro::double precision - analise_entrada.consumo_medio_mensal::double precision * 0.3::double precision) <= analise_entrada.ponto_pedido THEN round((analise_entrada.estoque_maximo - (analise_entrada.saldo_futuro::double precision - getconsumo_transito_grupo_entre_pedidos(analise_entrada.id_grupo::numeric, analise_entrada.idproduto)))::numeric, 2)::double precision
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision <= analise_entrada.ponto_pedido THEN round((analise_entrada.estoque_maximo - (analise_entrada.saldo_futuro::double precision - getconsumo_transito_grupo_entre_pedidos(analise_entrada.id_grupo::numeric, analise_entrada.idproduto)))::numeric, 2)::double precision
                    ELSE 0::double precision
                END AS lote_compras
           FROM ( 
                
           with produtos_grupo  as (         
                  select gf.id_grupo ,idproduto,sum(consumo_medio_mensal) as cmm_grupo ,sum(estoque_maximo) emax_grupo,sum(ponto_pedido) pp_grupo 
                 from produtos_filial pf  
                  inner join grupo_filial gf 
                   on gf.filial = pf.filial
                  where pf.idfornecedor= p_fornecedor 
                 group by gf.id_grupo ,idproduto)
                           
           
            SELECT b.id_grupo,
                    b.idfornecedor,
                    b.fornecedor,
                    b.idcomprador,
                    b.comprador,
                    b.idproduto,
                    b.descricao_produto,
                    b.iddepartamento,
                    b.descricao_departamento,
                    b.fator_conversao,
                    b.unidade_compra,
                    max(b.lote_minimo) AS lote_minimo,
                    max(b.data_ultima_riquisicao) AS data_ultima_riquisicao,
                    b.arvore_decisao,
                    b.nivel_servico,
                    b.peso_compras,
                    avg(b.compra_transito) AS compra_transito,
                    sum(b.consumo_transito) AS consumo_transito,
                    CASE
                        WHEN (greatest((avg(b.estoque) - sum(b.consumo_transito)),0) + avg(b.compra_transito)) < 0::numeric THEN 0::numeric
                        ELSE greatest((avg(b.estoque) - sum(b.consumo_transito)),0) + avg(b.compra_transito)
                    END AS saldo_futuro,
                    avg(b.amplitude_atual) AS amplitude_atual,
                    avg(b.estoque_maximo) AS estoque_maximo,
                    avg(b.ponto_pedido) AS ponto_pedido,
                    avg(b.consumo_medio_mensal) AS consumo_medio_mensal,
                    avg(b.tempo_ressuprimento) AS tempo_ressuprimento,
                    avg(b.desvio_padrao_ressuprimento) AS desvio_padrao_ressuprimento,
                    avg(b.estoque) AS estoque,
                    avg(b.status_compra) AS status_compra
                   FROM ( SELECT g.id_grupo,
                            p.filial,
                            fornecedor.id AS idfornecedor,
                            fornecedor.razao_social AS fornecedor,
                            comprador.id AS idcomprador,
                            comprador.nome_completo AS comprador,
                            p.idproduto,
                            p.descricao_produto,
                            dep.iddepartamento,
                            dep.descricao_departamento,
                            getcompra_transito_grupo(g.id_grupo::numeric, p.idproduto) AS compra_transito,
                            case when ((select count(*) from analise_requisicoes ar  
                                        where filial in(select filial from grupo_filial gf where gf.id_grupo=g.id_grupo::numeric)  
                                        and idproduto=p.idproduto and atraso  > 0) > 0)  then 
                                        
                                     getconsumo_transito_grupo_new(g.id_grupo::numeric, p.idproduto) +  getconsumo_transito_grupo_2(g.id_grupo::numeric, p.idproduto)
                                        
                               else 
                               
                                 getconsumo_transito_grupo_new(g.id_grupo::numeric, p.idproduto)
                               
                             end  as consumo_transito,
                            amplitude_transito_atual_filial(p.filial::numeric, p.idproduto) AS amplitude_atual,
                            COALESCE(vp.emax_grupo, 0) AS estoque_maximo,
                            COALESCE(vp.pp_grupo, 0) AS ponto_pedido,
                            coalesce(vp.cmm_grupo,0) as consumo_medio_mensal,
                            p.tempo_ressuprimento,
                            p.desvio_padrao_ressuprimento,
                            get_estoque_grupo(g.id_grupo::numeric, p.idproduto) AS estoque,
                            ( SELECT
                                CASE
                                 WHEN count(*) > 0 THEN 0
                                 ELSE 1
                                END AS "case"
                                 FROM entrada_mercadorias
                                  WHERE entrada_mercadorias.data_entrada <= 'now'::text::date AND entrada_mercadorias.idproduto::text = p.idproduto::text AND entrada_mercadorias.qtde > 0::double precision) AS status_compra,
                            p.fator_conversao,
                            p.unidade_compra,
                            COALESCE(p.lote_minimo::double precision, 1::double precision) AS lote_minimo,
                            p.data_ultima_riquisicao,
                            get_arvore_decisao_grupo(g.id_grupo::numeric, p.idproduto)::text AS arvore_decisao,
                            getnivelservico(get_arvore_decisao_grupo(g.id_grupo::numeric, p.idproduto)) AS nivel_servico,
                            getpesocompras(get_arvore_decisao_grupo(g.id_grupo::numeric, p.idproduto), "substring"(get_arvore_decisao_grupo(g.id_grupo::numeric, p.idproduto)::text, 3, 1)::numeric) AS peso_compras
                           FROM produtos_filial p
                             LEFT JOIN comprador ON comprador.id = p.idcomprador
                             LEFT JOIN fornecedor ON fornecedor.id = p.idfornecedor
                             JOIN grupo_filial g ON g.filial = p.filial
                             JOIN departamentos dep ON dep.iddepartamento = p.idfamilia_produto
                             JOIN produtos_grupo vp ON vp.id_grupo = g.id_grupo AND vp.idproduto::text = p.idproduto::text
                          where p.idfornecedor= p_fornecedor and p.revenda::text = 'S'::text AND p.status::text <> 'FL'::text AND getcompra_transito_grupo(g.id_grupo::numeric, p.idproduto) > 0::numeric) b
                  GROUP BY b.id_grupo, b.idfornecedor, b.fornecedor, b.idcomprador, b.comprador, b.idproduto, b.descricao_produto, b.descricao_departamento, b.fator_conversao, b.unidade_compra, b.arvore_decisao, b.nivel_servico, b.peso_compras, b.iddepartamento) analise_entrada
          WHERE analise_entrada.compra_transito > 0::numeric) a)
    loop 
        
        
        
      p_atraso=0;
      qtde_transito_atraso =0;
      qtde_transito=0;
      qtde_estoque=0;
      p_sugestao= 0;
      p_consumo_transito =0;
      p_consumo_transito2 = 0;
      qtde_saldo_futuro = 0;
      qtde_lote_minimo =  coalesce(rec_transito.lote_minimo,1);
      qtde_cobertura_futura=0;
      consumo_transito_cal = 0;
      
      
        --Identificar se o produto tem compra em atraso
      
        select count(*) into p_atraso  from analise_requisicoes ar  
        where filial in(select filial from grupo_filial gf where gf.id_grupo=rec_transito.id_grupo)  
        and idproduto=rec_transito.idproduto and atraso  >= 0  and qtde_pendente > 0;
       
       
        -- Pedidos em atraso;
       
        select  sum(qtde_pendente)  into qtde_transito_atraso 
          from analise_requisicoes r inner join produtos_filial pf on r.filial  = pf.filial and r.idproduto = pf.idproduto 
          where r.idproduto = rec_transito.idproduto and qtde_pendente > 0 and atraso >=0
        and r.filial  in (select filial from grupo_filial where id_grupo= rec_transito.id_grupo) ;  
       
        qtde_transito_atraso = coalesce(qtde_transito_atraso,0);
       
        --Pedidos em Transito Aberto;
      
          select  sum(qtde_pendente)  into qtde_transito 
          from analise_requisicoes r inner join produtos_filial pf on r.filial  = pf.filial and r.idproduto = pf.idproduto 
          where r.idproduto = rec_transito.idproduto and qtde_pendente > 0 and atraso < 0
        and r.filial  in (select filial from grupo_filial where id_grupo= rec_transito.id_grupo) ; 
         
        qtde_transito = coalesce(qtde_transito,0);

       
        -- Parâmetros do Estoque;
       
        qtde_estoque = rec_transito.estoque;
        p_ponto_pedido = rec_transito.ponto_pedido;
        p_emax = rec_transito.estoque_maximo;
        p_cmm = rec_transito.consumo_medio_mensal;
        p_tr =  rec_transito.tempo_ressuprimento;
       
        p_consumo_transito = getconsumo_transito_grupo_new(rec_transito.id_grupo,rec_transito.idproduto);
        
       
        --Somente itens atrasados
       
        if p_atraso > 0 and qtde_transito = 0 then   
        
        
            qtde_transito = greatest(qtde_transito,0);
           
            qtde_saldo = qtde_estoque + qtde_transito_atraso + qtde_transito;
        
            qtde_saldo_residual =  qtde_saldo - p_consumo_transito ;
           
           
            if qtde_saldo_residual > p_emax then -- Excesso
            
             
              p_sugestao =  p_emax - qtde_saldo_residual;
            
             
             if abs(p_sugestao) > qtde_transito_atraso then
             
              
                p_sugestao = qtde_transito_atraso *(-1);
             
             end if;
             
            
            elseif qtde_saldo_residual > p_ponto_pedido AND qtde_saldo_residual <= p_emax AND (qtde_saldo_residual - (p_cmm * 0.30)) > p_ponto_pedido then  -- Adequado
              
            
              p_sugestao = 0;
              p_status_transito = 'PREVISÃO ADEQUADA';
             
             
            elseif qtde_saldo_residual > p_ponto_pedido AND qtde_saldo_residual <= p_emax AND (qtde_saldo_residual - (p_cmm * 0.30)) <= p_ponto_pedido  then 
           
            
            
                p_consumo_transito2 = getconsumo_transito_grupo_2(rec_transito.id_grupo,rec_transito.idproduto);
          
     
                p_sugestao =  (p_emax - greatest(qtde_saldo_residual-p_consumo_transito2, 0));  
           

            
                  qtde_cobertura_futura =  round(qtde_saldo_residual/ greatest(p_cmm, 1),2);
                 
                  if qtde_cobertura_futura < p_tr then
                  
                    
                    p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';
                    
                  
                    else
                    
                    
                    p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';
                  
                  end if;
             
             
            elseif  ( qtde_saldo_residual  <= p_ponto_pedido) then
            
           
                        
              p_consumo_transito2 = getconsumo_transito_grupo_2(rec_transito.id_grupo,rec_transito.idproduto);
              
             
              p_sugestao =  (p_emax - greatest(qtde_saldo_residual-p_consumo_transito2, 0)); --
              qtde_cobertura_futura =  round(qtde_saldo_residual/ greatest(p_cmm, 1),2);
             
             
              if qtde_cobertura_futura < p_tr then
              
                
                p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';
                
              
                else
                
                
                p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';
              
              end if;
                      
            
            else
            
              p_sugestao = 0;
              p_status_transito = 'PRODUTO EM TRÂNSITO';
             
            
            end if;
            
          
            p_sugestao = gerar_lote_embalagem(p_sugestao,qtde_lote_minimo);
           
           
           
        elseif p_atraso = 0 and  qtde_transito > 0  then --Somente itens Abertos
        
        
        
            qtde_transito = greatest(qtde_transito,0);
        
            qtde_saldo = qtde_estoque;
        
        
            -- Quantidade de Pedidos Abertos 
        
        
            cont_ped = 1;
                          
            qtde_saldo_futuro= 0;
            
          
            for rec_pedidos in ( select  data_prevista_cal,sum(qtde) qtde
                    from analise_requisicoes r inner join produtos_filial pf on r.filial  = pf.filial and r.idproduto = pf.idproduto 
                where r.idproduto = rec_transito.idproduto and qtde_pendente > 0 and atraso < 0
              and r.filial  in (select filial from grupo_filial where id_grupo= rec_transito.id_grupo ) group by data_prevista_cal order by data_prevista_cal)
              
             loop 
                 
                 
                 if cont_ped = 1 then 
                 
                      data_temp= rec_pedidos.data_prevista_cal;
                      qtde_dias =  rec_pedidos.data_prevista_cal - current_date ;
                      p_tr = (qtde_dias/30);
                     
                 
                    else
                   
                    
                     qtde_dias = ((rec_pedidos.data_prevista_cal)  - data_temp) ;
                     p_tr = (qtde_dias/30);
                     data_temp= rec_pedidos.data_prevista_cal;
                    
                    
                 end if;  
                         
                
                 consumo_transito_cal = round((p_cmm * (qtde_dias/30)),2);
                
                 
                 if  consumo_transito_cal > qtde_saldo then 
                 
                 
                     consumo_transito_cal = qtde_saldo;
                    
                     qtde_saldo_residual = qtde_saldo - consumo_transito_cal;
                 
                 
                 else
                 
                    qtde_saldo_residual = qtde_saldo - consumo_transito_cal; 
                 
                 end if;
                 
                
                 qtde_saldo_futuro = qtde_saldo_residual + rec_pedidos.qtde;
                   
                 qtde_saldo = qtde_saldo_futuro;    
                        
                                 
                 cont_ped = cont_ped + 1;
                 
                
             end loop;
             
                   
           
            if qtde_saldo_futuro > p_emax then
            
          
              p_sugestao =  p_emax - qtde_saldo_futuro;
              p_status_transito = 'PREVISÃO EM EXCESSO';
             
              
             
              if abs(p_sugestao) > rec_transito.compra_transito then
             
              
                p_sugestao = rec_transito.compra_transito *(-1);
             
             end if;
             
            
            elseif qtde_saldo_futuro > p_ponto_pedido AND qtde_saldo_futuro <= p_emax AND (qtde_saldo_futuro - (p_cmm * 0.30)) > p_ponto_pedido then 
              
             p_sugestao = 0;
             p_status_transito = 'PREVISÃO ADEQUADA';
             
             
            elseif qtde_saldo_futuro > p_ponto_pedido AND qtde_saldo_futuro <= p_emax AND (qtde_saldo_futuro - (p_cmm * 0.30)) <= p_ponto_pedido  then 
           
             if qtde_transito > 0 then
            
                        select
    
                                --((current_date + (produtos.tempo_medio_ressuprimento::int4)) - ((current_date + ((vw_requisicoes.data_solicitacao+produtos.tempo_medio_ressuprimento::int4) - current_date)) - current_date) - current_date)::numeric/30  into p_tr
                           		GREATEST((current_date + produtos.tempo_medio_ressuprimento::int4) - COALESCE(vw_requisicoes.data_prevista_cal, vw_requisicoes.data_previsao), 0) / 30.0 into p_tr -- Lucas: tempo entre a ultima entrada prevista e a entrada da sugestão de compra
                           
                        from
                    
                            vw_requisicoes
                    
                         inner join produtos_filial  as produtos
                    
                       on  produtos.filial =vw_requisicoes.filial and  produtos.idproduto = vw_requisicoes.idproduto::varchar
                    
                        where
                    
                            vw_requisicoes.idproduto::varchar = rec_transito.idproduto  
                            and vw_requisicoes.filial in (select filial from grupo_filial gf where id_grupo= rec_transito.id_grupo )
                    
                            and data_entrada isnull  order by COALESCE(vw_requisicoes.data_prevista_cal, vw_requisicoes.data_previsao, vw_requisicoes.data_solicitacao) desc limit 1;
                
                  end if;   
                 
                 
              p_sugestao = (p_emax - (greatest(qtde_saldo_futuro-(p_cmm *p_tr),0)));     
			  
             
              qtde_cobertura_futura =  round(qtde_saldo_futuro/ greatest(p_cmm, 1),2);
             
              if qtde_cobertura_futura < p_tr then
              
                
                p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';
                
              
                else
                
                
                p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';
              
              end if;
             
             
            elseif  ( qtde_saldo_futuro  <= p_ponto_pedido) then
            
               
               
                if qtde_transito > 0 then
            
                        select
    
                                --((current_date + (produtos.tempo_medio_ressuprimento::int4)) - ((current_date + ((vw_requisicoes.data_solicitacao+produtos.tempo_medio_ressuprimento::int4) - current_date)) - current_date) - current_date)::numeric/30  into p_tr
                           		GREATEST((current_date + produtos.tempo_medio_ressuprimento::int4) - COALESCE(vw_requisicoes.data_prevista_cal, vw_requisicoes.data_previsao), 0) / 30.0 into p_tr -- Lucas: tempo entre a ultima entrada prevista e a entrada da sugestão de compra
                           
                        from
                    
                            vw_requisicoes
                    
                         inner join produtos_filial  as produtos
                    
                       on  produtos.filial =vw_requisicoes.filial and  produtos.idproduto = vw_requisicoes.idproduto::varchar
                    
                        where
                    
                            vw_requisicoes.idproduto::varchar = rec_transito.idproduto  
                            and vw_requisicoes.filial in (select filial from grupo_filial gf where id_grupo= rec_transito.id_grupo )
                    
                            and data_entrada isnull  order by COALESCE(vw_requisicoes.data_prevista_cal, vw_requisicoes.data_previsao, vw_requisicoes.data_solicitacao) desc limit 1;
                
                  end if;   
                 
                
                 p_sugestao = (p_emax - (greatest(qtde_saldo_futuro-(p_cmm *p_tr),0)));
			  
                
                  qtde_cobertura_futura =  round(qtde_saldo_futuro/ greatest(p_cmm, 1),2);
             
                  if qtde_cobertura_futura < p_tr then
                  
                    
                    p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';
                    
                  
                    else
                    
                    
                    p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';
                  
                  end if;
             
            
            
            else
            
              p_sugestao = 0;
             
              p_status_transito = 'PRODUTO EM TRÂNSITO';
             
            
            end if;
           
           
         else    -- COMPRAS HIBRIDAS
            
      
        
            qtde_transito = greatest(qtde_transito,0);
        
            qtde_saldo = qtde_estoque +  qtde_transito_atraso;

        
            cont_ped = 1;
           
          
            qtde_saldo_futuro= 0;
           
           
           
          
            for rec_pedidos in (select  data_prevista_cal,sum(qtde) qtde
                    from analise_requisicoes r inner join produtos_filial pf on r.filial  = pf.filial and r.idproduto = pf.idproduto 
                where r.idproduto = rec_transito.idproduto and qtde_pendente > 0 and atraso < 0
              and r.filial  in (select filial from grupo_filial where id_grupo= rec_transito.id_grupo ) group by data_prevista_cal order by data_prevista_cal)
              
             loop 
                 
                 
               if cont_ped = 1 then 
                 
                      data_temp= rec_pedidos.data_prevista_cal;
                      qtde_dias =  rec_pedidos.data_prevista_cal - current_date ;
                      p_tr = (qtde_dias/30);
                     
                 
                    else
                   
                    
                     qtde_dias = ((rec_pedidos.data_prevista_cal)  - data_temp) ;
                     p_tr = (qtde_dias/30);
                     data_temp= rec_pedidos.data_prevista_cal;
                    
                    
                 end if;  
                
                 
                
                 consumo_transito_cal = round((p_cmm * (qtde_dias/30)),2);
                
                 
                 if  consumo_transito_cal > qtde_saldo then 
                 
                 
                     consumo_transito_cal = qtde_saldo;
                    
                     qtde_saldo_residual = qtde_saldo - consumo_transito_cal;
                 
                 
                 else
                 
                    qtde_saldo_residual = qtde_saldo - consumo_transito_cal; 
                 
                 end if;
                 
                
                 qtde_saldo_futuro = qtde_saldo_residual + rec_pedidos.qtde;
                   
                 qtde_saldo = qtde_saldo_futuro;    
        
                 
                 cont_ped = cont_ped + 1;
                 
                
             end loop;
             
         
           
            if qtde_saldo_futuro > p_emax then
            
            
              p_sugestao =  p_emax - qtde_saldo_futuro;
              p_status_transito = 'PREVISÃO EM EXCESSO';
             
           
             
              if abs(p_sugestao) > rec_transito.compra_transito then
             
              
                p_sugestao = rec_transito.compra_transito *(-1);
             
             end if;
             
            
            elseif qtde_saldo_futuro > p_ponto_pedido AND qtde_saldo_futuro <= p_emax AND (qtde_saldo_futuro - (p_cmm * 0.30)) > p_ponto_pedido then 
              
             p_sugestao = 0;
             p_status_transito = 'PREVISÃO ADEQUADA';
             
             
            elseif qtde_saldo_futuro > p_ponto_pedido AND qtde_saldo_futuro <= p_emax AND (qtde_saldo_futuro - (p_cmm * 0.30)) <= p_ponto_pedido  then 
           
             if qtde_transito > 0 then
            
                        select
    
                                --((current_date + (produtos.tempo_medio_ressuprimento::int4)) - ((current_date + ((vw_requisicoes.data_solicitacao+produtos.tempo_medio_ressuprimento::int4) - current_date)) - current_date) - current_date)::numeric/30  into p_tr
                           		GREATEST((current_date + produtos.tempo_medio_ressuprimento::int4) - COALESCE(vw_requisicoes.data_prevista_cal, vw_requisicoes.data_previsao), 0) / 30.0 into p_tr -- Lucas: tempo entre a ultima entrada prevista e a entrada da sugestão de compra
                           
                        from
                    
                            vw_requisicoes
                    
                         inner join produtos_filial  as produtos
                    
                       on  produtos.filial =vw_requisicoes.filial and  produtos.idproduto = vw_requisicoes.idproduto::varchar
                    
                        where
                    
                            vw_requisicoes.idproduto::varchar = rec_transito.idproduto  
                            and vw_requisicoes.filial in (select filial from grupo_filial gf where id_grupo= rec_transito.id_grupo )
                    
                            and data_entrada isnull  order by COALESCE(vw_requisicoes.data_prevista_cal, vw_requisicoes.data_previsao, vw_requisicoes.data_solicitacao) desc limit 1;
                
                  end if;   
                 
                 
              p_sugestao = (p_emax - (greatest(qtde_saldo_futuro-(p_cmm *p_tr),0)));     
			  
             
              qtde_cobertura_futura =  round(qtde_saldo_futuro/ greatest(p_cmm, 1),2);
             
              if qtde_cobertura_futura < p_tr then
              
                
                p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';
                
              
                else
                
                
                p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';
              
              end if;
             
             
            elseif  ( qtde_saldo_futuro  <= p_ponto_pedido) then
            
               
               
                if qtde_transito > 0 then
            
                        select
    
                                --((current_date + (produtos.tempo_medio_ressuprimento::int4)) - ((current_date + ((vw_requisicoes.data_solicitacao+produtos.tempo_medio_ressuprimento::int4) - current_date)) - current_date) - current_date)::numeric/30  into p_tr
                           		GREATEST((current_date + produtos.tempo_medio_ressuprimento::int4) - COALESCE(vw_requisicoes.data_prevista_cal, vw_requisicoes.data_previsao), 0) / 30.0 into p_tr -- Lucas: tempo entre a ultima entrada prevista e a entrada da sugestão de compra
                           
                        from
                    
                            vw_requisicoes
                    
                         inner join produtos_filial  as produtos
                    
                       on  produtos.filial =vw_requisicoes.filial and  produtos.idproduto = vw_requisicoes.idproduto::varchar
                    
                        where
                    
                            vw_requisicoes.idproduto::varchar = rec_transito.idproduto  
                            and vw_requisicoes.filial in (select filial from grupo_filial gf where id_grupo= rec_transito.id_grupo )
                    
                            and data_entrada isnull  order by COALESCE(vw_requisicoes.data_prevista_cal, vw_requisicoes.data_previsao, vw_requisicoes.data_solicitacao) desc limit 1;
                
                  end if;   
                 
                
                 p_sugestao = (p_emax - (greatest(qtde_saldo_futuro-(p_cmm *p_tr),0)));
                
                
                  qtde_cobertura_futura =  round(qtde_saldo_futuro/ greatest(p_cmm, 1),2);
             
                  if qtde_cobertura_futura < p_tr then
                  
                    
                    p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';
                    
                  
                    else
                    
                    
                    p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';
                  
                  end if;
             
            
            
            else
            
              p_sugestao = 0;
             
              p_status_transito = 'PRODUTO EM TRÂNSITO';
             
            
            end if;
        
       
        end if;
       
       
           p_sugestao = gerar_lote_embalagem(p_sugestao,qtde_lote_minimo);
          
          
            -- Ajuste para Analisar os pedidos em compras após 15 dias 
          
          if rec_transito.tempo_pedido  <= 2   then 
          
      
              p_sugestao = 0;
             
              p_status_transito = 'PREVISÃO ADEQUADA';
           
          
          end if;
          
          
  
    --Update 
    
      update
        produtos_transito
        set
            idfornecedor = rec_transito.idfornecedor,
            fornecedor = rec_transito.fornecedor,
            idcomprador = rec_transito.idcomprador,
            comprador = rec_transito.comprador,
            descricao_produto = rec_transito.descricao_produto,
            iddepartamento = rec_transito.iddepartamento,
            departamento = rec_transito.departamento,
            compra_transito = rec_transito.compra_transito,
            consumo_transito = rec_transito.consumo_transito,
            saldo_futuro = qtde_saldo_futuro,
            estoque_maximo = rec_transito.estoque_maximo,
            ponto_pedido = rec_transito.ponto_pedido,
            consumo_medio_mensal = rec_transito.consumo_medio_mensal,
            tempo_ressuprimento = rec_transito.tempo_ressuprimento,
            desvio_padrao_ressuprimento = rec_transito.desvio_padrao_ressuprimento,
            estoque = rec_transito.estoque,
            status = p_status_transito,
            lote_compras = p_sugestao,
            fator_conversao = rec_transito.fator_conversao,
            unidade_compra = rec_transito.unidade_compra,
            data_ultima_riquisicao = rec_transito.data_ultima_riquisicao,
            tempo_pedido = rec_transito.tempo_pedido,
            nivel_servico = rec_transito.nivel_servico,
            peso_compras = rec_transito.peso_compras,
            gatilho_transito = rec_transito.gatilho_transito,
            flag = null,
            processamento = current_timestamp 
        where
            id_grupo = rec_transito.id_grupo 
            and idproduto = rec_transito.idproduto;

    
    if not found then 
    
      --Insert 
    
         insert
            into
            produtos_transito (
            id_grupo,
            idfornecedor,
            fornecedor,
            idcomprador,
            comprador,
            idproduto,
            descricao_produto,
            iddepartamento,
            departamento,
            compra_transito,
            consumo_transito,
            saldo_futuro,
            estoque_maximo,
            ponto_pedido,
            consumo_medio_mensal,
            tempo_ressuprimento,
            desvio_padrao_ressuprimento,
            estoque,
            status,
            lote_compras,
            fator_conversao,
            unidade_compra,
            data_ultima_riquisicao,
            tempo_pedido,
            nivel_servico,
            peso_compras,
            gatilho_transito,
            flag,
            processamento
            )
            values(
            rec_transito.id_grupo,
            rec_transito.idfornecedor,
            rec_transito.fornecedor,
            rec_transito.idcomprador,
            rec_transito.comprador,
            rec_transito.idproduto,
            rec_transito.descricao_produto,
            rec_transito.iddepartamento,
            rec_transito.departamento,
            rec_transito.compra_transito,
            rec_transito.consumo_transito,
            qtde_saldo_futuro,
            rec_transito.estoque_maximo,
            rec_transito.ponto_pedido,
            rec_transito.consumo_medio_mensal,
            rec_transito.tempo_ressuprimento,
            rec_transito.desvio_padrao_ressuprimento,
            rec_transito.estoque,
            p_status_transito,
            p_sugestao,
            rec_transito.fator_conversao,
            rec_transito.unidade_compra,
            rec_transito.data_ultima_riquisicao,
            rec_transito.tempo_pedido,
            rec_transito.nivel_servico,
            rec_transito.peso_compras,
            rec_transito.gatilho_transito,
            null,
            current_timestamp
            );
        
       end if;      
              
        
     end loop;  
end if;
         
delete from  produtos_transito  where  flag ='D';

end
$$;


ALTER FUNCTION public.processar_produtos_transito(p_fornecedor bigint) OWNER TO systock;

--
-- TOC entry 798 (class 1255 OID 53931)
-- Name: processar_produtos_transito_categoria(integer, character varying, character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_produtos_transito_categoria(p_grupo integer DEFAULT 0, p_departamento character varying DEFAULT '0'::character varying, p_idcategoria character varying DEFAULT '0'::character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
declare

	rec_produtos record;
	rec_transito record;
	rec_pedidos record;

	p_atraso int4;
	qtde_transito_atraso numeric;
	qtde_transito numeric;
	qtde_estoque numeric;
	qtde_saldo  numeric;
	p_ponto_pedido numeric;
	p_sugestao numeric;
	p_emax numeric;
	p_cmm numeric;
	p_tr numeric;
	p_consumo_transito numeric;
	p_consumo_transito2 numeric;
	qtde_saldo_futuro numeric;
	qtde_saldo_futuro_geral numeric;
	qtde_saldo_residual numeric;
	p_status_transito varchar;
	qtde_lote_minimo  numeric;
	qtde_cobertura_futura numeric;
	p_fornecedor int4;
	qtde_dias numeric;
	cont_ped numeric;
	consumo_transito_cal numeric;
	p_data_pedido_ant date;



begin



update produtos_transito_categorias
set flag ='D'
where
	(id_grupo = p_grupo or p_grupo = 0)
	and (iddepartamento = p_departamento or p_departamento = '0')
	and (idcategoria = p_idcategoria or p_idcategoria = '0');

for rec_transito in(
     select
		id_grupo,
		iddepartamento,
		idsecao,
		idcategoria,
		descricao_categoria,
		consumo_medio_mensal,
		desvio_padrao_consumo ,
		estoque,
		ponto_pedido,
		estoque_maximo,
		compra_transito,
		tempo_ressuprimento,
		lote_minimo
	from
		produtos_compras_categorias pcc
	where
		compra_transito > 0
		AND consumo_medio_mensal > 0
		AND (pcc.id_grupo = p_grupo or p_grupo = 0)
		AND (pcc.iddepartamento = p_departamento or p_departamento = '0')
		AND (pcc.idcategoria = p_idcategoria or p_idcategoria = '0')
)
  loop


	  p_atraso=0;
      qtde_transito_atraso =0;
      qtde_transito=0;
      qtde_estoque=0;
      p_sugestao= 0;
      p_consumo_transito =0;
      p_consumo_transito2 = 0;
      qtde_saldo_futuro = 0;
      qtde_lote_minimo = coalesce(rec_transito.lote_minimo,1);
      qtde_cobertura_futura=0;
      consumo_transito_cal = 0;




      --Identificar se o produto tem compra em atraso

       select count(*) into p_atraso  from analise_requisicoes ar
        inner join produtos_filial pf
         on pf.filial  = ar.filial
         and pf.idproduto  = ar.idproduto
	    where ar.filial in(select filial from grupo_filial gf where gf.id_grupo=rec_transito.id_grupo)
	    and pf.idcategoria  = rec_transito.idcategoria::varchar and atraso  >= 0  and qtde_pendente > 0 ;



	    -- Pedidos em atraso;


	   select sum(qtde_pendente)  into qtde_transito_atraso  from analise_requisicoes ar
        inner join produtos_filial pf
         on pf.filial  = ar.filial
         and pf.idproduto  = ar.idproduto
	    where ar.filial in(select filial from grupo_filial gf where gf.id_grupo=rec_transito.id_grupo)
	    and pf.idcategoria  = rec_transito.idcategoria::varchar and qtde_pendente > 0 and atraso >=0;


	    qtde_transito_atraso = coalesce(qtde_transito_atraso,0);

	    --Pedidos em Transito Aberto;

	    select sum(qtde_pendente)  into qtde_transito  from analise_requisicoes ar
        inner join produtos_filial pf
         on pf.filial  = ar.filial
         and pf.idproduto  = ar.idproduto
	    where ar.filial in(select filial from grupo_filial gf where gf.id_grupo=rec_transito.id_grupo)
	    and pf.idcategoria  = rec_transito.idcategoria::varchar and qtde_pendente > 0 and atraso < 0;

	    qtde_transito = coalesce(qtde_transito,0);


	    -- Parâmetros do Estoque;

	    qtde_estoque = rec_transito.estoque;
	    p_ponto_pedido = rec_transito.ponto_pedido;
	    p_emax = rec_transito.estoque_maximo;
	    p_cmm = rec_transito.consumo_medio_mensal;
	    p_tr =  rec_transito.tempo_ressuprimento;


	   --raise notice 'grupo = %',rec_transito.id_grupo;
	   --raise notice 'categoria = %',rec_transito.idcategoria;
	   --raise notice 'p_atraso = %',p_atraso;
	   --raise notice 'qtde_transito_atraso = %',qtde_transito_atraso;
	   --raise notice 'qtde_transito = %',qtde_transito;
	   --raise notice 'qtde_estoque = %',qtde_estoque;
	   --raise notice 'p_ponto_pedido = %',p_ponto_pedido;
	   --raise notice 'p_emax = %',p_emax;
	   --raise notice 'p_cmm = %',p_cmm;
	   --raise notice 'p_tr = %',p_tr;
	   --raise notice 'p_ponto_pedido = %',p_ponto_pedido;


	  p_consumo_transito = 0;

	   for rec_pedidos in (select distinct  gf.id_grupo  ,idproduto from produtos_filial pf
	                          inner join grupo_filial gf
	                           on gf.filial = pf.filial
	                          where gf.id_grupo = rec_transito.id_grupo
	                          and pf.idcategoria = rec_transito.idcategoria and revenda='S' and  status <> 'FL' )
	    loop

		    p_consumo_transito = p_consumo_transito + getconsumo_transito_grupo_new(rec_pedidos.id_grupo,rec_pedidos.idproduto);

		end loop;



	   --raise notice 'p_consumo_transito = %',p_consumo_transito;






	    --Somente itens atrasados

	    if p_atraso > 0 and qtde_transito = 0 then


	        --raise notice 'SOMENTE ATRASADO = %','';



	        qtde_transito = greatest(qtde_transito,0);

	    	qtde_saldo = qtde_estoque + qtde_transito_atraso + qtde_transito;

	        qtde_saldo_residual =  qtde_saldo - p_consumo_transito ;


	        --raise notice 'qtde_transito = %',qtde_transito;
	        --raise notice 'qtde_saldo = %',qtde_saldo;
	        --raise notice 'qtde_saldo_residual = %',qtde_saldo_residual;



	        if qtde_saldo_residual > p_emax then -- Excesso


	          p_sugestao =  p_emax - qtde_saldo_residual;


	         if abs(p_sugestao) > qtde_transito_atraso then


	            p_sugestao = qtde_transito_atraso *(-1);

	         end if;


	        elseif qtde_saldo_residual > p_ponto_pedido AND qtde_saldo_residual <= p_emax AND (qtde_saldo_residual - (p_cmm * 0.30)) > p_ponto_pedido then  -- Adequado


	          p_sugestao = 0;
	          p_status_transito = 'PREVISÃO ADEQUADA';


	        elseif qtde_saldo_residual > p_ponto_pedido AND qtde_saldo_residual <= p_emax AND (qtde_saldo_residual - (p_cmm * 0.30)) <= p_ponto_pedido  then


	            p_consumo_transito2 = 0;

	            for rec_pedidos in (select distinct  gf.id_grupo  ,idproduto from produtos_filial pf
	                          inner join grupo_filial gf
	                           on gf.filial = pf.filial
	                          where gf.id_grupo = rec_transito.id_grupo
	                          and pf.idcategoria = rec_transito.idcategoria and revenda='S' and  status <> 'FL' )
				    loop

					    p_consumo_transito2 = p_consumo_transito2 + getconsumo_transito_grupo_2(rec_pedidos.id_grupo,rec_pedidos.idproduto);

					end loop;


	            --raise notice 'AKI = %',p_consumo_transito2;
	            --raise notice 'p_consumo_transito2 = %',p_consumo_transito2;


	        	p_sugestao =  (p_emax - (greatest((qtde_saldo_residual-p_consumo_transito2),0)));



		          qtde_cobertura_futura =  round(qtde_saldo_residual/ p_cmm,2);

		          if qtde_cobertura_futura < p_tr then


		            p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';


		          	else


		          	p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';

		          end if;


	        elseif  ( qtde_saldo_residual  <= p_ponto_pedido) then



	           p_consumo_transito2 = 0;

	            for rec_pedidos in (select distinct  gf.id_grupo  ,idproduto from produtos_filial pf
	                          inner join grupo_filial gf
	                           on gf.filial = pf.filial
	                          where gf.id_grupo = rec_transito.id_grupo
	                          and pf.idcategoria = rec_transito.idcategoria and revenda='S' and  status <> 'FL' )
				    loop

					    p_consumo_transito2 = p_consumo_transito2 + getconsumo_transito_grupo_2(rec_pedidos.id_grupo,rec_pedidos.idproduto);

			    end loop;


			  --raise notice 'p_consumo_transito2 = %',p_consumo_transito2;


	          p_sugestao =  (p_emax - (greatest(qtde_saldo_residual-p_consumo_transito2,0))); --
	          qtde_cobertura_futura =  round(qtde_saldo_residual/ p_cmm,2);


	          if qtde_cobertura_futura < p_tr then


	            p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';


	          	else


	          	p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';

	          end if;


	        else

	          p_sugestao = 0;
	          p_status_transito = 'PRODUTO EM TRÂNSITO';


	        end if;


	        p_sugestao = gerar_lote_embalagem(p_sugestao,qtde_lote_minimo);



	    elseif p_atraso = 0 and  qtde_transito > 0  then --Somente itens Abertos


	     -- raise notice 'SOMENTE ABERTO = %','';


	        qtde_transito = greatest(qtde_transito,0);

	    	qtde_saldo = qtde_estoque;


	        --raise notice 'qtde_transito = %',qtde_transito;

	        -- Quantidade de Pedidos Abertos


	        cont_ped = 1;

	        qtde_saldo_futuro= 0;
	        qtde_saldo_futuro_geral=0;




	        for rec_produtos in (select distinct  gf.id_grupo  ,idproduto from produtos_filial pf
	                          inner join grupo_filial gf
	                           on gf.filial = pf.filial
	                          where gf.id_grupo = rec_transito.id_grupo
	                          and pf.idcategoria = rec_transito.idcategoria and revenda='S' and  status <> 'FL' )
				    loop


			    cont_ped = 1;
	            qtde_saldo_futuro= 0;




			   for rec_pedidos in ( select  data_prevista_cal,sum(qtde) qtde
	      			from analise_requisicoes r inner join produtos_filial pf on r.filial  = pf.filial and r.idproduto = pf.idproduto
		      		where r.idproduto = rec_produtos.idproduto and qtde_pendente > 0 and atraso < 0
		    	  and r.filial  in (select filial from grupo_filial where id_grupo= rec_produtos.id_grupo ) group by data_prevista_cal order by data_prevista_cal)

		    	 loop



			    	if cont_ped = 1 then

                      qtde_dias =  rec_pedidos.data_prevista_cal - current_date ;
                      p_tr = (qtde_dias/30);

                    else


                     qtde_dias =  ((rec_pedidos.data_prevista_cal)  - current_date) - qtde_dias ;
                     p_tr = (qtde_dias/30);

                 end if;


                 --raise notice 'qtde_dias = %',qtde_dias;
                 --raise notice 'rec_pedidos.data_prevista_cal = %',rec_pedidos.data_prevista_cal;



                 consumo_transito_cal = round((p_cmm * (qtde_dias/30)),2);


                 if  consumo_transito_cal > qtde_saldo then


                     consumo_transito_cal = qtde_saldo;

                     qtde_saldo_residual = qtde_saldo - consumo_transito_cal;


                 else

                    qtde_saldo_residual = qtde_saldo - consumo_transito_cal;

                 end if;


                 qtde_saldo_futuro = qtde_saldo_residual + rec_pedidos.qtde;

                 qtde_saldo = qtde_saldo_futuro;


                 cont_ped = cont_ped + 1;


                 p_data_pedido_ant = rec_pedidos.data_prevista_cal;



			        --raise notice '# - qtde_saldo_futuro = %',qtde_saldo_futuro;


		    	 end loop;


		    	 qtde_saldo_futuro_geral = qtde_saldo_futuro_geral + qtde_saldo_futuro;





			end loop;



		    qtde_saldo_futuro = qtde_saldo_futuro_geral ;


		   --raise notice 'qtde_saldo_futuro = %',qtde_saldo_futuro;



	        if qtde_saldo_futuro > p_emax then


	          p_sugestao =  p_emax - qtde_saldo_futuro;
	          p_status_transito = 'PREVISÃO EM EXCESSO';



	          if abs(p_sugestao) > rec_transito.compra_transito then


	            p_sugestao = rec_transito.compra_transito *(-1);

	         end if;


	        elseif qtde_saldo_futuro > p_ponto_pedido AND qtde_saldo_futuro <= p_emax AND (qtde_saldo_futuro - (p_cmm * 0.30)) > p_ponto_pedido then

	         p_sugestao = 0;
	         p_status_transito = 'PREVISÃO ADEQUADA';


	        elseif qtde_saldo_futuro > p_ponto_pedido AND qtde_saldo_futuro <= p_emax AND (qtde_saldo_futuro - (p_cmm * 0.30)) <= p_ponto_pedido  then



	         -- raise notice 'p_data_pedido_ant = %',p_data_pedido_ant;


	          p_tr = ((current_date +  (rec_transito.tempo_ressuprimento*30)::int4) - p_data_pedido_ant)::numeric/30;


			  p_sugestao = (p_emax - (greatest(qtde_saldo_futuro-(p_cmm *p_tr),0)));



	          qtde_cobertura_futura =  round(qtde_saldo_futuro/ p_cmm,2);

	          if qtde_cobertura_futura < p_tr then


	            p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';


	          	else


	          	p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';

	          end if;


	        elseif  ( qtde_saldo_futuro  <= p_ponto_pedido) then




	             p_tr = ((current_date +  (rec_transito.tempo_ressuprimento*30)::int4) - p_data_pedido_ant)::numeric/30;


	             --raise notice 'TRRRRRRRR = %',p_tr;



	             p_sugestao = (p_emax - (greatest(qtde_saldo_futuro-(p_cmm *p_tr),0)));


	              qtde_cobertura_futura =  round(qtde_saldo_futuro/ p_cmm,2);

		          if qtde_cobertura_futura < p_tr then


		            p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';


		          	else


		          	p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';

		          end if;



	        else

	          p_sugestao = 0;

	          p_status_transito = 'PRODUTO EM TRÂNSITO';


	        end if;


	       --raise notice 'p_status_transito = %',p_status_transito;
	      --raise notice 'p_sugestao = %',p_sugestao;


	     else    -- COMPRAS HIBRIDAS

	       --raise notice 'COMPRAS HIBRIDAS = %','';

	        qtde_transito = greatest(qtde_transito,0);

	    	qtde_saldo = qtde_estoque +  qtde_transito_atraso;


	       --raise notice 'qtde_estoque = %',qtde_saldo;


	        cont_ped = 1;

	        qtde_saldo_futuro= 0;
	        qtde_saldo_futuro_geral=0;


	        for rec_produtos in (select distinct  gf.id_grupo  ,idproduto from produtos_filial pf
	                          inner join grupo_filial gf
	                           on gf.filial = pf.filial
	                          where gf.id_grupo = rec_transito.id_grupo
	                          and pf.idcategoria = rec_transito.idcategoria and revenda='S' and  status <> 'FL' )
				    loop


			    cont_ped = 1;
	            qtde_saldo_futuro= 0;


			   for rec_pedidos in ( select  data_prevista_cal,sum(qtde) qtde
	      			from analise_requisicoes r inner join produtos_filial pf on r.filial  = pf.filial and r.idproduto = pf.idproduto
		      		where r.idproduto = rec_produtos.idproduto and qtde_pendente > 0 and atraso < 0
		    	  and r.filial  in (select filial from grupo_filial where id_grupo= rec_produtos.id_grupo ) group by data_prevista_cal order by data_prevista_cal)

		    	 loop



			    	if cont_ped = 1 then

                      qtde_dias =  rec_pedidos.data_prevista_cal - current_date ;
                      p_tr = (qtde_dias/30);

                    else


                     qtde_dias =  ((rec_pedidos.data_prevista_cal)  - current_date) - qtde_dias ;
                     p_tr = (qtde_dias/30);

                 end if;


                 --raise notice 'qtde_dias = %',qtde_dias;
                 --raise notice 'rec_pedidos.data_prevista_cal = %',rec_pedidos.data_prevista_cal;



                 consumo_transito_cal = round((p_cmm * (qtde_dias/30)),2);


                 if  consumo_transito_cal > qtde_saldo then


                     consumo_transito_cal = qtde_saldo;

                     qtde_saldo_residual = qtde_saldo - consumo_transito_cal;


                 else

                    qtde_saldo_residual = qtde_saldo - consumo_transito_cal;

                 end if;


                 qtde_saldo_futuro = qtde_saldo_residual + rec_pedidos.qtde;

                 qtde_saldo = qtde_saldo_futuro;


                 cont_ped = cont_ped + 1;


                 p_data_pedido_ant = rec_pedidos.data_prevista_cal;



			        --raise notice '# - qtde_saldo_futuro = %',qtde_saldo_futuro;


		    	 end loop;


		    	  --raise notice 'qtde_saldo_futuro  = %',qtde_saldo_futuro;


		    	 qtde_saldo_futuro_geral = qtde_saldo_futuro_geral + qtde_saldo_futuro;


			end loop;

		     --raise notice 'qtde_saldo_futuro_geral  = %',qtde_saldo_futuro_geral;

		    qtde_saldo_futuro = qtde_saldo_futuro_geral ;



	        if qtde_saldo_futuro > p_emax then


	          p_sugestao =  p_emax - qtde_saldo_futuro;
	          p_status_transito = 'PREVISÃO EM EXCESSO';



	          if abs(p_sugestao) > rec_transito.compra_transito then


	            p_sugestao = rec_transito.compra_transito *(-1);

	         end if;


	        elseif qtde_saldo_futuro > p_ponto_pedido AND qtde_saldo_futuro <= p_emax AND (qtde_saldo_futuro - (p_cmm * 0.30)) > p_ponto_pedido then

	         p_sugestao = 0;
	         p_status_transito = 'PREVISÃO ADEQUADA';


	        elseif qtde_saldo_futuro > p_ponto_pedido AND qtde_saldo_futuro <= p_emax AND (qtde_saldo_futuro - (p_cmm * 0.30)) <= p_ponto_pedido  then




	           --raise notice 'p_tr CONTA= %',p_tr;
	           --raise notice 'p_data_pedido_ant = %',p_data_pedido_ant;


	           p_tr = ((current_date +  (rec_transito.tempo_ressuprimento*30)::int4) - p_data_pedido_ant)::numeric/30;


	           --raise notice 'p_data_pedido_atual = %',p_tr;




			  p_sugestao = (p_emax - (greatest(qtde_saldo_futuro-(p_cmm *p_tr),0)));



	          qtde_cobertura_futura =  round(qtde_saldo_futuro/ p_cmm,2);

	          if qtde_cobertura_futura < p_tr then


	            p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';


	          	else


	          	p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';

	          end if;


	        elseif  ( qtde_saldo_futuro  <= p_ponto_pedido) then




	             p_tr = ((current_date +  (rec_transito.tempo_ressuprimento*30)::int4) - p_data_pedido_ant)::numeric/30;


	             p_sugestao = (p_emax - (greatest(qtde_saldo_futuro-(p_cmm *p_tr),0)));


	              qtde_cobertura_futura =  round(qtde_saldo_futuro/ p_cmm,2);

		          if qtde_cobertura_futura < p_tr then


		            p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';


		          	else


		          	p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';

		          end if;



	        else

	          p_sugestao = 0;

	          p_status_transito = 'PRODUTO EM TRÂNSITO';


	        end if;


	    end if;


	       p_sugestao = gerar_lote_embalagem(p_sugestao,qtde_lote_minimo);


	     -- p_sugestao=0;
	     -- p_status_transito = 'PRODUTO EM TRÂNSITO';


	      --raise notice 'p_sugestao = %',p_sugestao;
	      --raise notice 'p_status_transito = %',p_status_transito;

        --select * from produtos_transito_categorias

           --Update


			update
				produtos_transito_categorias
			set
				iddepartamento = rec_transito.iddepartamento,
				idsecao = rec_transito.idsecao,
				idcategoria = rec_transito.idcategoria,
				descricao_categoria = rec_transito.descricao_categoria,
				consumo_medio_mensal = rec_transito.consumo_medio_mensal,
				desvio_padrao_consumo = rec_transito.desvio_padrao_consumo,
				estoque = rec_transito.estoque,
				ponto_pedido = rec_transito.ponto_pedido,
				estoque_maximo = rec_transito.estoque_maximo,
				compra_transito = rec_transito.compra_transito,
				lote_compras = p_sugestao,
				status = p_status_transito,
				flag = null,
				processamento = current_timestamp
			where
				id_grupo = rec_transito.id_grupo
				and idcategoria = rec_transito.idcategoria;



			if not found then


				insert
				  into produtos_transito_categorias (
					id_grupo,
					iddepartamento,
					idsecao,
					idcategoria,
					descricao_categoria,
					consumo_medio_mensal,
					desvio_padrao_consumo,
					estoque,
					ponto_pedido,
					estoque_maximo,
					compra_transito,
					lote_compras,
					status,
					flag,
					processamento
				)
				values(
					rec_transito.id_grupo,
					rec_transito.iddepartamento,
					rec_transito.idsecao,
					rec_transito.idcategoria,
					rec_transito.descricao_categoria,
					rec_transito.consumo_medio_mensal,
					rec_transito.desvio_padrao_consumo,
					rec_transito.estoque,
					rec_transito.ponto_pedido,
					rec_transito.estoque_maximo,
					rec_transito.compra_transito,
					p_sugestao,
					p_status_transito,
					null,
					current_timestamp
				);


		    end if;


	 end loop;

 delete from  produtos_transito_categorias  where  flag ='D';

end
$$;


ALTER FUNCTION public.processar_produtos_transito_categoria(p_grupo integer, p_departamento character varying, p_idcategoria character varying) OWNER TO systock;

--
-- TOC entry 799 (class 1255 OID 53933)
-- Name: processar_produtos_transito_filial(bigint); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_produtos_transito_filial(p_fornecedor bigint DEFAULT 0) RETURNS void
    LANGUAGE plpgsql
    AS $$
declare
 
rec_transito record;
rec_pedidos record;

p_atraso int4;
qtde_transito_atraso numeric;
qtde_transito numeric;
qtde_estoque numeric;
qtde_saldo  numeric;
p_ponto_pedido numeric;
p_sugestao numeric;
p_emax numeric;
p_cmm numeric;
p_tr numeric;
p_consumo_transito numeric;
p_consumo_transito2 numeric;
qtde_saldo_futuro numeric;
qtde_saldo_residual numeric;
p_status_transito varchar;
qtde_lote_minimo  numeric;
qtde_cobertura_futura numeric;
qtde_dias numeric;
cont_ped numeric;
consumo_transito_cal numeric;
data_temp date;
begin

update produtos_transito_filial set flag ='D' where id_grupo in (select id from grupo_compras);

for rec_transito in(
	SELECT 
	a.id_grupo,
	a.filial,
    a.idfornecedor,
    a.fornecedor,
    a.idcomprador,
    a.comprador,
    a.idproduto,
    a.descricao_produto,
    a.iddepartamento,
    a.departamento,
    a.compra_transito,
    a.consumo_transito * a.fator_conversao AS consumo_transito,
    a.saldo_futuro * a.fator_conversao AS saldo_futuro,
    a.estoque_maximo * a.fator_conversao::double precision AS estoque_maximo,
    a.ponto_pedido * a.fator_conversao::double precision AS ponto_pedido,
    a.consumo_medio_mensal::double precision * a.fator_conversao::double precision AS consumo_medio_mensal,
    a.tempo_ressuprimento,
    a.desvio_padrao_ressuprimento,
    a.estoque::double precision * a.fator_conversao::double precision AS estoque,
    a.status,
        CASE
            WHEN a.status = 'PREVISÃO FUTURA EM EXCESSO'::text AND abs(a.lote_compras * a.fator_conversao::double precision) > a.compra_transito::double precision THEN (a.compra_transito * '-1'::integer::numeric)::double precision
            ELSE gerar_lote_embalagem((a.lote_compras * a.fator_conversao::double precision)::numeric, a.lote_minimo::numeric * a.fator_conversao)::double precision
        END AS lote_compras,
    a.fator_conversao,
    a.unidade_compra,
    a.data_ultima_riquisicao,
    'now'::text::date - a.data_ultima_riquisicao AS tempo_pedido,
    a.nivel_servico,
    a.peso_compras,
        CASE
            WHEN ('now'::text::date - a.data_ultima_riquisicao - 1) < 0 THEN NULL::integer
            ELSE 'now'::text::date - a.data_ultima_riquisicao - 1
        END AS gatilho_transito,
     a.lote_minimo    
   FROM ( SELECT analise_entrada.idfornecedor,
            analise_entrada.fornecedor,
            analise_entrada.idcomprador,
            analise_entrada.comprador,
            analise_entrada.idproduto,
            analise_entrada.descricao_produto,
            analise_entrada.compra_transito,
            analise_entrada.consumo_transito,
            analise_entrada.saldo_futuro,
            analise_entrada.estoque_maximo,
            analise_entrada.ponto_pedido,
            analise_entrada.consumo_medio_mensal,
            analise_entrada.tempo_ressuprimento,
            analise_entrada.desvio_padrao_ressuprimento,
            analise_entrada.estoque,
            analise_entrada.fator_conversao,
            analise_entrada.unidade_compra,
            analise_entrada.lote_minimo,
            analise_entrada.data_ultima_riquisicao,
            analise_entrada.id_grupo,
            analise_entrada.filial,
            analise_entrada.iddepartamento,
            analise_entrada.descricao_departamento AS departamento,
            analise_entrada.nivel_servico,
            analise_entrada.peso_compras,
                case
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) <= 1 THEN 'PRODUTO EM TRANSITO'::text
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.estoque_maximo THEN 'PREVISÃO FUTURA EM EXCESSO'::text
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.ponto_pedido AND analise_entrada.saldo_futuro::double precision <= analise_entrada.estoque_maximo AND (analise_entrada.saldo_futuro::double precision - analise_entrada.consumo_medio_mensal::double precision * 0.3::double precision) > analise_entrada.ponto_pedido THEN 'PREVISÃO FUTURA ADEQUADA'::text
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.ponto_pedido AND analise_entrada.saldo_futuro::double precision <= analise_entrada.estoque_maximo AND (analise_entrada.saldo_futuro::double precision - analise_entrada.consumo_medio_mensal::double precision * 0.3::double precision) <= analise_entrada.ponto_pedido THEN 'PREVISÃO COM SUTIL EXPOSIÇÃO A RUPTURA'::text
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision <= analise_entrada.ponto_pedido THEN 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA'::text
                    ELSE 'PRIMEIRA COMPRA'::text
                END AS status,
                CASE
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.estoque_maximo THEN analise_entrada.estoque_maximo - analise_entrada.saldo_futuro::double precision
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.ponto_pedido AND analise_entrada.saldo_futuro::double precision <= analise_entrada.estoque_maximo AND (analise_entrada.saldo_futuro::double precision - analise_entrada.consumo_medio_mensal::double precision * 0.3::double precision) > analise_entrada.ponto_pedido THEN 0::double precision
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision > analise_entrada.ponto_pedido AND analise_entrada.saldo_futuro::double precision <= analise_entrada.estoque_maximo AND (analise_entrada.saldo_futuro::double precision - analise_entrada.consumo_medio_mensal::double precision * 0.3::double precision) <= analise_entrada.ponto_pedido THEN round((analise_entrada.estoque_maximo - (analise_entrada.saldo_futuro::double precision- getconsumo_transito_grupo_filial_entre_pedidos(analise_entrada.id_grupo::integer, analise_entrada.filial::integer, analise_entrada.idproduto::character varying)))::numeric, 2)::double precision
                    WHEN analise_entrada.status_compra = 0::numeric AND ('now'::text::date - analise_entrada.data_ultima_riquisicao) > 1 AND analise_entrada.saldo_futuro::double precision <= analise_entrada.ponto_pedido THEN round((analise_entrada.estoque_maximo - (analise_entrada.saldo_futuro::double precision - getconsumo_transito_grupo_filial_entre_pedidos(analise_entrada.id_grupo::integer, analise_entrada.filial::integer, analise_entrada.idproduto)))::numeric, 2)::double precision
                    ELSE 0::double precision
                END AS lote_compras
           FROM ( SELECT 
           			b.id_grupo,
           			b.filial,
                    b.idfornecedor,
                    b.fornecedor,
                    b.idcomprador,
                    b.comprador,
                    b.idproduto,
                    max(b.descricao_produto::text) AS descricao_produto,
                    b.iddepartamento,
                    b.descricao_departamento,
                    b.fator_conversao,
                    b.unidade_compra,
                    max(b.lote_minimo) AS lote_minimo,
                    max(b.data_ultima_riquisicao) AS data_ultima_riquisicao,
                    b.arvore_decisao,
                    b.nivel_servico,
                    b.peso_compras,
                    avg(b.compra_transito) AS compra_transito,
                    sum(b.consumo_transito) AS consumo_transito,
                        CASE
                            WHEN (greatest((avg(b.estoque) - sum(b.consumo_transito)),0) + avg(b.compra_transito)) < 0::numeric THEN 0::numeric
                            ELSE greatest((avg(b.estoque) - sum(b.consumo_transito)),0) + avg(b.compra_transito)
                        END AS saldo_futuro,
                    avg(b.amplitude_atual) AS amplitude_atual,
                    avg(b.estoque_maximo) AS estoque_maximo,
                    avg(b.ponto_pedido) AS ponto_pedido,
                    avg(b.consumo_medio_mensal) AS consumo_medio_mensal,
                    avg(b.tempo_ressuprimento) AS tempo_ressuprimento,
                    avg(b.desvio_padrao_ressuprimento) AS desvio_padrao_ressuprimento,
                    avg(b.estoque) AS estoque,
                    avg(b.status_compra) AS status_compra
                   FROM ( SELECT g.id_grupo,
                            p.filial,
                            fornecedor.id AS idfornecedor,
                            fornecedor.razao_social AS fornecedor,
                            comprador.id AS idcomprador,
                            comprador.nome_completo AS comprador,
                            p.idproduto,
                            p.descricao_produto,
                            dep.iddepartamento,
                            dep.descricao_departamento,
                            getcompra_transito_filial(p.filial, p.idproduto) AS compra_transito,
                             case when ((select count(*) from analise_requisicoes ar  
                                        where filial in(select filial from grupo_filial gf where gf.id_grupo=g.id_grupo::numeric)  
                                        and idproduto=p.idproduto and atraso  > 0) > 0)  then
                                     getconsumo_transito_grupo_filial_new(g.id_grupo::integer, p.filial::integer, p.idproduto) +  getconsumo_transito_grupo_filial_2(g.id_grupo::integer, p.filial::integer, p.idproduto)
                               else 
                                 getconsumo_transito_grupo_filial_new(g.id_grupo::integer, p.filial::integer, p.idproduto)
                             end  as consumo_transito,
                            getconsumo_transito_grupo_filial_2(g.id_grupo::integer, p.filial::integer, p.idproduto) AS consumo_transito_2, 
                            amplitude_transito_atual_filial(p.filial::numeric, p.idproduto) AS amplitude_atual,
                            COALESCE(vp.estoque_maximo::double precision, 0::double precision) AS estoque_maximo,
                            COALESCE(vp.ponto_pedido::double precision, 0::double precision) AS ponto_pedido,
                            vp.consumo_medio_mensal,
                            p.tempo_ressuprimento,
                            p.desvio_padrao_ressuprimento,
                            p.estoque,
                            ( SELECT
                                    CASE
                                     WHEN count(*) > 0 THEN 0
                                     ELSE 1
                                    END AS "case"
                                   FROM entrada_mercadorias
                                  WHERE entrada_mercadorias.data_entrada <= 'now'::text::date AND entrada_mercadorias.idproduto::text = p.idproduto::text AND entrada_mercadorias.qtde > 0::double precision) AS status_compra,
                            p.fator_conversao,
                            p.unidade_compra,
                            COALESCE(p.lote_minimo::double precision, 1::double precision) AS lote_minimo,
                            p.data_ultima_riquisicao,
                            p.arvore_decisao,
                            getnivelservico(p.arvore_decisao) AS nivel_servico,
                            getpesocompras(p.arvore_decisao, "substring"(p.arvore_decisao, 3, 1)::numeric) AS peso_compras
                           FROM produtos_filial p
                             LEFT JOIN comprador ON comprador.id = p.idcomprador
                             JOIN grupo_filial g ON g.filial = p.filial
                             JOIN departamentos dep ON dep.iddepartamento = p.idfamilia_produto
                             JOIN vw_grupo_compras_produtos_filial vp ON vp.id_grupo = g.id_grupo AND vp.filial = p.filial AND vp.idproduto::text = p.idproduto::text
                             LEFT JOIN fornecedor ON fornecedor.id = vp.idfornecedor
                          where 
                          	p.revenda::text = 'S'::text AND p.status::text <> 'FL'::text 
                          	AND getcompra_transito_filial(p.filial, p.idproduto) > 0::NUMERIC
                          	AND (p_fornecedor = 0 or p_fornecedor = p.idfornecedor)
                          ) b
                  GROUP BY b.id_grupo, b.filial, b.idfornecedor, b.fornecedor, b.idcomprador, b.comprador, b.idproduto, b.descricao_departamento, b.fator_conversao,
                   b.unidade_compra, b.arvore_decisao, b.nivel_servico, b.peso_compras, b.iddepartamento) analise_entrada
          WHERE analise_entrada.compra_transito > 0::numeric) a
)
  loop 
      
      
      p_atraso=0;
      qtde_transito_atraso =0;
      qtde_transito=0;
      qtde_estoque=0;
      p_sugestao= 0;
      p_consumo_transito =0;
      p_consumo_transito2 = 0;
      qtde_saldo_futuro = 0;
      qtde_lote_minimo =  coalesce(rec_transito.lote_minimo,1);
      qtde_cobertura_futura=0;
      consumo_transito_cal = 0;
      
      
        --Identificar se o produto tem compra em atraso
      
        select count(*) into p_atraso  
		from analise_requisicoes ar  
        where filial = rec_transito.filial
        and idproduto=rec_transito.idproduto and atraso  >= 0  and qtde_pendente > 0;
       
       
        -- Pedidos em atraso;
       
        select  sum(qtde_pendente)  into qtde_transito_atraso 
          from analise_requisicoes r inner join produtos_filial pf on r.filial  = pf.filial and r.idproduto = pf.idproduto 
          where r.idproduto = rec_transito.idproduto and qtde_pendente > 0 and atraso >=0
        and r.filial = rec_transito.filial;  
       
        qtde_transito_atraso = coalesce(qtde_transito_atraso,0);
       
        --Pedidos em Transito Aberto;
      
          select  sum(qtde_pendente)  into qtde_transito 
          from analise_requisicoes r inner join produtos_filial pf on r.filial  = pf.filial and r.idproduto = pf.idproduto 
          where r.idproduto = rec_transito.idproduto and qtde_pendente > 0 and atraso < 0
        and r.filial = rec_transito.filial; 
         
        qtde_transito = coalesce(qtde_transito,0);

       
        -- Parâmetros do Estoque;
       
        qtde_estoque = rec_transito.estoque;
        p_ponto_pedido = rec_transito.ponto_pedido;
        p_emax = rec_transito.estoque_maximo;
        p_cmm = rec_transito.consumo_medio_mensal;
        p_tr =  rec_transito.tempo_ressuprimento;
       
        p_consumo_transito = getconsumo_transito_grupo_filial_new(rec_transito.id_grupo::integer, rec_transito.filial::integer, rec_transito.idproduto);
        
       
        --Somente itens atrasados
       
        if p_atraso > 0 and qtde_transito = 0 then   
        
        
            qtde_transito = greatest(qtde_transito,0);
           
            qtde_saldo = qtde_estoque + qtde_transito_atraso + qtde_transito;
        
            qtde_saldo_residual =  qtde_saldo - p_consumo_transito ;
           
           
            if qtde_saldo_residual > p_emax then -- Excesso
            
             
              p_sugestao =  p_emax - qtde_saldo_residual;
            
             
             if abs(p_sugestao) > qtde_transito_atraso then
             
              
                p_sugestao = qtde_transito_atraso *(-1);
             
             end if;
             
            
            elseif qtde_saldo_residual > p_ponto_pedido AND qtde_saldo_residual <= p_emax AND (qtde_saldo_residual - (p_cmm * 0.30)) > p_ponto_pedido then  -- Adequado
              
            
              p_sugestao = 0;
              p_status_transito = 'PREVISÃO ADEQUADA';
             
             
            elseif qtde_saldo_residual > p_ponto_pedido AND qtde_saldo_residual <= p_emax AND (qtde_saldo_residual - (p_cmm * 0.30)) <= p_ponto_pedido  then 
           
            
            
                p_consumo_transito2 = getconsumo_transito_grupo_filial_2(rec_transito.id_grupo::integer, rec_transito.filial::integer, rec_transito.idproduto);
          
     
                p_sugestao =  (p_emax - (qtde_saldo_residual-p_consumo_transito2));  
           

            
                  qtde_cobertura_futura =  round(qtde_saldo_residual/ greatest(p_cmm, 1),2);
                 
                  if qtde_cobertura_futura < p_tr then
                  
                    
                    p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';
                    
                  
                    else
                    
                    
                    p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';
                  
                  end if;
             
             
            elseif  ( qtde_saldo_residual  <= p_ponto_pedido) then
            
           
                        
              p_consumo_transito2 = getconsumo_transito_grupo_filial_2(rec_transito.id_grupo::integer, rec_transito.filial::integer, rec_transito.idproduto);
              
             
              p_sugestao =  (p_emax - (qtde_saldo_residual-p_consumo_transito2)); --
              qtde_cobertura_futura =  round(qtde_saldo_residual/ greatest(p_cmm, 1),2);
             
             
              if qtde_cobertura_futura < p_tr then
              
                
                p_status_transito = 'PREVISÃO COM ELEVADA EXPOSIÇÃO A RUPTURA';
                
              
                else
                
                
                p_status_transito = 'PREVISÃO COM BAIXA EXPOSIÇÃO A RUPTURA';
              
              end if;
                      
            
            else
            
              p_sugestao = 0;
              p_status_transito = 'PRODUTO EM TRÂNSITO';
             
            
            end if;
            
          
            p_sugestao = gerar_lote_embalagem(p_sugestao,qtde_lote_minimo);
           
           
           
        elseif p_atraso = 0 and  qtde_transito > 0  then --Somente itens Abertos
        
        
        
            qtde_transito = greatest(qtde_transito,0);
        
            qtde_saldo = qtde_estoque;
        
        
            -- Quantidade de Pedidos Abertos 
        
        
            cont_ped = 1;
                          
            qtde_saldo_futuro= 0;
            
          
            for rec_pedidos in ( 
				select  data_prevista_cal,sum(qtde) qtde
                from analise_requisicoes r inner join produtos_filial pf on r.filial  = pf.filial and r.idproduto = pf.idproduto 
                where 
					r.idproduto = rec_transito.idproduto 
					and qtde_pendente > 0 and atraso < 0
              		and r.filial = rec_transito.filial
				group by data_prevista_cal 
				order by data_prevista_cal
			)
              
             loop 
                 
                 
                  if cont_ped = 1 then 
                 
                      data_temp= rec_pedidos.data_prevista_cal;
                      qtde_dias =  rec_pedidos.data_prevista_cal - current_date ;
                      p_tr = (qtde_dias/30);
                     
                 
                    else
                   
                    
                     qtde_dias = ((rec_pedidos.data_prevista_cal)  - data_temp) ;
                     p_tr = (qtde_dias/30);
                     data_temp= rec_pedidos.data_prevista_cal;
                    
                    
                 end if;       
                         
                
                 consumo_transito_cal = round((p_cmm * (qtde_dias/30)),2);
                
                 
                 if  consumo_transito_cal > qtde_saldo then 
                 
                 
                     consumo_transito_cal = qtde_saldo;
                    
                     qtde_saldo_residual = qtde_saldo - consumo_transito_cal;
                 
                 
                 else
                 
                    qtde_saldo_residual = qtde_saldo - consumo_transito_cal; 
                 
                 end if;
                 
                
                 qtde_saldo_futuro = qtde_saldo_residual + rec_pedidos.qtde;
                   
                 qtde_saldo = qtde_saldo_futuro;    
                        
                                 
                 cont_ped = cont_ped + 1;
                 
                
             end loop;
             
                   
           
            if qtde_saldo_futuro > p_emax then
            
          
              p_sugestao =  p_emax - qtde_saldo_futuro;
              p_status_transito = 'PREVISÃO EM EXCESSO';
             
              
             
              if abs(p_sugestao) > rec_transito.compra_transito then
             
              
                p_sugestao = rec_transito.compra_transito *(-1);
             
             end if;
             
            
            elseif qtde_saldo_futuro > p_ponto_pedido AND qtde_saldo_futuro <= p_emax AND (qtde_saldo_futuro - (p_cmm * 0.30)) > p_ponto_pedido then 
              
             p_sugestao = 0;
             p_status_transito = 'PREVISÃO ADEQUADA';
             
             
            elseif qtde_saldo_futuro > p_ponto_pedido AND qtde_saldo_futuro <= p_emax AND (qtde_saldo_futuro - (p_cmm * 0.30)) <= p_ponto_pedido  then 
           
             if qtde_transito > 0 then
            
                        select 
							--((current_date + (produtos.tempo_medio_ressuprimento::int4)) - ((current_date + ((vw_requisicoes.data_solicitacao+produtos.tempo_medio_ressuprimento::int4) - current_date)) - current_date) - current_date)::numeric/30  into p_tr
							GREATEST((current_date + produtos.tempo_medio_ressuprimento::int4) - COALESCE(vw_requisicoes.data_prevista_cal, vw_requisicoes.data_previsao), 0) / 30.0 into p_tr -- Lucas: tempo entre a ultima entrada prevista e a entrada da sugestão de compra
                        from vw_requisicoes                    
