--

CREATE FUNCTION public.processar_sazonalidade() RETURNS void
    LANGUAGE plpgsql
    AS $$
declare
rec_prod record;
rec_total_tri record;
ano_ref numeric;
data_ini date;
data_fim date;
tot_ano_1 numeric;
tot_ano_2 numeric;
tot_ano_3 numeric;
tot_ano_4 numeric;
md_ano_1 numeric;
md_ano_2 numeric;
md_ano_3 numeric;
md_ano_4 numeric;
begin
	
	

	
   
for rec_prod in (select id_grupo ,idproduto from vw_grupo_compras_produtos_mt  where id_grupo=1 and idproduto='2373')
  loop 
    
  
     ano_ref = (select date_part('year',first_day_trimestre(current_date) - interval '4 year'));	
	 data_ini = (select ('01/01/'||ano_ref)::date);
 	 data_fim = (select ('31/12/'||ano_ref)::date);
  
    
    	 for rec_total_tri in (
         
            SELECT * FROM crosstab( 
			   'select date_part(''quarter'',emissao)::varchar trimestre,date_part(''year'',emissao)::varchar ano , sum(qtde)::numeric  total
			   from consumos where idproduto='''||rec_prod.idproduto||''' and emissao between '''||data_ini||''' and '''||data_fim||'''
			   group by idproduto, date_part(''year'',emissao) , date_part(''quarter'',emissao)
			   order by date_part(''quarter'',emissao)', 
			   'select distinct date_part(''year'',emissao) from consumos where  idproduto ='''||rec_prod.idproduto||'''  and emissao between '''||data_ini||''' and '''||data_fim||''' order by 1' 
			   ) as ct (trimestre varchar,total varchar)
			   
			   )
			   
         loop 
         
         
             UPDATE sazonalidade_produtos SET ano_referencia=date_part('year',current_date),sd_ano_1=rec_total_tri.total::numeric  WHERE id_grupo=rec_prod.id_grupo AND trimestre=rec_total_tri.trimestre::int4 AND idproduto=rec_prod.idproduto;

              if  NOT FOUND then
              
                 INSERT INTO sazonalidade_produtos (id_grupo, trimestre, idproduto, sd_ano_1,ano_referencia) VALUES(rec_prod.id_grupo,rec_total_tri.trimestre::int4,rec_prod.idproduto,rec_total_tri.total::numeric,date_part('year',current_date));
              
              end if;
         
             
         end loop;
        
        
        
     ano_ref = (select date_part('year',first_day_trimestre(current_date) - interval '3 year'));	
	 data_ini = (select ('01/01/'||ano_ref)::date);
 	 data_fim = (select ('31/12/'||ano_ref)::date);
  
    
    	 for rec_total_tri in (
         
            SELECT * FROM crosstab( 
			   'select date_part(''quarter'',emissao)::varchar trimestre,date_part(''year'',emissao)::varchar ano , sum(qtde)::numeric  total
			   from consumos where idproduto='''||rec_prod.idproduto||''' and emissao between '''||data_ini||''' and '''||data_fim||'''
			   group by idproduto, date_part(''year'',emissao) , date_part(''quarter'',emissao)
			   order by date_part(''quarter'',emissao)', 
			   'select distinct date_part(''year'',emissao) from consumos where  idproduto ='''||rec_prod.idproduto||'''  and emissao between '''||data_ini||''' and '''||data_fim||''' order by 1' 
			   ) as ct (trimestre varchar,total varchar)
			   
			   )
			   
         loop 
         
         
             UPDATE sazonalidade_produtos SET ano_referencia=date_part('year',current_date),sd_ano_2=rec_total_tri.total::numeric  WHERE id_grupo=rec_prod.id_grupo AND trimestre=rec_total_tri.trimestre::int4 AND idproduto=rec_prod.idproduto;

              if  NOT FOUND then
              
                 INSERT INTO sazonalidade_produtos (id_grupo, trimestre, idproduto, sd_ano_2,ano_referencia) VALUES(rec_prod.id_grupo,rec_total_tri.trimestre::int4,rec_prod.idproduto,rec_total_tri.total::numeric,date_part('year',current_date));
              
              end if;
         
             
         end loop;
        
        
        ano_ref = (select date_part('year',first_day_trimestre(current_date) - interval '2 year'));	
	 	data_ini = (select ('01/01/'||ano_ref)::date);
 	 	data_fim = (select ('31/12/'||ano_ref)::date);
  
    
    	 for rec_total_tri in (
         
            SELECT * FROM crosstab( 
			   'select date_part(''quarter'',emissao)::varchar trimestre,date_part(''year'',emissao)::varchar ano , sum(qtde)::numeric  total
			   from consumos where idproduto='''||rec_prod.idproduto||''' and emissao between '''||data_ini||''' and '''||data_fim||'''
			   group by idproduto, date_part(''year'',emissao) , date_part(''quarter'',emissao)
			   order by date_part(''quarter'',emissao)', 
			   'select distinct date_part(''year'',emissao) from consumos where  idproduto ='''||rec_prod.idproduto||'''  and emissao between '''||data_ini||''' and '''||data_fim||''' order by 1' 
			   ) as ct (trimestre varchar,total varchar)
			   
			   )
			   
         loop 
         
         
             UPDATE sazonalidade_produtos SET ano_referencia=date_part('year',current_date),sd_ano_3=rec_total_tri.total::numeric  WHERE id_grupo=rec_prod.id_grupo AND trimestre=rec_total_tri.trimestre::int4 AND idproduto=rec_prod.idproduto;

              if  NOT FOUND then
              
                 INSERT INTO sazonalidade_produtos (id_grupo, trimestre, idproduto, sd_ano_3,ano_referencia) VALUES(rec_prod.id_grupo,rec_total_tri.trimestre::int4,rec_prod.idproduto,rec_total_tri.total::numeric,date_part('year',current_date));
              
              end if;
         
             
         end loop;
        
        
        
        ano_ref = (select date_part('year',first_day_trimestre(current_date) - interval '1 year'));	
	 	data_ini = (select ('01/01/'||ano_ref)::date);
 	 	data_fim = (select ('31/12/'||ano_ref)::date);
  
    
    	 for rec_total_tri in (
         
            SELECT * FROM crosstab( 
			   'select date_part(''quarter'',emissao)::varchar trimestre,date_part(''year'',emissao)::varchar ano , sum(qtde)::numeric  total
			   from consumos where idproduto='''||rec_prod.idproduto||''' and emissao between '''||data_ini||''' and '''||data_fim||'''
			   group by idproduto, date_part(''year'',emissao) , date_part(''quarter'',emissao)
			   order by date_part(''quarter'',emissao)', 
			   'select distinct date_part(''year'',emissao) from consumos where  idproduto ='''||rec_prod.idproduto||'''  and emissao between '''||data_ini||''' and '''||data_fim||''' order by 1' 
			   ) as ct (trimestre varchar,total varchar)
			   
			   )
			   
         loop 
         
         
             UPDATE sazonalidade_produtos SET ano_referencia=date_part('year',current_date), sd_ano_4=rec_total_tri.total::numeric  WHERE id_grupo=rec_prod.id_grupo AND trimestre=rec_total_tri.trimestre::int4 AND idproduto=rec_prod.idproduto;

              if  NOT FOUND then
              
                 INSERT INTO sazonalidade_produtos (id_grupo, trimestre, idproduto, sd_ano_4,ano_referencia) VALUES(rec_prod.id_grupo,rec_total_tri.trimestre::int4,rec_prod.idproduto,rec_total_tri.total::numeric,date_part('year',current_date));
              
              end if;
         
             
         end loop;
        
        
         select
		 sum(nullif(sd_ano_1,0)),
		 sum(nullif(sd_ano_2,0)),
		 sum(nullif(sd_ano_3,0)),
		 sum(nullif(sd_ano_4,0)),
		 avg(nullif(sd_ano_1,0)),
		 avg(nullif(sd_ano_2,0)),
		 avg(nullif(sd_ano_3,0)),
		 avg(nullif(sd_ano_4,0))
		 into 
		 tot_ano_1,tot_ano_2,tot_ano_3,tot_ano_4,md_ano_1,md_ano_2,md_ano_3,md_ano_4
		 from sazonalidade_produtos sp  
		 where idproduto = rec_prod.idproduto;
		
		
		update
		sazonalidade_produtos
		set
		total_ano_1 = tot_ano_1,
		total_ano_2 = tot_ano_2,
		total_ano_3 = tot_ano_3,
		total_ano_4 = tot_ano_4,
		media_ano_1 = md_ano_1,
		media_ano_2 = md_ano_2,
		media_ano_3 = md_ano_3,
		media_ano_4 = md_ano_4,
		coef_ano_1 = round(sd_ano_1/md_ano_1,2),
	    coef_ano_2 = round(sd_ano_2/md_ano_2,2),
		coef_ano_3 = round(sd_ano_3/md_ano_3,2),
		coef_ano_4 = round(sd_ano_4/md_ano_4,2),
		coef_medio =round((round(sd_ano_1/md_ano_1,2)+round(sd_ano_2/md_ano_2,2)+round(sd_ano_3/md_ano_3,2)+round(sd_ano_4/md_ano_4,2))/4,2),
		mca =round((tot_ano_4-tot_ano_1)/4,2)
	  
	    
	where
		id_grupo =  rec_prod.id_grupo
		and idproduto =  rec_prod.idproduto;
	
	
    update
		sazonalidade_produtos
		set
		taxa_crescimento = round((total_ano_4+mca)/4,2),
	    prev_cresc_trim = round(coef_medio * round((total_ano_4+mca)/4,2),2)  
	where
		id_grupo =  rec_prod.id_grupo
		and idproduto =  rec_prod.idproduto;
	
  end loop;
	
 end;
$$;


ALTER FUNCTION public.processar_sazonalidade() OWNER TO systock;

--
-- TOC entry 806 (class 1255 OID 53941)
-- Name: processar_similares_filial(); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_similares_filial() RETURNS void
    LANGUAGE plpgsql
    AS $$  
declare
 
rec_dados record;
rec_similares record;
estoque_agrupado numeric;
est_temp numeric;
und_venda varchar;
estoque_pai numeric;
estoque_final numeric;
fator_conversao_pai numeric;
existe numeric;
est_similar numeric;
    
begin
	   
 for rec_similares in (select id_item_pai ,id_item_filho,agregar_estoque from similares s where s.agregar_estoque='S'  order by id_item_pai)	
 
 loop 
	   
   for rec_dados in (select id_grupo ,filial from grupo_filial gf order by filial)
     loop 
     
   
		    select coalesce(estoque_temp,0),unidade_compra,fator_conversao into est_temp,und_venda,fator_conversao_pai from produtos_filial pf 
		    	where filial = rec_dados.filial and idproduto = rec_similares.id_item_pai;
		
		   
		    estoque_pai = (select get_estoque_diario_filial(rec_dados.filial,rec_similares.id_item_pai,current_date));
		    
		    est_temp = estoque_pai;
			   
			   if rec_similares.agregar_estoque ='S' then
			   
				       select sum(get_estoque_diario_filial(p.filial,p.idproduto,current_date)*fator_conversao) 
				         into estoque_agrupado
				       from produtos_filial p 
				       where p.filial=rec_dados.filial and  p.idproduto in (select id_item_filho from similares 
				                           where id_item_pai= rec_similares.id_item_pai 
				                          and agregar_estoque='S')
				           and p.unidade_compra = und_venda;

    -- Ajuste feito via migration para agregar o estoque do produto combinado
    estoque_agrupado = coalesce(estoque_agrupado, 0) + coalesce((
        SELECT
            CASE
                WHEN coalesce(p.estoque, 0) < coalesce(get_estoque_similar_produto_combinado(p.id_grupo::int, p.filial::int, p.id_produto_combinado), 0) THEN coalesce(p.estoque, 0) -- devolve apenas estoque, porque o estoque do similar ainda não está sendo considerado
                ELSE GREATEST(coalesce(p.estoque, 0) - coalesce(get_estoque_similar_produto_combinado(p.id_grupo::int, p.filial::int, p.id_produto_combinado), 0), 0) -- estoque do similar está dentro de estoque, por isso ele é subtraido
            END
        FROM produtos_combinados_compras_filial p
        WHERE
            p.filial = rec_dados.filial
            AND p.id_produto_combinado IN (
                SELECT s.id_item_filho
                FROM similares s
                WHERE
                    s.id_item_pai = rec_similares.id_item_pai
                    AND substring(s.id_item_filho, 0, 8) = 'SYSCOMB'
                    AND s.agregar_estoque = 'S'
            )
        LIMIT 1
    ), 0); 
				      
				      
				      estoque_final = coalesce(estoque_agrupado/fator_conversao_pai,0)+ coalesce(estoque_pai,0);
				     
				      est_similar = coalesce(estoque_agrupado/fator_conversao_pai,0);
			   
			     else
			     
			     	  estoque_final=  coalesce(estoque_pai,0);
			     	  est_temp = 0;
			     	  estoque_agrupado=0;
			     	  est_similar = 0;
			   
			   end if;
		 
		       update produtos_filial set estoque = estoque_final,estoque_similar=est_similar,processamento = current_timestamp,estoque_temp=est_temp  where filial=rec_dados.filial and idproduto = rec_similares.id_item_pai;
		      
		      
	   end loop;	

  end loop;	   
 
      
end
  $$;


ALTER FUNCTION public.processar_similares_filial() OWNER TO systock;

--
-- TOC entry 807 (class 1255 OID 53942)
-- Name: processar_status_produto(date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_status_produto(p_dataref date DEFAULT (('now'::text)::date - 1)) RETURNS void
    LANGUAGE plpgsql PARALLEL SAFE
    AS $$
declare

rec_prod record;

    v_ultima_entrada date;
    v_ultima_solicitacao date;
    v_id_solicitacao int8;
    v_estoque_solicitacao numeric(12,4);
    v_status_percepcao varchar;
    v_media_mensal numeric(12,4);
    v_ult_saida date;
    v_tempo_ult_venda int8;
    v_qtde_dias_ruptura int8;
    v_dataini date;
    v_datafim date;
   	v_data_ruptura date;

begin


 update status_produto  set flag='D' where ano=date_part('year',p_dataref) and mes=date_part('month',p_dataref);

 select first_day(p_dataref) , last_day(p_dataref) into v_dataini,v_datafim;


 for rec_prod in ( SELECT a.id_grupo,
    a.filial,
    a.ano,
    a.mes,
    a.descricao_produto,
    a.descricao_familia_produto,
    a.custo_unitario,
    a.valor_unitario,
    a.estoque,
    a.estoque_transito,
    a.status_compra,
    a.idproduto,
    a.data_solicitacao,
    a.arvore_decisao,
    a.estoque_seguranca,
    a.ponto_pedido,
    a.estoque_maximo,
    a.consumo_medio,
    a.sugestao,
    a.necessidade,
    a.processamento,
    a.indice_nivel,
    a.nivel_servico,
    a.peso_nivel_servico,
    a.status_produto,
    a.status_exposicao,
    a.peso_status,
    a.revenda,
    a.fora_linha,
    a.nome_completo,
    a.id,
    a.razao_social,
    a.data_cadastro,
    a.peso_nivel_servico * a.peso_status::numeric AS analise_qualitativa,
    a.tempo_ressuprimento,
    a.desvio_padrao_ressuprimento
   FROM ( SELECT gf.id_grupo,
            s.filial,
            s.ano,
            s.mes,
            p.descricao_produto,
            familia_produtos.descricao_familia_produto,
            p.custo_unitario * p.fator_conversao AS custo_unitario,
            p.valor_unitario * p.fator_conversao AS valor_unitario,
            s.estoque,
            getcompra_transito_periodo_filial(s.filial::numeric, s.idproduto, s.data) AS estoque_transito,
                CASE
                    WHEN getcompra_transito_periodo_filial(s.filial::numeric, s.idproduto, s.data) > 0::numeric THEN 'COM PEDIDO'::text
                    ELSE 'SEM PEDIDO'::text
                END AS status_compra,
            s.idproduto,
            s."data"  as data_solicitacao,
            s.arvore_decisao ,
            s.esseg  as estoque_seguranca,
            s.ppd as ponto_pedido,
            s.emax  as estoque_maximo,
            s.cmm  as consumo_medio,
            s.sugestao_compras  as sugestao,
                CASE
                    WHEN s.ppd > (s.estoque + getcompra_transito_periodo_filial(s.filial::numeric, s.idproduto, s.data)) THEN s.emax - (s.estoque + getcompra_transito_periodo_filial(s.filial::numeric, s.idproduto, s.data))
                    ELSE 0::numeric
                END AS necessidade,
            s.processamento,
            n.indice AS indice_nivel,
            p.nivel_servico,
            n.peso AS peso_nivel_servico,
                CASE
                    WHEN s.estoque > (ceil(s.emax) * n.peso) THEN 'EXCESSO'::text
                    WHEN s.estoque = 0::numeric AND s.media_trimestre > 0::numeric THEN 'RUPTURA'::text
                    WHEN s.estoque = 0::numeric AND s.media_trimestre = 0::numeric THEN 'SEM MOVIMENTO'::text
                    WHEN s.estoque > s.ppd AND s.estoque <= (ceil(s.emax) * n.peso) THEN 'ADEQUADO'::text
                    WHEN s.estoque <= s.ppd AND getcompra_transito_periodo_filial(s.filial::numeric, s.idproduto, s.data) > 0::numeric THEN 'EXPOSTO COM PEDIDO'::text
                    WHEN s.estoque <= s.ppd AND getcompra_transito_periodo_filial(s.filial::numeric, s.idproduto, s.data) = 0::numeric THEN 'EXPOSTO SEM PEDIDO'::text
                    ELSE NULL::text
                END AS status_produto,
                CASE
                    WHEN s.estoque <= s.ppd AND s.estoque > (s.ppd - s.esseg) THEN 'SUTIL'::text
                    WHEN s.estoque <= s.ppd AND s.estoque < (s.ppd - s.esseg) THEN 'ELEVADA'::text
                    ELSE ' '::text
                END AS status_exposicao,
                CASE
                    WHEN s.estoque > (ceil(s.emax) * n.peso) THEN 10
                    WHEN s.estoque = 0::numeric THEN 25
                    WHEN s.estoque > s.ppd AND s.estoque <= (ceil(s.emax) * n.peso) THEN 30
                    WHEN s.estoque <= s.ppd AND getcompra_transito_periodo_filial(s.filial::numeric, s.idproduto, s.data) = 0::numeric THEN 15
                    WHEN s.estoque <= s.ppd AND getcompra_transito_periodo_filial(s.filial::numeric, s.idproduto, s.data) <> 0::numeric THEN 20
                    ELSE NULL::integer
                END AS peso_status,
            p.revenda,
            p.status AS fora_linha,
            c.nome_completo,
            f.id,
            f.razao_social,
              p.data_cadastro,
              s.tempo_ressuprimento,
              s.desvio_padrao_ressuprimento
           FROM saldo_filiais s
             JOIN produtos_filial p ON p.filial = s.filial AND p.idproduto::text = s.idproduto::text
             JOIN nivel_servico n ON n.descricao_nivel_servico::text = p.nivel_servico::text
             JOIN comprador c ON c.id = p.idcomprador
             JOIN fornecedor f ON p.idfornecedor = f.id
             JOIN familia_produtos ON p.idfamilia_produto = familia_produtos.idfamilia_produto
             JOIN grupo_filial gf ON gf.filial = s.filial
          where (s.data = p_dataref) AND (s."data" - COALESCE(p.data_cadastro,current_date-365)) > 180 AND p.status::text <> 'FL'::text AND p.revenda::text = 'S'::text AND familia_produtos.descricao_familia_produto::text !~~ '%FEIRAO%'::text AND familia_produtos.descricao_familia_produto::text !~~ '%AVARIA%'::text
          ORDER BY s.data)a)

          loop




               --   ult_saida;tempo_ult_venda ok

               select  max(c2.emissao)  ,   'now'::text::date - max(c2.emissao)
                into v_ult_saida,v_tempo_ult_venda
               FROM consumos c2
                  WHERE c2.filial = rec_prod.filial  AND c2.idproduto = rec_prod.idproduto;

                -- media_mensal ok

                select avg(s2.media_trimestre)
                   into v_media_mensal
                   FROM saldo_filiais s2
                  WHERE s2.filial = rec_prod.filial AND s2.idproduto = rec_prod.idproduto AND s2.data >= v_dataini AND s2.data <= v_datafim;


                --qtde_dias_ruptura ok

                SELECT count(*), min(data) as data_ruptura
                       into v_qtde_dias_ruptura, v_data_ruptura
			                   FROM saldo_filiais
			                  WHERE saldo_filiais.filial = rec_prod.filial
			                  AND saldo_filiais.idproduto  = rec_prod.idproduto
			                  AND saldo_filiais.data >= v_dataini AND saldo_filiais.data <= v_datafim
			                  AND saldo_filiais.media_trimestre > 0::numeric
			                  AND saldo_filiais.estoque = 0::numeric ;

                --status_percepcao ok


                SELECT w.status_percepcao
                   into v_status_percepcao
                   FROM analise_percepcao_compras_grupos w
                  WHERE w.filial = rec_prod.filial
                  AND w.idproduto = rec_prod.idproduto
                  AND w.ordem_compra = (( SELECT max(analise_requisicoes.id_solicitacao) AS max
                           					FROM analise_requisicoes
                         				  WHERE analise_requisicoes.idproduto = rec_prod.idproduto
                         				  AND analise_requisicoes.data_solicitacao <= v_datafim  LIMIT 1))
                 LIMIT 1;



                  --estoque_solicitacao ok

                  SELECT saldo_filiais.estoque
                   into v_estoque_solicitacao
                   FROM saldo_filiais
                  WHERE saldo_filiais.filial = rec_prod.filial
                  AND saldo_filiais.idproduto = rec_prod.idproduto
                  AND saldo_filiais.data = (( SELECT max(analise_requisicoes.data_solicitacao)
                           						FROM analise_requisicoes
                          					  WHERE analise_requisicoes.filial = rec_prod.filial
                          					  AND analise_requisicoes.idproduto = rec_prod.idproduto
                          					  AND analise_requisicoes.data_solicitacao <= v_datafim LIMIT 1));

                  --id_solicitacao ok

                  SELECT max(analise_requisicoes.id_solicitacao)
                   into v_id_solicitacao
                   FROM analise_requisicoes
                  WHERE (analise_requisicoes.filial IN ( SELECT grupo_filial.filial
                           FROM grupo_filial
                          WHERE grupo_filial.id_grupo = rec_prod.id_grupo))
                          AND analise_requisicoes.idproduto  = rec_prod.idproduto
                          AND analise_requisicoes.data_solicitacao <= v_datafim
                 LIMIT 1;


                  --ultima_solicitacao ok

                 SELECT max(analise_requisicoes.data_solicitacao)
                   into v_ultima_solicitacao
                   FROM analise_requisicoes
                  WHERE (analise_requisicoes.filial IN ( SELECT grupo_filial.filial
                           FROM grupo_filial
                          WHERE grupo_filial.id_grupo = rec_prod.id_grupo))
                          AND analise_requisicoes.idproduto = rec_prod.idproduto
                          AND analise_requisicoes.data_solicitacao <= v_datafim
                 LIMIT 1;

                 --ultima_entrada ok

                 SELECT max(em.data_entrada)
                   into v_ultima_entrada
                   FROM entrada_mercadorias em
                  WHERE (em.idfilial IN ( SELECT grupo_filial.filial
                           FROM grupo_filial
                          WHERE grupo_filial.id_grupo = rec_prod.id_grupo))
                          AND em.idproduto = rec_prod.idproduto
                          AND em.data_entrada <= v_datafim
                 LIMIT 1;




          update
				status_produto
			set
				descricao_produto = rec_prod.descricao_produto,
				descricao_familia_produto = rec_prod.descricao_familia_produto,
				custo_unitario = rec_prod.custo_unitario,
				valor_unitario = rec_prod.valor_unitario,
				estoque = rec_prod.estoque,
				estoque_transito = rec_prod.estoque_transito,
				status_compra = rec_prod.status_compra,
				data_solicitacao = rec_prod.data_solicitacao,
				arvore_decisao = rec_prod.arvore_decisao,
				estoque_seguranca = rec_prod.estoque_seguranca,
				ponto_pedido = rec_prod.ponto_pedido,
				estoque_maximo = rec_prod.estoque_maximo,
				consumo_medio = rec_prod.consumo_medio,
				sugestao = rec_prod.sugestao,
				necessidade = rec_prod.necessidade,
				processamento = rec_prod.processamento,
				indice_nivel = rec_prod.indice_nivel,
				nivel_servico = rec_prod.nivel_servico,
				peso_nivel_servico = rec_prod.peso_nivel_servico,
				status_produto = rec_prod.status_produto,
				status_exposicao = rec_prod.status_exposicao,
				peso_status = rec_prod.peso_status,
				revenda = rec_prod.revenda,
				fora_linha = rec_prod.fora_linha,
				nome_completo = rec_prod.nome_completo,
				ultima_entrada = v_ultima_entrada,
				ultima_solicitacao = v_ultima_solicitacao,
				id_solicitacao = v_id_solicitacao,
				estoque_solicitacao = v_estoque_solicitacao,
				status_percepcao = v_status_percepcao,
				razao_social = rec_prod.razao_social,
				qtde_dias_ruptura = v_qtde_dias_ruptura,
				data_cadastro = rec_prod.data_cadastro,
				media_mensal = v_media_mensal,
				ult_saida = v_ult_saida,
				tempo_ult_venda = v_tempo_ult_venda,
				analise_qualitativa = rec_prod.analise_qualitativa,
				tempo_ressuprimento =rec_prod.tempo_ressuprimento,
				desvio_padrao_ressuprimento =rec_prod.desvio_padrao_ressuprimento,
				flag=null,
				data_ruptura = v_data_ruptura
			where
				id_grupo = rec_prod.id_grupo
				and filial = rec_prod.filial
				and ano = rec_prod.ano
				and mes = rec_prod.mes
				and id = rec_prod.id
				and idproduto = rec_prod.idproduto;


	           if not found then

	            INSERT INTO status_produto
				(id_grupo, filial, ano, mes, descricao_produto, descricao_familia_produto, custo_unitario, valor_unitario, estoque,
				 estoque_transito, status_compra, idproduto, data_solicitacao, arvore_decisao, estoque_seguranca, ponto_pedido, estoque_maximo,
				 consumo_medio, sugestao, necessidade, processamento, indice_nivel, nivel_servico, peso_nivel_servico, status_produto,
				 status_exposicao, peso_status, revenda, fora_linha, nome_completo, ultima_entrada, ultima_solicitacao, id_solicitacao,
				 estoque_solicitacao, status_percepcao, id, razao_social, qtde_dias_ruptura, data_cadastro, media_mensal, ult_saida, tempo_ult_venda,
				 analise_qualitativa,data_referencia,tempo_ressuprimento,desvio_padrao_ressuprimento,
				data_ruptura)
				VALUES(rec_prod.id_grupo, rec_prod.filial, rec_prod.ano, rec_prod.mes, rec_prod.descricao_produto, rec_prod.descricao_familia_produto, rec_prod.custo_unitario, rec_prod.valor_unitario,
						rec_prod.estoque, rec_prod.estoque_transito, rec_prod.status_compra, rec_prod.idproduto, rec_prod.data_solicitacao, rec_prod.arvore_decisao, rec_prod.estoque_seguranca, rec_prod.ponto_pedido,
					rec_prod.estoque_maximo, rec_prod.consumo_medio, rec_prod.sugestao, rec_prod.necessidade, rec_prod.processamento, rec_prod.indice_nivel, rec_prod.nivel_servico, rec_prod.peso_nivel_servico, rec_prod.status_produto,
					rec_prod.status_exposicao, rec_prod.peso_status, rec_prod.revenda, rec_prod.fora_linha, rec_prod.nome_completo, v_ultima_entrada, v_ultima_solicitacao,v_id_solicitacao, v_estoque_solicitacao,
					v_status_percepcao, rec_prod.id, rec_prod.razao_social, v_qtde_dias_ruptura, rec_prod.data_cadastro, v_media_mensal, v_ult_saida, V_tempo_ult_venda, rec_prod.analise_qualitativa,
					('01/'||lpad(CAST(rec_prod.mes AS VARCHAR),2,'0')||'/'||rec_prod.ano)::date,rec_prod.tempo_ressuprimento,rec_prod.desvio_padrao_ressuprimento, v_data_ruptura

				);

	           end if;


          end loop;

          delete from  status_produto  where ano=date_part('year',p_dataref) and mes=date_part('month',p_dataref) and flag='D';

end
  $$;


ALTER FUNCTION public.processar_status_produto(p_dataref date) OWNER TO systock;

--
-- TOC entry 808 (class 1255 OID 53944)
-- Name: processar_tempo_cobertura_compras(); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_tempo_cobertura_compras() RETURNS void
    LANGUAGE plpgsql
    AS $$
            DECLARE
                filial_red record;
            BEGIN
                FOR filial_red IN (
                    SELECT
                        gf.id_grupo,
                        gf.filial,
                        t.pqr,
                        t.xyz,
                        t.id_user,
                        t.tempo_cobertura,
                        t.tempo_cobertura_esseg
                    FROM tempo_cobertura_compras_geral t
                    INNER JOIN grupo_filial gf ON TRUE
                    WHERE t.deleted_at IS NULL
                )
                LOOP
                    UPDATE
                        public.tempo_cobertura_compras
                    SET
                        tempo_cobertura = filial_red.tempo_cobertura,
                        tempo_cobertura_esseg = filial_red.tempo_cobertura_esseg,
                        updated_at = current_timestamp
                    WHERE
                        id_grupo = filial_red.id_grupo
                        AND filial = filial_red.filial
                        AND pqr = filial_red.pqr
                        AND xyz = filial_red.xyz
                        AND deleted_at IS NULL;

                    IF (NOT FOUND) THEN
                        INSERT INTO tempo_cobertura_compras (
                            id_grupo, filial, id_user, pqr, xyz,
                            tempo_cobertura, tempo_cobertura_esseg,
                            created_at, updated_at, aplicado)
                        VALUES (
                            filial_red.id_grupo,
                            filial_red.filial,
                            filial_red.id_user,
                            filial_red.pqr,
                            filial_red.xyz,
                            filial_red.tempo_cobertura,
                            filial_red.tempo_cobertura_esseg,
                            current_timestamp,
                            current_timestamp,
                            current_timestamp
                        );
                    END IF;
                END LOOP;
            END;
            $$;


ALTER FUNCTION public.processar_tempo_cobertura_compras() OWNER TO systock;

--
-- TOC entry 809 (class 1255 OID 53945)
-- Name: processar_totais(); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.processar_totais() RETURNS void
    LANGUAGE plpgsql PARALLEL SAFE
    AS $$
declare
 
rec_grupo record;
rec_totais_forn record; 
rec_totais_comp record;
rec_totais_seg record;
    
begin
	
update totais_produtos_fonecedores set status ='D' where idgrupo in (select id from grupo_compras);
update totais_produtos_compradores set status ='D' where idgrupo in (select id from grupo_compras);
update totais_produtos_segmentos set status ='D' where idgrupo in (select id from grupo_compras);	
	
for rec_grupo in (select id from grupo_compras gc)
  loop 
  
   -- totais_produtos_fonecedores
   
   for rec_totais_forn in(
   
   
   		with total_venda_tri as (
  
	     select pf.idfornecedor ,coalesce(round(round(sum(c.qtde * c.valor_unit::double precision)::numeric, 2)/3,2),0) AS total
	      from consumos c 
	       inner join produtos_filial pf  
	       on pf.filial = c.filial  
	       and pf.idproduto = c.idproduto 
	      inner join grupo_filial gf 
	       on gf.filial = c.filial 
	       where gf.id_grupo=rec_grupo.id and  emissao between (date_trunc('month', now()) - INTERVAL '3' month)::date  and (date_trunc('month', now())::date-1)::date and pf.idfornecedor is not null
	       group by pf.idfornecedor
	       
        ), produtos_saldos as (
        
            select 	idfornecedor,total_estoque,total_estoque_venda,
				(coalesce(round((total_estoque_venda/nullif(total_estoque,0)),4),0)) as fator_markup_medio,
				(coalesce(round((total_estoque_venda/nullif(total_estoque,0))-1,4),0))*100 as markup_medio,
				potencial_venda,
				coalesce(round(((potencial_venda/nullif(round(total_estoque_venda/nullif(total_estoque,0),4),0))),4),0) potencial_rentabilidade
				from (        
				select 
				idfornecedor, 
				round(sum(estoque*custo_unitario),2)  as total_estoque,
				round(sum(estoque*valor_unitario),2)  as total_estoque_venda,
				round(sum(consumo_medio_mensal * preco_medio_venda),2) as potencial_venda
				from produtos_filial 
				where  filial in (select filial from grupo_filial where id_grupo=rec_grupo.id) and status='A' and revenda = 'S' and processar_analise='S' group by idfornecedor) a	        
	       
        ), produtos_stats as (
        
        
           select idfornecedor,
			count(*) as qtde_geral_itens,
			count(*) filter (where lote_compras = 0 and estoque > estoque_maximo) qtde_itens_excesso,
			count(*) filter (where lote_compras = 0 and estoque <= estoque_maximo and estoque >= ponto_pedido) qtde_itens_ok,
			count(*) filter (where compra_transito > 0 ) qtde_itens_transito,
			round(avg(coalesce(round(((estoque/nullif(estoque_maximo,0))*100)::numeric,2),0)),2) as nivel_estoque_medio
			from produtos_compras_grupo vgcpm  where vgcpm.id_grupo=rec_grupo.id
			group by idfornecedor
        
        ),produtos_ressuprimento as (
        
        
            select w.idfornecedor ,count(*) as qtde_itens_ressuprir,coalesce(round(sum(w.sugestao * c.preco_compra)::numeric,2),0) as tot_ressuprir  from vw_lista_compras_dinamica_grupo w 
				  inner join produtos_compras_grupo c
					              on c.id_grupo = w.id_grupo 
					              and c.idproduto = w.idproduto 
				 where w.id_grupo=rec_grupo.id and (w.idfornecedor, w.idproduto) not in 
				             ( select npb.idfornecedor ,npb.idproduto from notificacao_produtos_blacklist npb 
						        where grupo= rec_grupo.id
						        and data_limite >= current_date 
						        and deleted_at is null
						        )
					 group by w.idfornecedor     
        
        
        )
        
           select 
	     	id,
			razao_social,
			coalesce(qtde_geral_itens,0) qtde_geral_itens,
			coalesce(qtde_itens_excesso,0) qtde_itens_excesso,
			coalesce(qtde_itens_ok,0) qtde_itens_ok,
			coalesce(qtde_itens_transito,0) qtde_itens_transito,
			coalesce(qtde_itens_ressuprir,0) qtde_itens_ressuprir,
	    	coalesce(tot_ressuprir,0) tot_ressuprir,
			coalesce(total_estoque,0) total_estoque,
			coalesce(total_estoque_venda,0) total_estoque_venda,
			coalesce(nivel_estoque_medio,0) nivel_estoque_medio,
			coalesce(fator_markup_medio,0) fator_markup_medio,
			coalesce(markup_medio,0) markup_medio,
			coalesce(potencial_venda,0) potencial_venda,
			coalesce(potencial_rentabilidade,0) potencial_rentabilidade,
			coalesce((select total from total_venda_tri tvt where tvt.idfornecedor = a.id),0) as venda_trimestral
	
	    from (
	        select f.id,
	        f.razao_social,
	        pst.qtde_geral_itens,
			pst.qtde_itens_excesso,
			pst.qtde_itens_ok,
			pst.qtde_itens_transito,
			prs.qtde_itens_ressuprir,
	    	prs.tot_ressuprir,
	    	psd.total_estoque,
			psd.total_estoque_venda,
			pst.nivel_estoque_medio,
			psd.fator_markup_medio,
			psd.markup_medio,
			psd.potencial_venda,
			psd.potencial_rentabilidade
	        from fornecedor f 
	        left join produtos_stats pst
	         on pst.idfornecedor = f.id
	        left join  produtos_ressuprimento prs
	         on prs.idfornecedor = f.id
	        left join produtos_saldos psd 
	         on psd.idfornecedor = f.id
	        where exists (select 'X' from produtos_compras_grupo where idfornecedor=f.id  and id_grupo=rec_grupo.id limit 1))a
   
        
   ) 
   
   	loop 
   	
   	
   	   UPDATE totais_produtos_fonecedores
		SET qtde_geral_itens=rec_totais_forn.qtde_geral_itens, qtde_itens_excesso=rec_totais_forn.qtde_itens_excesso, qtde_itens_ok=rec_totais_forn.qtde_itens_ok, 
		    qtde_itens_transito=rec_totais_forn.qtde_itens_transito, qtde_itens_ressuprir=rec_totais_forn.qtde_itens_ressuprir, total_estoque=rec_totais_forn.total_estoque,status=null,
		    total_ressuprir = rec_totais_forn.tot_ressuprir,
		    total_estoque_venda=rec_totais_forn.total_estoque_venda, markup_medio=rec_totais_forn.markup_medio, nivel_estoque=rec_totais_forn.nivel_estoque_medio, 
		    projecao_venda_mensal=rec_totais_forn.potencial_venda, projecao_rentabilidade_mensal=rec_totais_forn.potencial_rentabilidade,media_venda_trimestre_anterior=rec_totais_forn.venda_trimestral
		WHERE idgrupo=rec_grupo.id AND idfornecedor=rec_totais_forn.id;
   	
   		if not found then 
   		
   			INSERT INTO totais_produtos_fonecedores
				(idgrupo, idfornecedor, qtde_geral_itens, qtde_itens_excesso, qtde_itens_ok, qtde_itens_transito, qtde_itens_ressuprir, total_estoque,total_ressuprir,total_estoque_venda,markup_medio,nivel_estoque,projecao_venda_mensal,projecao_rentabilidade_mensal,media_venda_trimestre_anterior)
				VALUES(rec_grupo.id, rec_totais_forn.id, rec_totais_forn.qtde_geral_itens, rec_totais_forn.qtde_itens_excesso, rec_totais_forn.qtde_itens_ok, rec_totais_forn.qtde_itens_transito,
			rec_totais_forn.qtde_itens_ressuprir, rec_totais_forn.total_estoque,rec_totais_forn.tot_ressuprir,rec_totais_forn.total_estoque_venda,rec_totais_forn.fator_markup_medio,rec_totais_forn.nivel_estoque_medio,rec_totais_forn.potencial_venda,rec_totais_forn.potencial_rentabilidade,rec_totais_forn.venda_trimestral);

   		end if;
   	
   	end loop;
   
   
   --totais_produtos_compradores
  
   for rec_totais_comp in(
   
        with total_venda_tri as (
  
	     select pf.idcomprador ,coalesce(round(round(sum(c.qtde * c.valor_unit::double precision)::numeric, 2)/3,2),0) AS total
	      from consumos c 
	       inner join produtos_filial pf  
	       on pf.filial = c.filial  
	       and pf.idproduto = c.idproduto 
	      inner join grupo_filial gf 
	       on gf.filial = c.filial 
	       where gf.id_grupo=rec_grupo.id and  emissao between (date_trunc('month', now()) - INTERVAL '3' month)::date  and (date_trunc('month', now())::date-1)::date
	       group by pf.idcomprador
	       
        ), produtos_saldos as (
        
              select 	idcomprador,qtde_fornecedores,total_estoque,total_estoque_venda,
				(coalesce(round((total_estoque_venda/nullif(total_estoque,0)),4),0)) as fator_markup_medio,
				(coalesce(round((total_estoque_venda/nullif(total_estoque,0))-1,4),0))*100 as markup_medio,
				potencial_venda,
				coalesce(round(((potencial_venda/nullif(round(total_estoque_venda/nullif(total_estoque,0),4),0))),4),0) potencial_rentabilidade
				from (        
				select 
				idcomprador, 
				count( distinct idfornecedor) as qtde_fornecedores,
				round(sum(estoque*custo_unitario),2)  as total_estoque,
				round(sum(estoque*valor_unitario),2)  as total_estoque_venda,
				round(sum(consumo_medio_mensal * valor_unitario),2) as potencial_venda
				from produtos_filial 
				where  filial in (select filial from grupo_filial where id_grupo=rec_grupo.id) and status='A' and revenda = 'S' and processar_analise='S' group by idcomprador) a
        
        ), produtos_stats as  (
        
            select idcomprador ,
			count(*) as qtde_geral_itens,
			count(*) filter (where lote_compras = 0 and estoque > estoque_maximo) qtde_itens_excesso,
			count(*) filter (where lote_compras = 0 and estoque <= estoque_maximo and estoque >= ponto_pedido) qtde_itens_ok,
			count(*) filter (where compra_transito > 0 ) qtde_itens_transito,
			round(avg(coalesce(round(((estoque/nullif(estoque_maximo,0))*100)::numeric,2),0)),2) as nivel_estoque_medio
			from produtos_compras_grupo vgcpm  where vgcpm.id_grupo=rec_grupo.id
			group by idcomprador
             
        ), produtos_ressuprimento as (
        
        
	   	     select w.idcomprador ,count(*) as qtde_itens_ressuprir,coalesce(round(sum(w.sugestao * c.preco_compra)::numeric,2),0) as tot_ressuprir  from vw_lista_compras_dinamica_grupo w 
			  inner join produtos_compras_grupo c
				              on c.id_grupo = w.id_grupo 
				              and c.idproduto = w.idproduto 
			 where w.id_grupo=rec_grupo.id and (w.idfornecedor, w.idproduto) not in 
			             ( select npb.idfornecedor ,npb.idproduto from notificacao_produtos_blacklist npb 
					        where grupo=rec_grupo.id
					        and data_limite >= current_date 
					        and deleted_at is null
					        )
				 group by w.idcomprador     

        
        )
        
	      select 
	        id,
			nome_completo,
			coalesce(qtde_fornecedores,0) qtde_fornecedores,
			coalesce(qtde_geral_itens,0) qtde_geral_itens,
			coalesce(qtde_itens_excesso,0) qtde_itens_excesso,
			coalesce(qtde_itens_ok,0) qtde_itens_ok,
			coalesce(qtde_itens_transito,0) qtde_itens_transito,
			coalesce(qtde_itens_ressuprir,0) qtde_itens_ressuprir,
	    	coalesce(tot_ressuprir,0) tot_ressuprir,
			coalesce(total_estoque,0) total_estoque,
			coalesce(total_estoque_venda,0) total_estoque_venda,
			coalesce(nivel_estoque_medio,0) nivel_estoque_medio,
			coalesce(fator_markup_medio,0) fator_markup_medio,
			coalesce(markup_medio,0) markup_medio,
			coalesce(potencial_venda,0) potencial_venda,
			coalesce(potencial_rentabilidade,0) potencial_rentabilidade,
			coalesce(eficiencia,0) eficiencia,
			coalesce((select total from total_venda_tri tvt where tvt.idcomprador = a.id),0) as venda_trimestral
            from (
                select id,nome_completo,
                 
	                psd.qtde_fornecedores, 
	                pst.qtde_geral_itens,
					pst.qtde_itens_excesso,
					pst.qtde_itens_ok,
					pst.qtde_itens_transito,
					prs.qtde_itens_ressuprir,
			    	prs.tot_ressuprir,
			    	psd.total_estoque,
					psd.total_estoque_venda,
					pst.nivel_estoque_medio,
					psd.fator_markup_medio,
					psd.markup_medio,
					psd.potencial_venda,
					psd.potencial_rentabilidade,
	                get_eficiencia_comprador(c.id,rec_grupo.id) as eficiencia
                from comprador c
                  left join produtos_stats pst
	         		on pst.idcomprador = c.id
	        	 left join  produtos_ressuprimento prs
	         		on prs.idcomprador = c.id
	        	 left join produtos_saldos psd 
	         			on psd.idcomprador = c.id
                where   exists (select 'X' from produtos_compras_grupo where id_grupo=rec_grupo.id and idcomprador=c.id limit 1)
            ) a
        
   ) 
   
   	loop 
   	
   	
   	   UPDATE totais_produtos_compradores
		SET qtde_geral_itens=rec_totais_comp.qtde_geral_itens, qtde_itens_excesso=rec_totais_comp.qtde_itens_excesso, qtde_itens_ok=rec_totais_comp.qtde_itens_ok, 
		    qtde_itens_transito=rec_totais_comp.qtde_itens_transito, qtde_itens_ressuprir=rec_totais_comp.qtde_itens_ressuprir, total_estoque=rec_totais_comp.total_estoque,
		    qtde_fornecedores = rec_totais_comp.qtde_fornecedores,eficiencia =rec_totais_comp.eficiencia,status=null,total_ressuprir = rec_totais_comp.tot_ressuprir,
		    total_estoque_venda=rec_totais_comp.total_estoque_venda, markup_medio=rec_totais_comp.markup_medio, nivel_estoque=rec_totais_comp.nivel_estoque_medio, 
		    projecao_venda_mensal=rec_totais_comp.potencial_venda, projecao_rentabilidade_mensal=rec_totais_comp.potencial_rentabilidade,media_venda_trimestre_anterior=rec_totais_comp.venda_trimestral
		WHERE idgrupo=rec_grupo.id AND idcomprador=rec_totais_comp.id;
   	
   		if not found then 
   		
   			INSERT INTO totais_produtos_compradores
				(idgrupo, idcomprador, qtde_geral_itens, qtde_itens_excesso, qtde_itens_ok, qtde_itens_transito, qtde_itens_ressuprir, total_estoque,qtde_fornecedores,eficiencia,total_ressuprir,total_estoque_venda,markup_medio,nivel_estoque,projecao_venda_mensal,projecao_rentabilidade_mensal,media_venda_trimestre_anterior )
				VALUES(rec_grupo.id, rec_totais_comp.id, rec_totais_comp.qtde_geral_itens, rec_totais_comp.qtde_itens_excesso, rec_totais_comp.qtde_itens_ok, rec_totais_comp.qtde_itens_transito,
			rec_totais_comp.qtde_itens_ressuprir, rec_totais_comp.total_estoque,rec_totais_comp.qtde_fornecedores,rec_totais_comp.eficiencia,rec_totais_comp.tot_ressuprir,
		   rec_totais_comp.total_estoque_venda,rec_totais_comp.fator_markup_medio,rec_totais_comp.nivel_estoque_medio,rec_totais_comp.potencial_venda,rec_totais_comp.potencial_rentabilidade,rec_totais_comp.venda_trimestral);

   		end if;
   	
   	end loop;
   
   
   --totais_produtos_segmentos
  
   for rec_totais_seg in(
   
        with total_venda_tri as (
  
	     select pf.idfamilia_produto ,coalesce(round(round(sum(c.qtde * c.valor_unit::double precision)::numeric, 2)/3,2),0) AS total
	      from consumos c 
	       inner join produtos_filial pf  
	       on pf.filial = c.filial  
	       and pf.idproduto = c.idproduto 
	      inner join grupo_filial gf 
	       on gf.filial = c.filial 
	       where gf.id_grupo=rec_grupo.id and  emissao between (date_trunc('month', now()) - INTERVAL '3' month)::date  and (date_trunc('month', now())::date-1)::date
	       group by pf.idfamilia_produto
        ) , produtos_saldos as (
           
        
           		select 	idfamilia_produto,qtde_fornecedores,total_estoque,total_estoque_venda,
				(coalesce(round((total_estoque_venda/nullif(total_estoque,0)),4),0)) as fator_markup_medio,
				(coalesce(round((total_estoque_venda/nullif(total_estoque,0))-1,4),0))*100 as markup_medio,
				potencial_venda,
				coalesce(round(((potencial_venda/nullif(round(total_estoque_venda/nullif(total_estoque,0),4),0))),4),0) potencial_rentabilidade
				from (        
				select 
				idfamilia_produto, 
				count( distinct idfornecedor) as qtde_fornecedores,
				round(sum(estoque*custo_unitario),2)  as total_estoque,
				round(sum(estoque*valor_unitario),2)  as total_estoque_venda,
				round(sum(consumo_medio_mensal * valor_unitario),2) as potencial_venda
				from produtos_filial 
				where  filial in (select filial from grupo_filial where id_grupo=rec_grupo.id) and status='A' and revenda = 'S' and processar_analise='S' group by idfamilia_produto) a  
        
        ), produtos_stats as  (
        
        
	         select idfamilia_produto,
				count(*) as qtde_geral_itens,
				count(*) filter (where lote_compras = 0 and estoque > estoque_maximo) qtde_itens_excesso,
				count(*) filter (where lote_compras = 0 and estoque <= estoque_maximo and estoque >= ponto_pedido) qtde_itens_ok,
				count(*) filter (where compra_transito > 0 ) qtde_itens_transito,
				round(avg(coalesce(round(((estoque/nullif(estoque_maximo,0))*100)::numeric,2),0)),2) as nivel_estoque_medio
				from produtos_compras_grupo vgcpm  where vgcpm.id_grupo=rec_grupo.id
				group by idfamilia_produto
        
        
        ) , produtos_ressuprimento as (
        
        
	         select w.iddepartamento ,count(*) as qtde_itens_ressuprir,coalesce(round(sum(w.sugestao * c.preco_compra)::numeric,2),0) as tot_ressuprir  from vw_lista_compras_dinamica_grupo w 
					  inner join produtos_compras_grupo c
						              on c.id_grupo = w.id_grupo 
						              and c.idproduto = w.idproduto 
					 where w.id_grupo=rec_grupo.id and (w.idfornecedor, w.idproduto) not in 
					             ( select npb.idfornecedor ,npb.idproduto from notificacao_produtos_blacklist npb 
							        where grupo= rec_grupo.id
							        and data_limite >= current_date 
							        and deleted_at is null
							        )
						 group by w.iddepartamento 
        )
   
	      select 
            idfamilia_produto,
			descricao_familia_produto,
			coalesce(qtde_fornecedores,0) qtde_fornecedores,
			coalesce(qtde_geral_itens,0) qtde_geral_itens,
			coalesce(qtde_itens_excesso,0) qtde_itens_excesso,
			coalesce(qtde_itens_ok,0) qtde_itens_ok,
			coalesce(qtde_itens_ressuprir,0) qtde_itens_ressuprir,
			coalesce(tot_ressuprir,0) tot_ressuprir,
			coalesce(qtde_itens_transito,0) qtde_itens_transito,
			coalesce(total_estoque,0) total_estoque,
			coalesce(total_estoque_venda,0) total_estoque_venda,
			coalesce(fator_markup_medio,0) fator_markup_medio,
			coalesce(markup_medio,0) markup_medio,
			coalesce(nivel_estoque_medio,0) nivel_estoque_medio,
			coalesce(potencial_venda,0) potencial_venda,
			coalesce(potencial_rentabilidade,0) potencial_rentabilidade,
			coalesce((select total from total_venda_tri tvt where tvt.idfamilia_produto = a.idfamilia_produto),0) as venda_trimestral
          from ( 
          select 
               f.idfamilia_produto,
               f.descricao_familia_produto,
               psd.qtde_fornecedores, 
               pst.qtde_geral_itens,
			   pst.qtde_itens_excesso,
			   pst.qtde_itens_ok,
			   pst.qtde_itens_transito,
			   prs.qtde_itens_ressuprir,
	    	   prs.tot_ressuprir,
	    	   psd.total_estoque,
			   psd.total_estoque_venda,
			   pst.nivel_estoque_medio,
			   psd.fator_markup_medio,
			   psd.markup_medio,
			   psd.potencial_venda,
			 psd.potencial_rentabilidade
        from familia_produtos f
          left join produtos_stats pst
	         on pst.idfamilia_produto = f.idfamilia_produto
	      left join  produtos_ressuprimento prs
	         on prs.iddepartamento = f.idfamilia_produto
	      left join produtos_saldos psd 
	         on psd.idfamilia_produto = f.idfamilia_produto
        where exists (select 'X' from produtos_compras_grupo where id_grupo=rec_grupo.id and idfamilia_produto=f.idfamilia_produto limit 1)) a
            
   ) 
   
   	loop 
   	
   	
   	   UPDATE totais_produtos_segmentos
		SET qtde_geral_itens=rec_totais_seg.qtde_geral_itens, qtde_itens_excesso=rec_totais_seg.qtde_itens_excesso, qtde_itens_ok=rec_totais_seg.qtde_itens_ok, 
		    qtde_itens_transito=rec_totais_seg.qtde_itens_transito, qtde_itens_ressuprir=rec_totais_seg.qtde_itens_ressuprir, total_estoque=rec_totais_seg.total_estoque,
		    qtde_fornecedores = rec_totais_seg.qtde_fornecedores,status=null,total_ressuprir = rec_totais_seg.tot_ressuprir,
		    total_estoque_venda=rec_totais_seg.total_estoque_venda, markup_medio=rec_totais_seg.markup_medio, nivel_estoque=rec_totais_seg.nivel_estoque_medio, 
		    projecao_venda_mensal=rec_totais_seg.potencial_venda, projecao_rentabilidade_mensal=rec_totais_seg.potencial_rentabilidade,media_venda_trimestre_anterior=rec_totais_seg.venda_trimestral
		WHERE idgrupo=rec_grupo.id AND idfamilia_produto =rec_totais_seg.idfamilia_produto;
   	
   		if not found then 
   		
		   			insert
						into
						totais_produtos_segmentos (
						idgrupo,
						idfamilia_produto,
						qtde_geral_itens,
						qtde_itens_excesso,
						qtde_itens_ok,
						qtde_itens_transito,
						qtde_itens_ressuprir,
						total_estoque,
						qtde_fornecedores,
						total_ressuprir,
						total_estoque_venda,
						markup_medio,
						nivel_estoque,
						projecao_venda_mensal,
						projecao_rentabilidade_mensal,
						media_venda_trimestre_anterior)
					values(
					rec_grupo.id,
					rec_totais_seg.idfamilia_produto,
					rec_totais_seg.qtde_geral_itens,
					rec_totais_seg.qtde_itens_excesso,
					rec_totais_seg.qtde_itens_ok,
					rec_totais_seg.qtde_itens_transito,
					rec_totais_seg.qtde_itens_ressuprir,
					rec_totais_seg.total_estoque,
					rec_totais_seg.qtde_fornecedores,
					rec_totais_seg.tot_ressuprir,
					rec_totais_seg.total_estoque_venda,
				    rec_totais_seg.fator_markup_medio,
				    rec_totais_seg.nivel_estoque_medio,
				    rec_totais_seg.potencial_venda,
				    rec_totais_seg.potencial_rentabilidade,
				    rec_totais_seg.venda_trimestral);

   		end if;
   	
   	end loop;
   
   
  end loop;
 
 delete from  totais_produtos_fonecedores where status ='D';
 delete from  totais_produtos_compradores where status ='D';
 delete from  totais_produtos_segmentos  where  status ='D';
 refresh materialized view concurrently vw_lista_compras_dinamica_grupo_mt;
	
end
$$;


ALTER FUNCTION public.processar_totais() OWNER TO systock;

--
-- TOC entry 810 (class 1255 OID 53947)
-- Name: set_media_diaria_vendas_trimestral(character varying, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.set_media_diaria_vendas_trimestral(idprod character varying, data_venda date) RETURNS void
    LANGUAGE plpgsql
    AS $$
declare 
    media numeric;
    media_diaria numeric;
    desvio_padrao_tri numeric;
    cof_var numeric;
    primeiro_consumo numeric;
begin 
	
-- Tempo Primeiro Consumo

	select current_date- min(emissao) into  primeiro_consumo from consumos where idproduto=idprod;

   -- Calculo de Desvio Padrao do Trimestre (mes)
    /*select   coalesce(round(stddev_pop(total) :: numeric, 2),0) 
 			  into desvio_padrao_tri
			from (
  					SELECT sum(saidas) total
						from saldos
					where idproduto = idprod
				    and ano = date_part('year', data_venda)
 				    and trimestre = date_part('quarter',data_venda)
 			        and data >= (select min(data) from saldos where idproduto = idprod and saidas > 0)
					group by saldos.mes)a;*/	

      /*select coalesce(round(((avg(total) :: numeric)), 2),0) 
        into media 
        	from (
				select sum(saidas) as total
					from saldos
				where idproduto = idprod
 				and ano = date_part('year',data_venda)
 				and trimestre = date_part('quarter', data_venda)
 				and data >= (select min(data) from saldos where idproduto = idprod and saidas > 0)
			 group by mes) b;*/

			SELECT coalesce(round(cast(stddev_pop(saidas) as numeric), 2), 0)
     			 into desvio_padrao_tri
			  from (select mes,sum(saidas) as saidas from (SELECT to_char(emissao, 'YYYYMM') AS mes,to_char(emissao, 'YYYYMMDD') AS dia, sum(qtde)-coalesce(qtde_corte,0) AS saidas
			      FROM consumos
			      left join (
			         select  idproduto,to_char(data,'yyyymmdd') cod_mes,sum(qtde) as qtde_corte from cortes 
			             where data between (data_venda - 90) AND data_venda and cortes.idproduto=idprod
			             group by idproduto,cod_mes
			      ) as corte
			       on corte.cod_mes = to_char(emissao, 'YYYYMMdd')
			       and corte.idproduto = consumos.idproduto
			      WHERE     consumos.idproduto = idprod
			            AND emissao BETWEEN (data_venda - 90) AND data_venda
			      GROUP BY mes,dia,qtde_corte)a  group by a.mes )com;
			
			SELECT coalesce(round(cast(sum(saidas)/(abs( case when abs(datediff('mm',cast(to_char(data_venda,'YYYYMMDD') as date), cast(min(mes)||'01' as date)))+1 > 3 then 3 
			 when abs(datediff('mm',cast(to_char(data_venda,'YYYYMMDD') as date), cast(min(mes)||'01' as date)))+1 < 3 and primeiro_consumo >= 90 then 3                                                       
			 else abs(datediff('mm',cast(to_char(data_venda,'YYYYMMDD') as date), cast(min(mes)||'01' as date)))+1 end ))as numeric) ,2),0)
			  into media
			 FROM ( SELECT to_char(emissao, 'YYYYMM') AS mes,to_char(emissao, 'YYYYMMDD') AS dia, sum(qtde)-coalesce(qtde_corte,0) AS saidas
			      FROM consumos
			      left join (
			         select  idproduto,to_char(data,'yyyymmdd') cod_mes,sum(qtde) as qtde_corte from cortes 
			             where data between (data_venda - 90) AND data_venda and cortes.idproduto=idprod
			             group by idproduto,cod_mes
			      ) as corte
			       on corte.cod_mes = to_char(emissao, 'YYYYMMdd')
			       and corte.idproduto = consumos.idproduto
			      WHERE     consumos.idproduto = idprod
			            AND emissao BETWEEN (data_venda - 90) AND data_venda
			      GROUP BY mes,dia,qtde_corte) com;


   	if media > 0 then --Média do trimestre 
   
   
        cof_var = coalesce(round(desvio_padrao_tri / media,4),0) ;


 		if cof_var >= 1.5 then
 
    		media = media + desvio_padrao_tri;
    		media_diaria =  coalesce(round(media/30,2),0);
 
  			else
  
    		media_diaria =  coalesce(round(media/30,2),0);
 
  		end if; 
   

        update saldos set media_trimestre_ant=0,media_diaria_trimestre_ant=0,media_trimestre=media,media_diaria_trimestre=media_diaria,desvio_padrao_trimestre=desvio_padrao_tri,coeficiente_variacao=cof_var,processamento=current_timestamp where idproduto = idprod and "data"=data_venda;
       
    
    elsif media = 0 then -- Media do trimestre anterior
    
    
       
        update saldos set media_trimestre_ant=0,
                          media_diaria_trimestre_ant=0,
                          media_trimestre=0,
                          media_diaria_trimestre=0,
                          desvio_padrao_trimestre=0,
                          coeficiente_variacao=0,
                          media_anual_corrida=0,
                          media_diaria_anual=0,
                          desvio_padrao_anual=0,
                          processamento=current_timestamp where idproduto = idprod and "data"=data_venda;
    
         -- Calculo de Desvio Padrao do Trimestre (mes)
    
        /*  select   coalesce(round(stddev_pop(total) :: numeric, 2),0) 
 			  into desvio_padrao_tri
			from (
  					SELECT sum(saidas) total
						from saldos
					where idproduto = idprod
				       and cod_trimestre in (select max(cod_trimestre) from saldos
                                               where idproduto= idprod 
                                                and  cod_trimestre < to_char(data_venda,'yyyyq')::numeric)
                        and data >= (select min(data) from saldos where idproduto = idprod and saidas > 0)                         
					group by saldos.mes)a;	*/
    
        
                   
             
        /*  select coalesce(round(((avg(total) :: numeric)), 2),0) 
             into media 
        	from (
				select sum(saidas) as total
					from saldos
				where idproduto = idprod
 			       and cod_trimestre in(select max(cod_trimestre) from saldos
                                    where idproduto= idprod 
                                     and  cod_trimestre < to_char(data_venda,'yyyyq')::numeric)
              and data >= (select min(data) from saldos where idproduto = idprod and saidas > 0)
			 group by mes) b;    */
                                    
                                    
         
        /* if media > 0 then 
         
         
             
             cof_var = coalesce(round(desvio_padrao_tri / media,4),0) ;

         		if cof_var >= 1.5 then
 
            		media = media + desvio_padrao_tri;
            		media_diaria =  coalesce(round(media/30,2),0);
 
            	else
  
           			 media_diaria =  coalesce(round(media/30,2),0);
 
         		end if;
         
         
             update saldos set media_trimestre_ant=media,media_diaria_trimestre_ant=media_diaria,desvio_padrao_trimestre_ant=desvio_padrao_tri,coeficiente_variacao=cof_var,processamento=current_timestamp where idproduto = idprod and "data"=data_venda;
         
           else  -- Media Anual Corrida*/
           
           
             -- Calculo de Desvio Padrao do Trimestre (mes)
    
          /*  select   coalesce(round(stddev_pop(total) :: numeric, 2),0) 
 			  into desvio_padrao_tri
			from (
  					SELECT sum(saidas) total
						from saldos
					where idproduto = idprod
				     	and data  between data_venda - 365  and data_venda
					group by saldos.mes)a;	 
             
           
           
             select  coalesce(round(((avg(saidas) :: numeric)*30), 2),0)
        		into media
    				from saldos
   					where idproduto = idprod
     				and data  between data_venda - 365  and data_venda;
     		
     		
     		  if media > 0 then
     		  
     		        cof_var = coalesce(round(desvio_padrao_tri / COALESCE(NULLIF(media,0), desvio_padrao_tri) ,4),0) ;
     		  
     		    else
     		    
     		        cof_var = 0;
     		  
     		   end if;
   	    

            if cof_var >= 1.2 then
 
            	media = media + desvio_padrao_tri;
            	media_diaria =  coalesce(round(media/30,2),0);
 
            	else
  
            	media_diaria =  coalesce(round(media/30,2),0);
 
         	end if;*/
         
         
            -- Não usar mais Comportamento Anual
          /*     
              media = 0;
              media_diaria = 0;
              cof_var=0;
              desvio_padrao_tri=0;
      
           
             update saldos set media_anual_corrida=media,media_diaria_anual=media_diaria,desvio_padrao_anual=desvio_padrao_tri,coeficiente_variacao=cof_var,processamento=current_timestamp where idproduto = idprod and "data"=data_venda;
           
         end if;  */
    
    
   end if;
    

end;

$$;


ALTER FUNCTION public.set_media_diaria_vendas_trimestral(idprod character varying, data_venda date) OWNER TO systock;

--
-- TOC entry 811 (class 1255 OID 53949)
-- Name: set_media_diaria_vendas_trimestral_filial(numeric, character varying, date); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.set_media_diaria_vendas_trimestral_filial(p_filial numeric, idprod character varying, data_venda date) RETURNS void
    LANGUAGE plpgsql
    AS $$

declare 

    media numeric;

    media_diaria numeric;

    desvio_padrao_tri numeric;

    cof_var numeric;

    primeiro_consumo numeric;

begin 

	

   -- Tempo Primeiro Consumo



	select current_date- min(emissao) into  primeiro_consumo from consumos where filial = p_filial and idproduto=idprod;



   -- Calculo de Desvio Padrao do Trimestre (mes)

      select get_stddev_consumo(p_filial,idprod,data_venda) into desvio_padrao_tri;
   

	  /*    SELECT coalesce(round(cast(stddev_pop(saidas) as numeric), 2), 0)

	      into desvio_padrao_tri

	 		 from (SELECT to_char(emissao, 'YYYYMM') AS mes,sum(qtde) AS saidas

         FROM consumos c

      		WHERE c.filial = p_filial     

            and c.idproduto = idprod

            AND c.emissao BETWEEN (data_venda - 90) AND data_venda

        group by mes)com;*/

	       

	       

   -- Media de Consumos 90 dias Corrido

      select get_cmm_filial(p_filial,idprod,data_venda) into media;
   

  /*  SELECT coalesce(round(cast(sum(saidas)/(abs( case when abs(datediff('mm',cast(to_char(data_venda,'YYYYMMDD') as date), cast(min(mes)||'01' as date)))+1 > 3 then 3 

	 when abs(datediff('mm',cast(to_char(data_venda,'YYYYMMDD') as date), cast(min(mes)||'01' as date)))+1 < 3 and primeiro_consumo >= 90 then 3                                                       

	 else abs(datediff('mm',cast(to_char(data_venda,'YYYYMMDD') as date), cast(min(mes)||'01' as date)))+1 end ))as numeric) ,2),0)

	  into media

	 FROM ( SELECT to_char(emissao, 'YYYYMM') AS mes,to_char(emissao, 'YYYYMMDD') AS dia, sum(qtde) AS saidas

	      FROM consumos

	      WHERE consumos.filial = p_filial and consumos.idproduto = idprod

	            AND emissao BETWEEN (data_venda - 90) AND data_venda

	      GROUP BY mes,dia) com;*/

  



   	if media > 0 then --Média do trimestre 

   

   

        cof_var = coalesce(round(desvio_padrao_tri / media,4),0) ;





 		if cof_var >= 1.5 then

 

    		media = media + desvio_padrao_tri;

    		media_diaria =  coalesce(round(media/30,2),0);

 

  			else

  

    		media_diaria =  coalesce(round(media/30,2),0);

 

  		end if; 

   



        update saldo_filiais set media_trimestre=media,media_diaria_trimestre=media_diaria,desvio_padrao_trimestre=desvio_padrao_tri,coeficiente_variacao=cof_var,processamento=current_timestamp where filial= p_filial and idproduto = idprod and "data"=data_venda;

       

    

    elsif media = 0 then -- Media do trimestre anterior

    

    

       

        update saldo_filiais set media_trimestre=0,

                          media_diaria_trimestre=0,

                          desvio_padrao_trimestre=0,

                          coeficiente_variacao=0,

                          processamento=current_timestamp where filial= p_filial and idproduto = idprod and "data"=data_venda;

  

    

   end if;

    



end;



$$;


ALTER FUNCTION public.set_media_diaria_vendas_trimestral_filial(p_filial numeric, idprod character varying, data_venda date) OWNER TO systock;

--
-- TOC entry 812 (class 1255 OID 53950)
-- Name: totais_dashboard_adicionar_produtos_combinados(character varying, integer, integer, integer); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.totais_dashboard_adicionar_produtos_combinados(p_tipo character varying, p_id_grupo integer, p_id_parametro integer, p_adicional_fornecedor integer DEFAULT NULL::integer) RETURNS integer
    LANGUAGE plpgsql
    AS $$
            DECLARE
                produtos_a_adicionar INT;
            BEGIN
                SELECT COUNT(pccg.id_produto_combinado) 
                INTO produtos_a_adicionar
                FROM vw_lista_compras_dinamica_produtos_combinados_grupo vwc
                INNER JOIN produtos_combinados_compras_grupo pccg ON pccg.id_grupo = vwc.id_grupo AND pccg.id_produto_combinado = vwc.id_produto_combinado
                WHERE pccg.id_grupo = p_id_grupo
                and (case when p_adicional_fornecedor is not null then p_adicional_fornecedor = ANY(pccg.fornecedores) else true end)
                AND (
                    (p_tipo = 'fornecedor' AND p_id_parametro = ANY(pccg.fornecedores))
                    OR (p_tipo = 'segmento'   AND p_id_parametro = ANY(pccg.familias_produtos))
                    OR (p_tipo = 'comprador'  AND p_id_parametro = ANY(pccg.compradores))
                );
                RETURN produtos_a_adicionar;
            END;
            $$;


ALTER FUNCTION public.totais_dashboard_adicionar_produtos_combinados(p_tipo character varying, p_id_grupo integer, p_id_parametro integer, p_adicional_fornecedor integer) OWNER TO systock;

