--
-- TOC entry 823 (class 1255 OID 53964)
-- Name: valida_oportunidade_venda(character varying, numeric, numeric, numeric); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.valida_oportunidade_venda(idprod character varying, p_ano numeric, p_mes numeric, p_cod_trimestre numeric) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
declare 
    primeira_saida date;
    venda_trimestre_anterior numeric;
    venda_mes numeric;
begin 
	
	 primeira_saida = (select min(data) from saldos where idproduto = idprod and saidas > 0);

     select count(*) 
         into venda_trimestre_anterior
	    from saldos
	  where idproduto = idprod 
 		and cod_trimestre in(select max(cod_trimestre) from saldos
                                    where idproduto= idprod 
                                     and  cod_trimestre <  p_cod_trimestre )
       and data >= (select min(data) from saldos where idproduto =idprod and saidas > 0);
      
      
      select sum(saidas)  
       into venda_mes
      from saldos where idproduto =idprod and ano= p_ano and mes= p_mes;
     
     
     if venda_trimestre_anterior > 0 then
     
         return 1;
        
       elseif  venda_mes > 0 then
       
         return 1;
        
       else 
     
        return 0;
     
     end if;
    
end;

$$;


ALTER FUNCTION public.valida_oportunidade_venda(idprod character varying, p_ano numeric, p_mes numeric, p_cod_trimestre numeric) OWNER TO systock;

--
-- TOC entry 824 (class 1255 OID 53965)
-- Name: verificar_cobertura_personalizada_produto_filial(integer, character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.verificar_cobertura_personalizada_produto_filial(p_filial integer, p_idproduto character varying) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    cadastro_produto record;
BEGIN
    SELECT 
        NULLIF(max(pf.cobertura_manual_produto), 0) AS cobertura_manual_produto,
        max(pf.idfornecedor) AS idfornecedor, 
        max(pf.idfamilia_produto) AS idfamilia_produto,
        (sum(estoque_maximo)::NUMERIC / NULLIF(sum(consumo_medio_mensal)::NUMERIC, 0)) * 30 AS cobertura_emax
        INTO cadastro_produto
    FROM produtos_filial pf 
    WHERE pf.filial = p_filial AND pf.idproduto = p_idproduto;

    IF (cadastro_produto.cobertura_manual_produto IS NULL) THEN
        RETURN FALSE;
    END IF;

    /* 
     * ESSE CASO PODE ACONTECER POR DOIS MOTIVOS: 
     * - PP >= EMAX
     * - PERFIL_DEMANDA = 'OCASIONAL'
    */
    IF (round(cadastro_produto.cobertura_emax) <> round(cadastro_produto.cobertura_manual_produto)) THEN
        RETURN TRUE;
    END IF;
    

    RETURN EXISTS (
        SELECT tempo_cobertura FROM tempo_cobertura_compras_produtos tp WHERE tp.idproduto = p_idproduto
        UNION 
        SELECT tempo_cobertura FROM tempo_cobertura_compras_fornecedor tf WHERE tf.idfornecedor = cadastro_produto.idfornecedor
        UNION
        SELECT tempo_cobertura FROM tempo_cobertura_compras_segmentos ts WHERE ts.idfamilia_produto = cadastro_produto.idfamilia_produto
    );
END
$$;


ALTER FUNCTION public.verificar_cobertura_personalizada_produto_filial(p_filial integer, p_idproduto character varying) OWNER TO systock;

--
-- TOC entry 825 (class 1255 OID 53966)
-- Name: verificar_cobertura_personalizada_produto_grupo(integer, character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.verificar_cobertura_personalizada_produto_grupo(p_idgrupo integer, p_idproduto character varying) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    cadastro_produto record;
BEGIN
    SELECT 
        NULLIF(max(pf.cobertura_manual_produto), 0) AS cobertura_manual_produto,
        max(pf.idfornecedor) AS idfornecedor, 
        max(pf.idfamilia_produto) AS idfamilia_produto,
        (sum(estoque_maximo)::NUMERIC / NULLIF(sum(consumo_medio_mensal)::NUMERIC, 0)) * 30 AS cobertura_emax
        INTO cadastro_produto
    FROM produtos_filial pf 
        INNER JOIN grupo_filial gf ON gf.filial = pf.filial
    WHERE gf.id_grupo = p_idgrupo AND pf.idproduto = p_idproduto
    LIMIT 1;

    IF (cadastro_produto.cobertura_manual_produto IS NULL) THEN
        RETURN FALSE;
    END IF;

    /* 
     * ESSE CASO PODE ACONTECER POR DOIS MOTIVOS: 
     * - PP >= EMAX
     * - PERFIL_DEMANDA = 'OCASIONAL'
    */
    IF (round(cadastro_produto.cobertura_emax) <> round(cadastro_produto.cobertura_manual_produto)) THEN
        RETURN TRUE;
    END IF;
    

    RETURN EXISTS (
        SELECT tempo_cobertura FROM tempo_cobertura_compras_produtos tp WHERE tp.idproduto = p_idproduto
        UNION 
        SELECT tempo_cobertura FROM tempo_cobertura_compras_fornecedor tf WHERE tf.idfornecedor = cadastro_produto.idfornecedor
        UNION
        SELECT tempo_cobertura FROM tempo_cobertura_compras_segmentos ts WHERE ts.idfamilia_produto = cadastro_produto.idfamilia_produto
    );
END
$$;


