--
-- TOC entry 826 (class 1255 OID 53967)
-- Name: verificar_sazonalidade_periodo(integer, character varying, text, text); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.verificar_sazonalidade_periodo(param_filial integer, param_idproduto character varying, param_periodo_inicial text, param_periodo_final text) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
	DECLARE
		results record;
	BEGIN
		WITH temp_periodos_sazonalidades AS (
			SELECT DISTINCT
				q.filial ,
				q.idproduto ,
				UNNEST(string_to_array(q.datas_inicio, '#')) AS init,
				UNNEST(string_to_array(q.datas_final, '#')) AS finish
			FROM
				(
				SELECT
					param_filial AS filial,
					param_idproduto AS idproduto,
					REPLACE(REPLACE(REPLACE(REPLACE(param_periodo_inicial , '["', ''), '"]', ''), '\', ''), '","', '#') AS datas_inicio,
					REPLACE(REPLACE(REPLACE(REPLACE(param_periodo_final , '["', ''), '"]', ''), '\', ''), '","', '#') AS datas_final
				) AS q
			)
			SELECT
				sum(crescimento) / count(1) AS crescimento
			FROM (
				SELECT
					w.filial ,
					w.init ,
					w.finish ,
					(soma / meses) as crescimento
				FROM (
					SELECT
						c.filial ,
						c.idproduto ,
						t.init ,
						t.finish ,
						sum(c.qtde) as soma,
				        count(EXTRACT(MONTH FROM c.emissao)) as meses
					FROM consumos c
					LEFT JOIN temp_periodos_sazonalidades t ON t.idproduto = c.idproduto
					WHERE
						c.idproduto = t.idproduto
						AND c.filial = t.filial
						AND c.emissao >= concat(t.init, '/', date_part('year', now()) - 1)::date
			        	AND c.emissao <= concat(t.finish, '/', date_part('year', now()) - 1)::date
					group by
				        c.filial,
				        c.idproduto,
				        t.init ,
				        t.finish ,
				        EXTRACT(year FROM c.emissao),
				        EXTRACT(month FROM c.emissao)
				) AS w
			) AS p
			INTO results;
		RETURN sum(results.crescimento) ;
	END;
$$;


ALTER FUNCTION public.verificar_sazonalidade_periodo(param_filial integer, param_idproduto character varying, param_periodo_inicial text, param_periodo_final text) OWNER TO systock;

--
-- TOC entry 827 (class 1255 OID 53968)
-- Name: verificar_sazonalidade_produto(character varying); Type: FUNCTION; Schema: public; Owner: systock
--

CREATE FUNCTION public.verificar_sazonalidade_produto(param_idproduto character varying) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
            DECLARE
                results record;
                retorno boolean default false;
            begin
                for results in (
                    select distinct
                        q.ano,
                        q.recorrencia,
                        substring(unnest(string_to_array(q.datas_inicio, '#')) FROM 1 FOR 6) as init,
                        substring(unnest(string_to_array(q.datas_final, '#')) FROM 1 FOR 6) as finish
                    from (
                        select
                            s.ano,
                            s.recorrencia,
                            replace(replace(replace(replace(s.dia_mes_inicial, '["', ''), '"]', ''), '\', ''), '","', '#') as datas_inicio,
                            replace(replace(replace(replace(s.dia_mes_final, '["', ''), '"]', ''), '\', ''), '","', '#') as datas_final
                        from
                            sazonalidades_produtos s
                        where
                            s.idproduto = param_idproduto
                        ) as q
                    )
                    loop
                        if (
                            (
                                current_date >= date(concat(results.init, extract (year from current_date)))
                                and current_date <= date(concat(results.finish, extract (year from current_date)))
                                and results.recorrencia = '1'
                            ) OR (
                                current_date >= date(concat(results.init, extract (year from current_date)))
                                and current_date <= date(concat(results.finish, extract (year from current_date)))
                                and results.recorrencia = '0'
                                and results.ano = extract (year from current_date)::varchar
                            ) OR ( retorno )
                        ) then
                            retorno = true;
                        else
                            retorno = false;
                        end if;
                    end loop;

                return retorno;
            end;
    $$;


ALTER FUNCTION public.verificar_sazonalidade_produto(param_idproduto character varying) OWNER TO systock;

