--
-- TOC entry 549 (class 1259 OID 84229)
-- Name: produtos_compras_categorias_mp_pa_transito; Type: VIEW; Schema: public; Owner: systock
--

CREATE VIEW public.produtos_compras_categorias_mp_pa_transito AS
 WITH ultimas_entradas AS (
         SELECT gf.id_grupo,
            pcmp.id_categoria,
            max(r.data_previsao) AS data_ultima_entrada
           FROM ((public.analise_requisicoes r
             JOIN public.grupo_filial gf ON ((gf.filial = r.filial)))
             JOIN public.produtos_categoria_mp_pa pcmp ON (((pcmp.id_produto_mp)::text = (r.idproduto)::text)))
          GROUP BY gf.id_grupo, pcmp.id_categoria
        ), saldo_residual AS (
         SELECT v.id_grupo,
            v.id_categoria,
            v.estoque_maximo,
            v.ponto_pedido,
            v.tempo_medio_ressuprimento,
            v.cmm_pa_peso,
            v.lote_minimo,
            ue.data_ultima_entrada,
            public.get_estoque_futuro_tempo_ressuprimento_produto_categoria_mp_pa((v.id_grupo)::integer, v.id_categoria, ue.data_ultima_entrada) AS saldo_residual_ultima_entrada
           FROM (public.produtos_compras_categorias_mp_pa v
             JOIN ultimas_entradas ue ON (((ue.id_grupo = v.id_grupo) AND (ue.id_categoria = v.id_categoria))))
          WHERE (v.estoque_transito_peso > (0)::double precision)
        )
 SELECT id_grupo,
    id_categoria,
    ponto_pedido,
    estoque_maximo,
    lote_minimo,
    saldo_residual_ultima_entrada,
        CASE
            WHEN (saldo_residual_ultima_entrada < (ponto_pedido * 0.85)) THEN (estoque_maximo - GREATEST((saldo_residual_ultima_entrada - (((((CURRENT_DATE + tempo_medio_ressuprimento) - data_ultima_entrada) - 1))::numeric * (cmm_pa_peso / 30.0))), (0)::numeric))
            ELSE (0)::numeric
        END AS lote_compras_bruto,
        CASE
            WHEN (saldo_residual_ultima_entrada < (ponto_pedido * 0.85)) THEN public.gerar_lote_embalagem((estoque_maximo - GREATEST((saldo_residual_ultima_entrada - (((((CURRENT_DATE + tempo_medio_ressuprimento) - data_ultima_entrada) - 1))::numeric * (cmm_pa_peso / 30.0))), (0)::numeric)), (lote_minimo)::numeric)
            ELSE (0)::numeric
        END AS lote_compras
   FROM saldo_residual sr;


ALTER VIEW public.produtos_compras_categorias_mp_pa_transito OWNER TO systock;

