            END > (0)::numeric) THEN 'DRP'::text
            WHEN (((a.estoque - (a.consumo_futuro)::numeric) > a.tp_drp) AND ((a.estoque - (a.consumo_futuro)::numeric) <= a.emax_drp)) THEN 'OK'::text
