-- Name: vw_produtos; Type: VIEW; Schema: public; Owner: systock
--

CREATE VIEW public.vw_produtos AS
 SELECT DISTINCT idproduto,
    descricao_produto,
    unidade_medida,
    max(id_solicitacao) AS ultimo_idsolicitacao,
    max(data_solicitacao) AS ultima_solicitacao,
    max(data_entrada) AS ultima_entrada,
    public.gettemporessuprimento(idproduto) AS tempo_ressuprimento,
    public.getdesviopadrao(idproduto) AS desvio_padrao,
    atraso
   FROM public.vw_requisicoes
  GROUP BY idproduto, descricao_produto, unidade_medida, atraso
  ORDER BY idproduto;


